INSERT INTO profiles (id, version, content, big_five, mbti_label, decision_style, tags, summary, quality_score, status, generation_run_id) VALUES
('35f17b0c-a352-4d6c-9524-8a5bac209298', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.65,"extraversion":0.8,"agreeableness":0.8,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.38,"narcissism":0.63,"psychopathy":0.36},"prospect_theory":{"lambda":2.56,"alpha":0.87,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This community manager fills silence reflexively, even when nobody asked it to and reads other people''s discomfort before they voice it. Once things get tense adopts a conviction mainly because the room already has — in the version no one reviews, keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.65},{"slug":"optimism","strength":0.68},{"slug":"bandwagon","strength":0.81},{"slug":"fomo","strength":0.6}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","ipip-neo","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.65,"extraversion":0.8,"agreeableness":0.8,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','ipip-neo','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This community manager fills silence reflexively, even when nobody asked it to and reads other people''s discomfort before they voice it. Once things get tense adopts a conviction mainly because the room already has — in the version no one reviews, keeps score of favors without meaning to.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9825da7f-10fa-43e9-afd0-d7a672aed421', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.33,"extraversion":0.8,"agreeableness":0.73,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.35,"narcissism":0.72,"psychopathy":0.38},"prospect_theory":{"lambda":1.54,"alpha":0.92,"beta":0.94},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, finds it easier to believe something once it stops being a minority view. Otherwise, a steady pairs trader who draws energy from the crowd and wilts when working alone and collects half-finished manifestos and unconventional methods. Needs the room''s approval more than it needs to be right, and across the quiet stretches averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"dunning-kruger","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.33,"extraversion":0.8,"agreeableness":0.73,"neuroticism":0.42}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, finds it easier to believe something once it stops being a minority view. Otherwise, a steady pairs trader who draws energy from the crowd and wilts when working alone and collects half-finished manifestos and unconventional methods. Needs the room''s approval more than it needs to be right, and across the quiet stretches averages down on a name three times in a week.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4659ab53-d2a7-4362-8463-65cd5895b2ba', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.57,"extraversion":0.7,"agreeableness":0.97,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.36,"narcissism":0.55,"psychopathy":0.3},"prospect_theory":{"lambda":2.47,"alpha":0.88,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the safe option quietly expires, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced group-project default leader who would rather lose a point than win an argument badly and dominates the room then wonders why others stayed quiet. Outsources conviction to whoever spoke last with authority, and in the version no one reviews remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.75},{"slug":"authority-bias","strength":0.74},{"slug":"bandwagon","strength":0.76}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.72,"conscientiousness":0.57,"extraversion":0.7,"agreeableness":0.97,"neuroticism":0.51}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the safe option quietly expires, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced group-project default leader who would rather lose a point than win an argument badly and dominates the room then wonders why others stayed quiet. Outsources conviction to whoever spoke last with authority, and in the version no one reviews remembers everyone birthday and no one boundaries.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ba709019-820c-43e0-a82b-e7ae3310040e', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.43,"extraversion":0.87,"agreeableness":0.8,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.34,"narcissism":0.7,"psychopathy":0.32},"prospect_theory":{"lambda":1.35,"alpha":0.82,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced value investor who narrates the plan to whoever is nearby before committing to it. Seeks a second, third, and fourth opinion before committing to anything. Treats established procedure as a first draft to be rewritten. When the walls close in adopts a conviction mainly because the room already has; day to day, calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.84},{"slug":"herd-behavior","strength":0.8},{"slug":"dunning-kruger","strength":0.66},{"slug":"recency","strength":0.58}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.43,"extraversion":0.87,"agreeableness":0.8,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced value investor who narrates the plan to whoever is nearby before committing to it. Seeks a second, third, and fourth opinion before committing to anything. Treats established procedure as a first draft to be rewritten. When the walls close in adopts a conviction mainly because the room already has; day to day, calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3eb54fd2-a8b4-4325-a17d-c5f9721fe49f', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.5,"extraversion":0.76,"agreeableness":0.8,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.34,"narcissism":0.6,"psychopathy":0.32},"prospect_theory":{"lambda":2.43,"alpha":0.86,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A steady community manager: defaults to trust and gives the benefit of the doubt too freely, draws energy from the crowd and wilts when working alone. Trusts the group''s confidence more than its own, and when no one is watching over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.59},{"slug":"bandwagon","strength":0.68},{"slug":"herd-behavior","strength":0.74}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.5,"extraversion":0.76,"agreeableness":0.8,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A steady community manager: defaults to trust and gives the benefit of the doubt too freely, draws energy from the crowd and wilts when working alone. Trusts the group''s confidence more than its own, and when no one is watching over-commits to plans they later dread.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('117584b1-393b-48fc-8791-41dcfe330e46', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.63,"extraversion":0.71,"agreeableness":0.77,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.39,"narcissism":0.54,"psychopathy":0.27},"prospect_theory":{"lambda":2.31,"alpha":0.83,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A steady longtime regular at the same three places: reads other people''s discomfort before they voice it, maintains flawless records nobody asked for. Outsources conviction to whoever spoke last with authority, and without an audience texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.57},{"slug":"bandwagon","strength":0.67},{"slug":"herd-behavior","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.63,"extraversion":0.71,"agreeableness":0.77,"neuroticism":0.57}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A steady longtime regular at the same three places: reads other people''s discomfort before they voice it, maintains flawless records nobody asked for. Outsources conviction to whoever spoke last with authority, and without an audience texts an apology before confirming anyone is upset.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('18007c27-7d62-480d-8dad-f4a6a75e7d6d', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.63,"extraversion":0.86,"agreeableness":0.82,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.38,"narcissism":0.72,"psychopathy":0.28},"prospect_theory":{"lambda":2.25,"alpha":0.9,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Wedding-party diplomat, pronounced in style: narrates the plan to whoever is nearby before committing to it; takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything. When the safe option quietly expires finds it easier to believe something once it stops being a minority view.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"bandwagon","strength":0.8}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.71,"conscientiousness":0.63,"extraversion":0.86,"agreeableness":0.82,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Wedding-party diplomat, pronounced in style: narrates the plan to whoever is nearby before committing to it; takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything. When the safe option quietly expires finds it easier to believe something once it stops being a minority view.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('10bfa46c-5286-477d-bed9-3ed5ca2a5148', 1, '{"big_five":{"openness":0.95,"conscientiousness":0.45,"extraversion":0.88,"agreeableness":0.71,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.4,"narcissism":0.78,"psychopathy":0.34},"prospect_theory":{"lambda":1.34,"alpha":0.9,"beta":0.95},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Zero-DTE options gambler whose defining move is that they reads outside the field for ideas the field itself would reject. Needs the room''s approval more than it needs to be right. Defaults to trust and gives the benefit of the doubt too freely. When cornered, finds it hard to hold a contrarian position once the room disagrees; apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.66},{"slug":"fomo","strength":0.65},{"slug":"herd-behavior","strength":0.77},{"slug":"dunning-kruger","strength":0.58}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.95,"conscientiousness":0.45,"extraversion":0.88,"agreeableness":0.71,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Zero-DTE options gambler whose defining move is that they reads outside the field for ideas the field itself would reject. Needs the room''s approval more than it needs to be right. Defaults to trust and gives the benefit of the doubt too freely. When cornered, finds it hard to hold a contrarian position once the room disagrees; apes the launch before the contract is verified.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c0bfa7be-d470-4540-bf8b-f99d7df817b1', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.42,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.38,"narcissism":0.67,"psychopathy":0.35},"prospect_theory":{"lambda":1.5,"alpha":0.82,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once the exit narrows to one door, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady meme-coin rotator who fills silence reflexively, even when nobody asked it to and would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and in the version no one reviews averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.68},{"slug":"herd-behavior","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.42,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Once the exit narrows to one door, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady meme-coin rotator who fills silence reflexively, even when nobody asked it to and would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and in the version no one reviews averages down on a name three times in a week.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d2c0ac53-875c-4217-a8f6-5d750c3584fb', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.32,"extraversion":0.69,"agreeableness":0.59,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.42,"narcissism":0.6,"psychopathy":0.33},"prospect_theory":{"lambda":1.36,"alpha":0.89,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Retail momentum chaser, pronounced in style: reframes every problem as an excuse to learn a new system; is reliably surprised by deadlines that were never hidden. Trusts the group''s confidence more than its own. In a pinch takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.63},{"slug":"recency","strength":0.6},{"slug":"sunk-cost","strength":0.54},{"slug":"herd-behavior","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.85,"conscientiousness":0.32,"extraversion":0.69,"agreeableness":0.59,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Retail momentum chaser, pronounced in style: reframes every problem as an excuse to learn a new system; is reliably surprised by deadlines that were never hidden. Trusts the group''s confidence more than its own. In a pinch takes the crowd''s confidence as a substitute for its own analysis.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('b5e5153b-a928-4fbe-8f36-ba14045f55b0', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.32,"extraversion":0.77,"agreeableness":0.69,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.41,"narcissism":0.65,"psychopathy":0.35},"prospect_theory":{"lambda":1.32,"alpha":0.8,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A pronounced volatility arbitrageur: reframes every problem as an excuse to learn a new system, treats a plan as a suggestion the moment it is made. Seeks a second, third, and fourth opinion before committing to anything, and without an audience checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.73},{"slug":"recency","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.87,"conscientiousness":0.32,"extraversion":0.77,"agreeableness":0.69,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A pronounced volatility arbitrageur: reframes every problem as an excuse to learn a new system, treats a plan as a suggestion the moment it is made. Seeks a second, third, and fourth opinion before committing to anything, and without an audience checks the P&L blotter forty times before lunch.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
