('a2011847-a251-4ceb-9149-78ec89420d8d', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.31,"extraversion":0.8,"agreeableness":0.66,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.35,"narcissism":0.68,"psychopathy":0.36},"prospect_theory":{"lambda":1.42,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A steady prop-desk scalper: fills silence reflexively, even when nobody asked it to, leaves loose ends and trusts future-self to handle them. Needs the room''s approval more than it needs to be right, and in the version no one reviews keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.7},{"slug":"herd-behavior","strength":0.73},{"slug":"bandwagon","strength":0.7},{"slug":"sunk-cost","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.31,"extraversion":0.8,"agreeableness":0.66,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A steady prop-desk scalper: fills silence reflexively, even when nobody asked it to, leaves loose ends and trusts future-self to handle them. Needs the room''s approval more than it needs to be right, and in the version no one reviews keeps a losing-trade journal they never re-read.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
