('d4063602-c6bb-42bf-b487-575f24cd4688', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.4,"extraversion":0.89,"agreeableness":0.74,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.38,"narcissism":0.74,"psychopathy":0.3},"prospect_theory":{"lambda":1.46,"alpha":0.85,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the safe option quietly expires, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced prop-desk scalper who thinks out loud and recruits an audience for every decision and treats established procedure as a first draft to be rewritten. Needs the room''s approval more than it needs to be right, and when the stakes are trivial keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"dunning-kruger","strength":0.72},{"slug":"optimism","strength":0.56},{"slug":"fomo","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.4,"extraversion":0.89,"agreeableness":0.74,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the safe option quietly expires, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced prop-desk scalper who thinks out loud and recruits an audience for every decision and treats established procedure as a first draft to be rewritten. Needs the room''s approval more than it needs to be right, and when the stakes are trivial keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'efad67da-ca57-4cd