('b1fc465a-764a-491d-afdf-d8a3f9dafc3b', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.27,"extraversion":0.88,"agreeableness":0.74,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.32,"narcissism":0.71,"psychopathy":0.35},"prospect_theory":{"lambda":1.24,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced DeFi yield farmer who narrates the plan to whoever is nearby before committing to it and measures decisions by who they might upset. Needs the room''s approval more than it needs to be right, and on an ordinary week trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.77},{"slug":"sunk-cost","strength":0.61},{"slug":"herd-behavior","strength":0.79},{"slug":"dunning-kruger","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.27,"extraversion":0.88,"agreeableness":0.74,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced DeFi yield farmer who narrates the plan to whoever is nearby before committing to it and measures decisions by who they might upset. Needs the room''s approval more than it needs to be right, and on an ordinary week trusts the chart more than the fundamentals and won''t say why.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0ada3126-e865-4c86-9704-12f6292469ba', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.61,"extraversion":0.7,"agreeableness":0.84,"neuroticism":0.36},"dark_triad":{"machiavellianism":0.39,"narcissism":0.56,"psychopathy":0.35},"prospect_theory":{"lambda":2.25,"alpha":0.88,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the safe option quietly expires, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced longtime regular at the same three places who reads other people''s discomfort before they voice it and checks its own anxiety like a data point instead of obeying it. Trusts the group''s confidence more than its own, and in the version no one reviews remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.68},{"slug":"bandwagon","strength":0.75},{"slug":"herd-behavior","strength":0.71},{"slug":"optimism","strength":0.6}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.73,"conscientiousness":0.61,"extraversion":0.7,"agreeableness":0.84,"neuroticism":0.36}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the safe option quietly expires, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced longtime regular at the same three places who reads other people''s discomfort before they voice it and checks its own anxiety like a data point instead of obeying it. Trusts the group''s confidence more than its own, and in the version no one reviews remembers who didn''t get invited last time.', 0.98, 'approved', 'efad67da-ca57-4cd