('82f8f7b8-4bc6-42ce-9be1-559c12bfce4c', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.76,"extraversion":0.81,"agreeableness":0.83,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.47,"narcissism":0.67,"psychopathy":0.27},"prospect_theory":{"lambda":2.45,"alpha":0.88,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The friend who always drives whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Outsources conviction to whoever spoke last with authority. Thinks out loud and recruits an audience for every decision. When the number turns red, finds it easier to believe something once it stops being a minority view; texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.77},{"slug":"endowment","strength":0.57},{"slug":"herd-behavior","strength":0.75}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.76,"extraversion":0.81,"agreeableness":0.83,"neuroticism":0.49}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The friend who always drives whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Outsources conviction to whoever spoke last with authority. Thinks out loud and recruits an audience for every decision. When the number turns red, finds it easier to believe something once it stops being a minority view; texts an apology before confirming anyone is upset.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9a12e78a-9d7a-4750-82b1-d4b2c19e0a31', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.64,"extraversion":0.7,"agreeableness":0.83,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.41,"narcissism":0.6,"psychopathy":0.36},"prospect_theory":{"lambda":2.48,"alpha":0.93,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A steady family peacemaker: measures decisions by who they might upset, treats established procedure as a first draft to be rewritten. Circles back to ask what someone else would do even after deciding, and left to their own devices reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.64},{"slug":"bandwagon","strength":0.75},{"slug":"authority-bias","strength":0.57}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.64,"extraversion":0.7,"agreeableness":0.83,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A steady family peacemaker: measures decisions by who they might upset, treats established procedure as a first draft to be rewritten. Circles back to ask what someone else would do even after deciding, and left to their own devices reads the room then performs to it.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('02062023-271f-4963-8c48-0606e18cc12b', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.56,"extraversion":0.7,"agreeableness":0.78,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.39,"narcissism":0.51,"psychopathy":0.33},"prospect_theory":{"lambda":2.28,"alpha":0.87,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A steady newcomer welcomer: reads other people''s discomfort before they voice it, sleeps fine the night before the big call. Circles back to ask what someone else would do even after deciding, and in the parts nobody grades remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"herd-behavior","strength":0.62}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.55,"conscientiousness":0.56,"extraversion":0.7,"agreeableness":0.78,"neuroticism":0.38}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A steady newcomer welcomer: reads other people''s discomfort before they voice it, sleeps fine the night before the big call. Circles back to ask what someone else would do even after deciding, and in the parts nobody grades remembers who didn''t get invited last time.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('1b4f7342-f54c-4148-b25b-864b06bba499', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.48,"extraversion":0.71,"agreeableness":0.76,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.36,"narcissism":0.6,"psychopathy":0.29},"prospect_theory":{"lambda":1.5,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Bonding-curve sniper, steady in style: would rather lose a point than win an argument badly; draws energy from the crowd and wilts when working alone. Circles back to ask what someone else would do even after deciding. In a pinch jumps into whatever everyone else already seems to be winning at.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.66},{"slug":"herd-behavior","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.48,"extraversion":0.71,"agreeableness":0.76,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Bonding-curve sniper, steady in style: would rather lose a point than win an argument badly; draws energy from the crowd and wilts when working alone. Circles back to ask what someone else would do even after deciding. In a pinch jumps into whatever everyone else already seems to be winning at.', 0.89, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3bcca5da-66ff-446e-8f4e-bbaa0b0e6e09', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.36,"extraversion":0.82,"agreeableness":0.7,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.37,"narcissism":0.73,"psychopathy":0.34},"prospect_theory":{"lambda":1.48,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A steady penny-stock gambler: dominates the room then wonders why others stayed quiet, collects half-finished manifestos and unconventional methods. Needs the room''s approval more than it needs to be right, and when the pressure is off checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.68},{"slug":"bandwagon","strength":0.75},{"slug":"sunk-cost","strength":0.65},{"slug":"dunning-kruger","strength":0.61}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.36,"extraversion":0.82,"agreeableness":0.7,"neuroticism":0.5}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A steady penny-stock gambler: dominates the room then wonders why others stayed quiet, collects half-finished manifestos and unconventional methods. Needs the room''s approval more than it needs to be right, and when the pressure is off checks the P&L blotter forty times before lunch.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('7a4f79ef-6bf7-4be9-9ec8-8a92daef3988', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.43,"extraversion":0.76,"agreeableness":0.73,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.34,"narcissism":0.58,"psychopathy":0.28},"prospect_theory":{"lambda":1.53,"alpha":0.8,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once things get tense, adopts a conviction mainly because the room already has. Otherwise, a steady DeFi yield farmer who thinks out loud and recruits an audience for every decision and defaults to trust and gives the benefit of the doubt too freely. Circles back to ask what someone else would do even after deciding, and day to day calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.54},{"slug":"fomo","strength":0.61},{"slug":"bandwagon","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.65,"conscientiousness":0.43,"extraversion":0.76,"agreeableness":0.73,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Once things get tense, adopts a conviction mainly because the room already has. Otherwise, a steady DeFi yield farmer who thinks out loud and recruits an audience for every decision and defaults to trust and gives the benefit of the doubt too freely. Circles back to ask what someone else would do even after deciding, and day to day calls a 90% drawdown a long-term hold.', 0.9, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a9bef9b0-c362-4ae3-a380-f680ddf9c57f', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.54,"extraversion":0.85,"agreeableness":0.8,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.33,"narcissism":0.74,"psychopathy":0.3},"prospect_theory":{"lambda":2.33,"alpha":0.85,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This longtime regular at the same three places thinks out loud and recruits an audience for every decision and measures decisions by who they might upset. In a pinch finds it hard to hold a contrarian position once the room disagrees — on a slow afternoon, remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"herd-behavior","strength":0.83}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","cognition","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.54,"extraversion":0.85,"agreeableness":0.8,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','cognition','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This longtime regular at the same three places thinks out loud and recruits an audience for every decision and measures decisions by who they might upset. In a pinch finds it hard to hold a contrarian position once the room disagrees — on a slow afternoon, remembers everyone birthday and no one boundaries.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('1312c315-68a4-4fde-b6de-dd0bfb7de767', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.42,"extraversion":0.77,"agreeableness":0.64,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.38,"narcissism":0.64,"psychopathy":0.28},"prospect_theory":{"lambda":1.57,"alpha":0.91,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady index-fund holdout who fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Gets bored of the proven method exactly when it starts working. Under pressure takes the crowd''s confidence as a substitute for its own analysis; in the unglamorous middle of things, trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.69},{"slug":"dunning-kruger","strength":0.56},{"slug":"fomo","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.42,"extraversion":0.77,"agreeableness":0.64,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady index-fund holdout who fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Gets bored of the proven method exactly when it starts working. Under pressure takes the crowd''s confidence as a substitute for its own analysis; in the unglamorous middle of things, trusts the chart more than the fundamentals and won''t say why.', 0.9, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9d0b0fe6-3277-4086-88aa-709b6645e12f', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.54,"extraversion":0.83,"agreeableness":0.63,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.39,"narcissism":0.7,"psychopathy":0.29},"prospect_theory":{"lambda":1.52,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Quant researcher whose defining move is that they reads outside the field for ideas the field itself would reject. Feels the weight of a decision lighten the moment someone else co-signs it. Draws energy from the crowd and wilts when working alone. When the number turns red, adopts a conviction mainly because the room already has; keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.68},{"slug":"recency","strength":0.6},{"slug":"optimism","strength":0.61},{"slug":"fomo","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.83,"conscientiousness":0.54,"extraversion":0.83,"agreeableness":0.63,"neuroticism":0.56}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Quant researcher whose defining move is that they reads outside the field for ideas the field itself would reject. Feels the weight of a decision lighten the moment someone else co-signs it. Draws energy from the crowd and wilts when working alone. When the number turns red, adopts a conviction mainly because the room already has; keeps a losing-trade journal they never re-read.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
