('05fb2ffe-a5b4-4a0c-86bf-2c7eab35856d', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.4,"extraversion":0.84,"agreeableness":0.54,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.42,"narcissism":0.65,"psychopathy":0.36},"prospect_theory":{"lambda":1.47,"alpha":0.85,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once the exit narrows to one door, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced volatility arbitrageur who recharges by being around people, not away from them and chases novel frameworks and abandons them once the novelty fades. Waits for a permission that never quite arrives, and without an audience exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.64},{"slug":"herd-behavior","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.4,"extraversion":0.84,"agreeableness":0.54,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Once the exit narrows to one door, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced volatility arbitrageur who recharges by being around people, not away from them and chases novel frameworks and abandons them once the novelty fades. Waits for a permission that never quite arrives, and without an audience exits winners at the first green candle.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c8ab85ee-8c13-4c69-bcc6-8b25d61a9f50', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.36,"extraversion":0.97,"agreeableness":0.7,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.34,"narcissism":0.88,"psychopathy":0.31},"prospect_theory":{"lambda":1.56,"alpha":0.87,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When cornered, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced volatility arbitrageur who thinks out loud and recruits an audience for every decision and is reliably surprised by deadlines that were never hidden. Feels the weight of a decision lighten the moment someone else co-signs it, and as a rule backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.82},{"slug":"herd-behavior","strength":0.87},{"slug":"fomo","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.86,"conscientiousness":0.36,"extraversion":0.97,"agreeableness":0.7,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When cornered, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced volatility arbitrageur who thinks out loud and recruits an audience for every decision and is reliably surprised by deadlines that were never hidden. Feels the weight of a decision lighten the moment someone else co-signs it, and as a rule backtests for months but front-runs the model on impulse.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
