('c24310bf-fecb-42f5-997d-6b5acc97b531', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.49,"extraversion":0.91,"agreeableness":0.71,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.36,"narcissism":0.71,"psychopathy":0.25},"prospect_theory":{"lambda":1.53,"alpha":0.83,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This perps degen dominates the room then wonders why others stayed quiet and chases novel frameworks and abandons them once the novelty fades. In a pinch takes the crowd''s confidence as a substitute for its own analysis — in the routine of it, talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.72},{"slug":"dunning-kruger","strength":0.67},{"slug":"fomo","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.49,"extraversion":0.91,"agreeableness":0.71,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This perps degen dominates the room then wonders why others stayed quiet and chases novel frameworks and abandons them once the novelty fades. In a pinch takes the crowd''s confidence as a substitute for its own analysis — in the routine of it, talks in win rate and never mentions size.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bf3a18b6-69bb-4764-8860-a2b9b36cf4ce', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.61,"extraversion":0.76,"agreeableness":0.79,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.36,"narcissism":0.6,"psychopathy":0.27},"prospect_theory":{"lambda":2.54,"alpha":0.85,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady family peacemaker who measures decisions by who they might upset. Waits for a permission that never quite arrives. Chases novel frameworks and abandons them once the novelty fades. When the safe option quietly expires abandons a private read the instant the crowd leans the other way; on a slow afternoon, laughs first to test whether the room is safe to laugh.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.57},{"slug":"herd-behavior","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.61,"extraversion":0.76,"agreeableness":0.79,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady family peacemaker who measures decisions by who they might upset. Waits for a permission that never quite arrives. Chases novel frameworks and abandons them once the novelty fades. When the safe option quietly expires abandons a private read the instant the crowd leans the other way; on a slow afternoon, laughs first to test whether the room is safe to laugh.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('595e6027-749b-45c2-9814-50ccb0402a3a', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.58,"extraversion":0.7,"agreeableness":0.95,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.35,"narcissism":0.57,"psychopathy":0.29},"prospect_theory":{"lambda":2.44,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced peer mentor who defaults to trust and gives the benefit of the doubt too freely. Needs the room''s approval more than it needs to be right. Dominates the room then wonders why others stayed quiet. When the safe option quietly expires finds it hard to hold a contrarian position once the room disagrees; on an ordinary week, mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"endowment","strength":0.62}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.58,"extraversion":0.7,"agreeableness":0.95,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced peer mentor who defaults to trust and gives the benefit of the doubt too freely. Needs the room''s approval more than it needs to be right. Dominates the room then wonders why others stayed quiet. When the safe option quietly expires finds it hard to hold a contrarian position once the room disagrees; on an ordinary week, mediates conflicts they secretly started.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6cb5766e-1958-412f-bd74-d26ef11a2eb9', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.66,"extraversion":0.8,"agreeableness":0.87,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.39,"narcissism":0.68,"psychopathy":0.3},"prospect_theory":{"lambda":2.41,"alpha":0.91,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Group-project default leader, pronounced in style: absorbs conflict to keep the peace, often at their own cost; draws energy from the crowd and wilts when working alone. Outsources conviction to whoever spoke last with authority. As soon as real money or reputation is on the line abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.81},{"slug":"endowment","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.66,"extraversion":0.8,"agreeableness":0.87,"neuroticism":0.47}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Group-project default leader, pronounced in style: absorbs conflict to keep the peace, often at their own cost; draws energy from the crowd and wilts when working alone. Outsources conviction to whoever spoke last with authority. As soon as real money or reputation is on the line abandons a private read the instant the crowd leans the other way.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6378b66a-a750-4226-8526-f0d646f0ec67', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.36,"extraversion":0.8,"agreeableness":0.79,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.36,"narcissism":0.61,"psychopathy":0.35},"prospect_theory":{"lambda":1.5,"alpha":0.8,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Crypto day-trader whose defining move is that they treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it. Apologizes first in disputes regardless of fault. The moment risk appears, abandons a private read the instant the crowd leans the other way; talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.79},{"slug":"bandwagon","strength":0.72},{"slug":"fomo","strength":0.74},{"slug":"sunk-cost","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.64,"conscientiousness":0.36,"extraversion":0.8,"agreeableness":0.79,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Crypto day-trader whose defining move is that they treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it. Apologizes first in disputes regardless of fault. The moment risk appears, abandons a private read the instant the crowd leans the other way; talks in win rate and never mentions size.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('03246316-fe4f-4f20-a9cf-8bc11d287fff', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.67,"extraversion":0.64,"agreeableness":0.76,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.46,"narcissism":0.49,"psychopathy":0.27},"prospect_theory":{"lambda":2.54,"alpha":0.96,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This the one who remembers everyone''s order reads other people''s discomfort before they voice it and plans in exhaustive detail and resents any deviation. The moment it stops being hypothetical adopts a conviction mainly because the room already has — in the routine of it, remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"bandwagon","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.67,"extraversion":0.64,"agreeableness":0.76,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This the one who remembers everyone''s order reads other people''s discomfort before they voice it and plans in exhaustive detail and resents any deviation. The moment it stops being hypothetical adopts a conviction mainly because the room already has — in the routine of it, remembers everyone birthday and no one boundaries.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6734f0c5-1005-4050-83f4-e09b3505cfe0', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.41,"extraversion":0.81,"agreeableness":0.62,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.4,"narcissism":0.65,"psychopathy":0.3},"prospect_theory":{"lambda":1.37,"alpha":0.87,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady pairs trader who fills silence reflexively, even when nobody asked it to. Needs the room''s approval more than it needs to be right. Would rather lose a point than win an argument badly. When the safe option quietly expires finds it hard to hold a contrarian position once the room disagrees; on an ordinary week, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"herd-behavior","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.41,"extraversion":0.81,"agreeableness":0.62,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady pairs trader who fills silence reflexively, even when nobody asked it to. Needs the room''s approval more than it needs to be right. Would rather lose a point than win an argument badly. When the safe option quietly expires finds it hard to hold a contrarian position once the room disagrees; on an ordinary week, treats a green week as proof of skill and a red one as proof of bad luck.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('80f6b341-6a47-483e-8dff-d5becf17810a', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.77,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.34,"narcissism":0.64,"psychopathy":0.37},"prospect_theory":{"lambda":1.57,"alpha":0.9,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Quant researcher, steady in style: recharges by being around people, not away from them; gets bored of the proven method exactly when it starts working. Trusts the group''s confidence more than its own. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.6},{"slug":"sunk-cost","strength":0.69},{"slug":"dunning-kruger","strength":0.7},{"slug":"herd-behavior","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.77,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Quant researcher, steady in style: recharges by being around people, not away from them; gets bored of the proven method exactly when it starts working. Trusts the group''s confidence more than its own. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('565961da-1559-47bf-a24b-c1a41c01ed3c', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.37,"extraversion":0.81,"agreeableness":0.84,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.37,"narcissism":0.68,"psychopathy":0.31},"prospect_theory":{"lambda":1.24,"alpha":0.87,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under pressure, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced pairs trader who defaults to trust and gives the benefit of the doubt too freely and fills silence reflexively, even when nobody asked it to. Trusts the group''s confidence more than its own, and day to day keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.82},{"slug":"dunning-kruger","strength":0.63},{"slug":"fomo","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.37,"extraversion":0.81,"agreeableness":0.84,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under pressure, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced pairs trader who defaults to trust and gives the benefit of the doubt too freely and fills silence reflexively, even when nobody asked it to. Trusts the group''s confidence more than its own, and day to day keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8b9874fe-f04c-4b8c-a934-da0567d6e372', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.64,"extraversion":0.8,"agreeableness":0.73,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.42,"narcissism":0.64,"psychopathy":0.31},"prospect_theory":{"lambda":2.4,"alpha":0.91,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A steady group-chat ringleader: treats a quiet room as a problem to be solved, reads other people''s discomfort before they voice it. Needs the room''s approval more than it needs to be right, and in the routine of it remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.66},{"slug":"optimism","strength":0.58},{"slug":"bandwagon","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","risk","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.64,"extraversion":0.8,"agreeableness":0.73,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','risk','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A steady group-chat ringleader: treats a quiet room as a problem to be solved, reads other people''s discomfort before they voice it. Needs the room''s approval more than it needs to be right, and in the routine of it remembers who didn''t get invited last time.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('db849dd1-70c9-4aa7-b3d4-259f9784ec1b', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.4,"extraversion":0.78,"agreeableness":0.72,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.36,"narcissism":0.56,"psychopathy":0.32},"prospect_theory":{"lambda":1.3,"alpha":0.87,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment risk appears, finds it easier to believe something once it stops being a minority view. Otherwise, a steady index-fund holdout who narrates the plan to whoever is nearby before committing to it and reads a single setback as evidence of collapse. Circles back to ask what someone else would do even after deciding, and when the pressure is off backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.61},{"slug":"herd-behavior","strength":0.65},{"slug":"fomo","strength":0.69},{"slug":"bandwagon","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.4,"extraversion":0.78,"agreeableness":0.72,"neuroticism":0.68}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment risk appears, finds it easier to believe something once it stops being a minority view. Otherwise, a steady index-fund holdout who narrates the plan to whoever is nearby before committing to it and reads a single setback as evidence of collapse. Circles back to ask what someone else would do even after deciding, and when the pressure is off backtests for months but front-runs the model on impulse.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3b232ff6-3c78-4998-8e18-a563a98295a5', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.66,"extraversion":0.71,"agreeableness":0.75,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.41,"narcissism":0.61,"psychopathy":0.31},"prospect_theory":{"lambda":2.57,"alpha":0.94,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The one who remembers everyone''s order, steady in style: takes on other people''s problems as if they were their own; builds in buffer time and then fills the buffer with more work. Trusts the group''s confidence more than its own. As soon as real money or reputation is on the line abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.66},{"slug":"herd-behavior","strength":0.72},{"slug":"fomo","strength":0.56}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.66,"extraversion":0.71,"agreeableness":0.75,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The one who remembers everyone''s order, steady in style: takes on other people''s problems as if they were their own; builds in buffer time and then fills the buffer with more work. Trusts the group''s confidence more than its own. As soon as real money or reputation is on the line abandons a private read the instant the crowd leans the other way.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2e0abf00-056a-4e20-81b1-8dcecc453c48', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.46,"extraversion":0.78,"agreeableness":0.7,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.36,"narcissism":0.61,"psychopathy":0.28},"prospect_theory":{"lambda":1.33,"alpha":0.82,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When there is no clean exit, finds it easier to believe something once it stops being a minority view. Otherwise, a steady pairs trader who gets bored of the proven method exactly when it starts working and defaults to trust and gives the benefit of the doubt too freely. Seeks a second, third, and fourth opinion before committing to anything, and in the unglamorous middle of things confuses a bull market for a trading edge.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"dunning-kruger","strength":0.64},{"slug":"recency","strength":0.58},{"slug":"herd-behavior","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.46,"extraversion":0.78,"agreeableness":0.7,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When there is no clean exit, finds it easier to believe something once it stops being a minority view. Otherwise, a steady pairs trader who gets bored of the proven method exactly when it starts working and defaults to trust and gives the benefit of the doubt too freely. Seeks a second, third, and fourth opinion before committing to anything, and in the unglamorous middle of things confuses a bull market for a trading edge.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ef534b2a-6340-4434-a832-fe68247bd1df', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.36,"extraversion":0.88,"agreeableness":0.79,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.33,"narcissism":0.71,"psychopathy":0.37},"prospect_theory":{"lambda":1.43,"alpha":0.87,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Commodities speculator, pronounced in style: thinks out loud and recruits an audience for every decision; treats a plan as a suggestion the moment it is made. Circles back to ask what someone else would do even after deciding. Once the exit narrows to one door gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"sunk-cost","strength":0.67},{"slug":"bandwagon","strength":0.83},{"slug":"fomo","strength":0.65},{"slug":"dunning-kruger","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.36,"extraversion":0.88,"agreeableness":0.79,"neuroticism":0.48}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Commodities speculator, pronounced in style: thinks out loud and recruits an audience for every decision; treats a plan as a suggestion the moment it is made. Circles back to ask what someone else would do even after deciding. Once the exit narrows to one door gains confidence in a position in proportion to how many others hold it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bfa965db-a799-47ed-b52d-e04db45ef4cf', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.39,"extraversion":0.83,"agreeableness":0.62,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.39,"narcissism":0.66,"psychopathy":0.36},"prospect_theory":{"lambda":1.29,"alpha":0.91,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Pairs trader, steady in style: dominates the room then wonders why others stayed quiet; apologizes first in disputes regardless of fault. Trusts the group''s confidence more than its own. Under pressure abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.66},{"slug":"herd-behavior","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.39,"extraversion":0.83,"agreeableness":0.62,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Pairs trader, steady in style: dominates the room then wonders why others stayed quiet; apologizes first in disputes regardless of fault. Trusts the group''s confidence more than its own. Under pressure abandons a private read the instant the crowd leans the other way.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('fdb5ba93-6147-48f8-894a-18926912f580', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.59,"extraversion":0.76,"agreeableness":0.89,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.36,"narcissism":0.66,"psychopathy":0.32},"prospect_theory":{"lambda":2.38,"alpha":0.85,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"As soon as real money or reputation is on the line, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced social-media strategist who apologizes first in disputes regardless of fault and would rather invent a worse tool than use someone else''s good one. Waits for a permission that never quite arrives, and left to their own devices defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.6},{"slug":"herd-behavior","strength":0.74},{"slug":"authority-bias","strength":0.61},{"slug":"endowment","strength":0.65}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.59,"extraversion":0.76,"agreeableness":0.89,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'As soon as real money or reputation is on the line, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced social-media strategist who apologizes first in disputes regardless of fault and would rather invent a worse tool than use someone else''s good one. Waits for a permission that never quite arrives, and left to their own devices defuses tension with a joke that lands most of the time.', 0.97, 'approved', 'efad67da-ca5