('4edf9aab-44dd-48e1-8669-6067ffffd954', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.31,"extraversion":0.88,"agreeableness":0.58,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.39,"narcissism":0.74,"psychopathy":0.33},"prospect_theory":{"lambda":1.49,"alpha":0.84,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Algorithmic market-maker, pronounced in style: narrates the plan to whoever is nearby before committing to it; treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority. As soon as real money or reputation is on the line cannot see the gap in its own knowledge from inside the gap.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.65},{"slug":"fomo","strength":0.64},{"slug":"dunning-kruger","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.31,"extraversion":0.88,"agreeableness":0.58,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Algorithmic market-maker, pronounced in style: narrates the plan to whoever is nearby before committing to it; treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority. As soon as real money or reputation is on the line cannot see the gap in its own knowledge from inside the gap.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4696472d-8939-49d2-bc23-0cee6d7fd126', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.54,"extraversion":0.71,"agreeableness":0.9,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.32,"narcissism":0.56,"psychopathy":0.27},"prospect_theory":{"lambda":2.54,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced newcomer welcomer who measures decisions by who they might upset. Circles back to ask what someone else would do even after deciding. Would rather invent a worse tool than use someone else''s good one. When the downside gets concrete finds it hard to hold a contrarian position once the room disagrees; in the parts nobody grades, reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.66},{"slug":"herd-behavior","strength":0.76},{"slug":"authority-bias","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.74,"conscientiousness":0.54,"extraversion":0.71,"agreeableness":0.9,"neuroticism":0.56}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced newcomer welcomer who measures decisions by who they might upset. Circles back to ask what someone else would do even after deciding. Would rather invent a worse tool than use someone else''s good one. When the downside gets concrete finds it hard to hold a contrarian position once the room disagrees; in the parts nobody grades, reads the room then performs to it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ae326048-a7c5-42e1-b21d-784da5ba0027', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.65,"extraversion":0.81,"agreeableness":0.91,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.41,"narcissism":0.66,"psychopathy":0.27},"prospect_theory":{"lambda":2.28,"alpha":0.94,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This nonprofit convener takes on other people''s problems as if they were their own and builds in buffer time and then fills the buffer with more work. When there is no clean exit abandons a private read the instant the crowd leans the other way — once the urgency drains out, over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"endowment","strength":0.61},{"slug":"bandwagon","strength":0.77},{"slug":"herd-behavior","strength":0.78}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.57,"conscientiousness":0.65,"extraversion":0.81,"agreeableness":0.91,"neuroticism":0.51}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This nonprofit convener takes on other people''s problems as if they were their own and builds in buffer time and then fills the buffer with more work. When there is no clean exit abandons a private read the instant the crowd leans the other way — once the urgency drains out, over-explains a boundary rather than just stating it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('7506c44a-0032-42e2-98ed-09fe83713117', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.47,"extraversion":0.73,"agreeableness":0.84,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.33,"narcissism":0.59,"psychopathy":0.31},"prospect_theory":{"lambda":2.34,"alpha":0.86,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced team captain who apologizes first in disputes regardless of fault. Outsources conviction to whoever spoke last with authority. Draws energy from the crowd and wilts when working alone. When the stakes rise finds it easier to believe something once it stops being a minority view; when no one is watching, defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.7},{"slug":"endowment","strength":0.58},{"slug":"authority-bias","strength":0.58}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.71,"conscientiousness":0.47,"extraversion":0.73,"agreeableness":0.84,"neuroticism":0.42}'::jsonb, 'ENFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced team captain who apologizes first in disputes regardless of fault. Outsources conviction to whoever spoke last with authority. Draws energy from the crowd and wilts when working alone. When the stakes rise finds it easier to believe something once it stops being a minority view; when no one is watching, defuses tension with a joke that lands most of the time.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('536515d5-7b8a-414b-ba18-909920e4eb92', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.64,"extraversion":0.7,"agreeableness":0.94,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.35,"narcissism":0.6,"psychopathy":0.33},"prospect_theory":{"lambda":2.27,"alpha":0.86,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A pronounced social-media strategist: defaults to trust and gives the benefit of the doubt too freely, over-prepares to the point of diminishing returns. Waits for a permission that never quite arrives, and without an audience remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.74},{"slug":"herd-behavior","strength":0.7}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.64,"extraversion":0.7,"agreeableness":0.94,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A pronounced social-media strategist: defaults to trust and gives the benefit of the doubt too freely, over-prepares to the point of diminishing returns. Waits for a permission that never quite arrives, and without an audience remembers everyone birthday and no one boundaries.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3779cc44-8499-448f-9b6a-49879b8a76de', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.7,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.4,"narcissism":0.71,"psychopathy":0.33},"prospect_theory":{"lambda":1.48,"alpha":0.8,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment it stops being hypothetical, adopts a conviction mainly because the room already has. Otherwise, a pronounced prop-desk scalper who thinks out loud and recruits an audience for every decision and carries yesterday''s stress into today''s unrelated decision. Seeks a second, third, and fourth opinion before committing to anything, and in the unglamorous middle of things confuses a bull market for a trading edge.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.71},{"slug":"herd-behavior","strength":0.77},{"slug":"bandwagon","strength":0.78},{"slug":"fomo","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.7,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment it stops being hypothetical, adopts a conviction mainly because the room already has. Otherwise, a pronounced prop-desk scalper who thinks out loud and recruits an audience for every decision and carries yesterday''s stress into today''s unrelated decision. Seeks a second, third, and fourth opinion before committing to anything, and in the unglamorous middle of things confuses a bull market for a trading edge.', 0.98, 'approved', 'efad67da-ca57-4cd6-