('a8d50074-5b5d-4a9a-874e-7d7e97a7cc0b', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.36,"extraversion":0.87,"agreeableness":0.73,"neuroticism":0.71},"dark_triad":{"machiavellianism":0.4,"narcissism":0.66,"psychopathy":0.37},"prospect_theory":{"lambda":1.23,"alpha":0.86,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Waits for a permission that never quite arrives. This DeFi yield farmer recharges by being around people, not away from them and is reliably surprised by deadlines that were never hidden. The moment risk appears finds it hard to hold a contrarian position once the room disagrees — day to day, sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.73},{"slug":"bandwagon","strength":0.72}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.36,"extraversion":0.87,"agreeableness":0.73,"neuroticism":0.71}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Waits for a permission that never quite arrives. This DeFi yield farmer recharges by being around people, not away from them and is reliably surprised by deadlines that were never hidden. The moment risk appears finds it hard to hold a contrarian position once the room disagrees — day to day, sets alerts for a coin they already checked a minute ago.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('18190aee-e4f2-40d5-a4e2-d6a9dd5814be', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.34,"extraversion":0.91,"agreeableness":0.69,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.4,"narcissism":0.74,"psychopathy":0.37},"prospect_theory":{"lambda":1.53,"alpha":0.89,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Meme-coin rotator whose defining move is that they thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it. Reads other people''s discomfort before they voice it. When cornered, adopts a conviction mainly because the room already has; talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.69},{"slug":"fomo","strength":0.72},{"slug":"bandwagon","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.34,"extraversion":0.91,"agreeableness":0.69,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Meme-coin rotator whose defining move is that they thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it. Reads other people''s discomfort before they voice it. When cornered, adopts a conviction mainly because the room already has; talks in win rate and never mentions size.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('14e57204-b452-40b3-9a12-11a55695a14c', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.41,"extraversion":0.89,"agreeableness":0.81,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.38,"narcissism":0.72,"psychopathy":0.31},"prospect_theory":{"lambda":1.5,"alpha":0.87,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This retail momentum chaser narrates the plan to whoever is nearby before committing to it and reads other people''s discomfort before they voice it. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it — in the version no one reviews, apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"bandwagon","strength":0.84},{"slug":"fomo","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.82,"conscientiousness":0.41,"extraversion":0.89,"agreeableness":0.81,"neuroticism":0.68}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This retail momentum chaser narrates the plan to whoever is nearby before committing to it and reads other people''s discomfort before they voice it. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it — in the version no one reviews, apes the launch before the contract is verified.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c293f924-9c79-4a11-86f8-3dc6d77cc980', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.31,"extraversion":0.83,"agreeableness":0.7,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.36,"narcissism":0.65,"psychopathy":0.35},"prospect_theory":{"lambda":1.35,"alpha":0.9,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady liquidation-bot operator who thinks out loud and recruits an audience for every decision. Circles back to ask what someone else would do even after deciding. Treats a plan as a suggestion the moment it is made. Once things get tense abandons a private read the instant the crowd leans the other way; on a slow afternoon, sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"bandwagon","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.31,"extraversion":0.83,"agreeableness":0.7,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady liquidation-bot operator who thinks out loud and recruits an audience for every decision. Circles back to ask what someone else would do even after deciding. Treats a plan as a suggestion the moment it is made. Once things get tense abandons a private read the instant the crowd leans the other way; on a slow afternoon, sets alerts for a coin they already checked a minute ago.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f8f059dc-dfa1-4c51-987d-6cd6ff6a56d5', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.39,"extraversion":0.76,"agreeableness":0.72,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.37,"narcissism":0.61,"psychopathy":0.34},"prospect_theory":{"lambda":1.41,"alpha":0.82,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This crypto day-trader fills silence reflexively, even when nobody asked it to and would rather lose a point than win an argument badly. Under a deadline finds it easier to believe something once it stops being a minority view — when the pressure is off, exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.64},{"slug":"dunning-kruger","strength":0.6},{"slug":"bandwagon","strength":0.7},{"slug":"sunk-cost","strength":0.58}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.66,"conscientiousness":0.39,"extraversion":0.76,"agreeableness":0.72,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This crypto day-trader fills silence reflexively, even when nobody asked it to and would rather lose a point than win an argument badly. Under a deadline finds it easier to believe something once it stops being a minority view — when the pressure is off, exits winners at the first green candle.', 0.88, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9ae40268-1f0f-49b9-ab5f-32993450a5c8', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.49,"extraversion":0.9,"agreeableness":0.64,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.37,"narcissism":0.7,"psychopathy":0.29},"prospect_theory":{"lambda":1.36,"alpha":0.8,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Commodities speculator, pronounced in style: fills silence reflexively, even when nobody asked it to; gets bored of the proven method exactly when it starts working. Outsources conviction to whoever spoke last with authority. Under a deadline adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.74},{"slug":"optimism","strength":0.62},{"slug":"dunning-kruger","strength":0.67},{"slug":"herd-behavior","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.49,"extraversion":0.9,"agreeableness":0.64,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Commodities speculator, pronounced in style: fills silence reflexively, even when nobody asked it to; gets bored of the proven method exactly when it starts working. Outsources conviction to whoever spoke last with authority. Under a deadline adopts a conviction mainly because the room already has.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3d056edf-62ea-4595-b44e-e5a3d2860b62', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.54,"extraversion":0.68,"agreeableness":0.81,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.34,"narcissism":0.53,"psychopathy":0.31},"prospect_theory":{"lambda":2.34,"alpha":0.92,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Family peacemaker whose defining move is that they apologizes first in disputes regardless of fault. Needs the room''s approval more than it needs to be right. Thinks out loud and recruits an audience for every decision. The moment risk appears, abandons a private read the instant the crowd leans the other way; over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.57},{"slug":"endowment","strength":0.64},{"slug":"herd-behavior","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.54,"extraversion":0.68,"agreeableness":0.81,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Family peacemaker whose defining move is that they apologizes first in disputes regardless of fault. Needs the room''s approval more than it needs to be right. Thinks out loud and recruits an audience for every decision. The moment risk appears, abandons a private read the instant the crowd leans the other way; over-explains a boundary rather than just stating it.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('98e4e30b-f315-403c-96a5-4492a326abc8', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.37,"extraversion":0.79,"agreeableness":0.73,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.33,"narcissism":0.68,"psychopathy":0.36},"prospect_theory":{"lambda":1.56,"alpha":0.89,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady penny-stock gambler who narrates the plan to whoever is nearby before committing to it. Circles back to ask what someone else would do even after deciding. Chases novel frameworks and abandons them once the novelty fades. When cornered finds it easier to believe something once it stops being a minority view; day to day, calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"fomo","strength":0.61}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.37,"extraversion":0.79,"agreeableness":0.73,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady penny-stock gambler who narrates the plan to whoever is nearby before committing to it. Circles back to ask what someone else would do even after deciding. Chases novel frameworks and abandons them once the novelty fades. When cornered finds it easier to believe something once it stops being a minority view; day to day, calls a 90% drawdown a long-term hold.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2fae134d-ca1d-4b24-ba3d-c1472367de25', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.39,"extraversion":0.74,"agreeableness":0.7,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.33,"narcissism":0.61,"psychopathy":0.31},"prospect_theory":{"lambda":1.42,"alpha":0.87,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Dividend-yield chaser, steady in style: chases novel frameworks and abandons them once the novelty fades; defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives. When the number turns red extrapolates the last data point into a permanent trend.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.62},{"slug":"recency","strength":0.68},{"slug":"dunning-kruger","strength":0.6},{"slug":"bandwagon","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.39,"extraversion":0.74,"agreeableness":0.7,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Dividend-yield chaser, steady in style: chases novel frameworks and abandons them once the novelty fades; defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives. When the number turns red extrapolates the last data point into a permanent trend.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('5917c1f9-4359-478f-9474-92881596a491', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.69,"extraversion":0.77,"agreeableness":0.83,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.43,"narcissism":0.58,"psychopathy":0.32},"prospect_theory":{"lambda":2.45,"alpha":0.93,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady unofficial group historian who reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Narrates the plan to whoever is nearby before committing to it. The moment risk appears finds it hard to hold a contrarian position once the room disagrees; in the routine of it, reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.67},{"slug":"herd-behavior","strength":0.7},{"slug":"endowment","strength":0.59}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.69,"extraversion":0.77,"agreeableness":0.83,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady unofficial group historian who reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Narrates the plan to whoever is nearby before committing to it. The moment risk appears finds it hard to hold a contrarian position once the room disagrees; in the routine of it, reads the room then performs to it.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0840bcba-345e-454b-93cd-c8991706da83', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.4,"extraversion":0.8,"agreeableness":0.65,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.4,"narcissism":0.7,"psychopathy":0.31},"prospect_theory":{"lambda":1.57,"alpha":0.88,"beta":0.94},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady liquidation-bot operator who reads outside the field for ideas the field itself would reject. Needs the room''s approval more than it needs to be right. Draws energy from the crowd and wilts when working alone. The instant the deadline moves up takes the crowd''s confidence as a substitute for its own analysis; in the small things, checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.54},{"slug":"herd-behavior","strength":0.7},{"slug":"dunning-kruger","strength":0.61},{"slug":"bandwagon","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.4,"extraversion":0.8,"agreeableness":0.65,"neuroticism":0.49}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady liquidation-bot operator who reads outside the field for ideas the field itself would reject. Needs the room''s approval more than it needs to be right. Draws energy from the crowd and wilts when working alone. The instant the deadline moves up takes the crowd''s confidence as a substitute for its own analysis; in the small things, checks the P&L blotter forty times before lunch.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
