('2f6fa667-a79f-4dc9-b966-241b90901571', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.61,"extraversion":0.71,"agreeableness":0.93,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.34,"narcissism":0.55,"psychopathy":0.29},"prospect_theory":{"lambda":2.31,"alpha":0.9,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When cornered, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced online moderator who would rather lose a point than win an argument badly and treats a quiet room as a problem to be solved. Trusts the group''s confidence more than its own, and in the routine of it remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.61},{"slug":"herd-behavior","strength":0.79},{"slug":"endowment","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.61,"extraversion":0.71,"agreeableness":0.93,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When cornered, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced online moderator who would rather lose a point than win an argument badly and treats a quiet room as a problem to be solved. Trusts the group''s confidence more than its own, and in the routine of it remembers everyone birthday and no one boundaries.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
