('9fd44243-8175-453f-89db-2d64bab89787', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.53,"extraversion":0.81,"agreeableness":0.95,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.33,"narcissism":0.67,"psychopathy":0.33},"prospect_theory":{"lambda":2.27,"alpha":0.86,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced group-project default leader who absorbs conflict to keep the peace, often at their own cost. Waits for a permission that never quite arrives. Dominates the room then wonders why others stayed quiet. Under a deadline finds it easier to believe something once it stops being a minority view; on a slow afternoon, over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.83},{"slug":"fomo","strength":0.69},{"slug":"endowment","strength":0.7},{"slug":"authority-bias","strength":0.73}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.77,"conscientiousness":0.53,"extraversion":0.81,"agreeableness":0.95,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced group-project default leader who absorbs conflict to keep the peace, often at their own cost. Waits for a permission that never quite arrives. Dominates the room then wonders why others stayed quiet. Under a deadline finds it easier to believe something once it stops being a minority view; on a slow afternoon, over-commits to plans they later dread.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f41f934f-6e35-46bb-a9d0-9f30441f4927', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.63,"extraversion":0.73,"agreeableness":0.97,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.34,"narcissism":0.59,"psychopathy":0.33},"prospect_theory":{"lambda":2.4,"alpha":0.9,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced unofficial group historian who would rather lose a point than win an argument badly. Outsources conviction to whoever spoke last with authority. Narrates the plan to whoever is nearby before committing to it. When the stakes rise abandons a private read the instant the crowd leans the other way; left to their own devices, texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.8},{"slug":"endowment","strength":0.67},{"slug":"authority-bias","strength":0.66},{"slug":"sunk-cost","strength":0.6}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.63,"extraversion":0.73,"agreeableness":0.97,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced unofficial group historian who would rather lose a point than win an argument badly. Outsources conviction to whoever spoke last with authority. Narrates the plan to whoever is nearby before committing to it. When the stakes rise abandons a private read the instant the crowd leans the other way; left to their own devices, texts an apology before confirming anyone is upset.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('b38e1c76-eb16-4d18-a30e-b31c31ad5de6', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.45,"extraversion":0.84,"agreeableness":0.67,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.42,"narcissism":0.7,"psychopathy":0.28},"prospect_theory":{"lambda":1.41,"alpha":0.9,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A pronounced airdrop farmer: gets bored of the proven method exactly when it starts working, draws energy from the crowd and wilts when working alone. Trusts the group''s confidence more than its own, and as a rule exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"fomo","strength":0.66},{"slug":"bandwagon","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.87,"conscientiousness":0.45,"extraversion":0.84,"agreeableness":0.67,"neuroticism":0.52}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A pronounced airdrop farmer: gets bored of the proven method exactly when it starts working, draws energy from the crowd and wilts when working alone. Trusts the group''s confidence more than its own, and as a rule exits winners at the first green candle.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('5d4d1441-3628-4c21-babf-600250affae4', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.59,"extraversion":0.76,"agreeableness":0.78,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.41,"narcissism":0.61,"psychopathy":0.34},"prospect_theory":{"lambda":2.36,"alpha":0.9,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Online moderator, steady in style: measures decisions by who they might upset; treats established procedure as a first draft to be rewritten. Seeks a second, third, and fourth opinion before committing to anything. When the walls close in adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.55},{"slug":"herd-behavior","strength":0.67},{"slug":"bandwagon","strength":0.73},{"slug":"fomo","strength":0.55}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.59,"extraversion":0.76,"agreeableness":0.78,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Online moderator, steady in style: measures decisions by who they might upset; treats established procedure as a first draft to be rewritten. Seeks a second, third, and fourth opinion before committing to anything. When the walls close in adopts a conviction mainly because the room already has.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6e48462e-937a-4652-b2fb-497c7f41fa8d', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.63,"extraversion":0.76,"agreeableness":0.87,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.42,"narcissism":0.6,"psychopathy":0.36},"prospect_theory":{"lambda":2.44,"alpha":0.86,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This wedding-party diplomat reads other people''s discomfort before they voice it and over-prepares to the point of diminishing returns. When there is no clean exit gains confidence in a position in proportion to how many others hold it — in the parts nobody grades, can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.74},{"slug":"endowment","strength":0.59}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.55,"conscientiousness":0.63,"extraversion":0.76,"agreeableness":0.87,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This wedding-party diplomat reads other people''s discomfort before they voice it and over-prepares to the point of diminishing returns. When there is no clean exit gains confidence in a position in proportion to how many others hold it — in the parts nobody grades, can sense a mood shift from the doorway.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('45c9b913-85a4-43df-9d31-0d9bdc47dfe6', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.41,"extraversion":0.83,"agreeableness":0.65,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.42,"narcissism":0.66,"psychopathy":0.32},"prospect_theory":{"lambda":1.57,"alpha":0.85,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A pronounced retail momentum chaser: chases novel frameworks and abandons them once the novelty fades, apologizes first in disputes regardless of fault. Feels the weight of a decision lighten the moment someone else co-signs it, and as a rule exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"fomo","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.41,"extraversion":0.83,"agreeableness":0.65,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A pronounced retail momentum chaser: chases novel frameworks and abandons them once the novelty fades, apologizes first in disputes regardless of fault. Feels the weight of a decision lighten the moment someone else co-signs it, and as a rule exits winners at the first green candle.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
