('9e80b740-65e2-4af5-a3d3-de9ff25897f6', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.38,"extraversion":0.83,"agreeableness":0.7,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.34,"narcissism":0.64,"psychopathy":0.33},"prospect_theory":{"lambda":1.5,"alpha":0.79,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Jumps into whatever everyone else already seems to be winning at. A steady liquidation-bot operator: recharges by being around people, not away from them, starts strong and lets follow-through evaporate. Needs the room''s approval more than it needs to be right, and when the stakes are trivial sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.7},{"slug":"fomo","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.38,"extraversion":0.83,"agreeableness":0.7,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Jumps into whatever everyone else already seems to be winning at. A steady liquidation-bot operator: recharges by being around people, not away from them, starts strong and lets follow-through evaporate. Needs the room''s approval more than it needs to be right, and when the stakes are trivial sets stop-losses then cancels them at the open.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
