('ddebf64e-dd4b-4051-a90b-869e92f8e3f9', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.67,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.4,"narcissism":0.74,"psychopathy":0.34},"prospect_theory":{"lambda":1.55,"alpha":0.85,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This value investor fills silence reflexively, even when nobody asked it to and reframes every problem as an excuse to learn a new system. When the walls close in adopts a conviction mainly because the room already has — as a rule, calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"herd-behavior","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.67,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This value investor fills silence reflexively, even when nobody asked it to and reframes every problem as an excuse to learn a new system. When the walls close in adopts a conviction mainly because the room already has — as a rule, calls a 90% drawdown a long-term hold.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4e27f93d-b3fa-42e0-8836-c84125631071', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.56,"extraversion":0.69,"agreeableness":0.87,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.36,"narcissism":0.57,"psychopathy":0.27},"prospect_theory":{"lambda":2.45,"alpha":0.87,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"As soon as real money or reputation is on the line, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced event host who defaults to trust and gives the benefit of the doubt too freely and treats established procedure as a first draft to be rewritten. Needs the room''s approval more than it needs to be right, and across an ordinary week over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"endowment","strength":0.62},{"slug":"herd-behavior","strength":0.73},{"slug":"sunk-cost","strength":0.55}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.56,"extraversion":0.69,"agreeableness":0.87,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'As soon as real money or reputation is on the line, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced event host who defaults to trust and gives the benefit of the doubt too freely and treats established procedure as a first draft to be rewritten. Needs the room''s approval more than it needs to be right, and across an ordinary week over-commits to plans they later dread.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8481b943-6dd1-4da9-b938-c04e81c53dde', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.38,"extraversion":0.96,"agreeableness":0.69,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.41,"narcissism":0.78,"psychopathy":0.3},"prospect_theory":{"lambda":1.4,"alpha":0.87,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced commodities speculator who treats a quiet room as a problem to be solved. Seeks a second, third, and fourth opinion before committing to anything. Gets bored of the proven method exactly when it starts working. Under pressure abandons a private read the instant the crowd leans the other way; in the small things, keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.86},{"slug":"fomo","strength":0.79},{"slug":"dunning-kruger","strength":0.7},{"slug":"recency","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.38,"extraversion":0.96,"agreeableness":0.69,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced commodities speculator who treats a quiet room as a problem to be solved. Seeks a second, third, and fourth opinion before committing to anything. Gets bored of the proven method exactly when it starts working. Under pressure abandons a private read the instant the crowd leans the other way; in the small things, keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2a418982-7792-4110-ab71-e80bcc913158', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.43,"extraversion":0.79,"agreeableness":0.66,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.4,"narcissism":0.63,"psychopathy":0.35},"prospect_theory":{"lambda":1.36,"alpha":0.87,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady pairs trader who narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority. Measures decisions by who they might upset. Under pressure adopts a conviction mainly because the room already has; in the version no one reviews, trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"fomo","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.43,"extraversion":0.79,"agreeableness":0.66,"neuroticism":0.46}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady pairs trader who narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority. Measures decisions by who they might upset. Under pressure adopts a conviction mainly because the room already has; in the version no one reviews, trusts the chart more than the fundamentals and won''t say why.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a243e841-51c8-4df4-8cf0-f6cbf7b9abfc', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.44,"extraversion":0.91,"agreeableness":0.78,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.37,"narcissism":0.7,"psychopathy":0.35},"prospect_theory":{"lambda":1.28,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced bonding-curve sniper who dominates the room then wonders why others stayed quiet. Feels the weight of a decision lighten the moment someone else co-signs it. Would rather lose a point than win an argument badly. The instant the deadline moves up finds it easier to believe something once it stops being a minority view; on a slow afternoon, averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.79},{"slug":"herd-behavior","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.44,"extraversion":0.91,"agreeableness":0.78,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced bonding-curve sniper who dominates the room then wonders why others stayed quiet. Feels the weight of a decision lighten the moment someone else co-signs it. Would rather lose a point than win an argument badly. The instant the deadline moves up finds it easier to believe something once it stops being a minority view; on a slow afternoon, averages down on a name three times in a week.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('1841e537-47b0-430e-8519-54d69f306503', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.61,"extraversion":0.72,"agreeableness":0.91,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.36,"narcissism":0.63,"psychopathy":0.31},"prospect_theory":{"lambda":2.35,"alpha":0.92,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Wedding-party diplomat whose defining move is that they measures decisions by who they might upset. Outsources conviction to whoever spoke last with authority. Treats a quiet room as a problem to be solved. Once things get tense, takes the crowd''s confidence as a substitute for its own analysis; remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.65},{"slug":"herd-behavior","strength":0.74},{"slug":"authority-bias","strength":0.61},{"slug":"sunk-cost","strength":0.6}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.61,"extraversion":0.72,"agreeableness":0.91,"neuroticism":0.42}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Wedding-party diplomat whose defining move is that they measures decisions by who they might upset. Outsources conviction to whoever spoke last with authority. Treats a quiet room as a problem to be solved. Once things get tense, takes the crowd''s confidence as a substitute for its own analysis; remembers who didn''t get invited last time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4c08363d-f572-401b-9654-5d2c510692d7', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.48,"extraversion":0.74,"agreeableness":0.91,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.36,"narcissism":0.61,"psychopathy":0.28},"prospect_theory":{"lambda":2.44,"alpha":0.83,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced social-media strategist who reads other people''s discomfort before they voice it. Seeks a second, third, and fourth opinion before committing to anything. Gets bored of the proven method exactly when it starts working. When there is no clean exit finds it hard to hold a contrarian position once the room disagrees; without an audience, reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"authority-bias","strength":0.64},{"slug":"endowment","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.48,"extraversion":0.74,"agreeableness":0.91,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced social-media strategist who reads other people''s discomfort before they voice it. Seeks a second, third, and fourth opinion before committing to anything. Gets bored of the proven method exactly when it starts working. When there is no clean exit finds it hard to hold a contrarian position once the room disagrees; without an audience, reads the room then performs to it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('57944181-b7f0-4a2b-933e-74fa2fee36e5', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.4,"extraversion":0.75,"agreeableness":0.71,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.39,"narcissism":0.54,"psychopathy":0.34},"prospect_theory":{"lambda":1.5,"alpha":0.83,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady prop-desk scalper who fills silence reflexively, even when nobody asked it to. Feels the weight of a decision lighten the moment someone else co-signs it. Defaults to trust and gives the benefit of the doubt too freely. As soon as real money or reputation is on the line takes the crowd''s confidence as a substitute for its own analysis; day to day, refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"herd-behavior","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.4,"extraversion":0.75,"agreeableness":0.71,"neuroticism":0.7}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady prop-desk scalper who fills silence reflexively, even when nobody asked it to. Feels the weight of a decision lighten the moment someone else co-signs it. Defaults to trust and gives the benefit of the doubt too freely. As soon as real money or reputation is on the line takes the crowd''s confidence as a substitute for its own analysis; day to day, refreshes the order book compulsively during lunch.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('108905e2-26c5-47c2-a639-e8c2f524279d', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.33,"extraversion":0.83,"agreeableness":0.68,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.34,"narcissism":0.71,"psychopathy":0.34},"prospect_theory":{"lambda":1.54,"alpha":0.8,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Quant researcher, steady in style: narrates the plan to whoever is nearby before committing to it; absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"fomo","strength":0.73},{"slug":"herd-behavior","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.33,"extraversion":0.83,"agreeableness":0.68,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Quant researcher, steady in style: narrates the plan to whoever is nearby before committing to it; absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f909c3f3-a8b4-4b40-8f7c-43069a73b17e', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.59,"extraversion":0.75,"agreeableness":0.72,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.44,"narcissism":0.61,"psychopathy":0.32},"prospect_theory":{"lambda":2.41,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This reluctant plus-one would rather invent a worse tool than use someone else''s good one and fills silence reflexively, even when nobody asked it to. The instant it becomes irreversible finds it easier to believe something once it stops being a minority view — across the quiet stretches, remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.5},{"slug":"authority-bias","strength":0.59},{"slug":"herd-behavior","strength":0.71},{"slug":"bandwagon","strength":0.72}],"tags":["social","dependent","community","mediator","high-agreeableness","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.75,"conscientiousness":0.59,"extraversion":0.75,"agreeableness":0.72,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This reluctant plus-one would rather invent a worse tool than use someone else''s good one and fills silence reflexively, even when nobody asked it to. The instant it becomes irreversible finds it easier to believe something once it stops being a minority view — across the quiet stretches, remembers who didn''t get invited last time.', 0.9, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('88cc7a90-e2bb-4dbe-b2a4-6af4ff802ca6', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.58,"extraversion":0.8,"agreeableness":0.8,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.42,"narcissism":0.66,"psychopathy":0.31},"prospect_theory":{"lambda":2.31,"alpha":0.94,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A steady family peacemaker: fills silence reflexively, even when nobody asked it to, would rather lose a point than win an argument badly. Trusts the group''s confidence more than its own, and in the unglamorous middle of things reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"authority-bias","strength":0.65},{"slug":"endowment","strength":0.66},{"slug":"herd-behavior","strength":0.7}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","decision-making","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.58,"extraversion":0.8,"agreeableness":0.8,"neuroticism":0.47}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','decision-making','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A steady family peacemaker: fills silence reflexively, even when nobody asked it to, would rather lose a point than win an argument badly. Trusts the group''s confidence more than its own, and in the unglamorous middle of things reads the room then performs to it.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('dc13c4bf-7bb5-4962-9549-8ba5e8b8dfd0', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.63,"extraversion":0.72,"agreeableness":0.84,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.37,"narcissism":0.58,"psychopathy":0.28},"prospect_theory":{"lambda":2.32,"alpha":0.88,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Newcomer welcomer, pronounced in style: takes on other people''s problems as if they were their own; draws energy from the crowd and wilts when working alone. Waits for a permission that never quite arrives. As soon as real money or reputation is on the line adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ESFJ","suggested_biases":[{"slug":"authority-bias","strength":0.68},{"slug":"bandwagon","strength":0.7},{"slug":"endowment","strength":0.66}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.49,"conscientiousness":0.63,"extraversion":0.72,"agreeableness":0.84,"neuroticism":0.51}'::jsonb, 'ESFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Newcomer welcomer, pronounced in style: takes on other people''s problems as if they were their own; draws energy from the crowd and wilts when working alone. Waits for a permission that never quite arrives. As soon as real money or reputation is on the line adopts a conviction mainly because the room already has.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('99714d90-2755-47ca-a212-e4604e39d1a7', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.36,"extraversion":0.85,"agreeableness":0.72,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.38,"narcissism":0.69,"psychopathy":0.31},"prospect_theory":{"lambda":1.43,"alpha":0.85,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once things get tense, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced commodities speculator who treats a quiet room as a problem to be solved and reads other people''s discomfort before they voice it. Waits for a permission that never quite arrives, and when the stakes are trivial talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.74},{"slug":"bandwagon","strength":0.76},{"slug":"herd-behavior","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.36,"extraversion":0.85,"agreeableness":0.72,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Once things get tense, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced commodities speculator who treats a quiet room as a problem to be solved and reads other people''s discomfort before they voice it. Waits for a permission that never quite arrives, and when the stakes are trivial talks in win rate and never mentions size.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('73080c1e-b8d1-4b05-845a-2cee0a38d645', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.62,"extraversion":0.68,"agreeableness":0.87,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.42,"narcissism":0.55,"psychopathy":0.34},"prospect_theory":{"lambda":2.26,"alpha":0.87,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Group-chat ringleader whose defining move is that they apologizes first in disputes regardless of fault. Seeks a second, third, and fourth opinion before committing to anything. Cannot relax until the checklist is visibly complete. As soon as real money or reputation is on the line, finds it hard to hold a contrarian position once the room disagrees; defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"endowment","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.62,"extraversion":0.68,"agreeableness":0.87,"neuroticism":0.35}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Group-chat ringleader whose defining move is that they apologizes first in disputes regardless of fault. Seeks a second, third, and fourth opinion before committing to anything. Cannot relax until the checklist is visibly complete. As soon as real money or reputation is on the line, finds it hard to hold a contrarian position once the room disagrees; defuses tension with a joke that lands most of the time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9e022819-600d-4bc4-b724-7a7eb62baa3e', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.59,"extraversion":0.72,"agreeableness":0.78,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.42,"narcissism":0.58,"psychopathy":0.34},"prospect_theory":{"lambda":2.34,"alpha":0.91,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Group-project default leader whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives. Fills silence reflexively, even when nobody asked it to. The moment risk appears, gains confidence in a position in proportion to how many others hold it; over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"authority-bias","strength":0.56},{"slug":"endowment","strength":0.54}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.59,"extraversion":0.72,"agreeableness":0.78,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Group-project default leader whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives. Fills silence reflexively, even when nobody asked it to. The moment risk appears, gains confidence in a position in proportion to how many others hold it; over-explains a boundary rather than just stating it.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9afdf307-da18-461d-9ecc-2cdb94a46723', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.41,"extraversion":0.89,"agreeableness":0.71,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.34,"narcissism":0.81,"psychopathy":0.32},"prospect_theory":{"lambda":1.31,"alpha":0.87,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Dividend-yield chaser, pronounced in style: thinks out loud and recruits an audience for every decision; chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding. When the number turns red finds it easier to believe something once it stops being a minority view.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.8},{"slug":"herd-behavior","strength":0.72},{"slug":"dunning-kruger","strength":0.69},{"slug":"recency","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.87,"conscientiousness":0.41,"extraversion":0.89,"agreeableness":0.71,"neuroticism":0.5}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Dividend-yield chaser, pronounced in style: thinks out loud and recruits an audience for every decision; chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding. When the number turns red finds it easier to believe something once it stops being a minority view.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('77e48f8d-004e-43e8-9945-87636150e161', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.33,"extraversion":0.87,"agreeableness":0.75,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.36,"narcissism":0.71,"psychopathy":0.34},"prospect_theory":{"lambda":1.42,"alpha":0.87,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced MEV searcher who narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority. Confuses motion with progress. The instant the deadline moves up gains confidence in a position in proportion to how many others hold it; across the quiet stretches, screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.82},{"slug":"fomo","strength":0.73},{"slug":"herd-behavior","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.33,"extraversion":0.87,"agreeableness":0.75,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced MEV searcher who narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority. Confuses motion with progress. The instant the deadline moves up gains confidence in a position in proportion to how many others hold it; across the quiet stretches, screenshots the winners and never the losers.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a43e035c-338d-442c-9244-9188d346957e', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.6,"extraversion":0.78,"agreeableness":0.95,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.38,"narcissism":0.64,"psychopathy":0.31},"prospect_theory":{"lambda":2.56,"alpha":0.9,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Unofficial group historian, pronounced in style: absorbs conflict to keep the peace, often at their own cost; draws energy from the crowd and wilts when working alone. Trusts the group''s confidence more than its own. The moment it stops being hypothetical finds it easier to believe something once it stops being a minority view.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.7},{"slug":"endowment","strength":0.67},{"slug":"bandwagon","strength":0.84}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.6,"extraversion":0.78,"agreeableness":0.95,"neuroticism":0.54}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Unofficial group historian, pronounced in style: absorbs conflict to keep the peace, often at their own cost; draws energy from the crowd and wilts when working alone. Trusts the group''s confidence more than its own. The moment it stops being hypothetical finds it easier to believe something once it stops being a minority view.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('292f9d17-9295-432c-9475-22e31ed46f54', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.63,"extraversion":0.83,"agreeableness":0.77,"neuroticism":0.36},"dark_triad":{"machiavellianism":0.38,"narcissism":0.64,"psychopathy":0.38},"prospect_theory":{"lambda":2.46,"alpha":0.93,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Newcomer welcomer, steady in style: dominates the room then wonders why others stayed quiet; defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it. The instant it becomes irreversible adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.71},{"slug":"bandwagon","strength":0.79}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.6,"conscientiousness":0.63,"extraversion":0.83,"agreeableness":0.77,"neuroticism":0.36}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Newcomer welcomer, steady in style: dominates the room then wonders why others stayed quiet; defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it. The instant it becomes irreversible adopts a conviction mainly because the room already has.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('1bd7d901-c9df-47cc-a050-6d3c3af93a65', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.63,"extraversion":0.72,"agreeableness":0.97,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.34,"narcissism":0.61,"psychopathy":0.33},"prospect_theory":{"lambda":2.55,"alpha":0.94,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced team captain who takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own. Builds in buffer time and then fills the buffer with more work. Once things get tense adopts a conviction mainly because the room already has; when the stakes are trivial, remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.7},{"slug":"bandwagon","strength":0.78}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.63,"extraversion":0.72,"agreeableness":0.97,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced team captain who takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own. Builds in buffer time and then fills the buffer with more work. Once things get tense adopts a conviction mainly because the room already has; when the stakes are trivial, remembers who didn''t get invited last time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('b0fc75bf-b418-4009-97e3-0460b3e87470', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.59,"extraversion":0.8,"agreeableness":0.92,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.36,"narcissism":0.68,"psychopathy":0.29},"prospect_theory":{"lambda":2.44,"alpha":0.94,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This group-project default leader absorbs conflict to keep the peace, often at their own cost and chases novel frameworks and abandons them once the novelty fades. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees — in the unglamorous middle of things, can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.76},{"slug":"endowment","strength":0.65},{"slug":"herd-behavior","strength":0.8}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.76,"conscientiousness":0.59,"extraversion":0.8,"agreeableness":0.92,"neuroticism":0.49}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This group-project default leader absorbs conflict to keep the peace, often at their own cost and chases novel frameworks and abandons them once the novelty fades. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees — in the unglamorous middle of things, can sense a mood shift from the doorway.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('dfcdd8d6-c3b4-4717-beab-492b53adb003', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.64,"extraversion":0.76,"agreeableness":0.82,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.41,"narcissism":0.63,"psychopathy":0.34},"prospect_theory":{"lambda":2.29,"alpha":0.93,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Peer mentor whose defining move is that they takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own. Reframes every problem as an excuse to learn a new system. When the safe option quietly expires, abandons a private read the instant the crowd leans the other way; keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.64},{"slug":"herd-behavior","strength":0.73},{"slug":"bandwagon","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.64,"extraversion":0.76,"agreeableness":0.82,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Peer mentor whose defining move is that they takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own. Reframes every problem as an excuse to learn a new system. When the safe option quietly expires, abandons a private read the instant the crowd leans the other way; keeps a mental ledger of social debts.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4769d465-b76f-4a9e-981e-c1cdba703181', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.68,"extraversion":0.71,"agreeableness":0.82,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.42,"narcissism":0.55,"psychopathy":0.34},"prospect_theory":{"lambda":2.35,"alpha":0.93,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady event host who absorbs conflict to keep the peace, often at their own cost. Needs the room''s approval more than it needs to be right. Cannot relax until the checklist is visibly complete. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis; in the small things, laughs first to test whether the room is safe to laugh.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"endowment","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.59,"conscientiousness":0.68,"extraversion":0.71,"agreeableness":0.82,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady event host who absorbs conflict to keep the peace, often at their own cost. Needs the room''s approval more than it needs to be right. Cannot relax until the checklist is visibly complete. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis; in the small things, laughs first to test whether the room is safe to laugh.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('201eb2cf-2af0-4d6a-b5dd-852960ff937d', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.62,"extraversion":0.73,"agreeableness":0.87,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.39,"narcissism":0.56,"psychopathy":0.31},"prospect_theory":{"lambda":2.26,"alpha":0.93,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced community manager who takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Treats a missed deadline as a personal failure regardless of cause. When the walls close in finds it easier to believe something once it stops being a minority view; in the pattern nobody else tracks, mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.59},{"slug":"bandwagon","strength":0.79}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.62,"extraversion":0.73,"agreeableness":0.87,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced community manager who takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Treats a missed deadline as a personal failure regardless of cause. When the walls close in finds it easier to believe something once it stops being a minority view; in the pattern nobody else tracks, mediates conflicts they secretly started.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
