('2b905825-87ea-41cb-832f-71942b24ce39', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.44,"extraversion":0.95,"agreeableness":0.74,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.4,"narcissism":0.81,"psychopathy":0.32},"prospect_theory":{"lambda":1.48,"alpha":0.83,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This index-fund holdout narrates the plan to whoever is nearby before committing to it and would rather invent a worse tool than use someone else''s good one. When the safe option quietly expires finds it easier to believe something once it stops being a minority view — in the pattern nobody else tracks, averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.7},{"slug":"fomo","strength":0.78},{"slug":"herd-behavior","strength":0.82},{"slug":"bandwagon","strength":0.84}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.44,"extraversion":0.95,"agreeableness":0.74,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This index-fund holdout narrates the plan to whoever is nearby before committing to it and would rather invent a worse tool than use someone else''s good one. When the safe option quietly expires finds it easier to believe something once it stops being a minority view — in the pattern nobody else tracks, averages down on a name three times in a week.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
