('c7eed9bd-5aad-45fb-9335-b0697ff4a568', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.58,"extraversion":0.76,"agreeableness":0.8,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.38,"narcissism":0.58,"psychopathy":0.3},"prospect_theory":{"lambda":2.39,"alpha":0.91,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This family peacemaker takes on other people''s problems as if they were their own and treats a quiet room as a problem to be solved. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way — in the unglamorous middle of things, mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.62},{"slug":"herd-behavior","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.52,"conscientiousness":0.58,"extraversion":0.76,"agreeableness":0.8,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This family peacemaker takes on other people''s problems as if they were their own and treats a quiet room as a problem to be solved. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way — in the unglamorous middle of things, mediates conflicts they secretly started.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('85fd90e9-b2dd-42b5-be6b-7a2f5cff884b', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.5,"extraversion":0.64,"agreeableness":0.91,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.34,"narcissism":0.55,"psychopathy":0.27},"prospect_theory":{"lambda":2.48,"alpha":0.87,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Community manager whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Outsources conviction to whoever spoke last with authority. Treats established procedure as a first draft to be rewritten. When the safe option quietly expires, finds it hard to hold a contrarian position once the room disagrees; keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"authority-bias","strength":0.64},{"slug":"bandwagon","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.5,"extraversion":0.64,"agreeableness":0.91,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Community manager whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Outsources conviction to whoever spoke last with authority. Treats established procedure as a first draft to be rewritten. When the safe option quietly expires, finds it hard to hold a contrarian position once the room disagrees; keeps a mental ledger of social debts.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3acfe7da-30d6-458e-996d-803e83d4d0c5', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.37,"extraversion":0.81,"agreeableness":0.78,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.37,"narcissism":0.69,"psychopathy":0.33},"prospect_theory":{"lambda":1.46,"alpha":0.89,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced liquidation-bot operator who would rather invent a worse tool than use someone else''s good one. Circles back to ask what someone else would do even after deciding. Measures decisions by who they might upset. When the stakes rise abandons a private read the instant the crowd leans the other way; as a rule, checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.81},{"slug":"bandwagon","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.37,"extraversion":0.81,"agreeableness":0.78,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced liquidation-bot operator who would rather invent a worse tool than use someone else''s good one. Circles back to ask what someone else would do even after deciding. Measures decisions by who they might upset. When the stakes rise abandons a private read the instant the crowd leans the other way; as a rule, checks the P&L blotter forty times before lunch.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('231294e1-802f-4a2e-8a91-454962fba466', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.32,"extraversion":0.8,"agreeableness":0.7,"neuroticism":0.71},"dark_triad":{"machiavellianism":0.36,"narcissism":0.63,"psychopathy":0.36},"prospect_theory":{"lambda":1.5,"alpha":0.78,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Jumps into whatever everyone else already seems to be winning at. A steady discretionary swing trader: fills silence reflexively, even when nobody asked it to, absorbs conflict to keep the peace, often at their own cost. Waits for a permission that never quite arrives, and in the parts nobody grades sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.66},{"slug":"fomo","strength":0.72}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.32,"extraversion":0.8,"agreeableness":0.7,"neuroticism":0.71}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Jumps into whatever everyone else already seems to be winning at. A steady discretionary swing trader: fills silence reflexively, even when nobody asked it to, absorbs conflict to keep the peace, often at their own cost. Waits for a permission that never quite arrives, and in the parts nobody grades sizes every position at exactly 2% risk.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('454021b8-25d4-4f88-867d-a27e20796b09', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.38,"extraversion":0.84,"agreeableness":0.73,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.37,"narcissism":0.71,"psychopathy":0.34},"prospect_theory":{"lambda":1.48,"alpha":0.88,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This quant researcher draws energy from the crowd and wilts when working alone and gets bored of the proven method exactly when it starts working. When someone is watching the outcome finds it hard to hold a contrarian position once the room disagrees — once the urgency drains out, trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"bandwagon","strength":0.68},{"slug":"dunning-kruger","strength":0.63},{"slug":"recency","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.38,"extraversion":0.84,"agreeableness":0.73,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This quant researcher draws energy from the crowd and wilts when working alone and gets bored of the proven method exactly when it starts working. When someone is watching the outcome finds it hard to hold a contrarian position once the room disagrees — once the urgency drains out, trusts the chart more than the fundamentals and won''t say why.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
