('f762f5e6-1b8a-40c4-b2a2-879a492bc54d', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.36,"extraversion":0.86,"agreeableness":0.74,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.33,"narcissism":0.65,"psychopathy":0.37},"prospect_theory":{"lambda":1.32,"alpha":0.87,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced commodities speculator who thinks out loud and recruits an audience for every decision. Trusts the group''s confidence more than its own. Confuses motion with progress. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis; in the unglamorous middle of things, calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.7},{"slug":"bandwagon","strength":0.71},{"slug":"herd-behavior","strength":0.8}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.36,"extraversion":0.86,"agreeableness":0.74,"neuroticism":0.68}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced commodities speculator who thinks out loud and recruits an audience for every decision. Trusts the group''s confidence more than its own. Confuses motion with progress. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis; in the unglamorous middle of things, calls a 90% drawdown a long-term hold.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f0c06d1b-6cb0-4efa-9849-abc9de69bd95', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.59,"extraversion":0.73,"agreeableness":0.79,"neuroticism":0.31},"dark_triad":{"machiavellianism":0.43,"narcissism":0.59,"psychopathy":0.43},"prospect_theory":{"lambda":2.23,"alpha":0.92,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A steady online moderator: defaults to trust and gives the benefit of the doubt too freely, stays flat when the numbers go red. Needs the room''s approval more than it needs to be right, and across an ordinary week keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.59},{"slug":"bandwagon","strength":0.77},{"slug":"optimism","strength":0.63},{"slug":"endowment","strength":0.62}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.59,"conscientiousness":0.59,"extraversion":0.73,"agreeableness":0.79,"neuroticism":0.31}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A steady online moderator: defaults to trust and gives the benefit of the doubt too freely, stays flat when the numbers go red. Needs the room''s approval more than it needs to be right, and across an ordinary week keeps a mental ledger of social debts.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bfe84781-3161-4cb5-99e2-8602e6ee8cc5', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.28,"extraversion":0.83,"agreeableness":0.72,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.38,"narcissism":0.69,"psychopathy":0.34},"prospect_theory":{"lambda":1.46,"alpha":0.91,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When someone is watching the outcome, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady prop-desk scalper who treats a quiet room as a problem to be solved and would rather invent a worse tool than use someone else''s good one. Outsources conviction to whoever spoke last with authority, and when the stakes are trivial sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"herd-behavior","strength":0.79},{"slug":"dunning-kruger","strength":0.69},{"slug":"bandwagon","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.28,"extraversion":0.83,"agreeableness":0.72,"neuroticism":0.5}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When someone is watching the outcome, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady prop-desk scalper who treats a quiet room as a problem to be solved and would rather invent a worse tool than use someone else''s good one. Outsources conviction to whoever spoke last with authority, and when the stakes are trivial sets alerts for a coin they already checked a minute ago.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('473f2087-4d29-4a27-8685-3bff2fd69fcb', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.38,"extraversion":0.93,"agreeableness":0.73,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.33,"narcissism":0.77,"psychopathy":0.34},"prospect_theory":{"lambda":1.23,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once the exit narrows to one door, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced delta-neutral market maker who fills silence reflexively, even when nobody asked it to and confuses motion with progress. Feels the weight of a decision lighten the moment someone else co-signs it, and when the pressure is off averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.82},{"slug":"dunning-kruger","strength":0.71},{"slug":"recency","strength":0.63},{"slug":"bandwagon","strength":0.83}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.83,"conscientiousness":0.38,"extraversion":0.93,"agreeableness":0.73,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Once the exit narrows to one door, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced delta-neutral market maker who fills silence reflexively, even when nobody asked it to and confuses motion with progress. Feels the weight of a decision lighten the moment someone else co-signs it, and when the pressure is off averages down on a name three times in a week.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('dc4d19a0-a818-481c-ab57-a242ef46d7c4', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.35,"extraversion":0.82,"agreeableness":0.77,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.35,"narcissism":0.66,"psychopathy":0.34},"prospect_theory":{"lambda":1.34,"alpha":0.8,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"In a pinch, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady volatility arbitrageur who thinks out loud and recruits an audience for every decision and does the interesting 80% and abandons the tedious 20%. Waits for a permission that never quite arrives, and in the small things apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"dunning-kruger","strength":0.66},{"slug":"fomo","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.35,"extraversion":0.82,"agreeableness":0.77,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'In a pinch, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady volatility arbitrageur who thinks out loud and recruits an audience for every decision and does the interesting 80% and abandons the tedious 20%. Waits for a permission that never quite arrives, and in the small things apes the launch before the contract is verified.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9c3c0745-0b26-4dbc-9cf7-e7590bef0b6d', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.69,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.35,"narcissism":0.65,"psychopathy":0.39},"prospect_theory":{"lambda":1.36,"alpha":0.86,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady onchain copy-trader who thinks out loud and recruits an audience for every decision. Outsources conviction to whoever spoke last with authority. Apologizes first in disputes regardless of fault. When the number turns red finds it easier to believe something once it stops being a minority view; on an ordinary week, talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"dunning-kruger","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.69,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady onchain copy-trader who thinks out loud and recruits an audience for every decision. Outsources conviction to whoever spoke last with authority. Apologizes first in disputes regardless of fault. When the number turns red finds it easier to believe something once it stops being a minority view; on an ordinary week, talks in win rate and never mentions size.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('753cb6f7-2e75-4060-b396-0edd310a1a91', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.39,"extraversion":0.76,"agreeableness":0.59,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.42,"narcissism":0.63,"psychopathy":0.35},"prospect_theory":{"lambda":1.43,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Meme-coin rotator whose defining move is that they treats established procedure as a first draft to be rewritten. Feels the weight of a decision lighten the moment someone else co-signs it. Narrates the plan to whoever is nearby before committing to it. Once things get tense, abandons a private read the instant the crowd leans the other way; names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.63},{"slug":"herd-behavior","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.39,"extraversion":0.76,"agreeableness":0.59,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Meme-coin rotator whose defining move is that they treats established procedure as a first draft to be rewritten. Feels the weight of a decision lighten the moment someone else co-signs it. Narrates the plan to whoever is nearby before committing to it. Once things get tense, abandons a private read the instant the crowd leans the other way; names every strategy after the trade that almost worked.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('494cedcc-52a8-459b-a517-cb89b84fe6ae', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.63,"extraversion":0.84,"agreeableness":0.84,"neuroticism":0.37},"dark_triad":{"machiavellianism":0.43,"narcissism":0.68,"psychopathy":0.36},"prospect_theory":{"lambda":2.27,"alpha":0.91,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced community manager who thinks out loud and recruits an audience for every decision. Seeks a second, third, and fourth opinion before committing to anything. Absorbs conflict to keep the peace, often at their own cost. When cornered adopts a conviction mainly because the room already has; when the stakes are trivial, says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"optimism","strength":0.68},{"slug":"bandwagon","strength":0.85}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.63,"extraversion":0.84,"agreeableness":0.84,"neuroticism":0.37}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced community manager who thinks out loud and recruits an audience for every decision. Seeks a second, third, and fourth opinion before committing to anything. Absorbs conflict to keep the peace, often at their own cost. When cornered adopts a conviction mainly because the room already has; when the stakes are trivial, says yes out loud and no internally.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('14748933-f078-4ba1-b7cb-28bec82c58eb', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.69,"extraversion":0.7,"agreeableness":0.87,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.44,"narcissism":0.61,"psychopathy":0.29},"prospect_theory":{"lambda":2.54,"alpha":0.9,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Peer mentor whose defining move is that they apologizes first in disputes regardless of fault. Needs the room''s approval more than it needs to be right. Would rather invent a worse tool than use someone else''s good one. The instant the deadline moves up, adopts a conviction mainly because the room already has; says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.66},{"slug":"bandwagon","strength":0.73}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.69,"extraversion":0.7,"agreeableness":0.87,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Peer mentor whose defining move is that they apologizes first in disputes regardless of fault. Needs the room''s approval more than it needs to be right. Would rather invent a worse tool than use someone else''s good one. The instant the deadline moves up, adopts a conviction mainly because the room already has; says yes out loud and no internally.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a9a9d888-2f06-4209-a8dc-d733d60dd9fe', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.29,"extraversion":0.84,"agreeableness":0.68,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.36,"narcissism":0.73,"psychopathy":0.35},"prospect_theory":{"lambda":1.52,"alpha":0.82,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Value investor, pronounced in style: recharges by being around people, not away from them; absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. When the safe option quietly expires abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.77},{"slug":"dunning-kruger","strength":0.69},{"slug":"bandwagon","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.29,"extraversion":0.84,"agreeableness":0.68,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Value investor, pronounced in style: recharges by being around people, not away from them; absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. When the safe option quietly expires abandons a private read the instant the crowd leans the other way.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
