('6599e717-fee7-4ed9-92f4-80502570f61b', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.36,"extraversion":0.91,"agreeableness":0.7,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.33,"narcissism":0.78,"psychopathy":0.33},"prospect_theory":{"lambda":1.47,"alpha":0.84,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced value investor who recharges by being around people, not away from them. Needs the room''s approval more than it needs to be right. Would rather invent a worse tool than use someone else''s good one. The instant the deadline moves up abandons a private read the instant the crowd leans the other way; without an audience, names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.8},{"slug":"dunning-kruger","strength":0.73},{"slug":"bandwagon","strength":0.75},{"slug":"optimism","strength":0.56}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.36,"extraversion":0.91,"agreeableness":0.7,"neuroticism":0.49}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced value investor who recharges by being around people, not away from them. Needs the room''s approval more than it needs to be right. Would rather invent a worse tool than use someone else''s good one. The instant the deadline moves up abandons a private read the instant the crowd leans the other way; without an audience, names every strategy after the trade that almost worked.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a12d3b11-9278-4abe-82a4-3cda19d9143b', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.59,"extraversion":0.72,"agreeableness":0.65,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.41,"narcissism":0.56,"psychopathy":0.27},"prospect_theory":{"lambda":2.43,"alpha":0.94,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A steady online moderator: dominates the room then wonders why others stayed quiet, defaults to trust and gives the benefit of the doubt too freely. Seeks a second, third, and fourth opinion before committing to anything, and in the parts nobody grades keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.61},{"slug":"optimism","strength":0.54},{"slug":"fomo","strength":0.58}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","behavioral","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.59,"extraversion":0.72,"agreeableness":0.65,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','behavioral','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A steady online moderator: dominates the room then wonders why others stayed quiet, defaults to trust and gives the benefit of the doubt too freely. Seeks a second, third, and fourth opinion before committing to anything, and in the parts nobody grades keeps a mental ledger of social debts.', 0.89, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('07337c68-af79-47f7-a024-09261923f8b6', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.54,"extraversion":0.67,"agreeableness":0.88,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.32,"narcissism":0.58,"psychopathy":0.29},"prospect_theory":{"lambda":2.4,"alpha":0.92,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Would not buy back what it already owns at the price it would sell it for. A pronounced peer mentor: reads other people''s discomfort before they voice it, dominates the room then wonders why others stayed quiet. Needs the room''s approval more than it needs to be right, and on an ordinary week defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.68},{"slug":"endowment","strength":0.69},{"slug":"authority-bias","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.54,"extraversion":0.67,"agreeableness":0.88,"neuroticism":0.51}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Would not buy back what it already owns at the price it would sell it for. A pronounced peer mentor: reads other people''s discomfort before they voice it, dominates the room then wonders why others stayed quiet. Needs the room''s approval more than it needs to be right, and on an ordinary week defuses tension with a joke that lands most of the time.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('b42d8c00-7913-41a4-bd50-d843f87656c7', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.56,"extraversion":0.73,"agreeableness":0.89,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.34,"narcissism":0.63,"psychopathy":0.35},"prospect_theory":{"lambda":2.29,"alpha":0.84,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Team captain whose defining move is that they takes on other people''s problems as if they were their own. Needs the room''s approval more than it needs to be right. Narrates the plan to whoever is nearby before committing to it. The instant the deadline moves up, gains confidence in a position in proportion to how many others hold it; remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.68},{"slug":"bandwagon","strength":0.73}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.56,"extraversion":0.73,"agreeableness":0.89,"neuroticism":0.42}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Team captain whose defining move is that they takes on other people''s problems as if they were their own. Needs the room''s approval more than it needs to be right. Narrates the plan to whoever is nearby before committing to it. The instant the deadline moves up, gains confidence in a position in proportion to how many others hold it; remembers who didn''t get invited last time.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('fe886f19-3398-45a2-a6a0-d6b6debda4a8', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.37,"extraversion":0.8,"agreeableness":0.72,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.34,"narcissism":0.67,"psychopathy":0.31},"prospect_theory":{"lambda":1.57,"alpha":0.85,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady discretionary swing trader who thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it. Is reliably surprised by deadlines that were never hidden. When cornered abandons a private read the instant the crowd leans the other way; when no one is watching, trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"sunk-cost","strength":0.63},{"slug":"dunning-kruger","strength":0.69},{"slug":"herd-behavior","strength":0.76},{"slug":"bandwagon","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.66,"conscientiousness":0.37,"extraversion":0.8,"agreeableness":0.72,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady discretionary swing trader who thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it. Is reliably surprised by deadlines that were never hidden. When cornered abandons a private read the instant the crowd leans the other way; when no one is watching, trusts the chart more than the fundamentals and won''t say why.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ceb19eb1-9651-4005-8517-6f7967c3859b', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.49,"extraversion":0.78,"agreeableness":0.79,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.34,"narcissism":0.68,"psychopathy":0.38},"prospect_theory":{"lambda":2.35,"alpha":0.83,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The one who remembers everyone''s order, steady in style: measures decisions by who they might upset; draws energy from the crowd and wilts when working alone. Needs the room''s approval more than it needs to be right. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.66},{"slug":"herd-behavior","strength":0.73},{"slug":"bandwagon","strength":0.73}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.73,"conscientiousness":0.49,"extraversion":0.78,"agreeableness":0.79,"neuroticism":0.39}'::jsonb, 'ENFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The one who remembers everyone''s order, steady in style: measures decisions by who they might upset; draws energy from the crowd and wilts when working alone. Needs the room''s approval more than it needs to be right. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('68e42842-29eb-4e1c-a9cc-f3b472617a1d', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.47,"extraversion":0.79,"agreeableness":0.79,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.36,"narcissism":0.59,"psychopathy":0.32},"prospect_theory":{"lambda":1.44,"alpha":0.83,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment it stops being hypothetical, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady index-fund holdout who recharges by being around people, not away from them and reads other people''s discomfort before they voice it. Needs the room''s approval more than it needs to be right, and without an audience calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.58},{"slug":"herd-behavior","strength":0.74},{"slug":"endowment","strength":0.7},{"slug":"bandwagon","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.47,"extraversion":0.79,"agreeableness":0.79,"neuroticism":0.7}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment it stops being hypothetical, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady index-fund holdout who recharges by being around people, not away from them and reads other people''s discomfort before they voice it. Needs the room''s approval more than it needs to be right, and without an audience calls a 90% drawdown a long-term hold.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8cd70056-af90-48ff-89c0-4aa0196dba60', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.31,"extraversion":0.86,"agreeableness":0.62,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.37,"narcissism":0.66,"psychopathy":0.4},"prospect_theory":{"lambda":1.54,"alpha":0.76,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Options seller, pronounced in style: treats established procedure as a first draft to be rewritten; spirals on ambiguity and mistakes the spiral for diligence. Seeks a second, third, and fourth opinion before committing to anything. Once the exit narrows to one door discounts the older pattern in favor of whatever just happened.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.68},{"slug":"herd-behavior","strength":0.71},{"slug":"recency","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.86,"conscientiousness":0.31,"extraversion":0.86,"agreeableness":0.62,"neuroticism":0.77}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Options seller, pronounced in style: treats established procedure as a first draft to be rewritten; spirals on ambiguity and mistakes the spiral for diligence. Seeks a second, third, and fourth opinion before committing to anything. Once the exit narrows to one door discounts the older pattern in favor of whatever just happened.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c4874d10-cfb6-4d38-b5aa-71bcd31f6267', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.67,"extraversion":0.7,"agreeableness":0.95,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.38,"narcissism":0.6,"psychopathy":0.35},"prospect_theory":{"lambda":2.25,"alpha":0.95,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This community manager would rather lose a point than win an argument badly and treats a quiet room as a problem to be solved. The moment risk appears finds it easier to believe something once it stops being a minority view — in the small things, says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.64},{"slug":"herd-behavior","strength":0.71},{"slug":"authority-bias","strength":0.72},{"slug":"bandwagon","strength":0.78}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.67,"extraversion":0.7,"agreeableness":0.95,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This community manager would rather lose a point than win an argument badly and treats a quiet room as a problem to be solved. The moment risk appears finds it easier to believe something once it stops being a minority view — in the small things, says yes out loud and no internally.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('98d2ffce-bd37-435a-b0bc-d3230d003de6', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.33,"extraversion":0.73,"agreeableness":0.66,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.37,"narcissism":0.64,"psychopathy":0.39},"prospect_theory":{"lambda":1.3,"alpha":0.88,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the safe option quietly expires, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced DeFi yield farmer who would rather invent a worse tool than use someone else''s good one and reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own, and in the parts nobody grades rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.66},{"slug":"dunning-kruger","strength":0.66},{"slug":"sunk-cost","strength":0.63},{"slug":"bandwagon","strength":0.59}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.33,"extraversion":0.73,"agreeableness":0.66,"neuroticism":0.49}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the safe option quietly expires, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced DeFi yield farmer who would rather invent a worse tool than use someone else''s good one and reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own, and in the parts nobody grades rotates the whole book into whatever is pumping this hour.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
