('daab16ae-6cca-4fc1-9581-4595cd6e7930', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.41,"extraversion":0.79,"agreeableness":0.68,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.38,"narcissism":0.66,"psychopathy":0.29},"prospect_theory":{"lambda":1.31,"alpha":0.91,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The instant the deadline moves up, adopts a conviction mainly because the room already has. Otherwise, a steady discretionary swing trader who treats a quiet room as a problem to be solved and reads other people''s discomfort before they voice it. Feels the weight of a decision lighten the moment someone else co-signs it, and when the stakes are trivial exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"herd-behavior","strength":0.64},{"slug":"fomo","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.63,"conscientiousness":0.41,"extraversion":0.79,"agreeableness":0.68,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The instant the deadline moves up, adopts a conviction mainly because the room already has. Otherwise, a steady discretionary swing trader who treats a quiet room as a problem to be solved and reads other people''s discomfort before they voice it. Feels the weight of a decision lighten the moment someone else co-signs it, and when the stakes are trivial exits winners at the first green candle.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
