('b77bb547-c65c-4665-a5e0-a5958acd3751', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.6,"extraversion":0.7,"agreeableness":0.78,"neuroticism":0.32},"dark_triad":{"machiavellianism":0.41,"narcissism":0.55,"psychopathy":0.39},"prospect_theory":{"lambda":2.36,"alpha":0.87,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Community manager, steady in style: reads other people''s discomfort before they voice it; treats a crisis as an interesting problem rather than a threat. Waits for a permission that never quite arrives. Once the exit narrows to one door gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.6},{"slug":"bandwagon","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.6,"extraversion":0.7,"agreeableness":0.78,"neuroticism":0.32}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Community manager, steady in style: reads other people''s discomfort before they voice it; treats a crisis as an interesting problem rather than a threat. Waits for a permission that never quite arrives. Once the exit narrows to one door gains confidence in a position in proportion to how many others hold it.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('23d2997e-3263-4453-9406-348acc4e0833', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.43,"extraversion":0.86,"agreeableness":0.68,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.39,"narcissism":0.68,"psychopathy":0.34},"prospect_theory":{"lambda":1.37,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Perps degen whose defining move is that they draws energy from the crowd and wilts when working alone. Feels the weight of a decision lighten the moment someone else co-signs it. Treats established procedure as a first draft to be rewritten. When there is no clean exit, cannot watch a rally from the sidelines for long; holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"fomo","strength":0.69},{"slug":"bandwagon","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.43,"extraversion":0.86,"agreeableness":0.68,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Perps degen whose defining move is that they draws energy from the crowd and wilts when working alone. Feels the weight of a decision lighten the moment someone else co-signs it. Treats established procedure as a first draft to be rewritten. When there is no clean exit, cannot watch a rally from the sidelines for long; holds a bag from 2021 out of pure spite.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6fef5718-52e7-4f88-ab3c-a162dd969424', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.69,"extraversion":0.71,"agreeableness":0.85,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.41,"narcissism":0.62,"psychopathy":0.39},"prospect_theory":{"lambda":2.52,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Waits for a permission that never quite arrives. This unofficial group historian reads other people''s discomfort before they voice it and fills silence reflexively, even when nobody asked it to. The moment it stops being hypothetical discounts their own exposure to the risks they warn others about — left to their own devices, remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"endowment","strength":0.67},{"slug":"optimism","strength":0.68}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.69,"extraversion":0.71,"agreeableness":0.85,"neuroticism":0.34}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Waits for a permission that never quite arrives. This unofficial group historian reads other people''s discomfort before they voice it and fills silence reflexively, even when nobody asked it to. The moment it stops being hypothetical discounts their own exposure to the risks they warn others about — left to their own devices, remembers everyone birthday and no one boundaries.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('59de710f-0dc4-4307-bca2-5792bf9704c6', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.62,"extraversion":0.72,"agreeableness":0.85,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.38,"narcissism":0.59,"psychopathy":0.35},"prospect_theory":{"lambda":2.27,"alpha":0.87,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Neighborhood connector, pronounced in style: apologizes first in disputes regardless of fault; dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything. In a pinch adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.59},{"slug":"bandwagon","strength":0.68},{"slug":"optimism","strength":0.56},{"slug":"authority-bias","strength":0.59}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.79,"conscientiousness":0.62,"extraversion":0.72,"agreeableness":0.85,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Neighborhood connector, pronounced in style: apologizes first in disputes regardless of fault; dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything. In a pinch adopts a conviction mainly because the room already has.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ee1cd25b-a96c-4142-9d9b-3815bbceb5fc', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.35,"extraversion":0.78,"agreeableness":0.76,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.39,"narcissism":0.62,"psychopathy":0.36},"prospect_theory":{"lambda":1.56,"alpha":0.79,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady zero-DTE options gambler who treats established procedure as a first draft to be rewritten. Circles back to ask what someone else would do even after deciding. Rehearses catastrophes in vivid detail before they happen. When cornered finds it hard to hold a contrarian position once the room disagrees; left to their own devices, sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.7},{"slug":"bandwagon","strength":0.7},{"slug":"herd-behavior","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.35,"extraversion":0.78,"agreeableness":0.76,"neuroticism":0.65}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady zero-DTE options gambler who treats established procedure as a first draft to be rewritten. Circles back to ask what someone else would do even after deciding. Rehearses catastrophes in vivid detail before they happen. When cornered finds it hard to hold a contrarian position once the room disagrees; left to their own devices, sets stop-losses then cancels them at the open.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e1bc0bc4-277b-4efb-801a-93ab5d7e05a3', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.39,"extraversion":0.67,"agreeableness":0.68,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.37,"narcissism":0.54,"psychopathy":0.33},"prospect_theory":{"lambda":1.51,"alpha":0.92,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When there is no clean exit, cannot see the gap in its own knowledge from inside the gap. Otherwise, a steady bonding-curve sniper who reframes every problem as an excuse to learn a new system and thinks out loud and recruits an audience for every decision. Needs the room''s approval more than it needs to be right, and in the parts nobody grades exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.56},{"slug":"sunk-cost","strength":0.6},{"slug":"dunning-kruger","strength":0.63},{"slug":"bandwagon","strength":0.57}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.39,"extraversion":0.67,"agreeableness":0.68,"neuroticism":0.52}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When there is no clean exit, cannot see the gap in its own knowledge from inside the gap. Otherwise, a steady bonding-curve sniper who reframes every problem as an excuse to learn a new system and thinks out loud and recruits an audience for every decision. Needs the room''s approval more than it needs to be right, and in the parts nobody grades exits winners at the first green candle.', 0.89, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a3e08a2c-4dfc-4f3d-8f36-68dd4634ae3f', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.62,"extraversion":0.62,"agreeableness":0.83,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.36,"narcissism":0.52,"psychopathy":0.3},"prospect_theory":{"lambda":2.48,"alpha":0.88,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady neighborhood connector who apologizes first in disputes regardless of fault. Needs the room''s approval more than it needs to be right. Builds in buffer time and then fills the buffer with more work. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way; in the pattern nobody else tracks, says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.58},{"slug":"authority-bias","strength":0.61},{"slug":"herd-behavior","strength":0.67},{"slug":"endowment","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.74,"conscientiousness":0.62,"extraversion":0.62,"agreeableness":0.83,"neuroticism":0.54}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady neighborhood connector who apologizes first in disputes regardless of fault. Needs the room''s approval more than it needs to be right. Builds in buffer time and then fills the buffer with more work. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way; in the pattern nobody else tracks, says yes out loud and no internally.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('38b06c21-6da4-478d-98b0-6478e694424a', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.37,"extraversion":0.93,"agreeableness":0.81,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.33,"narcissism":0.71,"psychopathy":0.33},"prospect_theory":{"lambda":1.25,"alpha":0.87,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced pairs trader who dominates the room then wonders why others stayed quiet. Outsources conviction to whoever spoke last with authority. Is reliably surprised by deadlines that were never hidden. The instant it becomes irreversible finds it hard to hold a contrarian position once the room disagrees; in the version no one reviews, keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.86},{"slug":"fomo","strength":0.8}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.37,"extraversion":0.93,"agreeableness":0.81,"neuroticism":0.65}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced pairs trader who dominates the room then wonders why others stayed quiet. Outsources conviction to whoever spoke last with authority. Is reliably surprised by deadlines that were never hidden. The instant it becomes irreversible finds it hard to hold a contrarian position once the room disagrees; in the version no one reviews, keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0e2f241e-137f-4b40-91da-d7f572cc143e', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.32,"extraversion":0.68,"agreeableness":0.68,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.37,"narcissism":0.56,"psychopathy":0.37},"prospect_theory":{"lambda":1.52,"alpha":0.8,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A steady options seller: reframes every problem as an excuse to learn a new system, leaves loose ends and trusts future-self to handle them. Waits for a permission that never quite arrives, and as a rule refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.63},{"slug":"bandwagon","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.32,"extraversion":0.68,"agreeableness":0.68,"neuroticism":0.65}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A steady options seller: reframes every problem as an excuse to learn a new system, leaves loose ends and trusts future-self to handle them. Waits for a permission that never quite arrives, and as a rule refreshes the order book compulsively during lunch.', 0.89, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9cd54050-dbde-4293-a1ea-67c4310ddb74', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.5,"extraversion":0.79,"agreeableness":0.79,"neuroticism":0.37},"dark_triad":{"machiavellianism":0.39,"narcissism":0.64,"psychopathy":0.37},"prospect_theory":{"lambda":2.28,"alpha":0.91,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Wedding-party diplomat, steady in style: recharges by being around people, not away from them; checks its own anxiety like a data point instead of obeying it. Feels the weight of a decision lighten the moment someone else co-signs it. Under pressure finds it easier to believe something once it stops being a minority view.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"bandwagon","strength":0.73},{"slug":"endowment","strength":0.62},{"slug":"fomo","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.5,"extraversion":0.79,"agreeableness":0.79,"neuroticism":0.37}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Wedding-party diplomat, steady in style: recharges by being around people, not away from them; checks its own anxiety like a data point instead of obeying it. Feels the weight of a decision lighten the moment someone else co-signs it. Under pressure finds it easier to believe something once it stops being a minority view.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('60be7fb5-868b-42da-a2f7-8939bbe07abf', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.35,"extraversion":0.93,"agreeableness":0.68,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.34,"narcissism":0.79,"psychopathy":0.38},"prospect_theory":{"lambda":1.34,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"MEV searcher whose defining move is that they thinks out loud and recruits an audience for every decision. Needs the room''s approval more than it needs to be right. Starts strong and lets follow-through evaporate. In a pinch, treats being left out of a move as its own kind of loss; averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.73},{"slug":"bandwagon","strength":0.71},{"slug":"fomo","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.87,"conscientiousness":0.35,"extraversion":0.93,"agreeableness":0.68,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'MEV searcher whose defining move is that they thinks out loud and recruits an audience for every decision. Needs the room''s approval more than it needs to be right. Starts strong and lets follow-through evaporate. In a pinch, treats being left out of a move as its own kind of loss; averages down on a name three times in a week.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a369ec4f-7637-4c51-914d-a5e4cdf1feb8', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.56,"extraversion":0.7,"agreeableness":0.89,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.37,"narcissism":0.61,"psychopathy":0.32},"prospect_theory":{"lambda":2.57,"alpha":0.94,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Waits for a permission that never quite arrives. This group-project default leader absorbs conflict to keep the peace, often at their own cost and reframes every problem as an excuse to learn a new system. Once the exit narrows to one door finds it hard to hold a contrarian position once the room disagrees — day to day, over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.75},{"slug":"endowment","strength":0.65},{"slug":"bandwagon","strength":0.69},{"slug":"authority-bias","strength":0.59}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.56,"extraversion":0.7,"agreeableness":0.89,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Waits for a permission that never quite arrives. This group-project default leader absorbs conflict to keep the peace, often at their own cost and reframes every problem as an excuse to learn a new system. Once the exit narrows to one door finds it hard to hold a contrarian position once the room disagrees — day to day, over-commits to plans they later dread.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c50c1f2a-0e35-4595-9c5a-32164cf16137', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.59,"extraversion":0.7,"agreeableness":0.83,"neuroticism":0.37},"dark_triad":{"machiavellianism":0.39,"narcissism":0.55,"psychopathy":0.36},"prospect_theory":{"lambda":2.42,"alpha":0.91,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Group-chat ringleader whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives. Treats a quiet room as a problem to be solved. The instant it becomes irreversible, gains confidence in a position in proportion to how many others hold it; remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"bandwagon","strength":0.73},{"slug":"authority-bias","strength":0.58}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.59,"extraversion":0.7,"agreeableness":0.83,"neuroticism":0.37}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Group-chat ringleader whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives. Treats a quiet room as a problem to be solved. The instant it becomes irreversible, gains confidence in a position in proportion to how many others hold it; remembers who didn''t get invited last time.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3f55e7dc-87f5-4600-b588-966bada29a22', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.45,"extraversion":0.9,"agreeableness":0.59,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.38,"narcissism":0.72,"psychopathy":0.33},"prospect_theory":{"lambda":1.44,"alpha":0.83,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A pronounced value investor: narrates the plan to whoever is nearby before committing to it, reads outside the field for ideas the field itself would reject. Seeks a second, third, and fourth opinion before committing to anything, and in the parts nobody grades keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.7},{"slug":"bandwagon","strength":0.67},{"slug":"recency","strength":0.59},{"slug":"herd-behavior","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.45,"extraversion":0.9,"agreeableness":0.59,"neuroticism":0.65}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A pronounced value investor: narrates the plan to whoever is nearby before committing to it, reads outside the field for ideas the field itself would reject. Seeks a second, third, and fourth opinion before committing to anything, and in the parts nobody grades keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2457cfa5-c985-4831-b60d-51deade7ee75', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.48,"extraversion":0.83,"agreeableness":0.68,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.36,"narcissism":0.67,"psychopathy":0.31},"prospect_theory":{"lambda":1.5,"alpha":0.89,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Options seller whose defining move is that they dominates the room then wonders why others stayed quiet. Waits for a permission that never quite arrives. Defaults to trust and gives the benefit of the doubt too freely. Under pressure, takes the crowd''s confidence as a substitute for its own analysis; trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"dunning-kruger","strength":0.64},{"slug":"recency","strength":0.58},{"slug":"herd-behavior","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.48,"extraversion":0.83,"agreeableness":0.68,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Options seller whose defining move is that they dominates the room then wonders why others stayed quiet. Waits for a permission that never quite arrives. Defaults to trust and gives the benefit of the doubt too freely. Under pressure, takes the crowd''s confidence as a substitute for its own analysis; trusts the chart more than the fundamentals and won''t say why.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d5b595b2-32f7-47cf-9e48-9cddf00a35cd', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.65,"extraversion":0.66,"agreeableness":0.97,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.35,"narcissism":0.57,"psychopathy":0.42},"prospect_theory":{"lambda":2.55,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A pronounced wedding-party diplomat: apologizes first in disputes regardless of fault, checks its own anxiety like a data point instead of obeying it. Waits for a permission that never quite arrives, and when the stakes are trivial remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.69},{"slug":"authority-bias","strength":0.65},{"slug":"bandwagon","strength":0.75},{"slug":"endowment","strength":0.74}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.65,"extraversion":0.66,"agreeableness":0.97,"neuroticism":0.29}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A pronounced wedding-party diplomat: apologizes first in disputes regardless of fault, checks its own anxiety like a data point instead of obeying it. Waits for a permission that never quite arrives, and when the stakes are trivial remembers who didn''t get invited last time.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a4b4ab29-9f7c-4adc-9c61-7d7c0486c22e', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.54,"extraversion":0.63,"agreeableness":0.87,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.37,"narcissism":0.49,"psychopathy":0.25},"prospect_theory":{"lambda":2.43,"alpha":0.88,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Event host, pronounced in style: would rather lose a point than win an argument badly; treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it. When there is no clean exit adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.64},{"slug":"endowment","strength":0.67},{"slug":"bandwagon","strength":0.72}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.54,"extraversion":0.63,"agreeableness":0.87,"neuroticism":0.54}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Event host, pronounced in style: would rather lose a point than win an argument badly; treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it. When there is no clean exit adopts a conviction mainly because the room already has.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('cd0e208d-b8b0-4cad-b397-3662b630fc6d', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.3,"extraversion":0.75,"agreeableness":0.79,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.31,"narcissism":0.57,"psychopathy":0.35},"prospect_theory":{"lambda":1.38,"alpha":0.81,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A steady crypto day-trader: apologizes first in disputes regardless of fault, chases novel frameworks and abandons them once the novelty fades. Outsources conviction to whoever spoke last with authority, and when the stakes are trivial talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.68},{"slug":"bandwagon","strength":0.71},{"slug":"sunk-cost","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","accommodating","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.3,"extraversion":0.75,"agreeableness":0.79,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','accommodating','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A steady crypto day-trader: apologizes first in disputes regardless of fault, chases novel frameworks and abandons them once the novelty fades. Outsources conviction to whoever spoke last with authority, and when the stakes are trivial talks in win rate and never mentions size.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6f7fd2fd-511e-4357-b7c1-06401829d973', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.44,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.36,"narcissism":0.63,"psychopathy":0.27},"prospect_theory":{"lambda":1.34,"alpha":0.87,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A steady bonding-curve sniper: thinks out loud and recruits an audience for every decision, treats established procedure as a first draft to be rewritten. Trusts the group''s confidence more than its own, and when no one is watching rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.66},{"slug":"fomo","strength":0.66},{"slug":"herd-behavior","strength":0.72},{"slug":"recency","strength":0.55}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.44,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A steady bonding-curve sniper: thinks out loud and recruits an audience for every decision, treats established procedure as a first draft to be rewritten. Trusts the group''s confidence more than its own, and when no one is watching rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
