('ce53a00d-b58a-4259-ae0b-c049630a7d8a', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.6,"extraversion":0.89,"agreeableness":0.83,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.38,"narcissism":0.75,"psychopathy":0.36},"prospect_theory":{"lambda":2.53,"alpha":0.94,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A pronounced neighborhood connector: treats a quiet room as a problem to be solved, stays flat when the numbers go red. Trusts the group''s confidence more than its own, and on an ordinary week says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.87},{"slug":"bandwagon","strength":0.81},{"slug":"optimism","strength":0.72}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.6,"extraversion":0.89,"agreeableness":0.83,"neuroticism":0.38}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A pronounced neighborhood connector: treats a quiet room as a problem to be solved, stays flat when the numbers go red. Trusts the group''s confidence more than its own, and on an ordinary week says yes out loud and no internally.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
