('7ec9be37-bdec-4d9b-8165-570a5f79dfc8', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.45,"extraversion":0.83,"agreeableness":0.7,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.34,"narcissism":0.67,"psychopathy":0.26},"prospect_theory":{"lambda":1.42,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A steady meme-coin rotator: narrates the plan to whoever is nearby before committing to it, chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding, and day to day exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"fomo","strength":0.68},{"slug":"bandwagon","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.65,"conscientiousness":0.45,"extraversion":0.83,"agreeableness":0.7,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A steady meme-coin rotator: narrates the plan to whoever is nearby before committing to it, chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding, and day to day exits winners at the first green candle.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('385af5f7-c0de-434f-910a-5a9a75901c3c', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.38,"extraversion":0.82,"agreeableness":0.73,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.39,"narcissism":0.67,"psychopathy":0.35},"prospect_theory":{"lambda":1.39,"alpha":0.8,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This commodities speculator treats a quiet room as a problem to be solved and improvises past every deadline and calls it flexibility. Once the exit narrows to one door adopts a conviction mainly because the room already has — in the small things, exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.69},{"slug":"herd-behavior","strength":0.68},{"slug":"bandwagon","strength":0.72},{"slug":"fomo","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.38,"extraversion":0.82,"agreeableness":0.73,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This commodities speculator treats a quiet room as a problem to be solved and improvises past every deadline and calls it flexibility. Once the exit narrows to one door adopts a conviction mainly because the room already has — in the small things, exits winners at the first green candle.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9fbb3c44-f7be-44f1-84db-161358a40e49', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.45,"extraversion":0.89,"agreeableness":0.75,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.35,"narcissism":0.74,"psychopathy":0.34},"prospect_theory":{"lambda":1.55,"alpha":0.84,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced macro allocator who treats a quiet room as a problem to be solved and would rather invent a worse tool than use someone else''s good one. Waits for a permission that never quite arrives, and as a rule exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.8},{"slug":"fomo","strength":0.67},{"slug":"herd-behavior","strength":0.82}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.82,"conscientiousness":0.45,"extraversion":0.89,"agreeableness":0.75,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced macro allocator who treats a quiet room as a problem to be solved and would rather invent a worse tool than use someone else''s good one. Waits for a permission that never quite arrives, and as a rule exits winners at the first green candle.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('1ac3d6cb-154d-4e14-923e-cad82d8a140f', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.2,"extraversion":0.8,"agreeableness":0.76,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.39,"narcissism":0.69,"psychopathy":0.38},"prospect_theory":{"lambda":1.38,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Commodities speculator whose defining move is that they recharges by being around people, not away from them. Outsources conviction to whoever spoke last with authority. Treats a plan as a suggestion the moment it is made. In a pinch, mistakes a little fluency for real mastery; checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"dunning-kruger","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.2,"extraversion":0.8,"agreeableness":0.76,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Commodities speculator whose defining move is that they recharges by being around people, not away from them. Outsources conviction to whoever spoke last with authority. Treats a plan as a suggestion the moment it is made. In a pinch, mistakes a little fluency for real mastery; checks the P&L blotter forty times before lunch.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('010f4a57-a4d4-4660-b5b9-ae6514c69538', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.44,"extraversion":0.86,"agreeableness":0.72,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.35,"narcissism":0.73,"psychopathy":0.29},"prospect_theory":{"lambda":1.42,"alpha":0.83,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When there is no clean exit, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced futures spreader who recharges by being around people, not away from them and treats established procedure as a first draft to be rewritten. Needs the room''s approval more than it needs to be right, and when no one is watching sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"bandwagon","strength":0.72},{"slug":"herd-behavior","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.44,"extraversion":0.86,"agreeableness":0.72,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When there is no clean exit, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced futures spreader who recharges by being around people, not away from them and treats established procedure as a first draft to be rewritten. Needs the room''s approval more than it needs to be right, and when no one is watching sizes every position at exactly 2% risk.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('211662b2-8271-4347-8b21-3366052eb02e', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.31,"extraversion":0.77,"agreeableness":0.65,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.35,"narcissism":0.67,"psychopathy":0.39},"prospect_theory":{"lambda":1.42,"alpha":0.83,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Prop-desk scalper, pronounced in style: reads outside the field for ideas the field itself would reject; thinks out loud and recruits an audience for every decision. Circles back to ask what someone else would do even after deciding. Under a deadline gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.64},{"slug":"bandwagon","strength":0.7},{"slug":"fomo","strength":0.66},{"slug":"dunning-kruger","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.86,"conscientiousness":0.31,"extraversion":0.77,"agreeableness":0.65,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Prop-desk scalper, pronounced in style: reads outside the field for ideas the field itself would reject; thinks out loud and recruits an audience for every decision. Circles back to ask what someone else would do even after deciding. Under a deadline gains confidence in a position in proportion to how many others hold it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('98cd938b-1be6-42b3-9566-fcde8b903a82', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.35,"extraversion":0.88,"agreeableness":0.73,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.36,"narcissism":0.76,"psychopathy":0.35},"prospect_theory":{"lambda":1.47,"alpha":0.88,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Dividend-yield chaser whose defining move is that they recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything. Treats established procedure as a first draft to be rewritten. The moment it stops being hypothetical, takes the crowd''s confidence as a substitute for its own analysis; backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"herd-behavior","strength":0.82}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.35,"extraversion":0.88,"agreeableness":0.73,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Dividend-yield chaser whose defining move is that they recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything. Treats established procedure as a first draft to be rewritten. The moment it stops being hypothetical, takes the crowd''s confidence as a substitute for its own analysis; backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9fe324aa-e96f-46cc-86e1-175f9b47feda', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.42,"extraversion":0.84,"agreeableness":0.77,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.35,"narcissism":0.7,"psychopathy":0.3},"prospect_theory":{"lambda":1.29,"alpha":0.83,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Index-fund holdout, pronounced in style: collects half-finished manifestos and unconventional methods; narrates the plan to whoever is nearby before committing to it. Needs the room''s approval more than it needs to be right. When the safe option quietly expires takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.82},{"slug":"recency","strength":0.66},{"slug":"bandwagon","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.88,"conscientiousness":0.42,"extraversion":0.84,"agreeableness":0.77,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Index-fund holdout, pronounced in style: collects half-finished manifestos and unconventional methods; narrates the plan to whoever is nearby before committing to it. Needs the room''s approval more than it needs to be right. When the safe option quietly expires takes the crowd''s confidence as a substitute for its own analysis.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c5409348-cf12-447f-9606-c02ff9b66893', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.52,"extraversion":0.73,"agreeableness":0.92,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.37,"narcissism":0.58,"psychopathy":0.31},"prospect_theory":{"lambda":2.48,"alpha":0.85,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This online moderator measures decisions by who they might upset and thinks out loud and recruits an audience for every decision. Under a deadline gains confidence in a position in proportion to how many others hold it — day to day, can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.59},{"slug":"endowment","strength":0.68},{"slug":"authority-bias","strength":0.69},{"slug":"bandwagon","strength":0.79}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.52,"extraversion":0.73,"agreeableness":0.92,"neuroticism":0.54}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This online moderator measures decisions by who they might upset and thinks out loud and recruits an audience for every decision. Under a deadline gains confidence in a position in proportion to how many others hold it — day to day, can sense a mood shift from the doorway.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a93f2835-5ced-4f15-bcbf-b1b159ef87d7', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.43,"extraversion":0.86,"agreeableness":0.74,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.39,"narcissism":0.76,"psychopathy":0.32},"prospect_theory":{"lambda":1.5,"alpha":0.82,"beta":0.94},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Jumps into whatever everyone else already seems to be winning at. A pronounced prop-desk scalper: gets bored of the proven method exactly when it starts working, fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything, and once the urgency drains out calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.72},{"slug":"recency","strength":0.63},{"slug":"bandwagon","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.88,"conscientiousness":0.43,"extraversion":0.86,"agreeableness":0.74,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Jumps into whatever everyone else already seems to be winning at. A pronounced prop-desk scalper: gets bored of the proven method exactly when it starts working, fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything, and once the urgency drains out calls a 90% drawdown a long-term hold.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('fb38b893-4faa-4c2b-b862-f1e8a1dc8122', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.32,"extraversion":0.84,"agreeableness":0.74,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.33,"narcissism":0.66,"psychopathy":0.32},"prospect_theory":{"lambda":1.48,"alpha":0.89,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Discretionary swing trader whose defining move is that they draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything. Does the interesting 80% and abandons the tedious 20%. When the downside gets concrete, gains confidence in a position in proportion to how many others hold it; sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.79},{"slug":"herd-behavior","strength":0.79},{"slug":"dunning-kruger","strength":0.65},{"slug":"sunk-cost","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.32,"extraversion":0.84,"agreeableness":0.74,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Discretionary swing trader whose defining move is that they draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything. Does the interesting 80% and abandons the tedious 20%. When the downside gets concrete, gains confidence in a position in proportion to how many others hold it; sets stop-losses then cancels them at the open.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('968145b0-75b2-494c-a7b6-019264619d57', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.35,"extraversion":0.81,"agreeableness":0.72,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.39,"narcissism":0.74,"psychopathy":0.32},"prospect_theory":{"lambda":1.24,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This bonding-curve sniper narrates the plan to whoever is nearby before committing to it and reads other people''s discomfort before they voice it. The moment risk appears gains confidence in a position in proportion to how many others hold it — on an ordinary week, exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"bandwagon","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.35,"extraversion":0.81,"agreeableness":0.72,"neuroticism":0.49}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This bonding-curve sniper narrates the plan to whoever is nearby before committing to it and reads other people''s discomfort before they voice it. The moment risk appears gains confidence in a position in proportion to how many others hold it — on an ordinary week, exits winners at the first green candle.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9e3bfa2d-f0ae-44e5-8be8-7f1c80fb77c3', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.47,"extraversion":0.91,"agreeableness":0.68,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.39,"narcissism":0.78,"psychopathy":0.29},"prospect_theory":{"lambda":1.37,"alpha":0.83,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"DeFi yield farmer, pronounced in style: draws energy from the crowd and wilts when working alone; measures decisions by who they might upset. Waits for a permission that never quite arrives. When someone is watching the outcome gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"bandwagon","strength":0.76},{"slug":"dunning-kruger","strength":0.61},{"slug":"optimism","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.47,"extraversion":0.91,"agreeableness":0.68,"neuroticism":0.52}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'DeFi yield farmer, pronounced in style: draws energy from the crowd and wilts when working alone; measures decisions by who they might upset. Waits for a permission that never quite arrives. When someone is watching the outcome gains confidence in a position in proportion to how many others hold it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('479df6e0-febe-47e3-a307-05d1b7567cc5', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.56,"extraversion":0.67,"agreeableness":0.79,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.4,"narcissism":0.54,"psychopathy":0.33},"prospect_theory":{"lambda":2.55,"alpha":0.85,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A steady longtime regular at the same three places: would rather lose a point than win an argument badly, thinks out loud and recruits an audience for every decision. Needs the room''s approval more than it needs to be right, and in the routine of it reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"bandwagon","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.71,"conscientiousness":0.56,"extraversion":0.67,"agreeableness":0.79,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A steady longtime regular at the same three places: would rather lose a point than win an argument badly, thinks out loud and recruits an audience for every decision. Needs the room''s approval more than it needs to be right, and in the routine of it reads the room then performs to it.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2979a118-b7fb-43a9-a43c-b5d1859b8833', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.49,"extraversion":0.76,"agreeableness":0.88,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.33,"narcissism":0.6,"psychopathy":0.33},"prospect_theory":{"lambda":2.55,"alpha":0.9,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Family peacemaker whose defining move is that they reads other people''s discomfort before they voice it. Needs the room''s approval more than it needs to be right. Moves on from a mistake faster than the people around them do. When the number turns red, gains confidence in a position in proportion to how many others hold it; texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.82},{"slug":"endowment","strength":0.62}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.49,"extraversion":0.76,"agreeableness":0.88,"neuroticism":0.38}'::jsonb, 'ENFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Family peacemaker whose defining move is that they reads other people''s discomfort before they voice it. Needs the room''s approval more than it needs to be right. Moves on from a mistake faster than the people around them do. When the number turns red, gains confidence in a position in proportion to how many others hold it; texts an apology before confirming anyone is upset.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('747e39db-5216-49f9-a5b3-499a937b06dd', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.51,"extraversion":0.73,"agreeableness":0.77,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.34,"narcissism":0.57,"psychopathy":0.32},"prospect_theory":{"lambda":2.42,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the downside gets concrete, abandons a private read the instant the crowd leans the other way. Otherwise, a steady unofficial group historian who apologizes first in disputes regardless of fault and gets bored of the proven method exactly when it starts working. Feels the weight of a decision lighten the moment someone else co-signs it, and in the small things keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.63},{"slug":"herd-behavior","strength":0.75},{"slug":"bandwagon","strength":0.71},{"slug":"fomo","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.51,"extraversion":0.73,"agreeableness":0.77,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the downside gets concrete, abandons a private read the instant the crowd leans the other way. Otherwise, a steady unofficial group historian who apologizes first in disputes regardless of fault and gets bored of the proven method exactly when it starts working. Feels the weight of a decision lighten the moment someone else co-signs it, and in the small things keeps a mental ledger of social debts.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd75