('1905acda-6614-4e2d-a163-09373049c1f0', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.6,"extraversion":0.76,"agreeableness":0.8,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.41,"narcissism":0.65,"psychopathy":0.35},"prospect_theory":{"lambda":2.29,"alpha":0.85,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Team captain whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. Collects half-finished manifestos and unconventional methods. When the walls close in, adopts a conviction mainly because the room already has; texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.67},{"slug":"herd-behavior","strength":0.71},{"slug":"fomo","strength":0.62},{"slug":"bandwagon","strength":0.74}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.6,"extraversion":0.76,"agreeableness":0.8,"neuroticism":0.38}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Team captain whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. Collects half-finished manifestos and unconventional methods. When the walls close in, adopts a conviction mainly because the room already has; texts an apology before confirming anyone is upset.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
