('09f5a6e5-fa5a-4703-be2d-390f064b0fef', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.4,"extraversion":0.84,"agreeableness":0.76,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.37,"narcissism":0.67,"psychopathy":0.31},"prospect_theory":{"lambda":1.56,"alpha":0.82,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the safe option quietly expires, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced liquidation-bot operator who recharges by being around people, not away from them and carries yesterday''s stress into today''s unrelated decision. Waits for a permission that never quite arrives, and when the pressure is off holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.73},{"slug":"fomo","strength":0.72},{"slug":"endowment","strength":0.6},{"slug":"dunning-kruger","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.4,"extraversion":0.84,"agreeableness":0.76,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the safe option quietly expires, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced liquidation-bot operator who recharges by being around people, not away from them and carries yesterday''s stress into today''s unrelated decision. Waits for a permission that never quite arrives, and when the pressure is off holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('37e4bac1-bcbd-41ef-a833-bbfd71ff3351', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.53,"extraversion":0.66,"agreeableness":0.84,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.31,"narcissism":0.57,"psychopathy":0.27},"prospect_theory":{"lambda":2.47,"alpha":0.86,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This reluctant plus-one absorbs conflict to keep the peace, often at their own cost and chases novel frameworks and abandons them once the novelty fades. When the number turns red gains confidence in a position in proportion to how many others hold it — when no one is watching, over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.66},{"slug":"sunk-cost","strength":0.53},{"slug":"endowment","strength":0.6},{"slug":"bandwagon","strength":0.75}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.53,"extraversion":0.66,"agreeableness":0.84,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This reluctant plus-one absorbs conflict to keep the peace, often at their own cost and chases novel frameworks and abandons them once the novelty fades. When the number turns red gains confidence in a position in proportion to how many others hold it — when no one is watching, over-commits to plans they later dread.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e06d5059-c520-46d7-84f8-f2c1e8c0d92b', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.4,"extraversion":0.96,"agreeableness":0.75,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.32,"narcissism":0.77,"psychopathy":0.29},"prospect_theory":{"lambda":1.57,"alpha":0.8,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced value investor who treats a quiet room as a problem to be solved. Circles back to ask what someone else would do even after deciding. Measures decisions by who they might upset. When there is no clean exit finds it hard to hold a contrarian position once the room disagrees; when the pressure is off, rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"bandwagon","strength":0.8},{"slug":"herd-behavior","strength":0.87}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.4,"extraversion":0.96,"agreeableness":0.75,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced value investor who treats a quiet room as a problem to be solved. Circles back to ask what someone else would do even after deciding. Measures decisions by who they might upset. When there is no clean exit finds it hard to hold a contrarian position once the room disagrees; when the pressure is off, rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('14d67f56-e25b-42d9-bea7-43a0e2000b44', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.6,"extraversion":0.77,"agreeableness":0.94,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.39,"narcissism":0.64,"psychopathy":0.27},"prospect_theory":{"lambda":2.49,"alpha":0.91,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This event host defaults to trust and gives the benefit of the doubt too freely and draws energy from the crowd and wilts when working alone. Once things get tense adopts a conviction mainly because the room already has — in the small things, over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.62},{"slug":"bandwagon","strength":0.82},{"slug":"herd-behavior","strength":0.77}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.6,"extraversion":0.77,"agreeableness":0.94,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This event host defaults to trust and gives the benefit of the doubt too freely and draws energy from the crowd and wilts when working alone. Once things get tense adopts a conviction mainly because the room already has — in the small things, over-explains a boundary rather than just stating it.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f0dad059-f623-482c-96de-bfb12ba80fea', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.37,"extraversion":0.89,"agreeableness":0.66,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.4,"narcissism":0.76,"psychopathy":0.35},"prospect_theory":{"lambda":1.35,"alpha":0.82,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Macro allocator, pronounced in style: dominates the room then wonders why others stayed quiet; is reliably surprised by deadlines that were never hidden. Trusts the group''s confidence more than its own. When the stakes rise finds it hard to hold a contrarian position once the room disagrees.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.64},{"slug":"fomo","strength":0.67},{"slug":"herd-behavior","strength":0.72}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.37,"extraversion":0.89,"agreeableness":0.66,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Macro allocator, pronounced in style: dominates the room then wonders why others stayed quiet; is reliably surprised by deadlines that were never hidden. Trusts the group''s confidence more than its own. When the stakes rise finds it hard to hold a contrarian position once the room disagrees.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('231d631b-9b4c-4b0a-a7e8-fed155261536', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.64,"extraversion":0.78,"agreeableness":0.81,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.43,"narcissism":0.67,"psychopathy":0.32},"prospect_theory":{"lambda":2.44,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This group-project default leader measures decisions by who they might upset and gets bored of the proven method exactly when it starts working. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it — across the quiet stretches, mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"herd-behavior","strength":0.73},{"slug":"fomo","strength":0.59}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.64,"extraversion":0.78,"agreeableness":0.81,"neuroticism":0.42}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This group-project default leader measures decisions by who they might upset and gets bored of the proven method exactly when it starts working. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it — across the quiet stretches, mediates conflicts they secretly started.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('fb188347-fa2f-470e-998e-a4682c6ee0ac', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.61,"extraversion":0.68,"agreeableness":0.78,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.39,"narcissism":0.59,"psychopathy":0.3},"prospect_theory":{"lambda":2.35,"alpha":0.84,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This reluctant plus-one takes on other people''s problems as if they were their own and gets bored of the proven method exactly when it starts working. When the safe option quietly expires takes the crowd''s confidence as a substitute for its own analysis — on a slow afternoon, over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.63},{"slug":"herd-behavior","strength":0.66}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.72,"conscientiousness":0.61,"extraversion":0.68,"agreeableness":0.78,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This reluctant plus-one takes on other people''s problems as if they were their own and gets bored of the proven method exactly when it starts working. When the safe option quietly expires takes the crowd''s confidence as a substitute for its own analysis — on a slow afternoon, over-explains a boundary rather than just stating it.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c23f7e6c-e020-469e-bce1-c18048a482a1', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.5,"extraversion":0.9,"agreeableness":0.68,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.42,"narcissism":0.73,"psychopathy":0.25},"prospect_theory":{"lambda":1.32,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced crypto day-trader who draws energy from the crowd and wilts when working alone. Needs the room''s approval more than it needs to be right. Reads outside the field for ideas the field itself would reject. As soon as real money or reputation is on the line takes the crowd''s confidence as a substitute for its own analysis; in the small things, screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"dunning-kruger","strength":0.61},{"slug":"bandwagon","strength":0.68},{"slug":"fomo","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.5,"extraversion":0.9,"agreeableness":0.68,"neuroticism":0.56}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced crypto day-trader who draws energy from the crowd and wilts when working alone. Needs the room''s approval more than it needs to be right. Reads outside the field for ideas the field itself would reject. As soon as real money or reputation is on the line takes the crowd''s confidence as a substitute for its own analysis; in the small things, screenshots the winners and never the losers.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a97ead84-5da0-4130-a260-09ef9aca03f9', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.42,"extraversion":0.74,"agreeableness":0.73,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.38,"narcissism":0.62,"psychopathy":0.32},"prospect_theory":{"lambda":1.31,"alpha":0.83,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A steady discretionary swing trader: dominates the room then wonders why others stayed quiet, defaults to trust and gives the benefit of the doubt too freely. Outsources conviction to whoever spoke last with authority, and across the quiet stretches averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.63},{"slug":"dunning-kruger","strength":0.6},{"slug":"fomo","strength":0.55}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.42,"extraversion":0.74,"agreeableness":0.73,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A steady discretionary swing trader: dominates the room then wonders why others stayed quiet, defaults to trust and gives the benefit of the doubt too freely. Outsources conviction to whoever spoke last with authority, and across the quiet stretches averages down on a name three times in a week.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d74580f5-3a3f-4331-b862-3525e95058e7', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.33,"extraversion":0.87,"agreeableness":0.7,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.38,"narcissism":0.65,"psychopathy":0.39},"prospect_theory":{"lambda":1.33,"alpha":0.82,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Penny-stock gambler whose defining move is that they recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything. Starts strong and lets follow-through evaporate. Under a deadline, abandons a private read the instant the crowd leans the other way; sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.8},{"slug":"fomo","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.33,"extraversion":0.87,"agreeableness":0.7,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Penny-stock gambler whose defining move is that they recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything. Starts strong and lets follow-through evaporate. Under a deadline, abandons a private read the instant the crowd leans the other way; sets stop-losses then cancels them at the open.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a83da15b-bd91-441b-b2e1-0a8f0a0fe79e', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.53,"extraversion":0.66,"agreeableness":0.84,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.38,"narcissism":0.49,"psychopathy":0.29},"prospect_theory":{"lambda":2.26,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced the friend who always drives who absorbs conflict to keep the peace, often at their own cost and narrates the plan to whoever is nearby before committing to it. Circles back to ask what someone else would do even after deciding, and in the parts nobody grades remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.53},{"slug":"bandwagon","strength":0.66},{"slug":"herd-behavior","strength":0.73},{"slug":"authority-bias","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.55,"conscientiousness":0.53,"extraversion":0.66,"agreeableness":0.84,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced the friend who always drives who absorbs conflict to keep the peace, often at their own cost and narrates the plan to whoever is nearby before committing to it. Circles back to ask what someone else would do even after deciding, and in the parts nobody grades remembers everyone birthday and no one boundaries.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
