('8135184c-ef8e-4701-b731-d75a765db426', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.47,"extraversion":0.89,"agreeableness":0.7,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.37,"narcissism":0.69,"psychopathy":0.26},"prospect_theory":{"lambda":1.24,"alpha":0.87,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced DeFi yield farmer who recharges by being around people, not away from them. Trusts the group''s confidence more than its own. Would rather invent a worse tool than use someone else''s good one. When the number turns red treats being left out of a move as its own kind of loss; once the urgency drains out, names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.77},{"slug":"dunning-kruger","strength":0.59},{"slug":"herd-behavior","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.47,"extraversion":0.89,"agreeableness":0.7,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced DeFi yield farmer who recharges by being around people, not away from them. Trusts the group''s confidence more than its own. Would rather invent a worse tool than use someone else''s good one. When the number turns red treats being left out of a move as its own kind of loss; once the urgency drains out, names every strategy after the trade that almost worked.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
