('ef3994aa-ca84-4d20-84de-4dfadfa5ccdc', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.6,"extraversion":0.67,"agreeableness":0.86,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.35,"narcissism":0.53,"psychopathy":0.24},"prospect_theory":{"lambda":2.49,"alpha":0.87,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Longtime regular at the same three places whose defining move is that they reads other people''s discomfort before they voice it. Outsources conviction to whoever spoke last with authority. Fills silence reflexively, even when nobody asked it to. As soon as real money or reputation is on the line, would not buy back what it already owns at the price it would sell it for; reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.68},{"slug":"herd-behavior","strength":0.66},{"slug":"bandwagon","strength":0.67},{"slug":"authority-bias","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.72,"conscientiousness":0.6,"extraversion":0.67,"agreeableness":0.86,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Longtime regular at the same three places whose defining move is that they reads other people''s discomfort before they voice it. Outsources conviction to whoever spoke last with authority. Fills silence reflexively, even when nobody asked it to. As soon as real money or reputation is on the line, would not buy back what it already owns at the price it would sell it for; reads the room then performs to it.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758b