('5faabe9a-8ac7-4cb9-bd3f-d9ae4fc7f62d', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.54,"extraversion":0.72,"agreeableness":0.8,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.37,"narcissism":0.59,"psychopathy":0.31},"prospect_theory":{"lambda":2.45,"alpha":0.89,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A steady team captain: apologizes first in disputes regardless of fault, reframes every problem as an excuse to learn a new system. Outsources conviction to whoever spoke last with authority, and as a rule drafts the apology before the mistake.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.65},{"slug":"authority-bias","strength":0.55},{"slug":"endowment","strength":0.63},{"slug":"bandwagon","strength":0.76}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.54,"extraversion":0.72,"agreeableness":0.8,"neuroticism":0.47}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A steady team captain: apologizes first in disputes regardless of fault, reframes every problem as an excuse to learn a new system. Outsources conviction to whoever spoke last with authority, and as a rule drafts the apology before the mistake.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f355a36b-f7b5-4b97-82ec-4d65c145229c', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.54,"extraversion":0.68,"agreeableness":0.86,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.39,"narcissism":0.61,"psychopathy":0.25},"prospect_theory":{"lambda":2.25,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This the one who remembers everyone''s order measures decisions by who they might upset and treats a quiet room as a problem to be solved. Under pressure abandons a private read the instant the crowd leans the other way — in the small things, over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.66},{"slug":"sunk-cost","strength":0.56},{"slug":"endowment","strength":0.65},{"slug":"herd-behavior","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.81,"conscientiousness":0.54,"extraversion":0.68,"agreeableness":0.86,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This the one who remembers everyone''s order measures decisions by who they might upset and treats a quiet room as a problem to be solved. Under pressure abandons a private read the instant the crowd leans the other way — in the small things, over-explains a boundary rather than just stating it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c4b9a1ce-1660-4f5c-ab44-b8000c3d0ebf', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.62,"extraversion":0.72,"agreeableness":0.83,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.42,"narcissism":0.57,"psychopathy":0.25},"prospect_theory":{"lambda":2.24,"alpha":0.88,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Group-chat ringleader whose defining move is that they reads other people''s discomfort before they voice it. Seeks a second, third, and fourth opinion before committing to anything. Would rather invent a worse tool than use someone else''s good one. The instant the deadline moves up, gains confidence in a position in proportion to how many others hold it; keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"fomo","strength":0.66},{"slug":"bandwagon","strength":0.73},{"slug":"endowment","strength":0.59}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.62,"extraversion":0.72,"agreeableness":0.83,"neuroticism":0.57}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Group-chat ringleader whose defining move is that they reads other people''s discomfort before they voice it. Seeks a second, third, and fourth opinion before committing to anything. Would rather invent a worse tool than use someone else''s good one. The instant the deadline moves up, gains confidence in a position in proportion to how many others hold it; keeps score of favors without meaning to.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('40dd99e5-4002-487a-bbe8-01e82d168bc7', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.66,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.35,"narcissism":0.7,"psychopathy":0.35},"prospect_theory":{"lambda":1.36,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Dividend-yield chaser, steady in style: treats a quiet room as a problem to be solved; would rather invent a worse tool than use someone else''s good one. Trusts the group''s confidence more than its own. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"bandwagon","strength":0.73},{"slug":"herd-behavior","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.66,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Dividend-yield chaser, steady in style: treats a quiet room as a problem to be solved; would rather invent a worse tool than use someone else''s good one. Trusts the group''s confidence more than its own. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
