('4a95886d-e10d-4d6b-8c68-d718dfe82e62', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.38,"extraversion":0.9,"agreeableness":0.69,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.34,"narcissism":0.75,"psychopathy":0.34},"prospect_theory":{"lambda":1.39,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Cannot watch a rally from the sidelines for long. A pronounced perps degen: narrates the plan to whoever is nearby before committing to it, defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives, and without an audience trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.81},{"slug":"dunning-kruger","strength":0.71},{"slug":"bandwagon","strength":0.73},{"slug":"recency","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.38,"extraversion":0.9,"agreeableness":0.69,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Cannot watch a rally from the sidelines for long. A pronounced perps degen: narrates the plan to whoever is nearby before committing to it, defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives, and without an audience trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
