('653cef5a-0cf4-4b08-8e36-057e643f12b8', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.53,"extraversion":0.81,"agreeableness":0.82,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.39,"narcissism":0.64,"psychopathy":0.32},"prospect_theory":{"lambda":2.3,"alpha":0.92,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady neighborhood connector who takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority. Chases novel frameworks and abandons them once the novelty fades. When the stakes rise abandons a private read the instant the crowd leans the other way; across an ordinary week, remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"optimism","strength":0.58},{"slug":"bandwagon","strength":0.72}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.53,"extraversion":0.81,"agreeableness":0.82,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady neighborhood connector who takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority. Chases novel frameworks and abandons them once the novelty fades. When the stakes rise abandons a private read the instant the crowd leans the other way; across an ordinary week, remembers who didn''t get invited last time.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e4ebd1e9-29ce-45b7-9667-6820c912a3bd', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.46,"extraversion":0.67,"agreeableness":0.88,"neuroticism":0.36},"dark_triad":{"machiavellianism":0.32,"narcissism":0.54,"psychopathy":0.36},"prospect_theory":{"lambda":2.34,"alpha":0.83,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A pronounced newcomer welcomer: would rather lose a point than win an argument badly, fills silence reflexively, even when nobody asked it to. Outsources conviction to whoever spoke last with authority, and on an ordinary week keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"authority-bias","strength":0.67},{"slug":"endowment","strength":0.58},{"slug":"sunk-cost","strength":0.64},{"slug":"herd-behavior","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.75,"conscientiousness":0.46,"extraversion":0.67,"agreeableness":0.88,"neuroticism":0.36}'::jsonb, 'ENFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A pronounced newcomer welcomer: would rather lose a point than win an argument badly, fills silence reflexively, even when nobody asked it to. Outsources conviction to whoever spoke last with authority, and on an ordinary week keeps a mental ledger of social debts.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ec26d27a-7762-42b2-81b1-c97bf8ad93d4', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.31,"extraversion":0.85,"agreeableness":0.57,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.43,"narcissism":0.72,"psychopathy":0.4},"prospect_theory":{"lambda":1.5,"alpha":0.84,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced pairs trader who treats a quiet room as a problem to be solved. Circles back to ask what someone else would do even after deciding. Gets bored of the proven method exactly when it starts working. The instant it becomes irreversible finds it hard to hold a contrarian position once the room disagrees; across an ordinary week, holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"fomo","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.82,"conscientiousness":0.31,"extraversion":0.85,"agreeableness":0.57,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced pairs trader who treats a quiet room as a problem to be solved. Circles back to ask what someone else would do even after deciding. Gets bored of the proven method exactly when it starts working. The instant it becomes irreversible finds it hard to hold a contrarian position once the room disagrees; across an ordinary week, holds a bag from 2021 out of pure spite.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('558b22bc-ecfb-40d2-9460-cad975325ca2', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.53,"extraversion":0.68,"agreeableness":0.8,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.34,"narcissism":0.57,"psychopathy":0.27},"prospect_theory":{"lambda":2.52,"alpha":0.9,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady longtime regular at the same three places who takes on other people''s problems as if they were their own. Circles back to ask what someone else would do even after deciding. Narrates the plan to whoever is nearby before committing to it. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis; in the small things, mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.73},{"slug":"bandwagon","strength":0.65}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.53,"extraversion":0.68,"agreeableness":0.8,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady longtime regular at the same three places who takes on other people''s problems as if they were their own. Circles back to ask what someone else would do even after deciding. Narrates the plan to whoever is nearby before committing to it. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis; in the small things, mediates conflicts they secretly started.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('51e28d62-ee88-4b10-bd9c-77c95c12ae2a', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.46,"extraversion":0.9,"agreeableness":0.62,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.4,"narcissism":0.7,"psychopathy":0.31},"prospect_theory":{"lambda":1.31,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Treats being left out of a move as its own kind of loss. A pronounced retail momentum chaser: fills silence reflexively, even when nobody asked it to, measures decisions by who they might upset. Seeks a second, third, and fourth opinion before committing to anything, and when the stakes are trivial keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.79},{"slug":"dunning-kruger","strength":0.69},{"slug":"herd-behavior","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.46,"extraversion":0.9,"agreeableness":0.62,"neuroticism":0.65}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Treats being left out of a move as its own kind of loss. A pronounced retail momentum chaser: fills silence reflexively, even when nobody asked it to, measures decisions by who they might upset. Seeks a second, third, and fourth opinion before committing to anything, and when the stakes are trivial keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0412f67a-7a9f-4fbb-b302-2b2347aeea40', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.43,"extraversion":0.87,"agreeableness":0.69,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.35,"narcissism":0.68,"psychopathy":0.33},"prospect_theory":{"lambda":1.43,"alpha":0.81,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"In a pinch, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced crypto day-trader who fills silence reflexively, even when nobody asked it to and gets bored of the proven method exactly when it starts working. Trusts the group''s confidence more than its own, and left to their own devices sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.68},{"slug":"recency","strength":0.64},{"slug":"herd-behavior","strength":0.79},{"slug":"fomo","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.43,"extraversion":0.87,"agreeableness":0.69,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'In a pinch, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced crypto day-trader who fills silence reflexively, even when nobody asked it to and gets bored of the proven method exactly when it starts working. Trusts the group''s confidence more than its own, and left to their own devices sets stop-losses then cancels them at the open.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('fc01285e-5d26-4b2a-9887-968ff32ef00b', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.39,"extraversion":0.89,"agreeableness":0.66,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.36,"narcissism":0.73,"psychopathy":0.35},"prospect_theory":{"lambda":1.56,"alpha":0.83,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A pronounced options seller: thinks out loud and recruits an audience for every decision, takes on other people''s problems as if they were their own. Circles back to ask what someone else would do even after deciding, and in the version no one reviews rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.78},{"slug":"herd-behavior","strength":0.77},{"slug":"fomo","strength":0.73},{"slug":"dunning-kruger","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.39,"extraversion":0.89,"agreeableness":0.66,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A pronounced options seller: thinks out loud and recruits an audience for every decision, takes on other people''s problems as if they were their own. Circles back to ask what someone else would do even after deciding, and in the version no one reviews rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('b5cb3ac3-4cc2-4cc5-9c53-f6251b88c02d', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.58,"extraversion":0.87,"agreeableness":0.87,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.35,"narcissism":0.72,"psychopathy":0.31},"prospect_theory":{"lambda":2.23,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under pressure, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced reluctant plus-one who recharges by being around people, not away from them and takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own, and across the quiet stretches says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"herd-behavior","strength":0.87}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","decision-making","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.59,"conscientiousness":0.58,"extraversion":0.87,"agreeableness":0.87,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','decision-making','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under pressure, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced reluctant plus-one who recharges by being around people, not away from them and takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own, and across the quiet stretches says yes out loud and no internally.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('59181b6f-d7e3-4ed4-914e-1401a1f5c93c', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.64,"extraversion":0.75,"agreeableness":0.94,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.38,"narcissism":0.59,"psychopathy":0.29},"prospect_theory":{"lambda":2.41,"alpha":0.92,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under pressure, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced peer mentor who apologizes first in disputes regardless of fault and plans in exhaustive detail and resents any deviation. Outsources conviction to whoever spoke last with authority, and in the unglamorous middle of things keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.75},{"slug":"endowment","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.58,"conscientiousness":0.64,"extraversion":0.75,"agreeableness":0.94,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under pressure, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced peer mentor who apologizes first in disputes regardless of fault and plans in exhaustive detail and resents any deviation. Outsources conviction to whoever spoke last with authority, and in the unglamorous middle of things keeps a mental ledger of social debts.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6b4b4dc2-faf5-476f-b22f-7e8353e61d0f', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.67,"extraversion":0.63,"agreeableness":0.93,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.35,"narcissism":0.51,"psychopathy":0.26},"prospect_theory":{"lambda":2.41,"alpha":0.9,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced wedding-party diplomat who absorbs conflict to keep the peace, often at their own cost. Seeks a second, third, and fourth opinion before committing to anything. Reframes every problem as an excuse to learn a new system. When the stakes rise feels parting with something as a bigger loss than its market value explains; in the version no one reviews, drafts the apology before the mistake.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.58},{"slug":"endowment","strength":0.68},{"slug":"authority-bias","strength":0.64},{"slug":"herd-behavior","strength":0.65}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.73,"conscientiousness":0.67,"extraversion":0.63,"agreeableness":0.93,"neuroticism":0.51}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced wedding-party diplomat who absorbs conflict to keep the peace, often at their own cost. Seeks a second, third, and fourth opinion before committing to anything. Reframes every problem as an excuse to learn a new system. When the stakes rise feels parting with something as a bigger loss than its market value explains; in the version no one reviews, drafts the apology before the mistake.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('5f297334-ed2b-4a1d-8496-9c76fd13809c', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.54,"extraversion":0.71,"agreeableness":0.74,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.41,"narcissism":0.56,"psychopathy":0.26},"prospect_theory":{"lambda":2.35,"alpha":0.87,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the walls close in, finds it easier to believe something once it stops being a minority view. Otherwise, a steady reluctant plus-one who takes on other people''s problems as if they were their own and treats established procedure as a first draft to be rewritten. Needs the room''s approval more than it needs to be right, and when the pressure is off keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.54},{"slug":"bandwagon","strength":0.72},{"slug":"endowment","strength":0.56}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.54,"extraversion":0.71,"agreeableness":0.74,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the walls close in, finds it easier to believe something once it stops being a minority view. Otherwise, a steady reluctant plus-one who takes on other people''s problems as if they were their own and treats established procedure as a first draft to be rewritten. Needs the room''s approval more than it needs to be right, and when the pressure is off keeps score of favors without meaning to.', 0.89, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('fc0c10b5-c64e-4b1b-afc0-cc9aa931e50d', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.34,"extraversion":0.72,"agreeableness":0.76,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.36,"narcissism":0.63,"psychopathy":0.33},"prospect_theory":{"lambda":1.33,"alpha":0.9,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment risk appears, finds it easier to believe something once it stops being a minority view. Otherwise, a steady volatility arbitrageur who chases novel frameworks and abandons them once the novelty fades and dominates the room then wonders why others stayed quiet. Needs the room''s approval more than it needs to be right, and in the routine of it refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"sunk-cost","strength":0.58},{"slug":"dunning-kruger","strength":0.63},{"slug":"recency","strength":0.65},{"slug":"bandwagon","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.34,"extraversion":0.72,"agreeableness":0.76,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment risk appears, finds it easier to believe something once it stops being a minority view. Otherwise, a steady volatility arbitrageur who chases novel frameworks and abandons them once the novelty fades and dominates the room then wonders why others stayed quiet. Needs the room''s approval more than it needs to be right, and in the routine of it refreshes the order book compulsively during lunch.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('904563a8-1ab5-497d-9bf8-dc80a9a4fd30', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.47,"extraversion":0.69,"agreeableness":0.91,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.33,"narcissism":0.55,"psychopathy":0.31},"prospect_theory":{"lambda":2.55,"alpha":0.91,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment it stops being hypothetical, adopts a conviction mainly because the room already has. Otherwise, a pronounced reluctant plus-one who defaults to trust and gives the benefit of the doubt too freely and treats established procedure as a first draft to be rewritten. Trusts the group''s confidence more than its own, and across an ordinary week defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"authority-bias","strength":0.62},{"slug":"herd-behavior","strength":0.71},{"slug":"bandwagon","strength":0.77}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.47,"extraversion":0.69,"agreeableness":0.91,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment it stops being hypothetical, adopts a conviction mainly because the room already has. Otherwise, a pronounced reluctant plus-one who defaults to trust and gives the benefit of the doubt too freely and treats established procedure as a first draft to be rewritten. Trusts the group''s confidence more than its own, and across an ordinary week defuses tension with a joke that lands most of the time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('35ebfd4b-1291-4b64-a6be-e2dc48141cbf', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.43,"extraversion":0.94,"agreeableness":0.73,"neuroticism":0.72},"dark_triad":{"machiavellianism":0.36,"narcissism":0.74,"psychopathy":0.33},"prospect_theory":{"lambda":1.38,"alpha":0.78,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This airdrop farmer thinks out loud and recruits an audience for every decision and measures decisions by who they might upset. When the downside gets concrete jumps into whatever everyone else already seems to be winning at — in the pattern nobody else tracks, exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.8},{"slug":"bandwagon","strength":0.79},{"slug":"dunning-kruger","strength":0.69},{"slug":"herd-behavior","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.43,"extraversion":0.94,"agreeableness":0.73,"neuroticism":0.72}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This airdrop farmer thinks out loud and recruits an audience for every decision and measures decisions by who they might upset. When the downside gets concrete jumps into whatever everyone else already seems to be winning at — in the pattern nobody else tracks, exits winners at the first green candle.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a736557e-09be-4418-ab5a-f84b1a0a903a', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.36,"extraversion":0.79,"agreeableness":0.65,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.39,"narcissism":0.68,"psychopathy":0.36},"prospect_theory":{"lambda":1.36,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under pressure, treats being left out of a move as its own kind of loss. Otherwise, a steady volatility arbitrageur who narrates the plan to whoever is nearby before committing to it and improvises past every deadline and calls it flexibility. Waits for a permission that never quite arrives, and day to day treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.64},{"slug":"bandwagon","strength":0.62},{"slug":"recency","strength":0.59},{"slug":"fomo","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.36,"extraversion":0.79,"agreeableness":0.65,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under pressure, treats being left out of a move as its own kind of loss. Otherwise, a steady volatility arbitrageur who narrates the plan to whoever is nearby before committing to it and improvises past every deadline and calls it flexibility. Waits for a permission that never quite arrives, and day to day treats a green week as proof of skill and a red one as proof of bad luck.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc')
INSERT INTO profiles (id, version, content, big_five, mbti_label, decision_style, tags, summary, quality_score, status, generation_run_id) VALUES
('5e5b801e-8a17-4e64-a925-89d9476c5c5c', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.36,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.4,"narcissism":0.58,"psychopathy":0.33},"prospect_theory":{"lambda":1.57,"alpha":0.83,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady onchain copy-trader who draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything. Treats a plan as a suggestion the moment it is made. When the walls close in finds it hard to hold a contrarian position once the room disagrees; when no one is watching, sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.68},{"slug":"dunning-kruger","strength":0.62},{"slug":"herd-behavior","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.36,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.69}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady onchain copy-trader who draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything. Treats a plan as a suggestion the moment it is made. When the walls close in finds it hard to hold a contrarian position once the room disagrees; when no one is watching, sets stop-losses then cancels them at the open.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0bca2ead-3fd5-4a48-a4b6-036d00bdaf22', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.37,"extraversion":0.85,"agreeableness":0.74,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.38,"narcissism":0.76,"psychopathy":0.36},"prospect_theory":{"lambda":1.27,"alpha":0.87,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Delta-neutral market maker whose defining move is that they treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority. Improvises past every deadline and calls it flexibility. The instant it becomes irreversible, finds it easier to believe something once it stops being a minority view; treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.68},{"slug":"bandwagon","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.92,"conscientiousness":0.37,"extraversion":0.85,"agreeableness":0.74,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Delta-neutral market maker whose defining move is that they treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority. Improvises past every deadline and calls it flexibility. The instant it becomes irreversible, finds it easier to believe something once it stops being a minority view; treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('28248a24-a4b8-4928-8406-99bb8c06199d', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.72,"extraversion":0.74,"agreeableness":0.75,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.44,"narcissism":0.64,"psychopathy":0.28},"prospect_theory":{"lambda":2.55,"alpha":0.92,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This neighborhood connector absorbs conflict to keep the peace, often at their own cost and maintains flawless records nobody asked for. When there is no clean exit gains confidence in a position in proportion to how many others hold it — as a rule, can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.57},{"slug":"bandwagon","strength":0.73},{"slug":"fomo","strength":0.6}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.72,"extraversion":0.74,"agreeableness":0.75,"neuroticism":0.47}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This neighborhood connector absorbs conflict to keep the peace, often at their own cost and maintains flawless records nobody asked for. When there is no clean exit gains confidence in a position in proportion to how many others hold it — as a rule, can sense a mood shift from the doorway.', 0.88, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ef05f671-0995-4871-a357-f820dcca3506', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.53,"extraversion":0.71,"agreeableness":0.79,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.38,"narcissism":0.57,"psychopathy":0.33},"prospect_theory":{"lambda":2.33,"alpha":0.92,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A steady neighborhood connector: would rather lose a point than win an argument badly, gets bored of the proven method exactly when it starts working. Feels the weight of a decision lighten the moment someone else co-signs it, and in the unglamorous middle of things texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.57},{"slug":"herd-behavior","strength":0.68},{"slug":"optimism","strength":0.66}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.53,"extraversion":0.71,"agreeableness":0.79,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A steady neighborhood connector: would rather lose a point than win an argument badly, gets bored of the proven method exactly when it starts working. Feels the weight of a decision lighten the moment someone else co-signs it, and in the unglamorous middle of things texts an apology before confirming anyone is upset.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f0737841-2fdb-4c4f-88ba-c28fcfbaee98', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.45,"extraversion":0.87,"agreeableness":0.82,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.33,"narcissism":0.73,"psychopathy":0.29},"prospect_theory":{"lambda":1.44,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced crypto day-trader who narrates the plan to whoever is nearby before committing to it. Seeks a second, third, and fourth opinion before committing to anything. Notices the one thing that could go wrong before the nine that could go right. When the safe option quietly expires abandons a private read the instant the crowd leans the other way; in the parts nobody grades, refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"fomo","strength":0.75},{"slug":"herd-behavior","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.45,"extraversion":0.87,"agreeableness":0.82,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced crypto day-trader who narrates the plan to whoever is nearby before committing to it. Seeks a second, third, and fourth opinion before committing to anything. Notices the one thing that could go wrong before the nine that could go right. When the safe option quietly expires abandons a private read the instant the crowd leans the other way; in the parts nobody grades, refreshes the order book compulsively during lunch.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4d475cc4-fff5-4aee-82d2-93662e8a3a85', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.36,"extraversion":0.87,"agreeableness":0.66,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.42,"narcissism":0.66,"psychopathy":0.38},"prospect_theory":{"lambda":1.55,"alpha":0.86,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When someone is watching the outcome, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced meme-coin rotator who draws energy from the crowd and wilts when working alone and reads outside the field for ideas the field itself would reject. Waits for a permission that never quite arrives, and day to day apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.73},{"slug":"bandwagon","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.36,"extraversion":0.87,"agreeableness":0.66,"neuroticism":0.67}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When someone is watching the outcome, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced meme-coin rotator who draws energy from the crowd and wilts when working alone and reads outside the field for ideas the field itself would reject. Waits for a permission that never quite arrives, and day to day apes the launch before the contract is verified.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('58bb7ea4-d186-43e5-b79a-7eaf704a0f36', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.54,"extraversion":0.79,"agreeableness":0.7,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.42,"narcissism":0.66,"psychopathy":0.27},"prospect_theory":{"lambda":2.57,"alpha":0.93,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Online moderator whose defining move is that they recharges by being around people, not away from them. Circles back to ask what someone else would do even after deciding. Chases novel frameworks and abandons them once the novelty fades. The moment risk appears, finds it hard to hold a contrarian position once the room disagrees; remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"fomo","strength":0.57}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.54,"extraversion":0.79,"agreeableness":0.7,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Online moderator whose defining move is that they recharges by being around people, not away from them. Circles back to ask what someone else would do even after deciding. Chases novel frameworks and abandons them once the novelty fades. The moment risk appears, finds it hard to hold a contrarian position once the room disagrees; remembers everyone birthday and no one boundaries.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
