('f8f5beb5-911c-4a4c-a274-27102fe12faa', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.44,"extraversion":0.8,"agreeableness":0.63,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.41,"narcissism":0.65,"psychopathy":0.35},"prospect_theory":{"lambda":1.34,"alpha":0.88,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Liquidation-bot operator, pronounced in style: would rather invent a worse tool than use someone else''s good one; carries yesterday''s stress into today''s unrelated decision. Outsources conviction to whoever spoke last with authority. The instant it becomes irreversible treats being left out of a move as its own kind of loss.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.74},{"slug":"recency","strength":0.72},{"slug":"bandwagon","strength":0.68},{"slug":"herd-behavior","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.85,"conscientiousness":0.44,"extraversion":0.8,"agreeableness":0.63,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Liquidation-bot operator, pronounced in style: would rather invent a worse tool than use someone else''s good one; carries yesterday''s stress into today''s unrelated decision. Outsources conviction to whoever spoke last with authority. The instant it becomes irreversible treats being left out of a move as its own kind of loss.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
