('1ffd42a7-bebe-43e2-8f2a-492bf45165c9', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.53,"extraversion":0.74,"agreeableness":0.85,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.31,"narcissism":0.61,"psychopathy":0.3},"prospect_theory":{"lambda":2.38,"alpha":0.92,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced nonprofit convener who apologizes first in disputes regardless of fault and treats a quiet room as a problem to be solved. Outsources conviction to whoever spoke last with authority, and when the pressure is off remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.59},{"slug":"herd-behavior","strength":0.68}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.53,"extraversion":0.74,"agreeableness":0.85,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced nonprofit convener who apologizes first in disputes regardless of fault and treats a quiet room as a problem to be solved. Outsources conviction to whoever spoke last with authority, and when the pressure is off remembers who didn''t get invited last time.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
