('fa948268-f814-43ac-82a3-64e1044556e9', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.52,"extraversion":0.76,"agreeableness":0.72,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.37,"narcissism":0.66,"psychopathy":0.3},"prospect_theory":{"lambda":2.49,"alpha":0.92,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This unofficial group historian thinks out loud and recruits an audience for every decision and absorbs conflict to keep the peace, often at their own cost. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way — in the routine of it, says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"fomo","strength":0.63},{"slug":"endowment","strength":0.5},{"slug":"bandwagon","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","behavioral","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.52,"extraversion":0.76,"agreeableness":0.72,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','behavioral','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This unofficial group historian thinks out loud and recruits an audience for every decision and absorbs conflict to keep the peace, often at their own cost. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way — in the routine of it, says yes out loud and no internally.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6a657924-36a7-4410-bafc-6c5a16187d61', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.54,"extraversion":0.69,"agreeableness":0.87,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.38,"narcissism":0.59,"psychopathy":0.31},"prospect_theory":{"lambda":2.35,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This neighborhood connector reads other people''s discomfort before they voice it and chases novel frameworks and abandons them once the novelty fades. Under a deadline adopts a conviction mainly because the room already has — on an ordinary week, mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.64},{"slug":"herd-behavior","strength":0.72},{"slug":"sunk-cost","strength":0.62},{"slug":"bandwagon","strength":0.77}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.54,"extraversion":0.69,"agreeableness":0.87,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This neighborhood connector reads other people''s discomfort before they voice it and chases novel frameworks and abandons them once the novelty fades. Under a deadline adopts a conviction mainly because the room already has — on an ordinary week, mediates conflicts they secretly started.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('884f8767-cbbe-4586-847a-9740fda64f12', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.43,"extraversion":0.85,"agreeableness":0.74,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.34,"narcissism":0.66,"psychopathy":0.28},"prospect_theory":{"lambda":1.25,"alpha":0.84,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The instant the deadline moves up, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced retail momentum chaser who recharges by being around people, not away from them and apologizes first in disputes regardless of fault. Trusts the group''s confidence more than its own, and in the small things exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.58},{"slug":"fomo","strength":0.69},{"slug":"bandwagon","strength":0.7},{"slug":"herd-behavior","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.43,"extraversion":0.85,"agreeableness":0.74,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The instant the deadline moves up, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced retail momentum chaser who recharges by being around people, not away from them and apologizes first in disputes regardless of fault. Trusts the group''s confidence more than its own, and in the small things exits winners at the first green candle.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4bfd25e5-eeec-4ad2-8733-a2422e50588f', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.57,"extraversion":0.78,"agreeableness":0.83,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.4,"narcissism":0.64,"psychopathy":0.3},"prospect_theory":{"lambda":2.45,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"As soon as real money or reputation is on the line, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady newcomer welcomer who would rather lose a point than win an argument badly and gets bored of the proven method exactly when it starts working. Outsources conviction to whoever spoke last with authority, and across the quiet stretches texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.64},{"slug":"herd-behavior","strength":0.78},{"slug":"bandwagon","strength":0.8}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.57,"extraversion":0.78,"agreeableness":0.83,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'As soon as real money or reputation is on the line, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady newcomer welcomer who would rather lose a point than win an argument badly and gets bored of the proven method exactly when it starts working. Outsources conviction to whoever spoke last with authority, and across the quiet stretches texts an apology before confirming anyone is upset.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2f1d3f8f-8669-4721-b5d9-7f719410795c', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.56,"extraversion":0.62,"agreeableness":0.94,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.36,"narcissism":0.46,"psychopathy":0.27},"prospect_theory":{"lambda":2.57,"alpha":0.92,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A pronounced nonprofit convener: absorbs conflict to keep the peace, often at their own cost, treats established procedure as a first draft to be rewritten. Circles back to ask what someone else would do even after deciding, and once the urgency drains out over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"bandwagon","strength":0.76}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.56,"extraversion":0.62,"agreeableness":0.94,"neuroticism":0.54}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A pronounced nonprofit convener: absorbs conflict to keep the peace, often at their own cost, treats established procedure as a first draft to be rewritten. Circles back to ask what someone else would do even after deciding, and once the urgency drains out over-commits to plans they later dread.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d6c8dd47-fdd2-4a5f-98cf-a6fb8a884c04', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.37,"extraversion":0.73,"agreeableness":0.67,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.36,"narcissism":0.64,"psychopathy":0.37},"prospect_theory":{"lambda":1.37,"alpha":0.87,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The instant the deadline moves up, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady dividend-yield chaser who reframes every problem as an excuse to learn a new system and improvises past every deadline and calls it flexibility. Circles back to ask what someone else would do even after deciding, and in the pattern nobody else tracks sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.65},{"slug":"recency","strength":0.56}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.82,"conscientiousness":0.37,"extraversion":0.73,"agreeableness":0.67,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The instant the deadline moves up, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady dividend-yield chaser who reframes every problem as an excuse to learn a new system and improvises past every deadline and calls it flexibility. Circles back to ask what someone else would do even after deciding, and in the pattern nobody else tracks sizes every position at exactly 2% risk.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f4a889f7-9e06-4734-84e7-7d3a7c4f0c4e', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.4,"extraversion":0.81,"agreeableness":0.65,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.41,"narcissism":0.62,"psychopathy":0.33},"prospect_theory":{"lambda":1.49,"alpha":0.86,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This onchain copy-trader draws energy from the crowd and wilts when working alone and reframes every problem as an excuse to learn a new system. When the walls close in treats being left out of a move as its own kind of loss — in the pattern nobody else tracks, calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.59},{"slug":"bandwagon","strength":0.65},{"slug":"fomo","strength":0.7},{"slug":"recency","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.4,"extraversion":0.81,"agreeableness":0.65,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This onchain copy-trader draws energy from the crowd and wilts when working alone and reframes every problem as an excuse to learn a new system. When the walls close in treats being left out of a move as its own kind of loss — in the pattern nobody else tracks, calls a 90% drawdown a long-term hold.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('7f98c299-d437-4fa2-ba7c-2e26f8fc3409', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.59,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.36,"narcissism":0.73,"psychopathy":0.35},"prospect_theory":{"lambda":1.23,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced bonding-curve sniper who fills silence reflexively, even when nobody asked it to and collects half-finished manifestos and unconventional methods. Circles back to ask what someone else would do even after deciding, and across an ordinary week rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.72},{"slug":"bandwagon","strength":0.69},{"slug":"herd-behavior","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.59,"neuroticism":0.49}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced bonding-curve sniper who fills silence reflexively, even when nobody asked it to and collects half-finished manifestos and unconventional methods. Circles back to ask what someone else would do even after deciding, and across an ordinary week rotates the whole book into whatever is pumping this hour.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
