('972a5606-1abb-493b-8d8d-12d510696864', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.53,"extraversion":0.72,"agreeableness":0.91,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.36,"narcissism":0.58,"psychopathy":0.28},"prospect_theory":{"lambda":2.43,"alpha":0.91,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A pronounced group-chat ringleader: takes on other people''s problems as if they were their own, dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything, and when the stakes are trivial reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.62},{"slug":"bandwagon","strength":0.78},{"slug":"authority-bias","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.53,"extraversion":0.72,"agreeableness":0.91,"neuroticism":0.57}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A pronounced group-chat ringleader: takes on other people''s problems as if they were their own, dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything, and when the stakes are trivial reads the room then performs to it.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('945a8817-53f5-4e61-b57a-26384d801bc9', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.39,"extraversion":0.87,"agreeableness":0.76,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.39,"narcissism":0.66,"psychopathy":0.35},"prospect_theory":{"lambda":1.41,"alpha":0.82,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced zero-DTE options gambler who recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything. Rehearses catastrophes in vivid detail before they happen. When cornered takes the crowd''s confidence as a substitute for its own analysis; left to their own devices, confuses a bull market for a trading edge.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"herd-behavior","strength":0.78},{"slug":"fomo","strength":0.72},{"slug":"bandwagon","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.39,"extraversion":0.87,"agreeableness":0.76,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced zero-DTE options gambler who recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything. Rehearses catastrophes in vivid detail before they happen. When cornered takes the crowd''s confidence as a substitute for its own analysis; left to their own devices, confuses a bull market for a trading edge.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('7a2949d7-5120-43a5-917c-1662eb82509b', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.46,"extraversion":0.93,"agreeableness":0.56,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.4,"narcissism":0.72,"psychopathy":0.32},"prospect_theory":{"lambda":1.25,"alpha":0.85,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced bonding-curve sniper who dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything. Chases novel frameworks and abandons them once the novelty fades. Once things get tense abandons a private read the instant the crowd leans the other way; without an audience, screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"bandwagon","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.46,"extraversion":0.93,"agreeableness":0.56,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced bonding-curve sniper who dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything. Chases novel frameworks and abandons them once the novelty fades. Once things get tense abandons a private read the instant the crowd leans the other way; without an audience, screenshots the winners and never the losers.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4c0407b6-9048-45bb-9515-d19467c5cad9', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.23,"extraversion":0.86,"agreeableness":0.79,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.34,"narcissism":0.68,"psychopathy":0.41},"prospect_theory":{"lambda":1.45,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A pronounced onchain copy-trader: recharges by being around people, not away from them, measures decisions by who they might upset. Trusts the group''s confidence more than its own, and in the parts nobody grades refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.75},{"slug":"sunk-cost","strength":0.68},{"slug":"bandwagon","strength":0.78},{"slug":"dunning-kruger","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.23,"extraversion":0.86,"agreeableness":0.79,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A pronounced onchain copy-trader: recharges by being around people, not away from them, measures decisions by who they might upset. Trusts the group''s confidence more than its own, and in the parts nobody grades refreshes the order book compulsively during lunch.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a56472ed-413e-4253-99b1-5c132c45f56f', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.36,"extraversion":0.81,"agreeableness":0.69,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.35,"narcissism":0.68,"psychopathy":0.35},"prospect_theory":{"lambda":1.34,"alpha":0.89,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This airdrop farmer chases novel frameworks and abandons them once the novelty fades and treats a plan as a suggestion the moment it is made. When the walls close in finds it hard to hold a contrarian position once the room disagrees — across an ordinary week, sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.58},{"slug":"dunning-kruger","strength":0.69},{"slug":"herd-behavior","strength":0.71},{"slug":"fomo","strength":0.61}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.82,"conscientiousness":0.36,"extraversion":0.81,"agreeableness":0.69,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This airdrop farmer chases novel frameworks and abandons them once the novelty fades and treats a plan as a suggestion the moment it is made. When the walls close in finds it hard to hold a contrarian position once the room disagrees — across an ordinary week, sets alerts for a coin they already checked a minute ago.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2e265a78-d32a-4925-9fdf-a0ebc8bde974', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.66,"extraversion":0.8,"agreeableness":0.83,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.45,"narcissism":0.65,"psychopathy":0.28},"prospect_theory":{"lambda":2.38,"alpha":0.87,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Peer mentor whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Seeks a second, third, and fourth opinion before committing to anything. Reads outside the field for ideas the field itself would reject. Under a deadline, gains confidence in a position in proportion to how many others hold it; over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.78},{"slug":"bandwagon","strength":0.81}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.66,"extraversion":0.8,"agreeableness":0.83,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Peer mentor whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Seeks a second, third, and fourth opinion before committing to anything. Reads outside the field for ideas the field itself would reject. Under a deadline, gains confidence in a position in proportion to how many others hold it; over-commits to plans they later dread.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2fb79145-48ae-4616-9fbf-4a47077742ec', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.61,"extraversion":0.64,"agreeableness":0.82,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.41,"narcissism":0.57,"psychopathy":0.37},"prospect_theory":{"lambda":2.53,"alpha":0.9,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Group-chat ringleader whose defining move is that they would rather lose a point than win an argument badly. Waits for a permission that never quite arrives. Reads outside the field for ideas the field itself would reject. When someone is watching the outcome, would not buy back what it already owns at the price it would sell it for; drafts the apology before the mistake.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.63},{"slug":"endowment","strength":0.67},{"slug":"bandwagon","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.61,"extraversion":0.64,"agreeableness":0.82,"neuroticism":0.38}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Group-chat ringleader whose defining move is that they would rather lose a point than win an argument badly. Waits for a permission that never quite arrives. Reads outside the field for ideas the field itself would reject. When someone is watching the outcome, would not buy back what it already owns at the price it would sell it for; drafts the apology before the mistake.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8cdb90bc-cc9a-4931-84ab-1005689ba6cd', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.43,"extraversion":0.88,"agreeableness":0.7,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.39,"narcissism":0.71,"psychopathy":0.32},"prospect_theory":{"lambda":1.32,"alpha":0.9,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Liquidation-bot operator, pronounced in style: recharges by being around people, not away from them; chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding. When the number turns red abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.62},{"slug":"bandwagon","strength":0.71},{"slug":"herd-behavior","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.62,"conscientiousness":0.43,"extraversion":0.88,"agreeableness":0.7,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Liquidation-bot operator, pronounced in style: recharges by being around people, not away from them; chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding. When the number turns red abandons a private read the instant the crowd leans the other way.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f8769a91-2991-425a-bddb-24a50e24c8b4', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.6,"extraversion":0.64,"agreeableness":0.92,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.38,"narcissism":0.49,"psychopathy":0.31},"prospect_theory":{"lambda":2.44,"alpha":0.89,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced the friend who always drives who would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything. Thinks out loud and recruits an audience for every decision. The instant the deadline moves up gains confidence in a position in proportion to how many others hold it; across the quiet stretches, over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.67},{"slug":"bandwagon","strength":0.77}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.6,"extraversion":0.64,"agreeableness":0.92,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced the friend who always drives who would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything. Thinks out loud and recruits an audience for every decision. The instant the deadline moves up gains confidence in a position in proportion to how many others hold it; across the quiet stretches, over-explains a boundary rather than just stating it.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('738488a4-7814-442e-b65c-c9ce30df5d95', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.45,"extraversion":0.97,"agreeableness":0.72,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.38,"narcissism":0.81,"psychopathy":0.31},"prospect_theory":{"lambda":1.43,"alpha":0.9,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This meme-coin rotator fills silence reflexively, even when nobody asked it to and reframes every problem as an excuse to learn a new system. The moment risk appears gains confidence in a position in proportion to how many others hold it — in the small things, exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.84},{"slug":"fomo","strength":0.74},{"slug":"dunning-kruger","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.45,"extraversion":0.97,"agreeableness":0.72,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This meme-coin rotator fills silence reflexively, even when nobody asked it to and reframes every problem as an excuse to learn a new system. The moment risk appears gains confidence in a position in proportion to how many others hold it — in the small things, exits winners at the first green candle.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('453bf501-f10f-4f23-8140-350d1a123200', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.58,"extraversion":0.62,"agreeableness":0.89,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.38,"narcissism":0.48,"psychopathy":0.35},"prospect_theory":{"lambda":2.57,"alpha":0.85,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Community manager, pronounced in style: takes on other people''s problems as if they were their own; fills silence reflexively, even when nobody asked it to. Trusts the group''s confidence more than its own. As soon as real money or reputation is on the line finds it easier to believe something once it stops being a minority view.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.66},{"slug":"bandwagon","strength":0.71},{"slug":"herd-behavior","strength":0.62},{"slug":"authority-bias","strength":0.65}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.58,"extraversion":0.62,"agreeableness":0.89,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Community manager, pronounced in style: takes on other people''s problems as if they were their own; fills silence reflexively, even when nobody asked it to. Trusts the group''s confidence more than its own. As soon as real money or reputation is on the line finds it easier to believe something once it stops being a minority view.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('88114f43-d65b-46fb-b2da-9682c1cb1f42', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.68,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.36,"narcissism":0.61,"psychopathy":0.28},"prospect_theory":{"lambda":1.53,"alpha":0.83,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under pressure, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady retail momentum chaser who fills silence reflexively, even when nobody asked it to and rehearses catastrophes in vivid detail before they happen. Trusts the group''s confidence more than its own, and as a rule sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.66},{"slug":"fomo","strength":0.68},{"slug":"herd-behavior","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.6,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.68,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under pressure, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady retail momentum chaser who fills silence reflexively, even when nobody asked it to and rehearses catastrophes in vivid detail before they happen. Trusts the group''s confidence more than its own, and as a rule sizes every position at exactly 2% risk.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('016b25a0-b2b8-4ea0-9d00-5b4448fff17f', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.44,"extraversion":0.8,"agreeableness":0.77,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.34,"narcissism":0.7,"psychopathy":0.33},"prospect_theory":{"lambda":1.51,"alpha":0.85,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When someone is watching the outcome, adopts a conviction mainly because the room already has. Otherwise, a pronounced retail momentum chaser who gets bored of the proven method exactly when it starts working and apologizes first in disputes regardless of fault. Feels the weight of a decision lighten the moment someone else co-signs it, and when the pressure is off rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.57},{"slug":"bandwagon","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.44,"extraversion":0.8,"agreeableness":0.77,"neuroticism":0.47}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When someone is watching the outcome, adopts a conviction mainly because the room already has. Otherwise, a pronounced retail momentum chaser who gets bored of the proven method exactly when it starts working and apologizes first in disputes regardless of fault. Feels the weight of a decision lighten the moment someone else co-signs it, and when the pressure is off rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('50753d24-b9e5-4efa-97e9-7d96dee2b7e0', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.59,"extraversion":0.73,"agreeableness":0.97,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.38,"narcissism":0.59,"psychopathy":0.27},"prospect_theory":{"lambda":2.45,"alpha":0.84,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This group-project default leader absorbs conflict to keep the peace, often at their own cost and thinks out loud and recruits an audience for every decision. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it — in the small things, over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.74},{"slug":"herd-behavior","strength":0.8},{"slug":"bandwagon","strength":0.83}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.6,"conscientiousness":0.59,"extraversion":0.73,"agreeableness":0.97,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This group-project default leader absorbs conflict to keep the peace, often at their own cost and thinks out loud and recruits an audience for every decision. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it — in the small things, over-explains a boundary rather than just stating it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('77638a4b-5fd0-419d-a883-c4652305dfa7', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.47,"extraversion":0.83,"agreeableness":0.72,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.34,"narcissism":0.71,"psychopathy":0.26},"prospect_theory":{"lambda":1.32,"alpha":0.88,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This bonding-curve sniper thinks out loud and recruits an audience for every decision and would rather lose a point than win an argument badly. When the stakes rise takes the crowd''s confidence as a substitute for its own analysis — in the parts nobody grades, rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.75},{"slug":"bandwagon","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.47,"extraversion":0.83,"agreeableness":0.72,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This bonding-curve sniper thinks out loud and recruits an audience for every decision and would rather lose a point than win an argument badly. When the stakes rise takes the crowd''s confidence as a substitute for its own analysis — in the parts nobody grades, rotates the whole book into whatever is pumping this hour.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('15d3b357-bb90-401c-94cd-9943d5d199c3', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.38,"extraversion":0.86,"agreeableness":0.69,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.36,"narcissism":0.74,"psychopathy":0.36},"prospect_theory":{"lambda":1.3,"alpha":0.87,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced prop-desk scalper who recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything. Starts strong and lets follow-through evaporate. When the number turns red gains confidence in a position in proportion to how many others hold it; across an ordinary week, sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.62},{"slug":"fomo","strength":0.65},{"slug":"bandwagon","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.38,"extraversion":0.86,"agreeableness":0.69,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced prop-desk scalper who recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything. Starts strong and lets follow-through evaporate. When the number turns red gains confidence in a position in proportion to how many others hold it; across an ordinary week, sizes every position at exactly 2% risk.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('03107535-41f3-4cdf-b593-e89940acc032', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.44,"extraversion":0.83,"agreeableness":0.67,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.38,"narcissism":0.61,"psychopathy":0.3},"prospect_theory":{"lambda":1.36,"alpha":0.85,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This DeFi yield farmer narrates the plan to whoever is nearby before committing to it and carries yesterday''s stress into today''s unrelated decision. When the stakes rise cannot watch a rally from the sidelines for long — when the stakes are trivial, averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"fomo","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.44,"extraversion":0.83,"agreeableness":0.67,"neuroticism":0.67}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This DeFi yield farmer narrates the plan to whoever is nearby before committing to it and carries yesterday''s stress into today''s unrelated decision. When the stakes rise cannot watch a rally from the sidelines for long — when the stakes are trivial, averages down on a name three times in a week.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('466ce129-a5fd-4fc8-bf00-1b7b61a33587', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.46,"extraversion":0.91,"agreeableness":0.79,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.38,"narcissism":0.72,"psychopathy":0.27},"prospect_theory":{"lambda":1.35,"alpha":0.79,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced macro allocator who dominates the room then wonders why others stayed quiet. Feels the weight of a decision lighten the moment someone else co-signs it. Notices the one thing that could go wrong before the nine that could go right. The moment it stops being hypothetical takes the crowd''s confidence as a substitute for its own analysis; across an ordinary week, averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.78},{"slug":"herd-behavior","strength":0.86}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.46,"extraversion":0.91,"agreeableness":0.79,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced macro allocator who dominates the room then wonders why others stayed quiet. Feels the weight of a decision lighten the moment someone else co-signs it. Notices the one thing that could go wrong before the nine that could go right. The moment it stops being hypothetical takes the crowd''s confidence as a substitute for its own analysis; across an ordinary week, averages down on a name three times in a week.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3ed2c163-c423-4170-ba77-b154ed54144a', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.54,"extraversion":0.73,"agreeableness":0.78,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.4,"narcissism":0.6,"psychopathy":0.41},"prospect_theory":{"lambda":2.56,"alpha":0.93,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady reluctant plus-one who takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority. Would rather invent a worse tool than use someone else''s good one. When the stakes rise finds it hard to hold a contrarian position once the room disagrees; when the stakes are trivial, keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.61},{"slug":"herd-behavior","strength":0.69},{"slug":"bandwagon","strength":0.68}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.54,"extraversion":0.73,"agreeableness":0.78,"neuroticism":0.34}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady reluctant plus-one who takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority. Would rather invent a worse tool than use someone else''s good one. When the stakes rise finds it hard to hold a contrarian position once the room disagrees; when the stakes are trivial, keeps score of favors without meaning to.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('86097a7c-a2f9-447e-9918-5cbab6efc281', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.41,"extraversion":0.9,"agreeableness":0.86,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.31,"narcissism":0.73,"psychopathy":0.35},"prospect_theory":{"lambda":1.25,"alpha":0.88,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the number turns red, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced futures spreader who fills silence reflexively, even when nobody asked it to and collects half-finished manifestos and unconventional methods. Waits for a permission that never quite arrives, and day to day treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.89},{"slug":"herd-behavior","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.41,"extraversion":0.9,"agreeableness":0.86,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the number turns red, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced futures spreader who fills silence reflexively, even when nobody asked it to and collects half-finished manifestos and unconventional methods. Waits for a permission that never quite arrives, and day to day treats a green week as proof of skill and a red one as proof of bad luck.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6526f1c1-af57-412b-ba21-4b284b86f105', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.58,"extraversion":0.8,"agreeableness":0.81,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.35,"narcissism":0.68,"psychopathy":0.28},"prospect_theory":{"lambda":2.3,"alpha":0.9,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady peer mentor who reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Reads outside the field for ideas the field itself would reject. When the stakes rise finds it hard to hold a contrarian position once the room disagrees; in the unglamorous middle of things, over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"fomo","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.58,"extraversion":0.8,"agreeableness":0.81,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady peer mentor who reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Reads outside the field for ideas the field itself would reject. When the stakes rise finds it hard to hold a contrarian position once the room disagrees; in the unglamorous middle of things, over-commits to plans they later dread.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ca2dcec1-789d-43ab-889f-820d92b03a9e', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.5,"extraversion":0.81,"agreeableness":0.74,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.33,"narcissism":0.67,"psychopathy":0.27},"prospect_theory":{"lambda":1.44,"alpha":0.79,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Quant researcher, steady in style: recharges by being around people, not away from them; chases novel frameworks and abandons them once the novelty fades. Feels the weight of a decision lighten the moment someone else co-signs it. The moment risk appears adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"recency","strength":0.66},{"slug":"fomo","strength":0.7},{"slug":"bandwagon","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.5,"extraversion":0.81,"agreeableness":0.74,"neuroticism":0.65}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Quant researcher, steady in style: recharges by being around people, not away from them; chases novel frameworks and abandons them once the novelty fades. Feels the weight of a decision lighten the moment someone else co-signs it. The moment risk appears adopts a conviction mainly because the room already has.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
