('88e72fe2-6224-459b-8868-a568a6039b90', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.38,"extraversion":0.9,"agreeableness":0.66,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.4,"narcissism":0.8,"psychopathy":0.36},"prospect_theory":{"lambda":1.54,"alpha":0.91,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This options seller recharges by being around people, not away from them and treats established procedure as a first draft to be rewritten. When the downside gets concrete finds it easier to believe something once it stops being a minority view — when the stakes are trivial, refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.73},{"slug":"bandwagon","strength":0.75},{"slug":"fomo","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.38,"extraversion":0.9,"agreeableness":0.66,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This options seller recharges by being around people, not away from them and treats established procedure as a first draft to be rewritten. When the downside gets concrete finds it easier to believe something once it stops being a minority view — when the stakes are trivial, refreshes the order book compulsively during lunch.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
