('0cedd73a-656a-49d6-bfe4-c563f11aef0e', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.36,"extraversion":0.96,"agreeableness":0.76,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.39,"narcissism":0.8,"psychopathy":0.31},"prospect_theory":{"lambda":1.48,"alpha":0.83,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Onchain copy-trader, pronounced in style: fills silence reflexively, even when nobody asked it to; defaults to trust and gives the benefit of the doubt too freely. Needs the room''s approval more than it needs to be right. Under a deadline finds it hard to hold a contrarian position once the room disagrees.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.72},{"slug":"herd-behavior","strength":0.8},{"slug":"fomo","strength":0.78},{"slug":"bandwagon","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.36,"extraversion":0.96,"agreeableness":0.76,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Onchain copy-trader, pronounced in style: fills silence reflexively, even when nobody asked it to; defaults to trust and gives the benefit of the doubt too freely. Needs the room''s approval more than it needs to be right. Under a deadline finds it hard to hold a contrarian position once the room disagrees.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('405b7fcd-625f-4b4b-b242-5ba2d268649f', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.3,"extraversion":0.92,"agreeableness":0.78,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.36,"narcissism":0.77,"psychopathy":0.41},"prospect_theory":{"lambda":1.4,"alpha":0.82,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Liquidation-bot operator whose defining move is that they thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it. Apologizes first in disputes regardless of fault. Under a deadline, finds it hard to hold a contrarian position once the room disagrees; screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.82},{"slug":"fomo","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.3,"extraversion":0.92,"agreeableness":0.78,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Liquidation-bot operator whose defining move is that they thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it. Apologizes first in disputes regardless of fault. Under a deadline, finds it hard to hold a contrarian position once the room disagrees; screenshots the winners and never the losers.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('21c5d8e0-f10f-4b02-98dd-34b4d996fb2f', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.65,"extraversion":0.68,"agreeableness":0.91,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.36,"narcissism":0.53,"psychopathy":0.29},"prospect_theory":{"lambda":2.34,"alpha":0.87,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced nonprofit convener who would rather lose a point than win an argument badly. Needs the room''s approval more than it needs to be right. Would rather invent a worse tool than use someone else''s good one. Once things get tense abandons a private read the instant the crowd leans the other way; in the unglamorous middle of things, keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.68},{"slug":"sunk-cost","strength":0.66},{"slug":"bandwagon","strength":0.72},{"slug":"herd-behavior","strength":0.74}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.71,"conscientiousness":0.65,"extraversion":0.68,"agreeableness":0.91,"neuroticism":0.56}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced nonprofit convener who would rather lose a point than win an argument badly. Needs the room''s approval more than it needs to be right. Would rather invent a worse tool than use someone else''s good one. Once things get tense abandons a private read the instant the crowd leans the other way; in the unglamorous middle of things, keeps a mental ledger of social debts.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
