('105c561e-50c0-4aa5-8bab-315935e8f82c', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.47,"extraversion":0.82,"agreeableness":0.83,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.32,"narcissism":0.64,"psychopathy":0.28},"prospect_theory":{"lambda":1.28,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under a deadline, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady discretionary swing trader who takes on other people''s problems as if they were their own and collects half-finished manifestos and unconventional methods. Trusts the group''s confidence more than its own, and in the version no one reviews trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"authority-bias","strength":0.56},{"slug":"fomo","strength":0.71},{"slug":"endowment","strength":0.67},{"slug":"herd-behavior","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.47,"extraversion":0.82,"agreeableness":0.83,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under a deadline, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady discretionary swing trader who takes on other people''s problems as if they were their own and collects half-finished manifestos and unconventional methods. Trusts the group''s confidence more than its own, and in the version no one reviews trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-6