('26643169-cf38-4066-863b-c8b6dff0d953', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.37,"extraversion":0.81,"agreeableness":0.71,"neuroticism":0.71},"dark_triad":{"machiavellianism":0.34,"narcissism":0.58,"psychopathy":0.3},"prospect_theory":{"lambda":1.39,"alpha":0.79,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the number turns red, extrapolates the last data point into a permanent trend. Otherwise, a steady commodities speculator who dominates the room then wonders why others stayed quiet and is reliably surprised by deadlines that were never hidden. Waits for a permission that never quite arrives, and day to day names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"bandwagon","strength":0.67},{"slug":"dunning-kruger","strength":0.62},{"slug":"recency","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.37,"extraversion":0.81,"agreeableness":0.71,"neuroticism":0.71}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the number turns red, extrapolates the last data point into a permanent trend. Otherwise, a steady commodities speculator who dominates the room then wonders why others stayed quiet and is reliably surprised by deadlines that were never hidden. Waits for a permission that never quite arrives, and day to day names every strategy after the trade that almost worked.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('be3cfc39-3837-414b-a1bc-416697591296', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.67,"extraversion":0.77,"agreeableness":0.85,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.45,"narcissism":0.62,"psychopathy":0.36},"prospect_theory":{"lambda":2.47,"alpha":0.93,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced online moderator who apologizes first in disputes regardless of fault. Waits for a permission that never quite arrives. Draws energy from the crowd and wilts when working alone. In a pinch adopts a conviction mainly because the room already has; across the quiet stretches, texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.71},{"slug":"endowment","strength":0.57}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.67,"extraversion":0.77,"agreeableness":0.85,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced online moderator who apologizes first in disputes regardless of fault. Waits for a permission that never quite arrives. Draws energy from the crowd and wilts when working alone. In a pinch adopts a conviction mainly because the room already has; across the quiet stretches, texts an apology before confirming anyone is upset.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a5e7081e-a1dc-4710-a89e-821bd6d3ebd7', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.56,"extraversion":0.73,"agreeableness":0.77,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.4,"narcissism":0.65,"psychopathy":0.35},"prospect_theory":{"lambda":2.41,"alpha":0.9,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A steady online moderator: would rather lose a point than win an argument badly, reads outside the field for ideas the field itself would reject. Outsources conviction to whoever spoke last with authority, and left to their own devices reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.59},{"slug":"herd-behavior","strength":0.72},{"slug":"bandwagon","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.73,"conscientiousness":0.56,"extraversion":0.73,"agreeableness":0.77,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A steady online moderator: would rather lose a point than win an argument badly, reads outside the field for ideas the field itself would reject. Outsources conviction to whoever spoke last with authority, and left to their own devices reads the room then performs to it.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0261e521-e578-4ff2-b0ca-8f03811d3e75', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.54,"extraversion":0.66,"agreeableness":0.87,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.33,"narcissism":0.49,"psychopathy":0.36},"prospect_theory":{"lambda":2.34,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the downside gets concrete, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced wedding-party diplomat who would rather lose a point than win an argument badly and recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything, and once the urgency drains out defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.72},{"slug":"authority-bias","strength":0.69},{"slug":"endowment","strength":0.59}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.59,"conscientiousness":0.54,"extraversion":0.66,"agreeableness":0.87,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the downside gets concrete, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced wedding-party diplomat who would rather lose a point than win an argument badly and recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything, and once the urgency drains out defuses tension with a joke that lands most of the time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3b892f42-6d38-4578-acb8-6c6d085266e7', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.45,"extraversion":0.9,"agreeableness":0.75,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.4,"narcissism":0.76,"psychopathy":0.27},"prospect_theory":{"lambda":1.24,"alpha":0.88,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A pronounced retail momentum chaser: narrates the plan to whoever is nearby before committing to it, would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and when the pressure is off screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.78},{"slug":"dunning-kruger","strength":0.59},{"slug":"fomo","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.45,"extraversion":0.9,"agreeableness":0.75,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A pronounced retail momentum chaser: narrates the plan to whoever is nearby before committing to it, would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and when the pressure is off screenshots the winners and never the losers.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ace30368-1349-4d6b-adea-0eeff05f71e2', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.41,"extraversion":0.96,"agreeableness":0.79,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.32,"narcissism":0.73,"psychopathy":0.32},"prospect_theory":{"lambda":1.48,"alpha":0.87,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Index-fund holdout whose defining move is that they recharges by being around people, not away from them. Circles back to ask what someone else would do even after deciding. Reads other people''s discomfort before they voice it. Once the exit narrows to one door, takes the crowd''s confidence as a substitute for its own analysis; sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.89},{"slug":"endowment","strength":0.65},{"slug":"bandwagon","strength":0.8},{"slug":"dunning-kruger","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.41,"extraversion":0.96,"agreeableness":0.79,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Index-fund holdout whose defining move is that they recharges by being around people, not away from them. Circles back to ask what someone else would do even after deciding. Reads other people''s discomfort before they voice it. Once the exit narrows to one door, takes the crowd''s confidence as a substitute for its own analysis; sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8ddffc71-5058-434e-ab14-954a3a12a401', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.47,"extraversion":0.61,"agreeableness":0.84,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.38,"narcissism":0.53,"psychopathy":0.29},"prospect_theory":{"lambda":2.38,"alpha":0.83,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The instant the deadline moves up, overvalues whatever they already hold simply because it is theirs. Otherwise, a pronounced family peacemaker who takes on other people''s problems as if they were their own and chases novel frameworks and abandons them once the novelty fades. Needs the room''s approval more than it needs to be right, and once the urgency drains out remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.6},{"slug":"endowment","strength":0.67},{"slug":"authority-bias","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.47,"extraversion":0.61,"agreeableness":0.84,"neuroticism":0.48}'::jsonb, 'ENFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The instant the deadline moves up, overvalues whatever they already hold simply because it is theirs. Otherwise, a pronounced family peacemaker who takes on other people''s problems as if they were their own and chases novel frameworks and abandons them once the novelty fades. Needs the room''s approval more than it needs to be right, and once the urgency drains out remembers everyone birthday and no one boundaries.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d5913818-a840-4639-a84b-fe36e30c4d69', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.54,"extraversion":0.74,"agreeableness":0.82,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.35,"narcissism":0.54,"psychopathy":0.41},"prospect_theory":{"lambda":2.27,"alpha":0.84,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Team captain whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Waits for a permission that never quite arrives. Fills silence reflexively, even when nobody asked it to. When the downside gets concrete, abandons a private read the instant the crowd leans the other way; remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.74},{"slug":"herd-behavior","strength":0.76},{"slug":"optimism","strength":0.7}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.54,"conscientiousness":0.54,"extraversion":0.74,"agreeableness":0.82,"neuroticism":0.29}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Team captain whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Waits for a permission that never quite arrives. Fills silence reflexively, even when nobody asked it to. When the downside gets concrete, abandons a private read the instant the crowd leans the other way; remembers everyone birthday and no one boundaries.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ca34e6f3-19e5-4eaa-b713-76a4328aa744', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.66,"extraversion":0.73,"agreeableness":0.95,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.36,"narcissism":0.58,"psychopathy":0.36},"prospect_theory":{"lambda":2.24,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This community manager takes on other people''s problems as if they were their own and treats established procedure as a first draft to be rewritten. When the stakes rise abandons a private read the instant the crowd leans the other way — when no one is watching, keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.64},{"slug":"authority-bias","strength":0.67},{"slug":"herd-behavior","strength":0.76}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.74,"conscientiousness":0.66,"extraversion":0.73,"agreeableness":0.95,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This community manager takes on other people''s problems as if they were their own and treats established procedure as a first draft to be rewritten. When the stakes rise abandons a private read the instant the crowd leans the other way — when no one is watching, keeps a mental ledger of social debts.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f2bdae36-3bf2-462f-9778-5c15ed00bf3f', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.49,"extraversion":0.89,"agreeableness":0.71,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.37,"narcissism":0.74,"psychopathy":0.26},"prospect_theory":{"lambda":1.48,"alpha":0.86,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced penny-stock gambler who treats a quiet room as a problem to be solved. Outsources conviction to whoever spoke last with authority. Absorbs conflict to keep the peace, often at their own cost. Under pressure gains confidence in a position in proportion to how many others hold it; when the stakes are trivial, exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.6},{"slug":"bandwagon","strength":0.72},{"slug":"fomo","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.49,"extraversion":0.89,"agreeableness":0.71,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced penny-stock gambler who treats a quiet room as a problem to be solved. Outsources conviction to whoever spoke last with authority. Absorbs conflict to keep the peace, often at their own cost. Under pressure gains confidence in a position in proportion to how many others hold it; when the stakes are trivial, exits winners at the first green candle.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('05d7d23a-2c8d-4679-9717-deb5b819bd66', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.75,"extraversion":0.71,"agreeableness":0.91,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.43,"narcissism":0.59,"psychopathy":0.3},"prospect_theory":{"lambda":2.42,"alpha":0.92,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When cornered, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced the friend who always drives who apologizes first in disputes regardless of fault and gets bored of the proven method exactly when it starts working. Feels the weight of a decision lighten the moment someone else co-signs it, and when the pressure is off keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"authority-bias","strength":0.67},{"slug":"endowment","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.75,"extraversion":0.71,"agreeableness":0.91,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When cornered, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced the friend who always drives who apologizes first in disputes regardless of fault and gets bored of the proven method exactly when it starts working. Feels the weight of a decision lighten the moment someone else co-signs it, and when the pressure is off keeps a mental ledger of social debts.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('cded6207-8c3e-4099-8723-ae4da1280991', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.37,"extraversion":0.83,"agreeableness":0.73,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.4,"narcissism":0.66,"psychopathy":0.35},"prospect_theory":{"lambda":1.25,"alpha":0.9,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady quant researcher who recharges by being around people, not away from them. Waits for a permission that never quite arrives. Reframes every problem as an excuse to learn a new system. Once the exit narrows to one door finds it hard to hold a contrarian position once the room disagrees; in the version no one reviews, trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"bandwagon","strength":0.67},{"slug":"dunning-kruger","strength":0.65},{"slug":"fomo","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.37,"extraversion":0.83,"agreeableness":0.73,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady quant researcher who recharges by being around people, not away from them. Waits for a permission that never quite arrives. Reframes every problem as an excuse to learn a new system. Once the exit narrows to one door finds it hard to hold a contrarian position once the room disagrees; in the version no one reviews, trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6c47e3e5-3612-4b71-9833-e3a139ea370b', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.42,"extraversion":0.87,"agreeableness":0.69,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.41,"narcissism":0.7,"psychopathy":0.32},"prospect_theory":{"lambda":1.31,"alpha":0.89,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once things get tense, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced onchain copy-trader who fills silence reflexively, even when nobody asked it to and would rather lose a point than win an argument badly. Trusts the group''s confidence more than its own, and in the parts nobody grades refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"dunning-kruger","strength":0.65},{"slug":"herd-behavior","strength":0.81}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.61,"conscientiousness":0.42,"extraversion":0.87,"agreeableness":0.69,"neuroticism":0.5}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Once things get tense, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced onchain copy-trader who fills silence reflexively, even when nobody asked it to and would rather lose a point than win an argument badly. Trusts the group''s confidence more than its own, and in the parts nobody grades refreshes the order book compulsively during lunch.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0572fc5e-6391-4ac8-b685-170362c79f87', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.45,"extraversion":0.93,"agreeableness":0.79,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.34,"narcissism":0.71,"psychopathy":0.31},"prospect_theory":{"lambda":1.3,"alpha":0.79,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A pronounced discretionary swing trader: thinks out loud and recruits an audience for every decision, apologizes first in disputes regardless of fault. Outsources conviction to whoever spoke last with authority, and on a slow afternoon trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.84},{"slug":"herd-behavior","strength":0.8}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.66,"conscientiousness":0.45,"extraversion":0.93,"agreeableness":0.79,"neuroticism":0.65}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A pronounced discretionary swing trader: thinks out loud and recruits an audience for every decision, apologizes first in disputes regardless of fault. Outsources conviction to whoever spoke last with authority, and on a slow afternoon trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('abfcd753-9979-4419-889e-efd25fdd800b', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.69,"extraversion":0.74,"agreeableness":0.9,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.39,"narcissism":0.59,"psychopathy":0.33},"prospect_theory":{"lambda":2.25,"alpha":0.91,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A pronounced group-project default leader: absorbs conflict to keep the peace, often at their own cost, collects half-finished manifestos and unconventional methods. Feels the weight of a decision lighten the moment someone else co-signs it, and in the pattern nobody else tracks over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.64},{"slug":"bandwagon","strength":0.82},{"slug":"herd-behavior","strength":0.71},{"slug":"endowment","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.69,"extraversion":0.74,"agreeableness":0.9,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A pronounced group-project default leader: absorbs conflict to keep the peace, often at their own cost, collects half-finished manifestos and unconventional methods. Feels the weight of a decision lighten the moment someone else co-signs it, and in the pattern nobody else tracks over-explains a boundary rather than just stating it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('147cc705-c8f1-42de-8384-c26148c10937', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.71,"extraversion":0.64,"agreeableness":0.97,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.43,"narcissism":0.56,"psychopathy":0.3},"prospect_theory":{"lambda":2.57,"alpha":0.93,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This neighborhood connector takes on other people''s problems as if they were their own and plans in exhaustive detail and resents any deviation. Under pressure finds it easier to believe something once it stops being a minority view — day to day, remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.79},{"slug":"endowment","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.76,"conscientiousness":0.71,"extraversion":0.64,"agreeableness":0.97,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This neighborhood connector takes on other people''s problems as if they were their own and plans in exhaustive detail and resents any deviation. Under pressure finds it easier to believe something once it stops being a minority view — day to day, remembers who didn''t get invited last time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d89c257c-671f-42df-9f08-fd2071c5e658', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.34,"extraversion":0.81,"agreeableness":0.71,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.35,"narcissism":0.65,"psychopathy":0.38},"prospect_theory":{"lambda":1.3,"alpha":0.89,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady airdrop farmer who fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Leaves loose ends and trusts future-self to handle them. When the number turns red jumps into whatever everyone else already seems to be winning at; day to day, calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.65},{"slug":"fomo","strength":0.69},{"slug":"dunning-kruger","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.34,"extraversion":0.81,"agreeableness":0.71,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady airdrop farmer who fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Leaves loose ends and trusts future-self to handle them. When the number turns red jumps into whatever everyone else already seems to be winning at; day to day, calls a 90% drawdown a long-term hold.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('62a9684a-f860-4a64-a229-733796941621', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.3,"extraversion":0.82,"agreeableness":0.64,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.42,"narcissism":0.69,"psychopathy":0.37},"prospect_theory":{"lambda":1.47,"alpha":0.91,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady DeFi yield farmer who narrates the plan to whoever is nearby before committing to it. Seeks a second, third, and fourth opinion before committing to anything. Takes on other people''s problems as if they were their own. The instant it becomes irreversible takes the crowd''s confidence as a substitute for its own analysis; on an ordinary week, backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"bandwagon","strength":0.64},{"slug":"herd-behavior","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.67,"conscientiousness":0.3,"extraversion":0.82,"agreeableness":0.64,"neuroticism":0.52}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady DeFi yield farmer who narrates the plan to whoever is nearby before committing to it. Seeks a second, third, and fourth opinion before committing to anything. Takes on other people''s problems as if they were their own. The instant it becomes irreversible takes the crowd''s confidence as a substitute for its own analysis; on an ordinary week, backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('cc3bd19f-9e7a-4fa2-a33a-9cf01653915c', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.6,"extraversion":0.78,"agreeableness":0.91,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.34,"narcissism":0.65,"psychopathy":0.31},"prospect_theory":{"lambda":2.56,"alpha":0.93,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Event host whose defining move is that they takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Recharges by being around people, not away from them. The instant the deadline moves up, finds it easier to believe something once it stops being a minority view; reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"authority-bias","strength":0.71},{"slug":"herd-behavior","strength":0.73},{"slug":"bandwagon","strength":0.79}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.6,"extraversion":0.78,"agreeableness":0.91,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Event host whose defining move is that they takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Recharges by being around people, not away from them. The instant the deadline moves up, finds it easier to believe something once it stops being a minority view; reads the room then performs to it.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('eecef507-67f4-4609-ada6-a1ba56591f75', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.51,"extraversion":0.73,"agreeableness":0.69,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.4,"narcissism":0.63,"psychopathy":0.24},"prospect_theory":{"lambda":1.51,"alpha":0.81,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Prop-desk scalper, pronounced in style: collects half-finished manifestos and unconventional methods; fills silence reflexively, even when nobody asked it to. Waits for a permission that never quite arrives. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"bandwagon","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.86,"conscientiousness":0.51,"extraversion":0.73,"agreeableness":0.69,"neuroticism":0.61}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Prop-desk scalper, pronounced in style: collects half-finished manifestos and unconventional methods; fills silence reflexively, even when nobody asked it to. Waits for a permission that never quite arrives. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('eb0dbfab-3ca3-4592-a53a-a24fbf478fd8', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.41,"extraversion":0.94,"agreeableness":0.64,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.35,"narcissism":0.8,"psychopathy":0.31},"prospect_theory":{"lambda":1.56,"alpha":0.9,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Onchain copy-trader whose defining move is that they fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Would rather invent a worse tool than use someone else''s good one. In a pinch, treats being left out of a move as its own kind of loss; exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.66},{"slug":"bandwagon","strength":0.75},{"slug":"fomo","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.41,"extraversion":0.94,"agreeableness":0.64,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Onchain copy-trader whose defining move is that they fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Would rather invent a worse tool than use someone else''s good one. In a pinch, treats being left out of a move as its own kind of loss; exits winners at the first green candle.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d3ab601c-2e7e-4126-b037-b9b6a7546acf', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.36,"extraversion":0.74,"agreeableness":0.82,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.37,"narcissism":0.53,"psychopathy":0.32},"prospect_theory":{"lambda":1.32,"alpha":0.84,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A steady retail momentum chaser: measures decisions by who they might upset, would rather invent a worse tool than use someone else''s good one. Seeks a second, third, and fourth opinion before committing to anything, and on a slow afternoon exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.74},{"slug":"endowment","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.36,"extraversion":0.74,"agreeableness":0.82,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A steady retail momentum chaser: measures decisions by who they might upset, would rather invent a worse tool than use someone else''s good one. Seeks a second, third, and fourth opinion before committing to anything, and on a slow afternoon exits winners at the first green candle.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('52671a7a-b1a6-4fb8-974a-0305251a5f07', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.32,"extraversion":0.81,"agreeableness":0.75,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.32,"narcissism":0.68,"psychopathy":0.39},"prospect_theory":{"lambda":1.45,"alpha":0.87,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Futures spreader whose defining move is that they fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding. Absorbs conflict to keep the peace, often at their own cost. Under a deadline, mistakes a little fluency for real mastery; refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.66},{"slug":"dunning-kruger","strength":0.73},{"slug":"herd-behavior","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.32,"extraversion":0.81,"agreeableness":0.75,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Futures spreader whose defining move is that they fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding. Absorbs conflict to keep the peace, often at their own cost. Under a deadline, mistakes a little fluency for real mastery; refreshes the order book compulsively during lunch.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('61bfd754-bbff-483b-9fd3-ba5548e5c5ef', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.42,"extraversion":0.85,"agreeableness":0.73,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.37,"narcissism":0.64,"psychopathy":0.3},"prospect_theory":{"lambda":1.41,"alpha":0.87,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Cannot watch a rally from the sidelines for long. A pronounced meme-coin rotator: thinks out loud and recruits an audience for every decision, would rather lose a point than win an argument badly. Feels the weight of a decision lighten the moment someone else co-signs it, and when the pressure is off sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.7},{"slug":"dunning-kruger","strength":0.66},{"slug":"fomo","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.62,"conscientiousness":0.42,"extraversion":0.85,"agreeableness":0.73,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Cannot watch a rally from the sidelines for long. A pronounced meme-coin rotator: thinks out loud and recruits an audience for every decision, would rather lose a point than win an argument badly. Feels the weight of a decision lighten the moment someone else co-signs it, and when the pressure is off sets stop-losses then cancels them at the open.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8513b498-6251-4e6a-b186-ee3746aa01aa', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.53,"extraversion":0.88,"agreeableness":0.79,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.37,"narcissism":0.76,"psychopathy":0.28},"prospect_theory":{"lambda":1.43,"alpha":0.85,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Commodities speculator whose defining move is that they thinks out loud and recruits an audience for every decision. Trusts the group''s confidence more than its own. Treats established procedure as a first draft to be rewritten. As soon as real money or reputation is on the line, gains confidence in a position in proportion to how many others hold it; backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.77},{"slug":"bandwagon","strength":0.81},{"slug":"fomo","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.83,"conscientiousness":0.53,"extraversion":0.88,"agreeableness":0.79,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Commodities speculator whose defining move is that they thinks out loud and recruits an audience for every decision. Trusts the group''s confidence more than its own. Treats established procedure as a first draft to be rewritten. As soon as real money or reputation is on the line, gains confidence in a position in proportion to how many others hold it; backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9d8908a0-6b17-4564-a726-1e7da6c7a24b', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.46,"extraversion":0.71,"agreeableness":0.66,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.39,"narcissism":0.52,"psychopathy":0.32},"prospect_theory":{"lambda":1.55,"alpha":0.85,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Onchain copy-trader, steady in style: reframes every problem as an excuse to learn a new system; defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it. The instant it becomes irreversible gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"recency","strength":0.59},{"slug":"fomo","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.46,"extraversion":0.71,"agreeableness":0.66,"neuroticism":0.65}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Onchain copy-trader, steady in style: reframes every problem as an excuse to learn a new system; defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it. The instant it becomes irreversible gains confidence in a position in proportion to how many others hold it.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('04c0fdc8-3c7d-4d72-a4b3-b0ff49ea0b4e', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.58,"extraversion":0.87,"agreeableness":0.78,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.42,"narcissism":0.68,"psychopathy":0.27},"prospect_theory":{"lambda":2.47,"alpha":0.87,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This newcomer welcomer draws energy from the crowd and wilts when working alone and collects half-finished manifestos and unconventional methods. When the number turns red takes the crowd''s confidence as a substitute for its own analysis — left to their own devices, remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.82},{"slug":"bandwagon","strength":0.79},{"slug":"dunning-kruger","strength":0.56},{"slug":"fomo","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","decision-making","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.58,"extraversion":0.87,"agreeableness":0.78,"neuroticism":0.47}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','decision-making','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This newcomer welcomer draws energy from the crowd and wilts when working alone and collects half-finished manifestos and unconventional methods. When the number turns red takes the crowd''s confidence as a substitute for its own analysis — left to their own devices, remembers who didn''t get invited last time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('858f9fd1-152e-4b37-8b6d-634fde403ca4', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.63,"extraversion":0.85,"agreeableness":0.89,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.41,"narcissism":0.68,"psychopathy":0.27},"prospect_theory":{"lambda":2.49,"alpha":0.94,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Online moderator whose defining move is that they measures decisions by who they might upset. Circles back to ask what someone else would do even after deciding. Builds in buffer time and then fills the buffer with more work. When the safe option quietly expires, finds it easier to believe something once it stops being a minority view; texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.84},{"slug":"fomo","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.63,"extraversion":0.85,"agreeableness":0.89,"neuroticism":0.51}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Online moderator whose defining move is that they measures decisions by who they might upset. Circles back to ask what someone else would do even after deciding. Builds in buffer time and then fills the buffer with more work. When the safe option quietly expires, finds it easier to believe something once it stops being a minority view; texts an apology before confirming anyone is upset.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
