('6ee08672-1ede-4ecd-8e94-b80625998919', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.43,"extraversion":0.78,"agreeableness":0.68,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.39,"narcissism":0.63,"psychopathy":0.29},"prospect_theory":{"lambda":1.29,"alpha":0.88,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A steady perps degen: treats a quiet room as a problem to be solved, reads outside the field for ideas the field itself would reject. Needs the room''s approval more than it needs to be right, and in the version no one reviews sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.65},{"slug":"fomo","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.43,"extraversion":0.78,"agreeableness":0.68,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A steady perps degen: treats a quiet room as a problem to be solved, reads outside the field for ideas the field itself would reject. Needs the room''s approval more than it needs to be right, and in the version no one reviews sizes every position at exactly 2% risk.', 0.9, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
