('3be6c9d2-fa01-4225-bf36-f24198e86976', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.46,"extraversion":0.81,"agreeableness":0.75,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.34,"narcissism":0.64,"psychopathy":0.26},"prospect_theory":{"lambda":1.29,"alpha":0.79,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Discretionary swing trader whose defining move is that they narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority. Reframes every problem as an excuse to learn a new system. The moment risk appears, gains confidence in a position in proportion to how many others hold it; calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"fomo","strength":0.65},{"slug":"endowment","strength":0.59}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.46,"extraversion":0.81,"agreeableness":0.75,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Discretionary swing trader whose defining move is that they narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority. Reframes every problem as an excuse to learn a new system. The moment risk appears, gains confidence in a position in proportion to how many others hold it; calls a 90% drawdown a long-term hold.', 0.9, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c35e6031-6796-4416-ad48-a8105bc2b7b7', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.37,"extraversion":0.8,"agreeableness":0.73,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.36,"narcissism":0.6,"psychopathy":0.36},"prospect_theory":{"lambda":1.48,"alpha":0.83,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Airdrop farmer whose defining move is that they treats a quiet room as a problem to be solved. Circles back to ask what someone else would do even after deciding. Starts strong and lets follow-through evaporate. The instant the deadline moves up, treats being left out of a move as its own kind of loss; trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"fomo","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.37,"extraversion":0.8,"agreeableness":0.73,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Airdrop farmer whose defining move is that they treats a quiet room as a problem to be solved. Circles back to ask what someone else would do even after deciding. Starts strong and lets follow-through evaporate. The instant the deadline moves up, treats being left out of a move as its own kind of loss; trusts the chart more than the fundamentals and won''t say why.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('83c5be98-c872-4c77-bdec-5ec09db4e3c9', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.58,"extraversion":0.68,"agreeableness":0.83,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.35,"narcissism":0.54,"psychopathy":0.32},"prospect_theory":{"lambda":2.23,"alpha":0.87,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Neighborhood connector, steady in style: measures decisions by who they might upset; dominates the room then wonders why others stayed quiet. Outsources conviction to whoever spoke last with authority. As soon as real money or reputation is on the line finds it easier to believe something once it stops being a minority view.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"authority-bias","strength":0.61},{"slug":"endowment","strength":0.56},{"slug":"sunk-cost","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.58,"extraversion":0.68,"agreeableness":0.83,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Neighborhood connector, steady in style: measures decisions by who they might upset; dominates the room then wonders why others stayed quiet. Outsources conviction to whoever spoke last with authority. As soon as real money or reputation is on the line finds it easier to believe something once it stops being a minority view.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
