('3dc2aef7-183f-4327-b3b7-e3582f4f740e', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.23,"extraversion":0.83,"agreeableness":0.58,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.44,"narcissism":0.65,"psychopathy":0.43},"prospect_theory":{"lambda":1.47,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment risk appears, treats being left out of a move as its own kind of loss. Otherwise, a steady retail momentum chaser who draws energy from the crowd and wilts when working alone and leaves loose ends and trusts future-self to handle them. Seeks a second, third, and fourth opinion before committing to anything, and on a slow afternoon screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"gas-sunk-cost","strength":0.57},{"slug":"herd-behavior","strength":0.65},{"slug":"dunning-kruger","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.66,"conscientiousness":0.23,"extraversion":0.83,"agreeableness":0.58,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment risk appears, treats being left out of a move as its own kind of loss. Otherwise, a steady retail momentum chaser who draws energy from the crowd and wilts when working alone and leaves loose ends and trusts future-self to handle them. Seeks a second, third, and fourth opinion before committing to anything, and on a slow afternoon screenshots the winners and never the losers.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0bd0a0dd-1ce7-4919-8042-ab049944ea78', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.45,"extraversion":0.84,"agreeableness":0.74,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.35,"narcissism":0.64,"psychopathy":0.32},"prospect_theory":{"lambda":1.43,"alpha":0.9,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A pronounced pairs trader: draws energy from the crowd and wilts when working alone, apologizes first in disputes regardless of fault. Circles back to ask what someone else would do even after deciding, and in the small things holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"herd-behavior","strength":0.78},{"slug":"dunning-kruger","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.45,"extraversion":0.84,"agreeableness":0.74,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A pronounced pairs trader: draws energy from the crowd and wilts when working alone, apologizes first in disputes regardless of fault. Circles back to ask what someone else would do even after deciding, and in the small things holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bdaf9796-1a6b-4a5c-9ad7-7ee813a765c0', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.29,"extraversion":0.89,"agreeableness":0.64,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.42,"narcissism":0.72,"psychopathy":0.37},"prospect_theory":{"lambda":1.32,"alpha":0.86,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Airdrop farmer whose defining move is that they recharges by being around people, not away from them. Feels the weight of a decision lighten the moment someone else co-signs it. Rehearses catastrophes in vivid detail before they happen. Once things get tense, treats being left out of a move as its own kind of loss; trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"dunning-kruger","strength":0.71},{"slug":"fomo","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.29,"extraversion":0.89,"agreeableness":0.64,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Airdrop farmer whose defining move is that they recharges by being around people, not away from them. Feels the weight of a decision lighten the moment someone else co-signs it. Rehearses catastrophes in vivid detail before they happen. Once things get tense, treats being left out of a move as its own kind of loss; trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('01427c6a-39b8-4726-a496-a06e2adbf944', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.34,"extraversion":0.73,"agreeableness":0.71,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.35,"narcissism":0.62,"psychopathy":0.33},"prospect_theory":{"lambda":1.5,"alpha":0.82,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Discretionary swing trader, steady in style: would rather invent a worse tool than use someone else''s good one; confuses motion with progress. Trusts the group''s confidence more than its own. In a pinch takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.69},{"slug":"dunning-kruger","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.34,"extraversion":0.73,"agreeableness":0.71,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Discretionary swing trader, steady in style: would rather invent a worse tool than use someone else''s good one; confuses motion with progress. Trusts the group''s confidence more than its own. In a pinch takes the crowd''s confidence as a substitute for its own analysis.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f3bb7d20-b076-417d-b9cd-51877a4181de', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.48,"extraversion":0.87,"agreeableness":0.74,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.4,"narcissism":0.63,"psychopathy":0.27},"prospect_theory":{"lambda":1.23,"alpha":0.83,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Meme-coin rotator whose defining move is that they recharges by being around people, not away from them. Outsources conviction to whoever spoke last with authority. Would rather invent a worse tool than use someone else''s good one. When someone is watching the outcome, finds it easier to believe something once it stops being a minority view; backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.77},{"slug":"dunning-kruger","strength":0.64},{"slug":"endowment","strength":0.55},{"slug":"fomo","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.63,"conscientiousness":0.48,"extraversion":0.87,"agreeableness":0.74,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Meme-coin rotator whose defining move is that they recharges by being around people, not away from them. Outsources conviction to whoever spoke last with authority. Would rather invent a worse tool than use someone else''s good one. When someone is watching the outcome, finds it easier to believe something once it stops being a minority view; backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
