('4e8f5a59-40af-4afe-9b2c-ce47bb28382b', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.38,"extraversion":0.77,"agreeableness":0.72,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.34,"narcissism":0.62,"psychopathy":0.31},"prospect_theory":{"lambda":1.35,"alpha":0.81,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the downside gets concrete, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady perps degen who reframes every problem as an excuse to learn a new system and draws energy from the crowd and wilts when working alone. Circles back to ask what someone else would do even after deciding, and in the version no one reviews trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"herd-behavior","strength":0.72},{"slug":"bandwagon","strength":0.69},{"slug":"fomo","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.38,"extraversion":0.77,"agreeableness":0.72,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the downside gets concrete, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady perps degen who reframes every problem as an excuse to learn a new system and draws energy from the crowd and wilts when working alone. Circles back to ask what someone else would do even after deciding, and in the version no one reviews trusts the chart more than the fundamentals and won''t say why.', 0.91, 'approved', 'efad67da-ca57-4cd6-9