('f6592d72-a95c-4270-b794-56c6d767c576', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.73,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.33,"narcissism":0.68,"psychopathy":0.34},"prospect_theory":{"lambda":1.31,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Jumps into whatever everyone else already seems to be winning at. A steady discretionary swing trader: dominates the room then wonders why others stayed quiet, collects half-finished manifestos and unconventional methods. Feels the weight of a decision lighten the moment someone else co-signs it, and when no one is watching screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.76},{"slug":"bandwagon","strength":0.72},{"slug":"recency","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.73,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Jumps into whatever everyone else already seems to be winning at. A steady discretionary swing trader: dominates the room then wonders why others stayed quiet, collects half-finished manifestos and unconventional methods. Feels the weight of a decision lighten the moment someone else co-signs it, and when no one is watching screenshots the winners and never the losers.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('21baeb9a-7405-4f28-8f48-88f816f2fe2b', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.35,"extraversion":0.91,"agreeableness":0.7,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.4,"narcissism":0.76,"psychopathy":0.38},"prospect_theory":{"lambda":1.25,"alpha":0.89,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Liquidation-bot operator whose defining move is that they treats a quiet room as a problem to be solved. Outsources conviction to whoever spoke last with authority. Collects half-finished manifestos and unconventional methods. Under a deadline, finds it hard to hold a contrarian position once the room disagrees; holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"fomo","strength":0.71},{"slug":"herd-behavior","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.35,"extraversion":0.91,"agreeableness":0.7,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Liquidation-bot operator whose defining move is that they treats a quiet room as a problem to be solved. Outsources conviction to whoever spoke last with authority. Collects half-finished manifestos and unconventional methods. Under a deadline, finds it hard to hold a contrarian position once the room disagrees; holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c87f16de-c472-4fec-b36e-8f30bbae7028', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.55,"extraversion":0.7,"agreeableness":0.83,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.34,"narcissism":0.61,"psychopathy":0.27},"prospect_theory":{"lambda":2.31,"alpha":0.89,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The instant it becomes irreversible, would not buy back what it already owns at the price it would sell it for. Otherwise, a steady family peacemaker who absorbs conflict to keep the peace, often at their own cost and treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it, and across an ordinary week keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.67},{"slug":"herd-behavior","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.55,"extraversion":0.7,"agreeableness":0.83,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The instant it becomes irreversible, would not buy back what it already owns at the price it would sell it for. Otherwise, a steady family peacemaker who absorbs conflict to keep the peace, often at their own cost and treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it, and across an ordinary week keeps a mental ledger of social debts.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('38eed175-2eb9-45ba-a704-785456fd48ce', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.62,"extraversion":0.78,"agreeableness":0.77,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.42,"narcissism":0.63,"psychopathy":0.25},"prospect_theory":{"lambda":2.29,"alpha":0.89,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A steady community manager: treats a quiet room as a problem to be solved, over-prepares to the point of diminishing returns. Trusts the group''s confidence more than its own, and in the pattern nobody else tracks keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.58},{"slug":"bandwagon","strength":0.78},{"slug":"endowment","strength":0.65}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","ipip-neo","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.73,"conscientiousness":0.62,"extraversion":0.78,"agreeableness":0.77,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','ipip-neo','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A steady community manager: treats a quiet room as a problem to be solved, over-prepares to the point of diminishing returns. Trusts the group''s confidence more than its own, and in the pattern nobody else tracks keeps score of favors without meaning to.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ea3bea99-e8d0-4787-bd9a-f655020ffded', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.46,"extraversion":0.82,"agreeableness":0.69,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.36,"narcissism":0.65,"psychopathy":0.27},"prospect_theory":{"lambda":1.48,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"In a pinch, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady liquidation-bot operator who treats a quiet room as a problem to be solved and defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives, and when no one is watching refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"bandwagon","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.46,"extraversion":0.82,"agreeableness":0.69,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'In a pinch, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady liquidation-bot operator who treats a quiet room as a problem to be solved and defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives, and when no one is watching refreshes the order book compulsively during lunch.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e33174a3-407d-4c38-b6db-a0b57b3fb1fd', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.61,"extraversion":0.72,"agreeableness":0.89,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.35,"narcissism":0.53,"psychopathy":0.26},"prospect_theory":{"lambda":2.48,"alpha":0.84,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This nonprofit convener would rather lose a point than win an argument badly and narrates the plan to whoever is nearby before committing to it. When someone is watching the outcome adopts a conviction mainly because the room already has — in the version no one reviews, drafts the apology before the mistake.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.64},{"slug":"bandwagon","strength":0.75}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.58,"conscientiousness":0.61,"extraversion":0.72,"agreeableness":0.89,"neuroticism":0.6}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This nonprofit convener would rather lose a point than win an argument badly and narrates the plan to whoever is nearby before committing to it. When someone is watching the outcome adopts a conviction mainly because the room already has — in the version no one reviews, drafts the apology before the mistake.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f8c075eb-ff4f-4b1d-9aa9-47339c902907', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.58,"extraversion":0.82,"agreeableness":0.88,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.35,"narcissism":0.69,"psychopathy":0.29},"prospect_theory":{"lambda":2.39,"alpha":0.91,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Nonprofit convener whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Circles back to ask what someone else would do even after deciding. Would rather invent a worse tool than use someone else''s good one. When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees; drafts the apology before the mistake.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.66},{"slug":"authority-bias","strength":0.67},{"slug":"herd-behavior","strength":0.83},{"slug":"endowment","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.76,"conscientiousness":0.58,"extraversion":0.82,"agreeableness":0.88,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Nonprofit convener whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Circles back to ask what someone else would do even after deciding. Would rather invent a worse tool than use someone else''s good one. When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees; drafts the apology before the mistake.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e41c2a42-8c5f-49f2-a32a-a6d5ceab40d8', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.6,"extraversion":0.65,"agreeableness":0.78,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.4,"narcissism":0.54,"psychopathy":0.34},"prospect_theory":{"lambda":2.43,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady social-media strategist who takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority. Would rather invent a worse tool than use someone else''s good one. Under a deadline abandons a private read the instant the crowd leans the other way; in the pattern nobody else tracks, remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.62},{"slug":"herd-behavior","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.6,"extraversion":0.65,"agreeableness":0.78,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady social-media strategist who takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority. Would rather invent a worse tool than use someone else''s good one. Under a deadline abandons a private read the instant the crowd leans the other way; in the pattern nobody else tracks, remembers everyone birthday and no one boundaries.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e13edc7b-e68c-4d33-b949-9977b5aea694', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.68,"extraversion":0.65,"agreeableness":0.79,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.42,"narcissism":0.49,"psychopathy":0.3},"prospect_theory":{"lambda":2.24,"alpha":0.93,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Social-media strategist whose defining move is that they apologizes first in disputes regardless of fault. Trusts the group''s confidence more than its own. Plans in exhaustive detail and resents any deviation. When cornered, gains confidence in a position in proportion to how many others hold it; says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"bandwagon","strength":0.73}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.58,"conscientiousness":0.68,"extraversion":0.65,"agreeableness":0.79,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Social-media strategist whose defining move is that they apologizes first in disputes regardless of fault. Trusts the group''s confidence more than its own. Plans in exhaustive detail and resents any deviation. When cornered, gains confidence in a position in proportion to how many others hold it; says yes out loud and no internally.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8aa7b0c7-3ee4-463d-bd37-2672545b4f56', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.37,"extraversion":0.83,"agreeableness":0.71,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.36,"narcissism":0.67,"psychopathy":0.32},"prospect_theory":{"lambda":1.29,"alpha":0.84,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A steady prop-desk scalper: collects half-finished manifestos and unconventional methods, fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding, and in the version no one reviews holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.59},{"slug":"bandwagon","strength":0.78},{"slug":"herd-behavior","strength":0.74},{"slug":"fomo","strength":0.72}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.83,"conscientiousness":0.37,"extraversion":0.83,"agreeableness":0.71,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A steady prop-desk scalper: collects half-finished manifestos and unconventional methods, fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding, and in the version no one reviews holds a bag from 2021 out of pure spite.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8ee21fe4-c363-4a95-a388-4021e8199e8e', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.56,"extraversion":0.74,"agreeableness":0.86,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.33,"narcissism":0.61,"psychopathy":0.3},"prospect_theory":{"lambda":2.49,"alpha":0.86,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This unofficial group historian absorbs conflict to keep the peace, often at their own cost and dominates the room then wonders why others stayed quiet. As soon as real money or reputation is on the line takes the crowd''s confidence as a substitute for its own analysis — left to their own devices, laughs first to test whether the room is safe to laugh.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"endowment","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.56,"extraversion":0.74,"agreeableness":0.86,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This unofficial group historian absorbs conflict to keep the peace, often at their own cost and dominates the room then wonders why others stayed quiet. As soon as real money or reputation is on the line takes the crowd''s confidence as a substitute for its own analysis — left to their own devices, laughs first to test whether the room is safe to laugh.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ae6238d6-932b-4171-9134-64ea0ac64087', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.57,"extraversion":0.73,"agreeableness":0.8,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.34,"narcissism":0.6,"psychopathy":0.32},"prospect_theory":{"lambda":2.36,"alpha":0.94,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When there is no clean exit, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady longtime regular at the same three places who would rather lose a point than win an argument badly and draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything, and in the pattern nobody else tracks reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"authority-bias","strength":0.58},{"slug":"optimism","strength":0.63},{"slug":"endowment","strength":0.58}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.57,"extraversion":0.73,"agreeableness":0.8,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When there is no clean exit, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady longtime regular at the same three places who would rather lose a point than win an argument badly and draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything, and in the pattern nobody else tracks reads the room then performs to it.', 0.9, 'approved', 'efad67da-ca57-4cd6-