('27a3a94e-30b7-46f4-bfea-1d4dccec47d9', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.55,"extraversion":0.74,"agreeableness":0.88,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.34,"narcissism":0.62,"psychopathy":0.32},"prospect_theory":{"lambda":2.39,"alpha":0.86,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced team captain who reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Treats established procedure as a first draft to be rewritten. The instant it becomes irreversible finds it easier to believe something once it stops being a minority view; on an ordinary week, remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.68},{"slug":"endowment","strength":0.68},{"slug":"bandwagon","strength":0.74},{"slug":"sunk-cost","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.55,"extraversion":0.74,"agreeableness":0.88,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced team captain who reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Treats established procedure as a first draft to be rewritten. The instant it becomes irreversible finds it easier to believe something once it stops being a minority view; on an ordinary week, remembers everyone birthday and no one boundaries.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
