('46b87b9b-b0e3-4c5e-97a1-2d57bcd6f5dc', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.62,"extraversion":0.78,"agreeableness":0.92,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.38,"narcissism":0.66,"psychopathy":0.31},"prospect_theory":{"lambda":2.27,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Online moderator whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Circles back to ask what someone else would do even after deciding. Treats a quiet room as a problem to be solved. When the walls close in, takes the crowd''s confidence as a substitute for its own analysis; remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.66},{"slug":"bandwagon","strength":0.77},{"slug":"fomo","strength":0.64},{"slug":"herd-behavior","strength":0.81}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.62,"extraversion":0.78,"agreeableness":0.92,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Online moderator whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Circles back to ask what someone else would do even after deciding. Treats a quiet room as a problem to be solved. When the walls close in, takes the crowd''s confidence as a substitute for its own analysis; remembers everyone birthday and no one boundaries.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('59af6158-11b2-4cbc-8891-31df949ad958', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.31,"extraversion":0.86,"agreeableness":0.67,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.35,"narcissism":0.68,"psychopathy":0.39},"prospect_theory":{"lambda":1.32,"alpha":0.85,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced crypto day-trader who dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything. Collects half-finished manifestos and unconventional methods. When the safe option quietly expires finds it hard to hold a contrarian position once the room disagrees; left to their own devices, refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.66},{"slug":"herd-behavior","strength":0.73},{"slug":"dunning-kruger","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.31,"extraversion":0.86,"agreeableness":0.67,"neuroticism":0.67}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced crypto day-trader who dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything. Collects half-finished manifestos and unconventional methods. When the safe option quietly expires finds it hard to hold a contrarian position once the room disagrees; left to their own devices, refreshes the order book compulsively during lunch.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e9037dec-22f9-4674-b4d3-b212ab627da4', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.4,"extraversion":0.85,"agreeableness":0.64,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.36,"narcissism":0.71,"psychopathy":0.35},"prospect_theory":{"lambda":1.29,"alpha":0.91,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Volatility arbitrageur, pronounced in style: would rather invent a worse tool than use someone else''s good one; measures decisions by who they might upset. Waits for a permission that never quite arrives. When the safe option quietly expires takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"fomo","strength":0.61}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.86,"conscientiousness":0.4,"extraversion":0.85,"agreeableness":0.64,"neuroticism":0.48}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Volatility arbitrageur, pronounced in style: would rather invent a worse tool than use someone else''s good one; measures decisions by who they might upset. Waits for a permission that never quite arrives. When the safe option quietly expires takes the crowd''s confidence as a substitute for its own analysis.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('fc4be5ac-546f-42b7-8f1b-a90a59f0ae57', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.6,"extraversion":0.75,"agreeableness":0.86,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.34,"narcissism":0.63,"psychopathy":0.27},"prospect_theory":{"lambda":2.56,"alpha":0.87,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This group-project default leader apologizes first in disputes regardless of fault and treats established procedure as a first draft to be rewritten. When the stakes rise abandons a private read the instant the crowd leans the other way — in the routine of it, remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.6},{"slug":"herd-behavior","strength":0.73},{"slug":"endowment","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.6,"extraversion":0.75,"agreeableness":0.86,"neuroticism":0.47}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This group-project default leader apologizes first in disputes regardless of fault and treats established procedure as a first draft to be rewritten. When the stakes rise abandons a private read the instant the crowd leans the other way — in the routine of it, remembers who didn''t get invited last time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d9e86dad-7d7f-4601-9645-e18f2c752b66', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.5,"extraversion":0.85,"agreeableness":0.71,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.34,"narcissism":0.68,"psychopathy":0.27},"prospect_theory":{"lambda":1.31,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This futures spreader recharges by being around people, not away from them and would rather invent a worse tool than use someone else''s good one. When the number turns red jumps into whatever everyone else already seems to be winning at — in the parts nobody grades, names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.75},{"slug":"bandwagon","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.5,"extraversion":0.85,"agreeableness":0.71,"neuroticism":0.59}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This futures spreader recharges by being around people, not away from them and would rather invent a worse tool than use someone else''s good one. When the number turns red jumps into whatever everyone else already seems to be winning at — in the parts nobody grades, names every strategy after the trade that almost worked.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('758c8f2f-b4b0-452d-b826-b40e3ab24d39', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.65,"extraversion":0.74,"agreeableness":0.94,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.41,"narcissism":0.58,"psychopathy":0.3},"prospect_theory":{"lambda":2.34,"alpha":0.92,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Social-media strategist whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own. Dominates the room then wonders why others stayed quiet. Once the exit narrows to one door, finds it easier to believe something once it stops being a minority view; texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.71},{"slug":"herd-behavior","strength":0.83},{"slug":"bandwagon","strength":0.84}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.65,"extraversion":0.74,"agreeableness":0.94,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Social-media strategist whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own. Dominates the room then wonders why others stayed quiet. Once the exit narrows to one door, finds it easier to believe something once it stops being a minority view; texts an apology before confirming anyone is upset.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('5085c23d-88ba-4a39-8060-9f06c8d6e723', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.59,"extraversion":0.74,"agreeableness":0.94,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.39,"narcissism":0.63,"psychopathy":0.29},"prospect_theory":{"lambda":2.25,"alpha":0.87,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Wedding-party diplomat whose defining move is that they would rather lose a point than win an argument badly. Circles back to ask what someone else would do even after deciding. Reads outside the field for ideas the field itself would reject. When there is no clean exit, gains confidence in a position in proportion to how many others hold it; laughs first to test whether the room is safe to laugh.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.84},{"slug":"endowment","strength":0.74}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.59,"extraversion":0.74,"agreeableness":0.94,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Wedding-party diplomat whose defining move is that they would rather lose a point than win an argument badly. Circles back to ask what someone else would do even after deciding. Reads outside the field for ideas the field itself would reject. When there is no clean exit, gains confidence in a position in proportion to how many others hold it; laughs first to test whether the room is safe to laugh.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('635e7c8d-0842-44cd-9f58-5167105a9eef', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.53,"extraversion":0.87,"agreeableness":0.65,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.37,"narcissism":0.78,"psychopathy":0.27},"prospect_theory":{"lambda":1.24,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Meme-coin rotator, pronounced in style: thinks out loud and recruits an audience for every decision; absorbs conflict to keep the peace, often at their own cost. Waits for a permission that never quite arrives. In a pinch adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.76},{"slug":"herd-behavior","strength":0.74},{"slug":"fomo","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.53,"extraversion":0.87,"agreeableness":0.65,"neuroticism":0.47}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Meme-coin rotator, pronounced in style: thinks out loud and recruits an audience for every decision; absorbs conflict to keep the peace, often at their own cost. Waits for a permission that never quite arrives. In a pinch adopts a conviction mainly because the room already has.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('afb07978-739a-4af9-bfbd-0f840513e694', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.66,"extraversion":0.75,"agreeableness":0.79,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.39,"narcissism":0.61,"psychopathy":0.31},"prospect_theory":{"lambda":2.45,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Social-media strategist whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Outsources conviction to whoever spoke last with authority. Reads outside the field for ideas the field itself would reject. The instant the deadline moves up, abandons a private read the instant the crowd leans the other way; over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.77},{"slug":"bandwagon","strength":0.72},{"slug":"fomo","strength":0.65}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.72,"conscientiousness":0.66,"extraversion":0.75,"agreeableness":0.79,"neuroticism":0.6}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Social-media strategist whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Outsources conviction to whoever spoke last with authority. Reads outside the field for ideas the field itself would reject. The instant the deadline moves up, abandons a private read the instant the crowd leans the other way; over-commits to plans they later dread.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
