('35e88cb7-8807-4682-98b2-9b1ee57380a9', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.36,"extraversion":0.86,"agreeableness":0.7,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.36,"narcissism":0.73,"psychopathy":0.37},"prospect_theory":{"lambda":1.49,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced DeFi yield farmer who narrates the plan to whoever is nearby before committing to it. Trusts the group''s confidence more than its own. Improvises past every deadline and calls it flexibility. The instant the deadline moves up gains confidence in a position in proportion to how many others hold it; when the pressure is off, averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"bandwagon","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.36,"extraversion":0.86,"agreeableness":0.7,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced DeFi yield farmer who narrates the plan to whoever is nearby before committing to it. Trusts the group''s confidence more than its own. Improvises past every deadline and calls it flexibility. The instant the deadline moves up gains confidence in a position in proportion to how many others hold it; when the pressure is off, averages down on a name three times in a week.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
