('9c66e4f1-e8fa-477e-b2f9-f0d8e2dfa074', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.6,"extraversion":0.73,"agreeableness":0.9,"neuroticism":0.37},"dark_triad":{"machiavellianism":0.36,"narcissism":0.63,"psychopathy":0.34},"prospect_theory":{"lambda":2.35,"alpha":0.94,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Event host, pronounced in style: reads other people''s discomfort before they voice it; treats a crisis as an interesting problem rather than a threat. Needs the room''s approval more than it needs to be right. Under pressure adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.76},{"slug":"authority-bias","strength":0.66},{"slug":"herd-behavior","strength":0.71},{"slug":"endowment","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.6,"extraversion":0.73,"agreeableness":0.9,"neuroticism":0.37}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Event host, pronounced in style: reads other people''s discomfort before they voice it; treats a crisis as an interesting problem rather than a threat. Needs the room''s approval more than it needs to be right. Under pressure adopts a conviction mainly because the room already has.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d18e27dd-2db8-430c-8601-d2faabc90bc4', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.4,"extraversion":0.94,"agreeableness":0.77,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.32,"narcissism":0.73,"psychopathy":0.29},"prospect_theory":{"lambda":1.33,"alpha":0.86,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced onchain copy-trader who thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it. Reframes every problem as an excuse to learn a new system. When there is no clean exit finds it hard to hold a contrarian position once the room disagrees; once the urgency drains out, keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.79},{"slug":"herd-behavior","strength":0.81}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.4,"extraversion":0.94,"agreeableness":0.77,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced onchain copy-trader who thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it. Reframes every problem as an excuse to learn a new system. When there is no clean exit finds it hard to hold a contrarian position once the room disagrees; once the urgency drains out, keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('003fab98-1eb9-449d-9b5b-beba6c040ba1', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.44,"extraversion":0.8,"agreeableness":0.68,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.34,"narcissism":0.63,"psychopathy":0.33},"prospect_theory":{"lambda":1.43,"alpha":0.81,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"DeFi yield farmer whose defining move is that they treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it. Absorbs conflict to keep the peace, often at their own cost. The instant it becomes irreversible, takes the crowd''s confidence as a substitute for its own analysis; names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.63},{"slug":"dunning-kruger","strength":0.55},{"slug":"herd-behavior","strength":0.72},{"slug":"recency","strength":0.59}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.44,"extraversion":0.8,"agreeableness":0.68,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'DeFi yield farmer whose defining move is that they treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it. Absorbs conflict to keep the peace, often at their own cost. The instant it becomes irreversible, takes the crowd''s confidence as a substitute for its own analysis; names every strategy after the trade that almost worked.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a5118050-c9d0-475f-a38a-23093d6d899d', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.42,"extraversion":0.81,"agreeableness":0.69,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.4,"narcissism":0.67,"psychopathy":0.34},"prospect_theory":{"lambda":1.57,"alpha":0.92,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This volatility arbitrageur recharges by being around people, not away from them and would rather lose a point than win an argument badly. Once the exit narrows to one door adopts a conviction mainly because the room already has — in the version no one reviews, refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"herd-behavior","strength":0.67},{"slug":"bandwagon","strength":0.75},{"slug":"fomo","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.42,"extraversion":0.81,"agreeableness":0.69,"neuroticism":0.48}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This volatility arbitrageur recharges by being around people, not away from them and would rather lose a point than win an argument badly. Once the exit narrows to one door adopts a conviction mainly because the room already has — in the version no one reviews, refreshes the order book compulsively during lunch.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('81e583f2-a437-461c-a123-8fb654b29ad3', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.65,"extraversion":0.68,"agreeableness":0.82,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.41,"narcissism":0.6,"psychopathy":0.3},"prospect_theory":{"lambda":2.45,"alpha":0.91,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A steady social-media strategist: takes on other people''s problems as if they were their own, chases novel frameworks and abandons them once the novelty fades. Outsources conviction to whoever spoke last with authority, and on a slow afternoon says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.69},{"slug":"endowment","strength":0.59},{"slug":"bandwagon","strength":0.75}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.65,"extraversion":0.68,"agreeableness":0.82,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A steady social-media strategist: takes on other people''s problems as if they were their own, chases novel frameworks and abandons them once the novelty fades. Outsources conviction to whoever spoke last with authority, and on a slow afternoon says yes out loud and no internally.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c77b00ae-090d-4cff-a0ef-70abf6a0dcca', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.65,"extraversion":0.76,"agreeableness":0.97,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.34,"narcissism":0.62,"psychopathy":0.3},"prospect_theory":{"lambda":2.42,"alpha":0.91,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A pronounced unofficial group historian: measures decisions by who they might upset, would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and as a rule keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.78},{"slug":"endowment","strength":0.64},{"slug":"bandwagon","strength":0.85},{"slug":"authority-bias","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.65,"extraversion":0.76,"agreeableness":0.97,"neuroticism":0.42}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A pronounced unofficial group historian: measures decisions by who they might upset, would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and as a rule keeps score of favors without meaning to.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('eb8eceb3-fa8b-425e-ae52-e448f072478f', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.44,"extraversion":0.85,"agreeableness":0.7,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.36,"narcissism":0.72,"psychopathy":0.34},"prospect_theory":{"lambda":1.42,"alpha":0.86,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"As soon as real money or reputation is on the line, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced dividend-yield chaser who recharges by being around people, not away from them and reframes every problem as an excuse to learn a new system. Outsources conviction to whoever spoke last with authority, and in the unglamorous middle of things apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.68},{"slug":"herd-behavior","strength":0.79},{"slug":"dunning-kruger","strength":0.62},{"slug":"bandwagon","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.83,"conscientiousness":0.44,"extraversion":0.85,"agreeableness":0.7,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'As soon as real money or reputation is on the line, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced dividend-yield chaser who recharges by being around people, not away from them and reframes every problem as an excuse to learn a new system. Outsources conviction to whoever spoke last with authority, and in the unglamorous middle of things apes the launch before the contract is verified.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
