('c1dff0df-0805-4e7a-a3be-aab07636e8ac', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.7,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.39,"narcissism":0.67,"psychopathy":0.27},"prospect_theory":{"lambda":1.25,"alpha":0.84,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Commodities speculator whose defining move is that they dominates the room then wonders why others stayed quiet. Outsources conviction to whoever spoke last with authority. Needs repeated reassurance that a decision was the right one. When the safe option quietly expires, abandons a private read the instant the crowd leans the other way; trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.71},{"slug":"endowment","strength":0.54},{"slug":"dunning-kruger","strength":0.66},{"slug":"herd-behavior","strength":0.72}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.64,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.7,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Commodities speculator whose defining move is that they dominates the room then wonders why others stayed quiet. Outsources conviction to whoever spoke last with authority. Needs repeated reassurance that a decision was the right one. When the safe option quietly expires, abandons a private read the instant the crowd leans the other way; trusts the chart more than the fundamentals and won''t say why.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8e6ec1c2-05bb-40fc-824c-349bd715ff4c', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.26,"extraversion":0.88,"agreeableness":0.65,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.4,"narcissism":0.77,"psychopathy":0.42},"prospect_theory":{"lambda":1.56,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This liquidation-bot operator dominates the room then wonders why others stayed quiet and starts strong and lets follow-through evaporate. When cornered abandons a private read the instant the crowd leans the other way — day to day, sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"dunning-kruger","strength":0.74},{"slug":"bandwagon","strength":0.74},{"slug":"herd-behavior","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.26,"extraversion":0.88,"agreeableness":0.65,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This liquidation-bot operator dominates the room then wonders why others stayed quiet and starts strong and lets follow-through evaporate. When cornered abandons a private read the instant the crowd leans the other way — day to day, sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f242cdc0-cf56-44e5-b64b-67e05e18dc65', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.44,"extraversion":0.9,"agreeableness":0.63,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.35,"narcissism":0.75,"psychopathy":0.27},"prospect_theory":{"lambda":1.43,"alpha":0.82,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A pronounced quant researcher: narrates the plan to whoever is nearby before committing to it, would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything, and in the pattern nobody else tracks keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.76},{"slug":"dunning-kruger","strength":0.59},{"slug":"herd-behavior","strength":0.75},{"slug":"fomo","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.44,"extraversion":0.9,"agreeableness":0.63,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A pronounced quant researcher: narrates the plan to whoever is nearby before committing to it, would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything, and in the pattern nobody else tracks keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e8abaf81-1f66-4bb3-8bfa-e9e5c1a3d735', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.4,"extraversion":0.78,"agreeableness":0.56,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.39,"narcissism":0.6,"psychopathy":0.36},"prospect_theory":{"lambda":1.52,"alpha":0.82,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"In a pinch, mistakes a little fluency for real mastery. Otherwise, a steady retail momentum chaser who treats a quiet room as a problem to be solved and gets bored of the proven method exactly when it starts working. Circles back to ask what someone else would do even after deciding, and in the small things sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.63},{"slug":"dunning-kruger","strength":0.67},{"slug":"herd-behavior","strength":0.61},{"slug":"bandwagon","strength":0.57}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.67,"conscientiousness":0.4,"extraversion":0.78,"agreeableness":0.56,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'In a pinch, mistakes a little fluency for real mastery. Otherwise, a steady retail momentum chaser who treats a quiet room as a problem to be solved and gets bored of the proven method exactly when it starts working. Circles back to ask what someone else would do even after deciding, and in the small things sizes every position at exactly 2% risk.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c7985f66-9377-4e2c-b255-15d1aa2ddb16', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.62,"extraversion":0.68,"agreeableness":0.83,"neuroticism":0.33},"dark_triad":{"machiavellianism":0.38,"narcissism":0.56,"psychopathy":0.38},"prospect_theory":{"lambda":2.47,"alpha":0.89,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A steady family peacemaker: absorbs conflict to keep the peace, often at their own cost, maintains flawless records nobody asked for. Feels the weight of a decision lighten the moment someone else co-signs it, and when no one is watching says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.58},{"slug":"herd-behavior","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.6,"conscientiousness":0.62,"extraversion":0.68,"agreeableness":0.83,"neuroticism":0.33}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A steady family peacemaker: absorbs conflict to keep the peace, often at their own cost, maintains flawless records nobody asked for. Feels the weight of a decision lighten the moment someone else co-signs it, and when no one is watching says yes out loud and no internally.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('856a5fa1-60a0-4074-8aa6-0a552eadfebb', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.5,"extraversion":0.73,"agreeableness":0.82,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.36,"narcissism":0.57,"psychopathy":0.33},"prospect_theory":{"lambda":2.38,"alpha":0.88,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A steady reluctant plus-one: apologizes first in disputes regardless of fault, dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything, and left to their own devices keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.63},{"slug":"authority-bias","strength":0.64},{"slug":"herd-behavior","strength":0.74},{"slug":"bandwagon","strength":0.72}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.5,"extraversion":0.73,"agreeableness":0.82,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A steady reluctant plus-one: apologizes first in disputes regardless of fault, dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything, and left to their own devices keeps a mental ledger of social debts.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('51876b5e-fe09-48c0-be8e-83ffa3808ed0', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.47,"extraversion":0.68,"agreeableness":0.8,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.32,"narcissism":0.56,"psychopathy":0.37},"prospect_theory":{"lambda":2.31,"alpha":0.89,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When someone is watching the outcome, finds it easier to believe something once it stops being a minority view. Otherwise, a steady community manager who defaults to trust and gives the benefit of the doubt too freely and would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and across an ordinary week keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"sunk-cost","strength":0.64},{"slug":"bandwagon","strength":0.7},{"slug":"authority-bias","strength":0.6},{"slug":"endowment","strength":0.55}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.47,"extraversion":0.68,"agreeableness":0.8,"neuroticism":0.4}'::jsonb, 'ENFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When someone is watching the outcome, finds it easier to believe something once it stops being a minority view. Otherwise, a steady community manager who defaults to trust and gives the benefit of the doubt too freely and would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and across an ordinary week keeps a mental ledger of social debts.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0f791ad9-2d38-4e38-9d0d-f74a169d9aa8', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.56,"extraversion":0.67,"agreeableness":0.81,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.38,"narcissism":0.53,"psychopathy":0.33},"prospect_theory":{"lambda":2.46,"alpha":0.91,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady social-media strategist who defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives. Collects half-finished manifestos and unconventional methods. The instant the deadline moves up finds it easier to believe something once it stops being a minority view; when the pressure is off, over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.57},{"slug":"bandwagon","strength":0.73},{"slug":"herd-behavior","strength":0.7}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.56,"extraversion":0.67,"agreeableness":0.81,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady social-media strategist who defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives. Collects half-finished manifestos and unconventional methods. The instant the deadline moves up finds it easier to believe something once it stops being a minority view; when the pressure is off, over-explains a boundary rather than just stating it.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('74738be3-f9c1-440f-a65f-83c909eb474f', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.42,"extraversion":0.91,"agreeableness":0.74,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.38,"narcissism":0.72,"psychopathy":0.33},"prospect_theory":{"lambda":1.35,"alpha":0.81,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This algorithmic market-maker dominates the room then wonders why others stayed quiet and chases novel frameworks and abandons them once the novelty fades. When someone is watching the outcome adopts a conviction mainly because the room already has — on a slow afternoon, apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.79},{"slug":"dunning-kruger","strength":0.65},{"slug":"fomo","strength":0.72}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.42,"extraversion":0.91,"agreeableness":0.74,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This algorithmic market-maker dominates the room then wonders why others stayed quiet and chases novel frameworks and abandons them once the novelty fades. When someone is watching the outcome adopts a conviction mainly because the room already has — on a slow afternoon, apes the launch before the contract is verified.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e0a69210-7161-4dfd-8ed6-61530addc849', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.66,"extraversion":0.77,"agreeableness":0.91,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.38,"narcissism":0.61,"psychopathy":0.27},"prospect_theory":{"lambda":2.54,"alpha":0.91,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A pronounced group-chat ringleader: would rather lose a point than win an argument badly, treats established procedure as a first draft to be rewritten. Waits for a permission that never quite arrives, and day to day mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.71},{"slug":"bandwagon","strength":0.77},{"slug":"authority-bias","strength":0.68}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.66,"extraversion":0.77,"agreeableness":0.91,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A pronounced group-chat ringleader: would rather lose a point than win an argument badly, treats established procedure as a first draft to be rewritten. Waits for a permission that never quite arrives, and day to day mediates conflicts they secretly started.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('cb6ca3bf-fae2-4b93-92ab-aaa191411945', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.37,"extraversion":0.77,"agreeableness":0.68,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.38,"narcissism":0.66,"psychopathy":0.35},"prospect_theory":{"lambda":1.37,"alpha":0.89,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment risk appears, jumps into whatever everyone else already seems to be winning at. Otherwise, a steady index-fund holdout who reads outside the field for ideas the field itself would reject and takes on other people''s problems as if they were their own. Circles back to ask what someone else would do even after deciding, and in the routine of it averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"herd-behavior","strength":0.69},{"slug":"dunning-kruger","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.37,"extraversion":0.77,"agreeableness":0.68,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment risk appears, jumps into whatever everyone else already seems to be winning at. Otherwise, a steady index-fund holdout who reads outside the field for ideas the field itself would reject and takes on other people''s problems as if they were their own. Circles back to ask what someone else would do even after deciding, and in the routine of it averages down on a name three times in a week.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6b8e316f-1a02-489f-ba18-4a194a4949dc', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.61,"extraversion":0.66,"agreeableness":0.91,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.36,"narcissism":0.5,"psychopathy":0.36},"prospect_theory":{"lambda":2.39,"alpha":0.94,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced wedding-party diplomat who would rather lose a point than win an argument badly. Outsources conviction to whoever spoke last with authority. Recharges by being around people, not away from them. Under pressure adopts a conviction mainly because the room already has; on an ordinary week, over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.66},{"slug":"bandwagon","strength":0.79}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.6,"conscientiousness":0.61,"extraversion":0.66,"agreeableness":0.91,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced wedding-party diplomat who would rather lose a point than win an argument badly. Outsources conviction to whoever spoke last with authority. Recharges by being around people, not away from them. Under pressure adopts a conviction mainly because the room already has; on an ordinary week, over-explains a boundary rather than just stating it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('36046e00-363c-49e9-9885-1d6766139e3d', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.7,"extraversion":0.72,"agreeableness":0.95,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.43,"narcissism":0.64,"psychopathy":0.29},"prospect_theory":{"lambda":2.43,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This longtime regular at the same three places defaults to trust and gives the benefit of the doubt too freely and cannot relax until the checklist is visibly complete. As soon as real money or reputation is on the line adopts a conviction mainly because the room already has — on an ordinary week, reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.68},{"slug":"endowment","strength":0.67},{"slug":"herd-behavior","strength":0.76},{"slug":"bandwagon","strength":0.8}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.77,"conscientiousness":0.7,"extraversion":0.72,"agreeableness":0.95,"neuroticism":0.49}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This longtime regular at the same three places defaults to trust and gives the benefit of the doubt too freely and cannot relax until the checklist is visibly complete. As soon as real money or reputation is on the line adopts a conviction mainly because the room already has — on an ordinary week, reads the room then performs to it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9d75d2e0-01b1-4d3a-9d87-6f427307c621', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.36,"extraversion":0.78,"agreeableness":0.67,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.39,"narcissism":0.65,"psychopathy":0.34},"prospect_theory":{"lambda":1.4,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Retail momentum chaser whose defining move is that they thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it. Takes on other people''s problems as if they were their own. When there is no clean exit, adopts a conviction mainly because the room already has; sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"dunning-kruger","strength":0.61}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.36,"extraversion":0.78,"agreeableness":0.67,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Retail momentum chaser whose defining move is that they thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it. Takes on other people''s problems as if they were their own. When there is no clean exit, adopts a conviction mainly because the room already has; sizes every position at exactly 2% risk.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d8b88418-7919-4ae9-a40a-5eb50335313a', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.36,"extraversion":0.86,"agreeableness":0.74,"neuroticism":0.72},"dark_triad":{"machiavellianism":0.35,"narcissism":0.64,"psychopathy":0.31},"prospect_theory":{"lambda":1.46,"alpha":0.77,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A pronounced commodities speculator: thinks out loud and recruits an audience for every decision, confuses motion with progress. Waits for a permission that never quite arrives, and when the stakes are trivial sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.7},{"slug":"fomo","strength":0.7},{"slug":"bandwagon","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.36,"extraversion":0.86,"agreeableness":0.74,"neuroticism":0.72}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A pronounced commodities speculator: thinks out loud and recruits an audience for every decision, confuses motion with progress. Waits for a permission that never quite arrives, and when the stakes are trivial sets stop-losses then cancels them at the open.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f45107cc-acb7-4b6e-8009-203311dd9984', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.5,"extraversion":0.68,"agreeableness":0.8,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.37,"narcissism":0.59,"psychopathy":0.34},"prospect_theory":{"lambda":2.53,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This online moderator apologizes first in disputes regardless of fault and would rather invent a worse tool than use someone else''s good one. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way — in the parts nobody grades, can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.71},{"slug":"herd-behavior","strength":0.74}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.72,"conscientiousness":0.5,"extraversion":0.68,"agreeableness":0.8,"neuroticism":0.42}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This online moderator apologizes first in disputes regardless of fault and would rather invent a worse tool than use someone else''s good one. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way — in the parts nobody grades, can sense a mood shift from the doorway.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('43fc7276-671c-49f8-a463-86429b115d43', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.57,"extraversion":0.75,"agreeableness":0.88,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.37,"narcissism":0.61,"psychopathy":0.34},"prospect_theory":{"lambda":2.49,"alpha":0.89,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Group-project default leader, pronounced in style: reads other people''s discomfort before they voice it; thinks out loud and recruits an audience for every decision. Seeks a second, third, and fourth opinion before committing to anything. Once the exit narrows to one door adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.77},{"slug":"optimism","strength":0.65}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.57,"extraversion":0.75,"agreeableness":0.88,"neuroticism":0.34}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Group-project default leader, pronounced in style: reads other people''s discomfort before they voice it; thinks out loud and recruits an audience for every decision. Seeks a second, third, and fourth opinion before committing to anything. Once the exit narrows to one door adopts a conviction mainly because the room already has.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('810e4922-f553-472c-b6c4-6234b9173db9', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.4,"extraversion":0.82,"agreeableness":0.73,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.33,"narcissism":0.69,"psychopathy":0.36},"prospect_theory":{"lambda":1.32,"alpha":0.85,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This zero-DTE options gambler narrates the plan to whoever is nearby before committing to it and takes on other people''s problems as if they were their own. The moment it stops being hypothetical finds it hard to hold a contrarian position once the room disagrees — when the stakes are trivial, names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"dunning-kruger","strength":0.67},{"slug":"bandwagon","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.4,"extraversion":0.82,"agreeableness":0.73,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This zero-DTE options gambler narrates the plan to whoever is nearby before committing to it and takes on other people''s problems as if they were their own. The moment it stops being hypothetical finds it hard to hold a contrarian position once the room disagrees — when the stakes are trivial, names every strategy after the trade that almost worked.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ff8c057b-29e2-454e-bc33-5ac743302085', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.36,"extraversion":0.85,"agreeableness":0.67,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.37,"narcissism":0.67,"psychopathy":0.35},"prospect_theory":{"lambda":1.38,"alpha":0.82,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Macro allocator whose defining move is that they treats a quiet room as a problem to be solved. Waits for a permission that never quite arrives. Would rather invent a worse tool than use someone else''s good one. Once things get tense, finds it hard to hold a contrarian position once the room disagrees; keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"herd-behavior","strength":0.73},{"slug":"recency","strength":0.62},{"slug":"fomo","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.36,"extraversion":0.85,"agreeableness":0.67,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Macro allocator whose defining move is that they treats a quiet room as a problem to be solved. Waits for a permission that never quite arrives. Would rather invent a worse tool than use someone else''s good one. Once things get tense, finds it hard to hold a contrarian position once the room disagrees; keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a57fa168-bb4f-4539-8b17-2c72f6259b61', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.52,"extraversion":0.7,"agreeableness":0.87,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.32,"narcissism":0.54,"psychopathy":0.34},"prospect_theory":{"lambda":2.35,"alpha":0.92,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the safe option quietly expires, adopts a conviction mainly because the room already has. Otherwise, a pronounced neighborhood connector who measures decisions by who they might upset and recharges by being around people, not away from them. Needs the room''s approval more than it needs to be right, and left to their own devices can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"endowment","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.6,"conscientiousness":0.52,"extraversion":0.7,"agreeableness":0.87,"neuroticism":0.42}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the safe option quietly expires, adopts a conviction mainly because the room already has. Otherwise, a pronounced neighborhood connector who measures decisions by who they might upset and recharges by being around people, not away from them. Needs the room''s approval more than it needs to be right, and left to their own devices can sense a mood shift from the doorway.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('28d081dc-e5c6-4c70-9de7-de535240d213', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.43,"extraversion":0.89,"agreeableness":0.72,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.4,"narcissism":0.78,"psychopathy":0.31},"prospect_theory":{"lambda":1.55,"alpha":0.84,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Discretionary swing trader whose defining move is that they dominates the room then wonders why others stayed quiet. Needs the room''s approval more than it needs to be right. Reads outside the field for ideas the field itself would reject. The instant it becomes irreversible, finds it hard to hold a contrarian position once the room disagrees; backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.66},{"slug":"herd-behavior","strength":0.78},{"slug":"bandwagon","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.43,"extraversion":0.89,"agreeableness":0.72,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Discretionary swing trader whose defining move is that they dominates the room then wonders why others stayed quiet. Needs the room''s approval more than it needs to be right. Reads outside the field for ideas the field itself would reject. The instant it becomes irreversible, finds it hard to hold a contrarian position once the room disagrees; backtests for months but front-runs the model on impulse.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('29111728-1248-4336-bc3c-1db696f205d6', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.4,"extraversion":0.83,"agreeableness":0.59,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.43,"narcissism":0.68,"psychopathy":0.33},"prospect_theory":{"lambda":1.51,"alpha":0.86,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A steady index-fund holdout: dominates the room then wonders why others stayed quiet, treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority, and in the unglamorous middle of things sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.6},{"slug":"bandwagon","strength":0.67},{"slug":"fomo","strength":0.66},{"slug":"recency","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.4,"extraversion":0.83,"agreeableness":0.59,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A steady index-fund holdout: dominates the room then wonders why others stayed quiet, treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority, and in the unglamorous middle of things sets stop-losses then cancels them at the open.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('33e09b61-12ae-4254-b246-133137295b55', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.47,"extraversion":0.86,"agreeableness":0.73,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.38,"narcissism":0.66,"psychopathy":0.31},"prospect_theory":{"lambda":1.51,"alpha":0.8,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This futures spreader draws energy from the crowd and wilts when working alone and treats established procedure as a first draft to be rewritten. Under pressure finds it hard to hold a contrarian position once the room disagrees — left to their own devices, apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"endowment","strength":0.58},{"slug":"fomo","strength":0.69},{"slug":"herd-behavior","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.65,"conscientiousness":0.47,"extraversion":0.86,"agreeableness":0.73,"neuroticism":0.69}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This futures spreader draws energy from the crowd and wilts when working alone and treats established procedure as a first draft to be rewritten. Under pressure finds it hard to hold a contrarian position once the room disagrees — left to their own devices, apes the launch before the contract is verified.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bd4d586c-9fd7-4cee-81f4-ed25b5cb0805', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.54,"extraversion":0.74,"agreeableness":0.87,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.35,"narcissism":0.63,"psychopathy":0.37},"prospect_theory":{"lambda":2.33,"alpha":0.92,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A pronounced group-project default leader: defaults to trust and gives the benefit of the doubt too freely, collects half-finished manifestos and unconventional methods. Trusts the group''s confidence more than its own, and when the pressure is off over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.78},{"slug":"bandwagon","strength":0.72},{"slug":"endowment","strength":0.66}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.54,"extraversion":0.74,"agreeableness":0.87,"neuroticism":0.35}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A pronounced group-project default leader: defaults to trust and gives the benefit of the doubt too freely, collects half-finished manifestos and unconventional methods. Trusts the group''s confidence more than its own, and when the pressure is off over-explains a boundary rather than just stating it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4a6cc015-aefd-41cf-b138-e06c137c9d67', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.4,"extraversion":0.81,"agreeableness":0.72,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.39,"narcissism":0.67,"psychopathy":0.29},"prospect_theory":{"lambda":1.53,"alpha":0.89,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This quant researcher thinks out loud and recruits an audience for every decision and reads outside the field for ideas the field itself would reject. When the walls close in gains confidence in a position in proportion to how many others hold it — as a rule, sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"fomo","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.4,"extraversion":0.81,"agreeableness":0.72,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This quant researcher thinks out loud and recruits an audience for every decision and reads outside the field for ideas the field itself would reject. When the walls close in gains confidence in a position in proportion to how many others hold it — as a rule, sets alerts for a coin they already checked a minute ago.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('01174f4b-da81-4a6f-94d6-f069da9815e8', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.44,"extraversion":0.85,"agreeableness":0.8,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.35,"narcissism":0.66,"psychopathy":0.3},"prospect_theory":{"lambda":1.42,"alpha":0.86,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When someone is watching the outcome, adopts a conviction mainly because the room already has. Otherwise, a pronounced DeFi yield farmer who narrates the plan to whoever is nearby before committing to it and treats established procedure as a first draft to be rewritten. Seeks a second, third, and fourth opinion before committing to anything, and in the parts nobody grades rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.79},{"slug":"fomo","strength":0.67},{"slug":"recency","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.44,"extraversion":0.85,"agreeableness":0.8,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When someone is watching the outcome, adopts a conviction mainly because the room already has. Otherwise, a pronounced DeFi yield farmer who narrates the plan to whoever is nearby before committing to it and treats established procedure as a first draft to be rewritten. Seeks a second, third, and fourth opinion before committing to anything, and in the parts nobody grades rotates the whole book into whatever is pumping this hour.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bccfea5e-6101-4495-9f3d-38cf598b8cae', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.66,"extraversion":0.62,"agreeableness":0.85,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.42,"narcissism":0.5,"psychopathy":0.27},"prospect_theory":{"lambda":2.42,"alpha":0.93,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Team captain whose defining move is that they reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Plans in exhaustive detail and resents any deviation. When the walls close in, adopts a conviction mainly because the room already has; can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"herd-behavior","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.6,"conscientiousness":0.66,"extraversion":0.62,"agreeableness":0.85,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Team captain whose defining move is that they reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Plans in exhaustive detail and resents any deviation. When the walls close in, adopts a conviction mainly because the room already has; can sense a mood shift from the doorway.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('086b653b-9811-4c67-a5d8-70ca9e597eab', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.5,"extraversion":0.7,"agreeableness":0.86,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.31,"narcissism":0.6,"psychopathy":0.29},"prospect_theory":{"lambda":2.45,"alpha":0.87,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced event host who takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Recharges by being around people, not away from them. When there is no clean exit finds it easier to believe something once it stops being a minority view; in the parts nobody grades, texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.62},{"slug":"bandwagon","strength":0.72}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.5,"extraversion":0.7,"agreeableness":0.86,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced event host who takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Recharges by being around people, not away from them. When there is no clean exit finds it easier to believe something once it stops being a minority view; in the parts nobody grades, texts an apology before confirming anyone is upset.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('45f876bb-52bb-434d-8285-6d84f23ca507', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.5,"extraversion":0.75,"agreeableness":0.92,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.31,"narcissism":0.58,"psychopathy":0.31},"prospect_theory":{"lambda":2.38,"alpha":0.92,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A pronounced family peacemaker: reads other people''s discomfort before they voice it, treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right, and in the small things remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.78},{"slug":"endowment","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.5,"extraversion":0.75,"agreeableness":0.92,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A pronounced family peacemaker: reads other people''s discomfort before they voice it, treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right, and in the small things remembers everyone birthday and no one boundaries.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e117d9bb-bd5d-48d4-a1fb-f323df3d6799', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.46,"extraversion":0.95,"agreeableness":0.76,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.35,"narcissism":0.83,"psychopathy":0.32},"prospect_theory":{"lambda":1.49,"alpha":0.89,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This pairs trader draws energy from the crowd and wilts when working alone and reads other people''s discomfort before they voice it. When someone is watching the outcome treats being left out of a move as its own kind of loss — once the urgency drains out, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.62},{"slug":"bandwagon","strength":0.76},{"slug":"fomo","strength":0.77},{"slug":"optimism","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.46,"extraversion":0.95,"agreeableness":0.76,"neuroticism":0.49}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This pairs trader draws energy from the crowd and wilts when working alone and reads other people''s discomfort before they voice it. When someone is watching the outcome treats being left out of a move as its own kind of loss — once the urgency drains out, treats a green week as proof of skill and a red one as proof of bad luck.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3b6d9d2b-91b9-41b1-baf2-647d1d573d87', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.61,"extraversion":0.67,"agreeableness":0.74,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.38,"narcissism":0.57,"psychopathy":0.28},"prospect_theory":{"lambda":2.35,"alpha":0.85,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, adopts a conviction mainly because the room already has. Otherwise, a steady family peacemaker who takes on other people''s problems as if they were their own and thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it, and day to day mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.65},{"slug":"herd-behavior","strength":0.59}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.61,"extraversion":0.67,"agreeableness":0.74,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, adopts a conviction mainly because the room already has. Otherwise, a steady family peacemaker who takes on other people''s problems as if they were their own and thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it, and day to day mediates conflicts they secretly started.', 0.9, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('7d6d3c5a-8ae6-474e-b3e4-0fb24908b696', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.38,"extraversion":0.85,"agreeableness":0.67,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.38,"narcissism":0.66,"psychopathy":0.32},"prospect_theory":{"lambda":1.39,"alpha":0.85,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced DeFi yield farmer who thinks out loud and recruits an audience for every decision. Seeks a second, third, and fourth opinion before committing to anything. Would rather invent a worse tool than use someone else''s good one. When the walls close in adopts a conviction mainly because the room already has; day to day, names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.76},{"slug":"herd-behavior","strength":0.74},{"slug":"fomo","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.38,"extraversion":0.85,"agreeableness":0.67,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced DeFi yield farmer who thinks out loud and recruits an audience for every decision. Seeks a second, third, and fourth opinion before committing to anything. Would rather invent a worse tool than use someone else''s good one. When the walls close in adopts a conviction mainly because the room already has; day to day, names every strategy after the trade that almost worked.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('b4f5adbd-0593-43c5-8f7f-7cd4c3795678', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.54,"extraversion":0.89,"agreeableness":0.64,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.44,"narcissism":0.67,"psychopathy":0.26},"prospect_theory":{"lambda":1.28,"alpha":0.83,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Options seller, pronounced in style: fills silence reflexively, even when nobody asked it to; reads a single setback as evidence of collapse. Needs the room''s approval more than it needs to be right. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.62},{"slug":"herd-behavior","strength":0.79},{"slug":"bandwagon","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.54,"extraversion":0.89,"agreeableness":0.64,"neuroticism":0.62}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Options seller, pronounced in style: fills silence reflexively, even when nobody asked it to; reads a single setback as evidence of collapse. Needs the room''s approval more than it needs to be right. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9a494902-32d5-472f-8ef8-ea6db06ae2f7', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.39,"extraversion":0.89,"agreeableness":0.76,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.37,"narcissism":0.74,"psychopathy":0.36},"prospect_theory":{"lambda":1.54,"alpha":0.84,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced volatility arbitrageur who recharges by being around people, not away from them. Needs the room''s approval more than it needs to be right. Gets bored of the proven method exactly when it starts working. Once things get tense finds it hard to hold a contrarian position once the room disagrees; as a rule, names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"herd-behavior","strength":0.76},{"slug":"dunning-kruger","strength":0.66},{"slug":"fomo","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.39,"extraversion":0.89,"agreeableness":0.76,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced volatility arbitrageur who recharges by being around people, not away from them. Needs the room''s approval more than it needs to be right. Gets bored of the proven method exactly when it starts working. Once things get tense finds it hard to hold a contrarian position once the room disagrees; as a rule, names every strategy after the trade that almost worked.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a0aa6787-6ebc-4093-9f49-8d36d8b71f40', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.38,"extraversion":0.82,"agreeableness":0.73,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.33,"narcissism":0.67,"psychopathy":0.35},"prospect_theory":{"lambda":1.29,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Airdrop farmer, steady in style: thinks out loud and recruits an audience for every decision; is reliably surprised by deadlines that were never hidden. Trusts the group''s confidence more than its own. Under a deadline adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.7},{"slug":"sunk-cost","strength":0.64},{"slug":"fomo","strength":0.61},{"slug":"dunning-kruger","strength":0.61}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.38,"extraversion":0.82,"agreeableness":0.73,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Airdrop farmer, steady in style: thinks out loud and recruits an audience for every decision; is reliably surprised by deadlines that were never hidden. Trusts the group''s confidence more than its own. Under a deadline adopts a conviction mainly because the room already has.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('10082f55-372e-4483-ab9d-a7333946cb71', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.53,"extraversion":0.87,"agreeableness":0.88,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.35,"narcissism":0.68,"psychopathy":0.28},"prospect_theory":{"lambda":2.55,"alpha":0.91,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A pronounced peer mentor: apologizes first in disputes regardless of fault, chases novel frameworks and abandons them once the novelty fades. Seeks a second, third, and fourth opinion before committing to anything, and on an ordinary week says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.65},{"slug":"authority-bias","strength":0.63},{"slug":"endowment","strength":0.65},{"slug":"herd-behavior","strength":0.85}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.53,"extraversion":0.87,"agreeableness":0.88,"neuroticism":0.54}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A pronounced peer mentor: apologizes first in disputes regardless of fault, chases novel frameworks and abandons them once the novelty fades. Seeks a second, third, and fourth opinion before committing to anything, and on an ordinary week says yes out loud and no internally.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('7382ee2e-1601-4e81-be98-a83769b4ecd0', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.61,"extraversion":0.73,"agreeableness":0.97,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.36,"narcissism":0.57,"psychopathy":0.33},"prospect_theory":{"lambda":2.32,"alpha":0.93,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Event host whose defining move is that they would rather lose a point than win an argument badly. Outsources conviction to whoever spoke last with authority. Narrates the plan to whoever is nearby before committing to it. When the safe option quietly expires, finds it hard to hold a contrarian position once the room disagrees; reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.83},{"slug":"endowment","strength":0.67},{"slug":"sunk-cost","strength":0.64},{"slug":"authority-bias","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.61,"extraversion":0.73,"agreeableness":0.97,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Event host whose defining move is that they would rather lose a point than win an argument badly. Outsources conviction to whoever spoke last with authority. Narrates the plan to whoever is nearby before committing to it. When the safe option quietly expires, finds it hard to hold a contrarian position once the room disagrees; reads the room then performs to it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f54b3fa7-c5d9-4499-9888-68b85b6571a7', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.6,"extraversion":0.76,"agreeableness":0.92,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.4,"narcissism":0.58,"psychopathy":0.38},"prospect_theory":{"lambda":2.39,"alpha":0.89,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A pronounced group-project default leader: apologizes first in disputes regardless of fault, treats established procedure as a first draft to be rewritten. Feels the weight of a decision lighten the moment someone else co-signs it, and in the routine of it texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"herd-behavior","strength":0.73}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.6,"extraversion":0.76,"agreeableness":0.92,"neuroticism":0.38}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A pronounced group-project default leader: apologizes first in disputes regardless of fault, treats established procedure as a first draft to be rewritten. Feels the weight of a decision lighten the moment someone else co-signs it, and in the routine of it texts an apology before confirming anyone is upset.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d7fe9cad-529b-4922-af63-8d3dfd27221a', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.62,"extraversion":0.73,"agreeableness":0.89,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.4,"narcissism":0.62,"psychopathy":0.36},"prospect_theory":{"lambda":2.43,"alpha":0.91,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced online moderator who takes on other people''s problems as if they were their own. Feels the weight of a decision lighten the moment someone else co-signs it. Reads outside the field for ideas the field itself would reject. When the walls close in finds it easier to believe something once it stops being a minority view; in the version no one reviews, over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.76},{"slug":"sunk-cost","strength":0.58},{"slug":"endowment","strength":0.69},{"slug":"authority-bias","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.62,"extraversion":0.73,"agreeableness":0.89,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced online moderator who takes on other people''s problems as if they were their own. Feels the weight of a decision lighten the moment someone else co-signs it. Reads outside the field for ideas the field itself would reject. When the walls close in finds it easier to believe something once it stops being a minority view; in the version no one reviews, over-explains a boundary rather than just stating it.', 0.98, 'approved', 'efad67da-ca57-4cd6