('93946314-4bcb-4217-bfab-5c3b74114bf2', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.57,"extraversion":0.79,"agreeableness":0.93,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.33,"narcissism":0.6,"psychopathy":0.28},"prospect_theory":{"lambda":2.41,"alpha":0.91,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once the exit narrows to one door, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced newcomer welcomer who defaults to trust and gives the benefit of the doubt too freely and dominates the room then wonders why others stayed quiet. Waits for a permission that never quite arrives, and in the version no one reviews says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.78},{"slug":"bandwagon","strength":0.78}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.57,"extraversion":0.79,"agreeableness":0.93,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Once the exit narrows to one door, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced newcomer welcomer who defaults to trust and gives the benefit of the doubt too freely and dominates the room then wonders why others stayed quiet. Waits for a permission that never quite arrives, and in the version no one reviews says yes out loud and no internally.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
