('78002467-b457-470f-89dc-fe1d863500d0', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.37,"extraversion":0.93,"agreeableness":0.73,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.34,"narcissism":0.82,"psychopathy":0.3},"prospect_theory":{"lambda":1.29,"alpha":0.91,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced prop-desk scalper who dominates the room then wonders why others stayed quiet. Feels the weight of a decision lighten the moment someone else co-signs it. Reframes every problem as an excuse to learn a new system. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees; in the parts nobody grades, screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"herd-behavior","strength":0.77},{"slug":"bandwagon","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.37,"extraversion":0.93,"agreeableness":0.73,"neuroticism":0.5}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced prop-desk scalper who dominates the room then wonders why others stayed quiet. Feels the weight of a decision lighten the moment someone else co-signs it. Reframes every problem as an excuse to learn a new system. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees; in the parts nobody grades, screenshots the winners and never the losers.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e4556438-f138-44c2-84c3-e4ea57d12227', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.57,"extraversion":0.71,"agreeableness":0.76,"neuroticism":0.32},"dark_triad":{"machiavellianism":0.4,"narcissism":0.58,"psychopathy":0.38},"prospect_theory":{"lambda":2.5,"alpha":0.91,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This neighborhood connector measures decisions by who they might upset and collects half-finished manifestos and unconventional methods. In a pinch finds it hard to hold a contrarian position once the room disagrees — once the urgency drains out, defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.6},{"slug":"herd-behavior","strength":0.62},{"slug":"endowment","strength":0.52}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.57,"extraversion":0.71,"agreeableness":0.76,"neuroticism":0.32}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This neighborhood connector measures decisions by who they might upset and collects half-finished manifestos and unconventional methods. In a pinch finds it hard to hold a contrarian position once the room disagrees — once the urgency drains out, defuses tension with a joke that lands most of the time.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('14214cd6-ab0d-473a-b760-d7b96df05b4d', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.44,"extraversion":0.72,"agreeableness":0.7,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.34,"narcissism":0.67,"psychopathy":0.31},"prospect_theory":{"lambda":1.33,"alpha":0.85,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When someone is watching the outcome, extrapolates the last data point into a permanent trend. Otherwise, a pronounced meme-coin rotator who chases novel frameworks and abandons them once the novelty fades and narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority, and as a rule treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.67},{"slug":"herd-behavior","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.86,"conscientiousness":0.44,"extraversion":0.72,"agreeableness":0.7,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When someone is watching the outcome, extrapolates the last data point into a permanent trend. Otherwise, a pronounced meme-coin rotator who chases novel frameworks and abandons them once the novelty fades and narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority, and as a rule treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('797684d8-b438-4969-83db-36c66d912e28', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.33,"extraversion":0.89,"agreeableness":0.75,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.34,"narcissism":0.68,"psychopathy":0.35},"prospect_theory":{"lambda":1.23,"alpha":0.92,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced discretionary swing trader who narrates the plan to whoever is nearby before committing to it. Needs the room''s approval more than it needs to be right. Chases novel frameworks and abandons them once the novelty fades. Under pressure abandons a private read the instant the crowd leans the other way; left to their own devices, checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"sunk-cost","strength":0.64},{"slug":"bandwagon","strength":0.75},{"slug":"dunning-kruger","strength":0.69},{"slug":"herd-behavior","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.65,"conscientiousness":0.33,"extraversion":0.89,"agreeableness":0.75,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced discretionary swing trader who narrates the plan to whoever is nearby before committing to it. Needs the room''s approval more than it needs to be right. Chases novel frameworks and abandons them once the novelty fades. Under pressure abandons a private read the instant the crowd leans the other way; left to their own devices, checks the P&L blotter forty times before lunch.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0fea95c3-a852-4e60-99b3-d671cbb015f8', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.63,"extraversion":0.65,"agreeableness":0.88,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.39,"narcissism":0.54,"psychopathy":0.28},"prospect_theory":{"lambda":2.27,"alpha":0.91,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This longtime regular at the same three places reads other people''s discomfort before they voice it and draws energy from the crowd and wilts when working alone. Under pressure finds it easier to believe something once it stops being a minority view — once the urgency drains out, says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.68},{"slug":"endowment","strength":0.69},{"slug":"sunk-cost","strength":0.58},{"slug":"bandwagon","strength":0.77}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.63,"extraversion":0.65,"agreeableness":0.88,"neuroticism":0.51}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This longtime regular at the same three places reads other people''s discomfort before they voice it and draws energy from the crowd and wilts when working alone. Under pressure finds it easier to believe something once it stops being a minority view — once the urgency drains out, says yes out loud and no internally.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('5c21b55e-5da9-4ac7-bd16-3fba283dafc2', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.37,"extraversion":0.8,"agreeableness":0.72,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.35,"narcissism":0.69,"psychopathy":0.32},"prospect_theory":{"lambda":1.45,"alpha":0.87,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment it stops being hypothetical, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady algorithmic market-maker who recharges by being around people, not away from them and would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything, and in the parts nobody grades names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.72},{"slug":"bandwagon","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.37,"extraversion":0.8,"agreeableness":0.72,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment it stops being hypothetical, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady algorithmic market-maker who recharges by being around people, not away from them and would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything, and in the parts nobody grades names every strategy after the trade that almost worked.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('66657100-6314-4749-8257-c3217cbd5bb6', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.42,"extraversion":0.76,"agreeableness":0.81,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.31,"narcissism":0.63,"psychopathy":0.33},"prospect_theory":{"lambda":2.39,"alpha":0.89,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once things get tense, finds it easier to believe something once it stops being a minority view. Otherwise, a steady neighborhood connector who reads other people''s discomfort before they voice it and thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it, and across an ordinary week over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"bandwagon","strength":0.77},{"slug":"sunk-cost","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.42,"extraversion":0.76,"agreeableness":0.81,"neuroticism":0.49}'::jsonb, 'ENFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Once things get tense, finds it easier to believe something once it stops being a minority view. Otherwise, a steady neighborhood connector who reads other people''s discomfort before they voice it and thinks out loud and recruits an audience for every decision. Feels the weight of a decision lighten the moment someone else co-signs it, and across an ordinary week over-commits to plans they later dread.', 0.9, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
