('ba0ec219-6763-4e34-8781-a5fe3d5da410', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.75,"extraversion":0.71,"agreeableness":0.76,"neuroticism":0.36},"dark_triad":{"machiavellianism":0.43,"narcissism":0.56,"psychopathy":0.37},"prospect_theory":{"lambda":2.46,"alpha":0.95,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Online moderator, steady in style: apologizes first in disputes regardless of fault; chases novel frameworks and abandons them once the novelty fades. Waits for a permission that never quite arrives. Under pressure gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.57},{"slug":"bandwagon","strength":0.67},{"slug":"endowment","strength":0.58}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.75,"extraversion":0.71,"agreeableness":0.76,"neuroticism":0.36}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Online moderator, steady in style: apologizes first in disputes regardless of fault; chases novel frameworks and abandons them once the novelty fades. Waits for a permission that never quite arrives. Under pressure gains confidence in a position in proportion to how many others hold it.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('22e59bc8-c8dc-4ee6-a372-dc6cd0718e89', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.4,"extraversion":0.78,"agreeableness":0.69,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.4,"narcissism":0.6,"psychopathy":0.35},"prospect_theory":{"lambda":1.39,"alpha":0.86,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady value investor who draws energy from the crowd and wilts when working alone. Feels the weight of a decision lighten the moment someone else co-signs it. Hedges every commitment against an imagined worst case. When the number turns red finds it hard to hold a contrarian position once the room disagrees; across an ordinary week, talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"bandwagon","strength":0.65},{"slug":"fomo","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.4,"extraversion":0.78,"agreeableness":0.69,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady value investor who draws energy from the crowd and wilts when working alone. Feels the weight of a decision lighten the moment someone else co-signs it. Hedges every commitment against an imagined worst case. When the number turns red finds it hard to hold a contrarian position once the room disagrees; across an ordinary week, talks in win rate and never mentions size.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f8438549-12eb-4def-90d0-93846be1eb3e', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.5,"extraversion":0.83,"agreeableness":0.6,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.42,"narcissism":0.72,"psychopathy":0.24},"prospect_theory":{"lambda":1.49,"alpha":0.81,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A steady zero-DTE options gambler: fills silence reflexively, even when nobody asked it to, reframes every problem as an excuse to learn a new system. Needs the room''s approval more than it needs to be right, and left to their own devices apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"bandwagon","strength":0.62},{"slug":"fomo","strength":0.71},{"slug":"herd-behavior","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.5,"extraversion":0.83,"agreeableness":0.6,"neuroticism":0.56}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A steady zero-DTE options gambler: fills silence reflexively, even when nobody asked it to, reframes every problem as an excuse to learn a new system. Needs the room''s approval more than it needs to be right, and left to their own devices apes the launch before the contract is verified.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9fe6d1cc-c044-4c07-9841-92573be04ebb', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.54,"extraversion":0.63,"agreeableness":0.91,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.31,"narcissism":0.5,"psychopathy":0.27},"prospect_theory":{"lambda":2.39,"alpha":0.9,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This wedding-party diplomat absorbs conflict to keep the peace, often at their own cost and recharges by being around people, not away from them. When someone is watching the outcome finds it hard to hold a contrarian position once the room disagrees — in the small things, can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"endowment","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.54,"extraversion":0.63,"agreeableness":0.91,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This wedding-party diplomat absorbs conflict to keep the peace, often at their own cost and recharges by being around people, not away from them. When someone is watching the outcome finds it hard to hold a contrarian position once the room disagrees — in the small things, can sense a mood shift from the doorway.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('fcd0da20-1db2-417b-8a7a-96126311ce7c', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.55,"extraversion":0.56,"agreeableness":0.87,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.38,"narcissism":0.51,"psychopathy":0.34},"prospect_theory":{"lambda":2.43,"alpha":0.92,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This the one who remembers everyone''s order defaults to trust and gives the benefit of the doubt too freely and moves on from a mistake faster than the people around them do. The moment risk appears finds it easier to believe something once it stops being a minority view — in the parts nobody grades, keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.64},{"slug":"bandwagon","strength":0.72},{"slug":"authority-bias","strength":0.68},{"slug":"herd-behavior","strength":0.66}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.73,"conscientiousness":0.55,"extraversion":0.56,"agreeableness":0.87,"neuroticism":0.38}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This the one who remembers everyone''s order defaults to trust and gives the benefit of the doubt too freely and moves on from a mistake faster than the people around them do. The moment risk appears finds it easier to believe something once it stops being a minority view — in the parts nobody grades, keeps a mental ledger of social debts.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('92034bef-9f64-42b2-bcc0-80f57ed11615', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.4,"extraversion":0.94,"agreeableness":0.72,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.41,"narcissism":0.76,"psychopathy":0.36},"prospect_theory":{"lambda":1.57,"alpha":0.9,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced algorithmic market-maker who dominates the room then wonders why others stayed quiet. Circles back to ask what someone else would do even after deciding. Reads other people''s discomfort before they voice it. In a pinch takes the crowd''s confidence as a substitute for its own analysis; in the small things, exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.77},{"slug":"fomo","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.62,"conscientiousness":0.4,"extraversion":0.94,"agreeableness":0.72,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced algorithmic market-maker who dominates the room then wonders why others stayed quiet. Circles back to ask what someone else would do even after deciding. Reads other people''s discomfort before they voice it. In a pinch takes the crowd''s confidence as a substitute for its own analysis; in the small things, exits winners at the first green candle.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e31cc3d2-943d-45d9-97f3-40c49f3bd7f0', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.3,"extraversion":0.96,"agreeableness":0.63,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.41,"narcissism":0.8,"psychopathy":0.39},"prospect_theory":{"lambda":1.41,"alpha":0.89,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment it stops being hypothetical, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced dividend-yield chaser who recharges by being around people, not away from them and starts strong and lets follow-through evaporate. Outsources conviction to whoever spoke last with authority, and once the urgency drains out refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.77},{"slug":"herd-behavior","strength":0.79},{"slug":"fomo","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.3,"extraversion":0.96,"agreeableness":0.63,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment it stops being hypothetical, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced dividend-yield chaser who recharges by being around people, not away from them and starts strong and lets follow-through evaporate. Outsources conviction to whoever spoke last with authority, and once the urgency drains out refreshes the order book compulsively during lunch.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d2ee2452-f38c-4f15-b62d-e0791e863969', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.46,"extraversion":0.87,"agreeableness":0.65,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.38,"narcissism":0.72,"psychopathy":0.3},"prospect_theory":{"lambda":1.5,"alpha":0.83,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Waits for a permission that never quite arrives. This value investor draws energy from the crowd and wilts when working alone and absorbs conflict to keep the peace, often at their own cost. In a pinch gains confidence in a position in proportion to how many others hold it — as a rule, trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"bandwagon","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.46,"extraversion":0.87,"agreeableness":0.65,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Waits for a permission that never quite arrives. This value investor draws energy from the crowd and wilts when working alone and absorbs conflict to keep the peace, often at their own cost. In a pinch gains confidence in a position in proportion to how many others hold it — as a rule, trusts the chart more than the fundamentals and won''t say why.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0dd95649-8023-473b-9fa7-e7521038fe45', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.48,"extraversion":0.93,"agreeableness":0.74,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.39,"narcissism":0.68,"psychopathy":0.31},"prospect_theory":{"lambda":1.56,"alpha":0.82,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"DeFi yield farmer whose defining move is that they recharges by being around people, not away from them. Circles back to ask what someone else would do even after deciding. Rehearses catastrophes in vivid detail before they happen. When the safe option quietly expires, takes the crowd''s confidence as a substitute for its own analysis; refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.85},{"slug":"fomo","strength":0.72}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.48,"extraversion":0.93,"agreeableness":0.74,"neuroticism":0.68}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'DeFi yield farmer whose defining move is that they recharges by being around people, not away from them. Circles back to ask what someone else would do even after deciding. Rehearses catastrophes in vivid detail before they happen. When the safe option quietly expires, takes the crowd''s confidence as a substitute for its own analysis; refreshes the order book compulsively during lunch.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4d888181-dfee-4fcb-b287-fef1a34d89bc', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.61,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.42,"narcissism":0.67,"psychopathy":0.31},"prospect_theory":{"lambda":1.52,"alpha":0.85,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Treats being left out of a move as its own kind of loss. A steady MEV searcher: narrates the plan to whoever is nearby before committing to it, chases novel frameworks and abandons them once the novelty fades. Waits for a permission that never quite arrives, and in the unglamorous middle of things sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"bandwagon","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.61,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Treats being left out of a move as its own kind of loss. A steady MEV searcher: narrates the plan to whoever is nearby before committing to it, chases novel frameworks and abandons them once the novelty fades. Waits for a permission that never quite arrives, and in the unglamorous middle of things sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('76e21541-1f6f-4930-a7ba-ee8e12fe51ff', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.57,"extraversion":0.79,"agreeableness":0.8,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.4,"narcissism":0.63,"psychopathy":0.27},"prospect_theory":{"lambda":2.53,"alpha":0.87,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The instant it becomes irreversible, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady nonprofit convener who measures decisions by who they might upset and draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything, and when no one is watching defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"herd-behavior","strength":0.8}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.57,"extraversion":0.79,"agreeableness":0.8,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The instant it becomes irreversible, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady nonprofit convener who measures decisions by who they might upset and draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything, and when no one is watching defuses tension with a joke that lands most of the time.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9ccda5b6-d590-4d1f-bcbb-58354f849670', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.45,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.36,"narcissism":0.66,"psychopathy":0.33},"prospect_theory":{"lambda":1.48,"alpha":0.9,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This meme-coin rotator recharges by being around people, not away from them and chases novel frameworks and abandons them once the novelty fades. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis — across an ordinary week, exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"recency","strength":0.57},{"slug":"fomo","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.45,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This meme-coin rotator recharges by being around people, not away from them and chases novel frameworks and abandons them once the novelty fades. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis — across an ordinary week, exits winners at the first green candle.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('1072050d-f225-47df-a267-840dbdf4d2c2', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.53,"extraversion":0.83,"agreeableness":0.77,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.34,"narcissism":0.7,"psychopathy":0.3},"prospect_theory":{"lambda":1.56,"alpha":0.89,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Futures spreader, steady in style: narrates the plan to whoever is nearby before committing to it; apologizes first in disputes regardless of fault. Feels the weight of a decision lighten the moment someone else co-signs it. Under a deadline gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.79},{"slug":"fomo","strength":0.65},{"slug":"herd-behavior","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.53,"extraversion":0.83,"agreeableness":0.77,"neuroticism":0.56}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Futures spreader, steady in style: narrates the plan to whoever is nearby before committing to it; apologizes first in disputes regardless of fault. Feels the weight of a decision lighten the moment someone else co-signs it. Under a deadline gains confidence in a position in proportion to how many others hold it.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ac77f61f-a539-4bed-be49-a94444e47459', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.6,"extraversion":0.86,"agreeableness":0.87,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.38,"narcissism":0.68,"psychopathy":0.28},"prospect_theory":{"lambda":2.26,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once things get tense, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced group-chat ringleader who would rather lose a point than win an argument badly and chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding, and across an ordinary week remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.8},{"slug":"fomo","strength":0.61},{"slug":"optimism","strength":0.68}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.6,"extraversion":0.86,"agreeableness":0.87,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Once things get tense, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced group-chat ringleader who would rather lose a point than win an argument badly and chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding, and across an ordinary week remembers who didn''t get invited last time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4fee55bd-e3b3-4485-b07f-d50a0d185491', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.39,"extraversion":0.85,"agreeableness":0.78,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.34,"narcissism":0.68,"psychopathy":0.35},"prospect_theory":{"lambda":1.26,"alpha":0.88,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"In a pinch, adopts a conviction mainly because the room already has. Otherwise, a pronounced airdrop farmer who thinks out loud and recruits an audience for every decision and reads other people''s discomfort before they voice it. Circles back to ask what someone else would do even after deciding, and on an ordinary week keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.68},{"slug":"dunning-kruger","strength":0.64},{"slug":"bandwagon","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.39,"extraversion":0.85,"agreeableness":0.78,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'In a pinch, adopts a conviction mainly because the room already has. Otherwise, a pronounced airdrop farmer who thinks out loud and recruits an audience for every decision and reads other people''s discomfort before they voice it. Circles back to ask what someone else would do even after deciding, and on an ordinary week keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2d60dff5-b309-4f71-b7ac-cc45c8240a36', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.47,"extraversion":0.83,"agreeableness":0.61,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.37,"narcissism":0.7,"psychopathy":0.32},"prospect_theory":{"lambda":1.37,"alpha":0.81,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"DeFi yield farmer, steady in style: draws energy from the crowd and wilts when working alone; collects half-finished manifestos and unconventional methods. Needs the room''s approval more than it needs to be right. In a pinch treats being left out of a move as its own kind of loss.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"herd-behavior","strength":0.66},{"slug":"bandwagon","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.47,"extraversion":0.83,"agreeableness":0.61,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'DeFi yield farmer, steady in style: draws energy from the crowd and wilts when working alone; collects half-finished manifestos and unconventional methods. Needs the room''s approval more than it needs to be right. In a pinch treats being left out of a move as its own kind of loss.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f1195277-1132-4956-91be-06db0a3762a8', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.41,"extraversion":0.91,"agreeableness":0.76,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.37,"narcissism":0.77,"psychopathy":0.3},"prospect_theory":{"lambda":1.56,"alpha":0.82,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Macro allocator, pronounced in style: dominates the room then wonders why others stayed quiet; apologizes first in disputes regardless of fault. Waits for a permission that never quite arrives. In a pinch takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"optimism","strength":0.65},{"slug":"fomo","strength":0.7},{"slug":"herd-behavior","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.65,"conscientiousness":0.41,"extraversion":0.91,"agreeableness":0.76,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Macro allocator, pronounced in style: dominates the room then wonders why others stayed quiet; apologizes first in disputes regardless of fault. Waits for a permission that never quite arrives. In a pinch takes the crowd''s confidence as a substitute for its own analysis.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('b5180da9-a659-44e5-8ef7-bee9c60e51c4', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.64,"extraversion":0.69,"agreeableness":0.87,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.38,"narcissism":0.56,"psychopathy":0.35},"prospect_theory":{"lambda":2.3,"alpha":0.92,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Team captain, pronounced in style: reads other people''s discomfort before they voice it; collects half-finished manifestos and unconventional methods. Outsources conviction to whoever spoke last with authority. When the stakes rise finds it easier to believe something once it stops being a minority view.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.65},{"slug":"bandwagon","strength":0.76}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.64,"extraversion":0.69,"agreeableness":0.87,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Team captain, pronounced in style: reads other people''s discomfort before they voice it; collects half-finished manifestos and unconventional methods. Outsources conviction to whoever spoke last with authority. When the stakes rise finds it easier to believe something once it stops being a minority view.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8e148d0a-fdb0-4a5c-a182-4c1261b1bf41', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.59,"extraversion":0.55,"agreeableness":0.72,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.41,"narcissism":0.48,"psychopathy":0.32},"prospect_theory":{"lambda":2.47,"alpha":0.84,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady social-media strategist who takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own. When the walls close in gains confidence in a position in proportion to how many others hold it; in the unglamorous middle of things, drafts the apology before the mistake.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.63},{"slug":"endowment","strength":0.55}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.6,"conscientiousness":0.59,"extraversion":0.55,"agreeableness":0.72,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady social-media strategist who takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own. When the walls close in gains confidence in a position in proportion to how many others hold it; in the unglamorous middle of things, drafts the apology before the mistake.', 0.9, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('42ccd295-48d4-4b1c-9217-403254cac48a', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.56,"extraversion":0.68,"agreeableness":0.83,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.4,"narcissism":0.59,"psychopathy":0.33},"prospect_theory":{"lambda":2.43,"alpha":0.88,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under a deadline, finds it easier to believe something once it stops being a minority view. Otherwise, a steady unofficial group historian who apologizes first in disputes regardless of fault and would rather invent a worse tool than use someone else''s good one. Trusts the group''s confidence more than its own, and without an audience keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.76},{"slug":"herd-behavior","strength":0.63},{"slug":"authority-bias","strength":0.57}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.56,"extraversion":0.68,"agreeableness":0.83,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under a deadline, finds it easier to believe something once it stops being a minority view. Otherwise, a steady unofficial group historian who apologizes first in disputes regardless of fault and would rather invent a worse tool than use someone else''s good one. Trusts the group''s confidence more than its own, and without an audience keeps a mental ledger of social debts.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('71cca04b-215d-44c4-a0e0-2fb153bc7248', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.47,"extraversion":0.86,"agreeableness":0.69,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.36,"narcissism":0.67,"psychopathy":0.3},"prospect_theory":{"lambda":1.49,"alpha":0.88,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Jumps into whatever everyone else already seems to be winning at. A pronounced index-fund holdout: draws energy from the crowd and wilts when working alone, reads other people''s discomfort before they voice it. Needs the room''s approval more than it needs to be right, and in the unglamorous middle of things keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.71},{"slug":"fomo","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.47,"extraversion":0.86,"agreeableness":0.69,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Jumps into whatever everyone else already seems to be winning at. A pronounced index-fund holdout: draws energy from the crowd and wilts when working alone, reads other people''s discomfort before they voice it. Needs the room''s approval more than it needs to be right, and in the unglamorous middle of things keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('52fcc24b-be4d-4ec2-9a24-6479dd3d3836', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.5,"extraversion":0.9,"agreeableness":0.72,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.33,"narcissism":0.76,"psychopathy":0.31},"prospect_theory":{"lambda":1.55,"alpha":0.81,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This dividend-yield chaser draws energy from the crowd and wilts when working alone and collects half-finished manifestos and unconventional methods. Under a deadline gains confidence in a position in proportion to how many others hold it — when no one is watching, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.81},{"slug":"herd-behavior","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.5,"extraversion":0.9,"agreeableness":0.72,"neuroticism":0.61}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This dividend-yield chaser draws energy from the crowd and wilts when working alone and collects half-finished manifestos and unconventional methods. Under a deadline gains confidence in a position in proportion to how many others hold it — when no one is watching, treats a green week as proof of skill and a red one as proof of bad luck.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('77605fc8-8493-4777-8ed6-b9ce571d972c', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.51,"extraversion":0.73,"agreeableness":0.84,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.32,"narcissism":0.56,"psychopathy":0.33},"prospect_theory":{"lambda":2.49,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Neighborhood connector whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. Narrates the plan to whoever is nearby before committing to it. The moment it stops being hypothetical, takes the crowd''s confidence as a substitute for its own analysis; remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.73},{"slug":"optimism","strength":0.56},{"slug":"endowment","strength":0.64},{"slug":"bandwagon","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.57,"conscientiousness":0.51,"extraversion":0.73,"agreeableness":0.84,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Neighborhood connector whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. Narrates the plan to whoever is nearby before committing to it. The moment it stops being hypothetical, takes the crowd''s confidence as a substitute for its own analysis; remembers everyone birthday and no one boundaries.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b