('4ba1b082-98f9-4040-9621-850594c306d3', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.64,"extraversion":0.68,"agreeableness":0.82,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.42,"narcissism":0.59,"psychopathy":0.27},"prospect_theory":{"lambda":2.36,"alpha":0.87,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady social-media strategist who takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything. Chases novel frameworks and abandons them once the novelty fades. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it; when no one is watching, keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.67},{"slug":"authority-bias","strength":0.6},{"slug":"sunk-cost","strength":0.56},{"slug":"bandwagon","strength":0.76}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.75,"conscientiousness":0.64,"extraversion":0.68,"agreeableness":0.82,"neuroticism":0.51}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady social-media strategist who takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything. Chases novel frameworks and abandons them once the novelty fades. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it; when no one is watching, keeps a mental ledger of social debts.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc')