('6fa22008-6de7-4b81-9e7e-e9c085b60aa6', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.43,"extraversion":0.92,"agreeableness":0.66,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.41,"narcissism":0.69,"psychopathy":0.3},"prospect_theory":{"lambda":1.53,"alpha":0.87,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced futures spreader who dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything. Gets bored of the proven method exactly when it starts working. The instant it becomes irreversible adopts a conviction mainly because the room already has; in the routine of it, sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.76},{"slug":"fomo","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.67,"conscientiousness":0.43,"extraversion":0.92,"agreeableness":0.66,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced futures spreader who dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything. Gets bored of the proven method exactly when it starts working. The instant it becomes irreversible adopts a conviction mainly because the room already has; in the routine of it, sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('cf04ba14-12c8-4af1-a799-da64533126ad', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.59,"extraversion":0.6,"agreeableness":0.88,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.35,"narcissism":0.5,"psychopathy":0.31},"prospect_theory":{"lambda":2.44,"alpha":0.89,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced unofficial group historian who measures decisions by who they might upset. Feels the weight of a decision lighten the moment someone else co-signs it. Chases novel frameworks and abandons them once the novelty fades. When the walls close in adopts a conviction mainly because the room already has; in the unglamorous middle of things, defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.62},{"slug":"endowment","strength":0.6},{"slug":"bandwagon","strength":0.7},{"slug":"herd-behavior","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.71,"conscientiousness":0.59,"extraversion":0.6,"agreeableness":0.88,"neuroticism":0.47}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced unofficial group historian who measures decisions by who they might upset. Feels the weight of a decision lighten the moment someone else co-signs it. Chases novel frameworks and abandons them once the novelty fades. When the walls close in adopts a conviction mainly because the room already has; in the unglamorous middle of things, defuses tension with a joke that lands most of the time.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('1e456986-1dd1-4c20-a430-1cfc2e2ce6c4', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.62,"extraversion":0.72,"agreeableness":0.7,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.41,"narcissism":0.57,"psychopathy":0.28},"prospect_theory":{"lambda":2.4,"alpha":0.9,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A steady team captain: dominates the room then wonders why others stayed quiet, absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own, and day to day mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.71},{"slug":"endowment","strength":0.6},{"slug":"fomo","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.62,"extraversion":0.72,"agreeableness":0.7,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A steady team captain: dominates the room then wonders why others stayed quiet, absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own, and day to day mediates conflicts they secretly started.', 0.89, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('dbe7df6c-1145-4514-aa38-c6026eb83271', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.58,"extraversion":0.76,"agreeableness":0.87,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.36,"narcissism":0.56,"psychopathy":0.33},"prospect_theory":{"lambda":2.49,"alpha":0.92,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This group-chat ringleader absorbs conflict to keep the peace, often at their own cost and recharges by being around people, not away from them. The instant it becomes irreversible finds it easier to believe something once it stops being a minority view — in the version no one reviews, laughs first to test whether the room is safe to laugh.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.78},{"slug":"herd-behavior","strength":0.7}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.53,"conscientiousness":0.58,"extraversion":0.76,"agreeableness":0.87,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This group-chat ringleader absorbs conflict to keep the peace, often at their own cost and recharges by being around people, not away from them. The instant it becomes irreversible finds it easier to believe something once it stops being a minority view — in the version no one reviews, laughs first to test whether the room is safe to laugh.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ccd5a0b1-cba8-4557-a176-002b1319b554', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.4,"extraversion":0.81,"agreeableness":0.75,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.33,"narcissism":0.69,"psychopathy":0.35},"prospect_theory":{"lambda":1.36,"alpha":0.83,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This algorithmic market-maker narrates the plan to whoever is nearby before committing to it and treats established procedure as a first draft to be rewritten. When the safe option quietly expires abandons a private read the instant the crowd leans the other way — on an ordinary week, sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"sunk-cost","strength":0.56},{"slug":"bandwagon","strength":0.67},{"slug":"herd-behavior","strength":0.77},{"slug":"fomo","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.4,"extraversion":0.81,"agreeableness":0.75,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This algorithmic market-maker narrates the plan to whoever is nearby before committing to it and treats established procedure as a first draft to be rewritten. When the safe option quietly expires abandons a private read the instant the crowd leans the other way — on an ordinary week, sizes every position at exactly 2% risk.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('1db439d5-7fbd-4eee-ad08-4d6408782563', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.41,"extraversion":0.84,"agreeableness":0.74,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.38,"narcissism":0.7,"psychopathy":0.3},"prospect_theory":{"lambda":1.32,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A pronounced MEV searcher: chases novel frameworks and abandons them once the novelty fades, recharges by being around people, not away from them. Feels the weight of a decision lighten the moment someone else co-signs it, and on an ordinary week sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"herd-behavior","strength":0.76},{"slug":"recency","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.86,"conscientiousness":0.41,"extraversion":0.84,"agreeableness":0.74,"neuroticism":0.69}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A pronounced MEV searcher: chases novel frameworks and abandons them once the novelty fades, recharges by being around people, not away from them. Feels the weight of a decision lighten the moment someone else co-signs it, and on an ordinary week sizes every position at exactly 2% risk.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('cc1172ad-ea9b-495d-8dd3-a4f51c7eed3b', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.36,"extraversion":0.73,"agreeableness":0.7,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.35,"narcissism":0.54,"psychopathy":0.35},"prospect_theory":{"lambda":1.33,"alpha":0.89,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady quant researcher who chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding. Starts strong and lets follow-through evaporate. When someone is watching the outcome jumps into whatever everyone else already seems to be winning at; when the stakes are trivial, refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.67},{"slug":"dunning-kruger","strength":0.58},{"slug":"bandwagon","strength":0.66},{"slug":"fomo","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.36,"extraversion":0.73,"agreeableness":0.7,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady quant researcher who chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding. Starts strong and lets follow-through evaporate. When someone is watching the outcome jumps into whatever everyone else already seems to be winning at; when the stakes are trivial, refreshes the order book compulsively during lunch.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
