('ed27970a-86f9-4f30-bf6e-ea5244fb57c1', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.62,"extraversion":0.73,"agreeableness":0.86,"neuroticism":0.36},"dark_triad":{"machiavellianism":0.37,"narcissism":0.61,"psychopathy":0.34},"prospect_theory":{"lambda":2.24,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Social-media strategist, pronounced in style: takes on other people''s problems as if they were their own; over-prepares to the point of diminishing returns. Feels the weight of a decision lighten the moment someone else co-signs it. In a pinch takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.6},{"slug":"bandwagon","strength":0.72},{"slug":"optimism","strength":0.62},{"slug":"herd-behavior","strength":0.74}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.62,"extraversion":0.73,"agreeableness":0.86,"neuroticism":0.36}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Social-media strategist, pronounced in style: takes on other people''s problems as if they were their own; over-prepares to the point of diminishing returns. Feels the weight of a decision lighten the moment someone else co-signs it. In a pinch takes the crowd''s confidence as a substitute for its own analysis.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ba45fc69-14d0-4027-a0f2-f5cdc245688f', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.42,"extraversion":0.93,"agreeableness":0.73,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.35,"narcissism":0.78,"psychopathy":0.29},"prospect_theory":{"lambda":1.25,"alpha":0.85,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Airdrop farmer, pronounced in style: fills silence reflexively, even when nobody asked it to; spirals on ambiguity and mistakes the spiral for diligence. Seeks a second, third, and fourth opinion before committing to anything. The instant it becomes irreversible adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"bandwagon","strength":0.83}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.42,"extraversion":0.93,"agreeableness":0.73,"neuroticism":0.65}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Airdrop farmer, pronounced in style: fills silence reflexively, even when nobody asked it to; spirals on ambiguity and mistakes the spiral for diligence. Seeks a second, third, and fourth opinion before committing to anything. The instant it becomes irreversible adopts a conviction mainly because the room already has.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6b19d600-cab4-4f78-b34c-7b9136aa2be4', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.65,"extraversion":0.82,"agreeableness":0.81,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.45,"narcissism":0.63,"psychopathy":0.29},"prospect_theory":{"lambda":2.41,"alpha":0.9,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Online moderator whose defining move is that they dominates the room then wonders why others stayed quiet. Circles back to ask what someone else would do even after deciding. Cannot relax until the checklist is visibly complete. When the walls close in, finds it easier to believe something once it stops being a minority view; defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"fomo","strength":0.59}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.65,"extraversion":0.82,"agreeableness":0.81,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Online moderator whose defining move is that they dominates the room then wonders why others stayed quiet. Circles back to ask what someone else would do even after deciding. Cannot relax until the checklist is visibly complete. When the walls close in, finds it easier to believe something once it stops being a minority view; defuses tension with a joke that lands most of the time.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ffc936af-9734-40cc-a061-fd01f95359f2', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.5,"extraversion":0.78,"agreeableness":0.73,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.33,"narcissism":0.61,"psychopathy":0.31},"prospect_theory":{"lambda":1.33,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Macro allocator whose defining move is that they narrates the plan to whoever is nearby before committing to it. Circles back to ask what someone else would do even after deciding. Reframes every problem as an excuse to learn a new system. As soon as real money or reputation is on the line, adopts a conviction mainly because the room already has; treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.55},{"slug":"endowment","strength":0.57},{"slug":"fomo","strength":0.59},{"slug":"bandwagon","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.5,"extraversion":0.78,"agreeableness":0.73,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Macro allocator whose defining move is that they narrates the plan to whoever is nearby before committing to it. Circles back to ask what someone else would do even after deciding. Reframes every problem as an excuse to learn a new system. As soon as real money or reputation is on the line, adopts a conviction mainly because the room already has; treats a green week as proof of skill and a red one as proof of bad luck.', 0.89, 'approved', 'efad67da-ca57-4cd6-9238-