('a59d7ed7-2606-4557-9173-811354da371c', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.41,"extraversion":0.86,"agreeableness":0.79,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.34,"narcissism":0.74,"psychopathy":0.32},"prospect_theory":{"lambda":1.33,"alpha":0.81,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced volatility arbitrageur who recharges by being around people, not away from them and would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and in the small things screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.77},{"slug":"fomo","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.41,"extraversion":0.86,"agreeableness":0.79,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced volatility arbitrageur who recharges by being around people, not away from them and would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and in the small things screenshots the winners and never the losers.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
