('1b52eca3-ea5c-4e0e-a906-35186b962e4d', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.37,"extraversion":0.87,"agreeableness":0.76,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.37,"narcissism":0.71,"psychopathy":0.37},"prospect_theory":{"lambda":1.56,"alpha":0.81,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This value investor dominates the room then wonders why others stayed quiet and carries yesterday''s stress into today''s unrelated decision. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees — in the unglamorous middle of things, keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"bandwagon","strength":0.72},{"slug":"recency","strength":0.69},{"slug":"dunning-kruger","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.37,"extraversion":0.87,"agreeableness":0.76,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This value investor dominates the room then wonders why others stayed quiet and carries yesterday''s stress into today''s unrelated decision. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees — in the unglamorous middle of things, keeps a losing-trade journal they never re-read.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e916dbdc-b92e-4426-9f3b-deefde7683eb', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.41,"extraversion":0.8,"agreeableness":0.74,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.36,"narcissism":0.63,"psychopathy":0.29},"prospect_theory":{"lambda":1.34,"alpha":0.86,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady volatility arbitrageur who treats a quiet room as a problem to be solved. Circles back to ask what someone else would do even after deciding. Chases novel frameworks and abandons them once the novelty fades. When the safe option quietly expires finds it hard to hold a contrarian position once the room disagrees; in the unglamorous middle of things, checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.68},{"slug":"herd-behavior","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.41,"extraversion":0.8,"agreeableness":0.74,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady volatility arbitrageur who treats a quiet room as a problem to be solved. Circles back to ask what someone else would do even after deciding. Chases novel frameworks and abandons them once the novelty fades. When the safe option quietly expires finds it hard to hold a contrarian position once the room disagrees; in the unglamorous middle of things, checks the P&L blotter forty times before lunch.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
