('94d8c4b0-c800-4476-a771-23a60164d570', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.66,"extraversion":0.78,"agreeableness":0.85,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.38,"narcissism":0.59,"psychopathy":0.37},"prospect_theory":{"lambda":2.36,"alpha":0.87,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A pronounced social-media strategist: absorbs conflict to keep the peace, often at their own cost, treats a missed deadline as a personal failure regardless of cause. Needs the room''s approval more than it needs to be right, and on a slow afternoon remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.59},{"slug":"bandwagon","strength":0.72}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.57,"conscientiousness":0.66,"extraversion":0.78,"agreeableness":0.85,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A pronounced social-media strategist: absorbs conflict to keep the peace, often at their own cost, treats a missed deadline as a personal failure regardless of cause. Needs the room''s approval more than it needs to be right, and on a slow afternoon remembers who didn''t get invited last time.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('dcbc2478-713c-49cb-a619-0bb8f82cec5e', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.51,"extraversion":0.68,"agreeableness":0.9,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.36,"narcissism":0.57,"psychopathy":0.31},"prospect_theory":{"lambda":2.5,"alpha":0.9,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced unofficial group historian who takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything. Recharges by being around people, not away from them. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way; when the stakes are trivial, remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"endowment","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.54,"conscientiousness":0.51,"extraversion":0.68,"agreeableness":0.9,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced unofficial group historian who takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything. Recharges by being around people, not away from them. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way; when the stakes are trivial, remembers everyone birthday and no one boundaries.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
