('a4ebe7b9-a9fb-4aaa-b4b2-0525b335b1a7', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.65,"extraversion":0.67,"agreeableness":0.85,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.4,"narcissism":0.52,"psychopathy":0.31},"prospect_theory":{"lambda":2.34,"alpha":0.95,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The friend who always drives whose defining move is that they would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything. Treats a missed deadline as a personal failure regardless of cause. When someone is watching the outcome, abandons a private read the instant the crowd leans the other way; over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.61},{"slug":"herd-behavior","strength":0.67},{"slug":"bandwagon","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.58,"conscientiousness":0.65,"extraversion":0.67,"agreeableness":0.85,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The friend who always drives whose defining move is that they would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything. Treats a missed deadline as a personal failure regardless of cause. When someone is watching the outcome, abandons a private read the instant the crowd leans the other way; over-explains a boundary rather than just stating it.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8a71d1df-e0d7-440f-a2c8-f5dfb6e88d09', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.44,"extraversion":0.95,"agreeableness":0.81,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.31,"narcissism":0.77,"psychopathy":0.33},"prospect_theory":{"lambda":1.51,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced DeFi yield farmer who recharges by being around people, not away from them and treats established procedure as a first draft to be rewritten. Trusts the group''s confidence more than its own, and in the routine of it exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.7},{"slug":"bandwagon","strength":0.78},{"slug":"herd-behavior","strength":0.85},{"slug":"dunning-kruger","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.87,"conscientiousness":0.44,"extraversion":0.95,"agreeableness":0.81,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced DeFi yield farmer who recharges by being around people, not away from them and treats established procedure as a first draft to be rewritten. Trusts the group''s confidence more than its own, and in the routine of it exits winners at the first green candle.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2cf13736-2f58-432d-90fe-2290496c116a', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.69,"extraversion":0.65,"agreeableness":0.74,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.43,"narcissism":0.52,"psychopathy":0.28},"prospect_theory":{"lambda":2.42,"alpha":0.85,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When there is no clean exit, abandons a private read the instant the crowd leans the other way. Otherwise, a steady newcomer welcomer who takes on other people''s problems as if they were their own and recharges by being around people, not away from them. Feels the weight of a decision lighten the moment someone else co-signs it, and in the version no one reviews over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.57},{"slug":"authority-bias","strength":0.6},{"slug":"herd-behavior","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.69,"extraversion":0.65,"agreeableness":0.74,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When there is no clean exit, abandons a private read the instant the crowd leans the other way. Otherwise, a steady newcomer welcomer who takes on other people''s problems as if they were their own and recharges by being around people, not away from them. Feels the weight of a decision lighten the moment someone else co-signs it, and in the version no one reviews over-commits to plans they later dread.', 0.88, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('50ec90bd-9639-464c-abcf-f9eb92b87fbc', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.45,"extraversion":0.73,"agreeableness":0.91,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.33,"narcissism":0.61,"psychopathy":0.36},"prospect_theory":{"lambda":2.55,"alpha":0.86,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A pronounced group-project default leader: absorbs conflict to keep the peace, often at their own cost, collects half-finished manifestos and unconventional methods. Seeks a second, third, and fourth opinion before committing to anything, and without an audience texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"endowment","strength":0.63},{"slug":"bandwagon","strength":0.79},{"slug":"authority-bias","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.45,"extraversion":0.73,"agreeableness":0.91,"neuroticism":0.39}'::jsonb, 'ENFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A pronounced group-project default leader: absorbs conflict to keep the peace, often at their own cost, collects half-finished manifestos and unconventional methods. Seeks a second, third, and fourth opinion before committing to anything, and without an audience texts an apology before confirming anyone is upset.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ce50b417-7c0d-4f96-8ab8-607ce4ea6837', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.67,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.35,"narcissism":0.71,"psychopathy":0.28},"prospect_theory":{"lambda":1.43,"alpha":0.79,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This options seller collects half-finished manifestos and unconventional methods and treats a quiet room as a problem to be solved. When the stakes rise finds it hard to hold a contrarian position once the room disagrees — in the unglamorous middle of things, apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"fomo","strength":0.68},{"slug":"bandwagon","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.89,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.67,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This options seller collects half-finished manifestos and unconventional methods and treats a quiet room as a problem to be solved. When the stakes rise finds it hard to hold a contrarian position once the room disagrees — in the unglamorous middle of things, apes the launch before the contract is verified.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('79495bd6-cb0e-4c06-a042-ad058e3c051d', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.42,"extraversion":0.84,"agreeableness":0.71,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.4,"narcissism":0.68,"psychopathy":0.28},"prospect_theory":{"lambda":1.39,"alpha":0.86,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Meme-coin rotator whose defining move is that they draws energy from the crowd and wilts when working alone. Feels the weight of a decision lighten the moment someone else co-signs it. Treats established procedure as a first draft to be rewritten. When the number turns red, takes the crowd''s confidence as a substitute for its own analysis; sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.74},{"slug":"fomo","strength":0.7},{"slug":"herd-behavior","strength":0.76},{"slug":"dunning-kruger","strength":0.58}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.42,"extraversion":0.84,"agreeableness":0.71,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Meme-coin rotator whose defining move is that they draws energy from the crowd and wilts when working alone. Feels the weight of a decision lighten the moment someone else co-signs it. Treats established procedure as a first draft to be rewritten. When the number turns red, takes the crowd''s confidence as a substitute for its own analysis; sets stop-losses then cancels them at the open.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('5557f749-8446-4013-861e-8d098ec7feab', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.35,"extraversion":0.95,"agreeableness":0.72,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.36,"narcissism":0.81,"psychopathy":0.37},"prospect_theory":{"lambda":1.38,"alpha":0.83,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced crypto day-trader who thinks out loud and recruits an audience for every decision. Seeks a second, third, and fourth opinion before committing to anything. Reads other people''s discomfort before they voice it. The moment risk appears takes the crowd''s confidence as a substitute for its own analysis; when no one is watching, refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.8},{"slug":"fomo","strength":0.73},{"slug":"dunning-kruger","strength":0.72}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.35,"extraversion":0.95,"agreeableness":0.72,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced crypto day-trader who thinks out loud and recruits an audience for every decision. Seeks a second, third, and fourth opinion before committing to anything. Reads other people''s discomfort before they voice it. The moment risk appears takes the crowd''s confidence as a substitute for its own analysis; when no one is watching, refreshes the order book compulsively during lunch.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('98d9ef1f-c5dc-4900-8a69-8fb5282118aa', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.32,"extraversion":0.79,"agreeableness":0.74,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.37,"narcissism":0.65,"psychopathy":0.39},"prospect_theory":{"lambda":1.51,"alpha":0.89,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A steady penny-stock gambler: treats a quiet room as a problem to be solved, apologizes first in disputes regardless of fault. Circles back to ask what someone else would do even after deciding, and without an audience talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"sunk-cost","strength":0.58},{"slug":"dunning-kruger","strength":0.66},{"slug":"herd-behavior","strength":0.78},{"slug":"bandwagon","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.32,"extraversion":0.79,"agreeableness":0.74,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A steady penny-stock gambler: treats a quiet room as a problem to be solved, apologizes first in disputes regardless of fault. Circles back to ask what someone else would do even after deciding, and without an audience talks in win rate and never mentions size.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8f7d9293-cfb4-4f9e-8fbd-5cc79be5c7ce', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.34,"extraversion":0.91,"agreeableness":0.77,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.36,"narcissism":0.77,"psychopathy":0.32},"prospect_theory":{"lambda":1.5,"alpha":0.82,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced volatility arbitrageur who thinks out loud and recruits an audience for every decision. Waits for a permission that never quite arrives. Leaves loose ends and trusts future-self to handle them. Under pressure finds it hard to hold a contrarian position once the room disagrees; in the parts nobody grades, rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.82},{"slug":"dunning-kruger","strength":0.77},{"slug":"fomo","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.34,"extraversion":0.91,"agreeableness":0.77,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced volatility arbitrageur who thinks out loud and recruits an audience for every decision. Waits for a permission that never quite arrives. Leaves loose ends and trusts future-self to handle them. Under pressure finds it hard to hold a contrarian position once the room disagrees; in the parts nobody grades, rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
