('2276edda-2c11-4ee6-b71c-f32d78127f31', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.66,"extraversion":0.73,"agreeableness":0.76,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.44,"narcissism":0.58,"psychopathy":0.38},"prospect_theory":{"lambda":2.53,"alpha":0.93,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady unofficial group historian who measures decisions by who they might upset. Trusts the group''s confidence more than its own. Cannot relax until the checklist is visibly complete. When there is no clean exit gains confidence in a position in proportion to how many others hold it; left to their own devices, mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.69},{"slug":"herd-behavior","strength":0.7},{"slug":"bandwagon","strength":0.73}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.66,"extraversion":0.73,"agreeableness":0.76,"neuroticism":0.34}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady unofficial group historian who measures decisions by who they might upset. Trusts the group''s confidence more than its own. Cannot relax until the checklist is visibly complete. When there is no clean exit gains confidence in a position in proportion to how many others hold it; left to their own devices, mediates conflicts they secretly started.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('dda146a8-a57c-4bc0-a38a-07747d28cbce', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.6,"extraversion":0.73,"agreeableness":0.82,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.39,"narcissism":0.53,"psychopathy":0.25},"prospect_theory":{"lambda":2.3,"alpha":0.91,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The friend who always drives whose defining move is that they reads other people''s discomfort before they voice it. Waits for a permission that never quite arrives. Thinks out loud and recruits an audience for every decision. In a pinch, abandons a private read the instant the crowd leans the other way; over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.61},{"slug":"endowment","strength":0.66},{"slug":"herd-behavior","strength":0.72},{"slug":"authority-bias","strength":0.57}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.6,"extraversion":0.73,"agreeableness":0.82,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The friend who always drives whose defining move is that they reads other people''s discomfort before they voice it. Waits for a permission that never quite arrives. Thinks out loud and recruits an audience for every decision. In a pinch, abandons a private read the instant the crowd leans the other way; over-commits to plans they later dread.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('d6830cc1-20ed-48eb-9b22-f413f350bc30', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.41,"extraversion":0.76,"agreeableness":0.7,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.34,"narcissism":0.6,"psychopathy":0.34},"prospect_theory":{"lambda":1.57,"alpha":0.86,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Quant researcher, steady in style: dominates the room then wonders why others stayed quiet; collects half-finished manifestos and unconventional methods. Circles back to ask what someone else would do even after deciding. The moment risk appears cannot watch a rally from the sidelines for long.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"dunning-kruger","strength":0.57},{"slug":"recency","strength":0.57},{"slug":"bandwagon","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.41,"extraversion":0.76,"agreeableness":0.7,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Quant researcher, steady in style: dominates the room then wonders why others stayed quiet; collects half-finished manifestos and unconventional methods. Circles back to ask what someone else would do even after deciding. The moment risk appears cannot watch a rally from the sidelines for long.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('09023bb1-83c3-4bd7-9981-c89f508088a0', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.35,"extraversion":0.86,"agreeableness":0.72,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.39,"narcissism":0.75,"psychopathy":0.38},"prospect_theory":{"lambda":1.34,"alpha":0.89,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Dividend-yield chaser, pronounced in style: recharges by being around people, not away from them; absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own. When the number turns red abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"bandwagon","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.35,"extraversion":0.86,"agreeableness":0.72,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Dividend-yield chaser, pronounced in style: recharges by being around people, not away from them; absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own. When the number turns red abandons a private read the instant the crowd leans the other way.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3ec7fa98-591c-4843-a06e-a78b0d26e88c', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.37,"extraversion":0.93,"agreeableness":0.82,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.32,"narcissism":0.72,"psychopathy":0.37},"prospect_theory":{"lambda":1.57,"alpha":0.84,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under a deadline, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced DeFi yield farmer who thinks out loud and recruits an audience for every decision and measures decisions by who they might upset. Feels the weight of a decision lighten the moment someone else co-signs it, and in the small things treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.78},{"slug":"herd-behavior","strength":0.85}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.37,"extraversion":0.93,"agreeableness":0.82,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under a deadline, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced DeFi yield farmer who thinks out loud and recruits an audience for every decision and measures decisions by who they might upset. Feels the weight of a decision lighten the moment someone else co-signs it, and in the small things treats a green week as proof of skill and a red one as proof of bad luck.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4fb5b1c2-f80d-4f34-8b13-482dd8c21486', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.38,"extraversion":0.83,"agreeableness":0.81,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.32,"narcissism":0.64,"psychopathy":0.34},"prospect_theory":{"lambda":1.45,"alpha":0.89,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A steady delta-neutral market maker: fills silence reflexively, even when nobody asked it to, improvises past every deadline and calls it flexibility. Outsources conviction to whoever spoke last with authority, and when no one is watching rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"endowment","strength":0.69},{"slug":"fomo","strength":0.69},{"slug":"bandwagon","strength":0.79},{"slug":"herd-behavior","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.38,"extraversion":0.83,"agreeableness":0.81,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A steady delta-neutral market maker: fills silence reflexively, even when nobody asked it to, improvises past every deadline and calls it flexibility. Outsources conviction to whoever spoke last with authority, and when no one is watching rotates the whole book into whatever is pumping this hour.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ee3696d5-74af-451e-9a41-552a426c44de', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.33,"extraversion":0.89,"agreeableness":0.76,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.39,"narcissism":0.73,"psychopathy":0.33},"prospect_theory":{"lambda":1.55,"alpha":0.85,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"DeFi yield farmer, pronounced in style: thinks out loud and recruits an audience for every decision; treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority. When the safe option quietly expires adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.83},{"slug":"herd-behavior","strength":0.77},{"slug":"fomo","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.33,"extraversion":0.89,"agreeableness":0.76,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'DeFi yield farmer, pronounced in style: thinks out loud and recruits an audience for every decision; treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority. When the safe option quietly expires adopts a conviction mainly because the room already has.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f546deaf-6385-4ad0-9278-187d4ddcc339', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.32,"extraversion":0.94,"agreeableness":0.7,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.35,"narcissism":0.8,"psychopathy":0.33},"prospect_theory":{"lambda":1.41,"alpha":0.86,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Meme-coin rotator, pronounced in style: draws energy from the crowd and wilts when working alone; confuses motion with progress. Seeks a second, third, and fourth opinion before committing to anything. Once the exit narrows to one door treats being left out of a move as its own kind of loss.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.77},{"slug":"herd-behavior","strength":0.77},{"slug":"dunning-kruger","strength":0.72},{"slug":"optimism","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.32,"extraversion":0.94,"agreeableness":0.7,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Meme-coin rotator, pronounced in style: draws energy from the crowd and wilts when working alone; confuses motion with progress. Seeks a second, third, and fourth opinion before committing to anything. Once the exit narrows to one door treats being left out of a move as its own kind of loss.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('02168722-2525-483b-a302-d207d863aeb1', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.64,"extraversion":0.76,"agreeableness":0.81,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.41,"narcissism":0.65,"psychopathy":0.37},"prospect_theory":{"lambda":2.47,"alpha":0.91,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Reluctant plus-one, steady in style: defaults to trust and gives the benefit of the doubt too freely; fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Once the exit narrows to one door gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.65},{"slug":"bandwagon","strength":0.71},{"slug":"herd-behavior","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.64,"extraversion":0.76,"agreeableness":0.81,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Reluctant plus-one, steady in style: defaults to trust and gives the benefit of the doubt too freely; fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Once the exit narrows to one door gains confidence in a position in proportion to how many others hold it.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
