('0d8c5201-1bc2-44ed-b19f-326ef35f5c5d', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.53,"extraversion":0.77,"agreeableness":0.75,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.39,"narcissism":0.65,"psychopathy":0.37},"prospect_theory":{"lambda":2.25,"alpha":0.89,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This reluctant plus-one draws energy from the crowd and wilts when working alone and measures decisions by who they might upset. When cornered finds it easier to believe something once it stops being a minority view — across the quiet stretches, says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"herd-behavior","strength":0.66}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","behavioral","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.53,"extraversion":0.77,"agreeableness":0.75,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','behavioral','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This reluctant plus-one draws energy from the crowd and wilts when working alone and measures decisions by who they might upset. When cornered finds it easier to believe something once it stops being a minority view — across the quiet stretches, says yes out loud and no internally.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
