('e6a0c319-10f2-4f09-b140-f157f4febf3a', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.46,"extraversion":0.88,"agreeableness":0.65,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.42,"narcissism":0.73,"psychopathy":0.27},"prospect_theory":{"lambda":1.26,"alpha":0.85,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once things get tense, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced options seller who treats a quiet room as a problem to be solved and treats established procedure as a first draft to be rewritten. Trusts the group''s confidence more than its own, and once the urgency drains out keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.72},{"slug":"fomo","strength":0.71},{"slug":"dunning-kruger","strength":0.61}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.46,"extraversion":0.88,"agreeableness":0.65,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Once things get tense, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced options seller who treats a quiet room as a problem to be solved and treats established procedure as a first draft to be rewritten. Trusts the group''s confidence more than its own, and once the urgency drains out keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('7a7bf446-bc68-4017-b9b1-afbba7e426a6', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.5,"extraversion":0.66,"agreeableness":0.8,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.38,"narcissism":0.56,"psychopathy":0.24},"prospect_theory":{"lambda":2.46,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment it stops being hypothetical, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady the friend who always drives who absorbs conflict to keep the peace, often at their own cost and fills silence reflexively, even when nobody asked it to. Needs the room''s approval more than it needs to be right, and once the urgency drains out can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.61},{"slug":"herd-behavior","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.5,"extraversion":0.66,"agreeableness":0.8,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment it stops being hypothetical, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady the friend who always drives who absorbs conflict to keep the peace, often at their own cost and fills silence reflexively, even when nobody asked it to. Needs the room''s approval more than it needs to be right, and once the urgency drains out can sense a mood shift from the doorway.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8f29a8b0-781a-4a27-a36b-b88b65114685', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.62,"extraversion":0.76,"agreeableness":0.83,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.41,"narcissism":0.66,"psychopathy":0.35},"prospect_theory":{"lambda":2.55,"alpha":0.86,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady group-chat ringleader who absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. Recharges by being around people, not away from them. Once the exit narrows to one door finds it hard to hold a contrarian position once the room disagrees; on an ordinary week, keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.8},{"slug":"endowment","strength":0.67},{"slug":"bandwagon","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.75,"conscientiousness":0.62,"extraversion":0.76,"agreeableness":0.83,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady group-chat ringleader who absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. Recharges by being around people, not away from them. Once the exit narrows to one door finds it hard to hold a contrarian position once the room disagrees; on an ordinary week, keeps score of favors without meaning to.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('91579983-a1f4-4ecb-b8eb-31e9e961b6a2', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.65,"extraversion":0.71,"agreeableness":0.75,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.4,"narcissism":0.53,"psychopathy":0.28},"prospect_theory":{"lambda":2.5,"alpha":0.92,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady nonprofit convener who apologizes first in disputes regardless of fault. Waits for a permission that never quite arrives. Treats a missed deadline as a personal failure regardless of cause. The moment risk appears adopts a conviction mainly because the room already has; on a slow afternoon, defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.58},{"slug":"bandwagon","strength":0.74},{"slug":"endowment","strength":0.6}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.65,"extraversion":0.71,"agreeableness":0.75,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady nonprofit convener who apologizes first in disputes regardless of fault. Waits for a permission that never quite arrives. Treats a missed deadline as a personal failure regardless of cause. The moment risk appears adopts a conviction mainly because the room already has; on a slow afternoon, defuses tension with a joke that lands most of the time.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('899d8368-c813-45b9-a689-33d8d3a8a04d', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.39,"extraversion":0.83,"agreeableness":0.69,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.4,"narcissism":0.7,"psychopathy":0.34},"prospect_theory":{"lambda":1.28,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A steady DeFi yield farmer: recharges by being around people, not away from them, reads other people''s discomfort before they voice it. Waits for a permission that never quite arrives, and across the quiet stretches calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.68},{"slug":"dunning-kruger","strength":0.6},{"slug":"recency","strength":0.65},{"slug":"herd-behavior","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.39,"extraversion":0.83,"agreeableness":0.69,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A steady DeFi yield farmer: recharges by being around people, not away from them, reads other people''s discomfort before they voice it. Waits for a permission that never quite arrives, and across the quiet stretches calls a 90% drawdown a long-term hold.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('539a9f10-9af6-4e79-a6d0-e1db6bbb26fc', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.52,"extraversion":0.61,"agreeableness":0.8,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.32,"narcissism":0.56,"psychopathy":0.34},"prospect_theory":{"lambda":2.28,"alpha":0.87,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Unofficial group historian, steady in style: measures decisions by who they might upset; would rather invent a worse tool than use someone else''s good one. Seeks a second, third, and fourth opinion before committing to anything. When someone is watching the outcome defers to the most senior voice even against their own evidence.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.54},{"slug":"authority-bias","strength":0.6},{"slug":"bandwagon","strength":0.6},{"slug":"sunk-cost","strength":0.55}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.75,"conscientiousness":0.52,"extraversion":0.61,"agreeableness":0.8,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Unofficial group historian, steady in style: measures decisions by who they might upset; would rather invent a worse tool than use someone else''s good one. Seeks a second, third, and fourth opinion before committing to anything. When someone is watching the outcome defers to the most senior voice even against their own evidence.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3cbd6b65-63da-4a71-8eb6-0572eecbb5ef', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.44,"extraversion":0.9,"agreeableness":0.73,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.39,"narcissism":0.69,"psychopathy":0.28},"prospect_theory":{"lambda":1.46,"alpha":0.86,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced commodities speculator who narrates the plan to whoever is nearby before committing to it. Circles back to ask what someone else would do even after deciding. Would rather lose a point than win an argument badly. The instant it becomes irreversible adopts a conviction mainly because the room already has; in the parts nobody grades, calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"bandwagon","strength":0.82},{"slug":"recency","strength":0.66},{"slug":"fomo","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.44,"extraversion":0.9,"agreeableness":0.73,"neuroticism":0.69}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced commodities speculator who narrates the plan to whoever is nearby before committing to it. Circles back to ask what someone else would do even after deciding. Would rather lose a point than win an argument badly. The instant it becomes irreversible adopts a conviction mainly because the room already has; in the parts nobody grades, calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
