('5602583a-37e8-4489-a934-8fab8a8fca0d', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.37,"extraversion":0.9,"agreeableness":0.7,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.35,"narcissism":0.74,"psychopathy":0.31},"prospect_theory":{"lambda":1.34,"alpha":0.85,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Commodities speculator whose defining move is that they treats a quiet room as a problem to be solved. Trusts the group''s confidence more than its own. Leaves loose ends and trusts future-self to handle them. When someone is watching the outcome, takes the crowd''s confidence as a substitute for its own analysis; apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.8},{"slug":"fomo","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.37,"extraversion":0.9,"agreeableness":0.7,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Commodities speculator whose defining move is that they treats a quiet room as a problem to be solved. Trusts the group''s confidence more than its own. Leaves loose ends and trusts future-self to handle them. When someone is watching the outcome, takes the crowd''s confidence as a substitute for its own analysis; apes the launch before the contract is verified.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e1d891f4-6b84-44b9-9bb9-e443f52a6016', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.41,"extraversion":0.82,"agreeableness":0.77,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.36,"narcissism":0.65,"psychopathy":0.32},"prospect_theory":{"lambda":1.29,"alpha":0.8,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under pressure, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady MEV searcher who narrates the plan to whoever is nearby before committing to it and notices the one thing that could go wrong before the nine that could go right. Circles back to ask what someone else would do even after deciding, and in the routine of it refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.72},{"slug":"bandwagon","strength":0.72}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.41,"extraversion":0.82,"agreeableness":0.77,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under pressure, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady MEV searcher who narrates the plan to whoever is nearby before committing to it and notices the one thing that could go wrong before the nine that could go right. Circles back to ask what someone else would do even after deciding, and in the routine of it refreshes the order book compulsively during lunch.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2e141a0a-02f2-4c67-8389-2ccdab992a43', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.31,"extraversion":0.82,"agreeableness":0.74,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.38,"narcissism":0.68,"psychopathy":0.4},"prospect_theory":{"lambda":1.34,"alpha":0.86,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Meme-coin rotator whose defining move is that they thinks out loud and recruits an audience for every decision. Waits for a permission that never quite arrives. Apologizes first in disputes regardless of fault. The instant it becomes irreversible, finds it easier to believe something once it stops being a minority view; calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.77},{"slug":"fomo","strength":0.71},{"slug":"bandwagon","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.31,"extraversion":0.82,"agreeableness":0.74,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Meme-coin rotator whose defining move is that they thinks out loud and recruits an audience for every decision. Waits for a permission that never quite arrives. Apologizes first in disputes regardless of fault. The instant it becomes irreversible, finds it easier to believe something once it stops being a minority view; calls a 90% drawdown a long-term hold.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('536d8e79-f469-427c-b9b5-0aa92e1cc24c', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.54,"extraversion":0.85,"agreeableness":0.71,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.39,"narcissism":0.69,"psychopathy":0.27},"prospect_theory":{"lambda":1.48,"alpha":0.9,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Value investor, pronounced in style: draws energy from the crowd and wilts when working alone; absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. The instant the deadline moves up adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"dunning-kruger","strength":0.53},{"slug":"optimism","strength":0.6},{"slug":"bandwagon","strength":0.7},{"slug":"fomo","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.54,"extraversion":0.85,"agreeableness":0.71,"neuroticism":0.56}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Value investor, pronounced in style: draws energy from the crowd and wilts when working alone; absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding. The instant the deadline moves up adopts a conviction mainly because the room already has.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('eaa92918-a86e-4d6d-a7c6-0cfe4f11c8b3', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.41,"extraversion":0.8,"agreeableness":0.69,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.4,"narcissism":0.63,"psychopathy":0.3},"prospect_theory":{"lambda":1.47,"alpha":0.9,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady index-fund holdout who treats a quiet room as a problem to be solved. Waits for a permission that never quite arrives. Defaults to trust and gives the benefit of the doubt too freely. The instant it becomes irreversible takes the crowd''s confidence as a substitute for its own analysis; in the unglamorous middle of things, keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.65},{"slug":"fomo","strength":0.67},{"slug":"sunk-cost","strength":0.6},{"slug":"herd-behavior","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.61,"conscientiousness":0.41,"extraversion":0.8,"agreeableness":0.69,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady index-fund holdout who treats a quiet room as a problem to be solved. Waits for a permission that never quite arrives. Defaults to trust and gives the benefit of the doubt too freely. The instant it becomes irreversible takes the crowd''s confidence as a substitute for its own analysis; in the unglamorous middle of things, keeps three monitors for a portfolio that fits on one screen.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('09d3502f-cce4-463f-a7eb-fdf4c30b7109', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.44,"extraversion":0.75,"agreeableness":0.63,"neuroticism":0.74},"dark_triad":{"machiavellianism":0.4,"narcissism":0.57,"psychopathy":0.29},"prospect_theory":{"lambda":1.51,"alpha":0.79,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When there is no clean exit, assumes the current streak is the new normal. Otherwise, a steady commodities speculator who chases novel frameworks and abandons them once the novelty fades and takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything, and on an ordinary week apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.65},{"slug":"herd-behavior","strength":0.66},{"slug":"recency","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.83,"conscientiousness":0.44,"extraversion":0.75,"agreeableness":0.63,"neuroticism":0.74}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When there is no clean exit, assumes the current streak is the new normal. Otherwise, a steady commodities speculator who chases novel frameworks and abandons them once the novelty fades and takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything, and on an ordinary week apes the launch before the contract is verified.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc')
INSERT INTO profiles (id, version, content, big_five, mbti_label, decision_style, tags, summary, quality_score, status, generation_run_id) VALUES
('e6025083-6df8-40b7-bb9e-3d0517dcd44e', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.52,"extraversion":0.76,"agreeableness":0.84,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.35,"narcissism":0.66,"psychopathy":0.37},"prospect_theory":{"lambda":2.51,"alpha":0.92,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced group-chat ringleader who takes on other people''s problems as if they were their own. Needs the room''s approval more than it needs to be right. Reframes every problem as an excuse to learn a new system. When the number turns red adopts a conviction mainly because the room already has; when the stakes are trivial, defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.61},{"slug":"endowment","strength":0.6},{"slug":"bandwagon","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.74,"conscientiousness":0.52,"extraversion":0.76,"agreeableness":0.84,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced group-chat ringleader who takes on other people''s problems as if they were their own. Needs the room''s approval more than it needs to be right. Reframes every problem as an excuse to learn a new system. When the number turns red adopts a conviction mainly because the room already has; when the stakes are trivial, defuses tension with a joke that lands most of the time.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('29624ee7-6544-46d5-9be4-e5a22e04126c', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.59,"extraversion":0.73,"agreeableness":0.6,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.41,"narcissism":0.61,"psychopathy":0.29},"prospect_theory":{"lambda":1.48,"alpha":0.85,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This meme-coin rotator narrates the plan to whoever is nearby before committing to it and reframes every problem as an excuse to learn a new system. The moment risk appears treats being left out of a move as its own kind of loss — when the pressure is off, rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.61},{"slug":"herd-behavior","strength":0.58}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.59,"extraversion":0.73,"agreeableness":0.6,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This meme-coin rotator narrates the plan to whoever is nearby before committing to it and reframes every problem as an excuse to learn a new system. The moment risk appears treats being left out of a move as its own kind of loss — when the pressure is off, rotates the whole book into whatever is pumping this hour.', 0.87, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2beb4215-bd4b-49b0-a383-423fd5cfce74', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.37,"extraversion":0.86,"agreeableness":0.74,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.4,"narcissism":0.66,"psychopathy":0.33},"prospect_theory":{"lambda":1.36,"alpha":0.84,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This DeFi yield farmer narrates the plan to whoever is nearby before committing to it and reads outside the field for ideas the field itself would reject. Under a deadline finds it hard to hold a contrarian position once the room disagrees — once the urgency drains out, keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"fomo","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.37,"extraversion":0.86,"agreeableness":0.74,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This DeFi yield farmer narrates the plan to whoever is nearby before committing to it and reads outside the field for ideas the field itself would reject. Under a deadline finds it hard to hold a contrarian position once the room disagrees — once the urgency drains out, keeps a losing-trade journal they never re-read.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e1df9f17-e399-47bf-b4b6-f6dc8e25a48a', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.54,"extraversion":0.82,"agreeableness":0.62,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.45,"narcissism":0.67,"psychopathy":0.3},"prospect_theory":{"lambda":1.3,"alpha":0.83,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This airdrop farmer collects half-finished manifestos and unconventional methods and apologizes first in disputes regardless of fault. When the walls close in finds it hard to hold a contrarian position once the room disagrees — as a rule, sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.61},{"slug":"bandwagon","strength":0.63},{"slug":"herd-behavior","strength":0.69},{"slug":"recency","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.54,"extraversion":0.82,"agreeableness":0.62,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This airdrop farmer collects half-finished manifestos and unconventional methods and apologizes first in disputes regardless of fault. When the walls close in finds it hard to hold a contrarian position once the room disagrees — as a rule, sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('523ce2b0-5094-48b9-a7d0-031b48af84cd', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.6,"extraversion":0.8,"agreeableness":0.84,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.34,"narcissism":0.68,"psychopathy":0.3},"prospect_theory":{"lambda":2.33,"alpha":0.92,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Neighborhood connector, pronounced in style: takes on other people''s problems as if they were their own; recharges by being around people, not away from them. Outsources conviction to whoever spoke last with authority. When there is no clean exit gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.68},{"slug":"herd-behavior","strength":0.75},{"slug":"bandwagon","strength":0.82}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.6,"extraversion":0.8,"agreeableness":0.84,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Neighborhood connector, pronounced in style: takes on other people''s problems as if they were their own; recharges by being around people, not away from them. Outsources conviction to whoever spoke last with authority. When there is no clean exit gains confidence in a position in proportion to how many others hold it.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3b726d27-95f4-4091-9c70-da2ce713f531', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.41,"extraversion":0.89,"agreeableness":0.62,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.42,"narcissism":0.71,"psychopathy":0.3},"prospect_theory":{"lambda":1.33,"alpha":0.87,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment it stops being hypothetical, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced quant researcher who recharges by being around people, not away from them and absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding, and as a rule sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"herd-behavior","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.41,"extraversion":0.89,"agreeableness":0.62,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment it stops being hypothetical, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced quant researcher who recharges by being around people, not away from them and absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding, and as a rule sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2bd96734-05ce-4a22-9fb1-f7f9957d84f7', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.41,"extraversion":0.87,"agreeableness":0.66,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.36,"narcissism":0.71,"psychopathy":0.3},"prospect_theory":{"lambda":1.44,"alpha":0.83,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Waits for a permission that never quite arrives. This prop-desk scalper thinks out loud and recruits an audience for every decision and absorbs conflict to keep the peace, often at their own cost. As soon as real money or reputation is on the line abandons a private read the instant the crowd leans the other way — as a rule, names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"herd-behavior","strength":0.79}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.41,"extraversion":0.87,"agreeableness":0.66,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Waits for a permission that never quite arrives. This prop-desk scalper thinks out loud and recruits an audience for every decision and absorbs conflict to keep the peace, often at their own cost. As soon as real money or reputation is on the line abandons a private read the instant the crowd leans the other way — as a rule, names every strategy after the trade that almost worked.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bf46cee2-8d84-4f74-b4ee-cca3af2fb11f', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.66,"extraversion":0.7,"agreeableness":0.83,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.44,"narcissism":0.57,"psychopathy":0.33},"prospect_theory":{"lambda":2.43,"alpha":0.86,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Group-project default leader whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it. Plans in exhaustive detail and resents any deviation. When the downside gets concrete, adopts a conviction mainly because the room already has; keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.66},{"slug":"bandwagon","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.66,"extraversion":0.7,"agreeableness":0.83,"neuroticism":0.38}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Group-project default leader whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it. Plans in exhaustive detail and resents any deviation. When the downside gets concrete, adopts a conviction mainly because the room already has; keeps score of favors without meaning to.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('999f3451-9c9a-4871-b6d8-72b0672de33b', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.45,"extraversion":0.74,"agreeableness":0.83,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.35,"narcissism":0.59,"psychopathy":0.3},"prospect_theory":{"lambda":2.5,"alpha":0.9,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Peer mentor whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Seeks a second, third, and fourth opinion before committing to anything. Collects half-finished manifestos and unconventional methods. As soon as real money or reputation is on the line, finds it hard to hold a contrarian position once the room disagrees; over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"endowment","strength":0.66},{"slug":"authority-bias","strength":0.57},{"slug":"herd-behavior","strength":0.76},{"slug":"bandwagon","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.45,"extraversion":0.74,"agreeableness":0.83,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Peer mentor whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Seeks a second, third, and fourth opinion before committing to anything. Collects half-finished manifestos and unconventional methods. As soon as real money or reputation is on the line, finds it hard to hold a contrarian position once the room disagrees; over-explains a boundary rather than just stating it.', 0.92, 'approved', 'efad67da-c