('c0ae5051-2998-429f-aa21-156a5d52f57f', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.62,"extraversion":0.73,"agreeableness":0.81,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.41,"narcissism":0.64,"psychopathy":0.27},"prospect_theory":{"lambda":2.41,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the safe option quietly expires, abandons a private read the instant the crowd leans the other way. Otherwise, a steady nonprofit convener who would rather lose a point than win an argument badly and treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it, and when no one is watching keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.64},{"slug":"authority-bias","strength":0.57},{"slug":"bandwagon","strength":0.74},{"slug":"herd-behavior","strength":0.75}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.62,"extraversion":0.73,"agreeableness":0.81,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the safe option quietly expires, abandons a private read the instant the crowd leans the other way. Otherwise, a steady nonprofit convener who would rather lose a point than win an argument badly and treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it, and when no one is watching keeps a mental ledger of social debts.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e0bae7aa-4130-4079-9ef5-a7ad8e87dd74', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.43,"extraversion":0.9,"agreeableness":0.59,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.39,"narcissism":0.69,"psychopathy":0.33},"prospect_theory":{"lambda":1.26,"alpha":0.83,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Jumps into whatever everyone else already seems to be winning at. A pronounced delta-neutral market maker: dominates the room then wonders why others stayed quiet, collects half-finished manifestos and unconventional methods. Feels the weight of a decision lighten the moment someone else co-signs it, and across the quiet stretches screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"recency","strength":0.58},{"slug":"fomo","strength":0.8},{"slug":"bandwagon","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.43,"extraversion":0.9,"agreeableness":0.59,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Jumps into whatever everyone else already seems to be winning at. A pronounced delta-neutral market maker: dominates the room then wonders why others stayed quiet, collects half-finished manifestos and unconventional methods. Feels the weight of a decision lighten the moment someone else co-signs it, and across the quiet stretches screenshots the winners and never the losers.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('218a9324-f138-41fa-a4f6-3e8552a5ff89', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.39,"extraversion":0.84,"agreeableness":0.66,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.38,"narcissism":0.64,"psychopathy":0.32},"prospect_theory":{"lambda":1.29,"alpha":0.81,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Onchain copy-trader whose defining move is that they thinks out loud and recruits an audience for every decision. Trusts the group''s confidence more than its own. Reads other people''s discomfort before they voice it. As soon as real money or reputation is on the line, finds it hard to hold a contrarian position once the room disagrees; confuses a bull market for a trading edge.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.64},{"slug":"fomo","strength":0.72},{"slug":"herd-behavior","strength":0.73},{"slug":"recency","strength":0.59}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.67,"conscientiousness":0.39,"extraversion":0.84,"agreeableness":0.66,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Onchain copy-trader whose defining move is that they thinks out loud and recruits an audience for every decision. Trusts the group''s confidence more than its own. Reads other people''s discomfort before they voice it. As soon as real money or reputation is on the line, finds it hard to hold a contrarian position once the room disagrees; confuses a bull market for a trading edge.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3e710ffd-57f1-4f41-bac9-01bb099c04a9', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.38,"extraversion":0.73,"agreeableness":0.55,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.44,"narcissism":0.59,"psychopathy":0.35},"prospect_theory":{"lambda":1.32,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady futures spreader who reframes every problem as an excuse to learn a new system. Trusts the group''s confidence more than its own. Hedges every commitment against an imagined worst case. In a pinch treats being left out of a move as its own kind of loss; when the stakes are trivial, trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.66},{"slug":"herd-behavior","strength":0.66},{"slug":"fomo","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.38,"extraversion":0.73,"agreeableness":0.55,"neuroticism":0.67}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady futures spreader who reframes every problem as an excuse to learn a new system. Trusts the group''s confidence more than its own. Hedges every commitment against an imagined worst case. In a pinch treats being left out of a move as its own kind of loss; when the stakes are trivial, trusts the chart more than the fundamentals and won''t say why.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('df6828b6-9aa0-4d1a-aae1-5bf6c6b2a150', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.43,"extraversion":0.9,"agreeableness":0.57,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.41,"narcissism":0.73,"psychopathy":0.29},"prospect_theory":{"lambda":1.29,"alpha":0.8,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Zero-DTE options gambler, pronounced in style: draws energy from the crowd and wilts when working alone; treats established procedure as a first draft to be rewritten. Seeks a second, third, and fourth opinion before committing to anything. When the downside gets concrete finds it hard to hold a contrarian position once the room disagrees.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"bandwagon","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.82,"conscientiousness":0.43,"extraversion":0.9,"agreeableness":0.57,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Zero-DTE options gambler, pronounced in style: draws energy from the crowd and wilts when working alone; treats established procedure as a first draft to be rewritten. Seeks a second, third, and fourth opinion before committing to anything. When the downside gets concrete finds it hard to hold a contrarian position once the room disagrees.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('7f2f4735-40ac-40e2-9a77-1108ddf8abf7', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.45,"extraversion":0.92,"agreeableness":0.74,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.33,"narcissism":0.69,"psychopathy":0.27},"prospect_theory":{"lambda":1.23,"alpha":0.85,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced zero-DTE options gambler who treats a quiet room as a problem to be solved. Outsources conviction to whoever spoke last with authority. Notices the one thing that could go wrong before the nine that could go right. When there is no clean exit abandons a private read the instant the crowd leans the other way; on a slow afternoon, keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.84},{"slug":"fomo","strength":0.77},{"slug":"dunning-kruger","strength":0.67},{"slug":"optimism","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.45,"extraversion":0.92,"agreeableness":0.74,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced zero-DTE options gambler who treats a quiet room as a problem to be solved. Outsources conviction to whoever spoke last with authority. Notices the one thing that could go wrong before the nine that could go right. When there is no clean exit abandons a private read the instant the crowd leans the other way; on a slow afternoon, keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('03082e1e-45d6-4f56-bf96-60e906c78312', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.37,"extraversion":0.88,"agreeableness":0.74,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.37,"narcissism":0.7,"psychopathy":0.3},"prospect_theory":{"lambda":1.27,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"MEV searcher whose defining move is that they draws energy from the crowd and wilts when working alone. Circles back to ask what someone else would do even after deciding. Apologizes first in disputes regardless of fault. When cornered, abandons a private read the instant the crowd leans the other way; checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.83},{"slug":"bandwagon","strength":0.82}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.37,"extraversion":0.88,"agreeableness":0.74,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'MEV searcher whose defining move is that they draws energy from the crowd and wilts when working alone. Circles back to ask what someone else would do even after deciding. Apologizes first in disputes regardless of fault. When cornered, abandons a private read the instant the crowd leans the other way; checks the P&L blotter forty times before lunch.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('36818af9-262b-4e44-88c3-66b0361313b9', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.56,"extraversion":0.69,"agreeableness":0.79,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.35,"narcissism":0.54,"psychopathy":0.32},"prospect_theory":{"lambda":2.49,"alpha":0.91,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A steady newcomer welcomer: reads other people''s discomfort before they voice it, would rather invent a worse tool than use someone else''s good one. Needs the room''s approval more than it needs to be right, and on an ordinary week defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.61},{"slug":"sunk-cost","strength":0.51},{"slug":"endowment","strength":0.56},{"slug":"herd-behavior","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.56,"extraversion":0.69,"agreeableness":0.79,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A steady newcomer welcomer: reads other people''s discomfort before they voice it, would rather invent a worse tool than use someone else''s good one. Needs the room''s approval more than it needs to be right, and on an ordinary week defuses tension with a joke that lands most of the time.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2797ddac-d615-40b7-876f-4c9c91f74dd0', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.38,"extraversion":0.85,"agreeableness":0.75,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.37,"narcissism":0.64,"psychopathy":0.34},"prospect_theory":{"lambda":1.33,"alpha":0.84,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Airdrop farmer whose defining move is that they narrates the plan to whoever is nearby before committing to it. Needs the room''s approval more than it needs to be right. Defaults to trust and gives the benefit of the doubt too freely. In a pinch, abandons a private read the instant the crowd leans the other way; sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.77},{"slug":"dunning-kruger","strength":0.61},{"slug":"bandwagon","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.38,"extraversion":0.85,"agreeableness":0.75,"neuroticism":0.68}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Airdrop farmer whose defining move is that they narrates the plan to whoever is nearby before committing to it. Needs the room''s approval more than it needs to be right. Defaults to trust and gives the benefit of the doubt too freely. In a pinch, abandons a private read the instant the crowd leans the other way; sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a26aad56-2abd-4a50-b4c7-78499feee62c', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.52,"extraversion":0.81,"agreeableness":0.86,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.31,"narcissism":0.68,"psychopathy":0.38},"prospect_theory":{"lambda":2.37,"alpha":0.84,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The one who remembers everyone''s order, pronounced in style: absorbs conflict to keep the peace, often at their own cost; dominates the room then wonders why others stayed quiet. Waits for a permission that never quite arrives. When the number turns red finds it hard to hold a contrarian position once the room disagrees.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.68},{"slug":"herd-behavior","strength":0.8},{"slug":"fomo","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.52,"extraversion":0.81,"agreeableness":0.86,"neuroticism":0.35}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The one who remembers everyone''s order, pronounced in style: absorbs conflict to keep the peace, often at their own cost; dominates the room then wonders why others stayed quiet. Waits for a permission that never quite arrives. When the number turns red finds it hard to hold a contrarian position once the room disagrees.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('b49de0dd-6cc4-4ecf-9ce5-42669291c206', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.51,"extraversion":0.94,"agreeableness":0.69,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.36,"narcissism":0.75,"psychopathy":0.32},"prospect_theory":{"lambda":1.25,"alpha":0.82,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Treats being left out of a move as its own kind of loss. A pronounced MEV searcher: narrates the plan to whoever is nearby before committing to it, needs repeated reassurance that a decision was the right one. Waits for a permission that never quite arrives, and without an audience checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"recency","strength":0.59},{"slug":"fomo","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.51,"extraversion":0.94,"agreeableness":0.69,"neuroticism":0.63}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Treats being left out of a move as its own kind of loss. A pronounced MEV searcher: narrates the plan to whoever is nearby before committing to it, needs repeated reassurance that a decision was the right one. Waits for a permission that never quite arrives, and without an audience checks the P&L blotter forty times before lunch.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6d051838-bb0c-4b0d-80bf-dcaeefd925ef', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.58,"extraversion":0.75,"agreeableness":0.9,"neuroticism":0.32},"dark_triad":{"machiavellianism":0.35,"narcissism":0.63,"psychopathy":0.43},"prospect_theory":{"lambda":2.29,"alpha":0.88,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Wedding-party diplomat whose defining move is that they would rather lose a point than win an argument badly. Needs the room''s approval more than it needs to be right. Treats a crisis as an interesting problem rather than a threat. When the number turns red, finds it easier to believe something once it stops being a minority view; remembers everyone birthday and no one boundaries.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.7},{"slug":"bandwagon","strength":0.79},{"slug":"herd-behavior","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.6,"conscientiousness":0.58,"extraversion":0.75,"agreeableness":0.9,"neuroticism":0.32}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Wedding-party diplomat whose defining move is that they would rather lose a point than win an argument badly. Needs the room''s approval more than it needs to be right. Treats a crisis as an interesting problem rather than a threat. When the number turns red, finds it easier to believe something once it stops being a minority view; remembers everyone birthday and no one boundaries.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('22032254-b154-40e4-8cb0-997861a47c73', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.63,"extraversion":0.7,"agreeableness":0.81,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.44,"narcissism":0.58,"psychopathy":0.33},"prospect_theory":{"lambda":2.27,"alpha":0.95,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This nonprofit convener takes on other people''s problems as if they were their own and treats a quiet room as a problem to be solved. As soon as real money or reputation is on the line defers to the most senior voice even against their own evidence — when the pressure is off, remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.64},{"slug":"herd-behavior","strength":0.64},{"slug":"endowment","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.63,"extraversion":0.7,"agreeableness":0.81,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This nonprofit convener takes on other people''s problems as if they were their own and treats a quiet room as a problem to be solved. As soon as real money or reputation is on the line defers to the most senior voice even against their own evidence — when the pressure is off, remembers who didn''t get invited last time.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('06b24aab-37c0-40d4-9d1e-4cdbb1d71484', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.38,"extraversion":0.86,"agreeableness":0.6,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.42,"narcissism":0.65,"psychopathy":0.33},"prospect_theory":{"lambda":1.32,"alpha":0.9,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Onchain copy-trader whose defining move is that they fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding. Does the interesting 80% and abandons the tedious 20%. The instant it becomes irreversible, treats being left out of a move as its own kind of loss; screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"optimism","strength":0.55},{"slug":"herd-behavior","strength":0.65},{"slug":"fomo","strength":0.73},{"slug":"bandwagon","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.67,"conscientiousness":0.38,"extraversion":0.86,"agreeableness":0.6,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Onchain copy-trader whose defining move is that they fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding. Does the interesting 80% and abandons the tedious 20%. The instant it becomes irreversible, treats being left out of a move as its own kind of loss; screenshots the winners and never the losers.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('19817f0d-5131-417a-987b-1bc743847c08', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.48,"extraversion":0.9,"agreeableness":0.78,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.38,"narcissism":0.7,"psychopathy":0.3},"prospect_theory":{"lambda":1.52,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Liquidation-bot operator whose defining move is that they recharges by being around people, not away from them. Outsources conviction to whoever spoke last with authority. Defaults to trust and gives the benefit of the doubt too freely. The moment it stops being hypothetical, adopts a conviction mainly because the room already has; exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.78},{"slug":"fomo","strength":0.76},{"slug":"endowment","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.48,"extraversion":0.9,"agreeableness":0.78,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Liquidation-bot operator whose defining move is that they recharges by being around people, not away from them. Outsources conviction to whoever spoke last with authority. Defaults to trust and gives the benefit of the doubt too freely. The moment it stops being hypothetical, adopts a conviction mainly because the room already has; exits winners at the first green candle.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('1f76c1ba-073f-4e5d-aefc-48053412f07f', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.56,"extraversion":0.72,"agreeableness":0.79,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.39,"narcissism":0.61,"psychopathy":0.34},"prospect_theory":{"lambda":2.34,"alpha":0.86,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A steady wedding-party diplomat: apologizes first in disputes regardless of fault, reads outside the field for ideas the field itself would reject. Outsources conviction to whoever spoke last with authority, and without an audience keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.68},{"slug":"endowment","strength":0.55},{"slug":"herd-behavior","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.71,"conscientiousness":0.56,"extraversion":0.72,"agreeableness":0.79,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A steady wedding-party diplomat: apologizes first in disputes regardless of fault, reads outside the field for ideas the field itself would reject. Outsources conviction to whoever spoke last with authority, and without an audience keeps score of favors without meaning to.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('5609b194-84ac-4845-90e5-db364405798c', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.38,"extraversion":0.84,"agreeableness":0.8,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.32,"narcissism":0.67,"psychopathy":0.32},"prospect_theory":{"lambda":1.27,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced bonding-curve sniper who draws energy from the crowd and wilts when working alone. Feels the weight of a decision lighten the moment someone else co-signs it. Chases novel frameworks and abandons them once the novelty fades. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it; left to their own devices, keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.81},{"slug":"herd-behavior","strength":0.81}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.38,"extraversion":0.84,"agreeableness":0.8,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced bonding-curve sniper who draws energy from the crowd and wilts when working alone. Feels the weight of a decision lighten the moment someone else co-signs it. Chases novel frameworks and abandons them once the novelty fades. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it; left to their own devices, keeps a losing-trade journal they never re-read.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('b17d0dd7-e20c-4d3e-8e8f-98ec22509960', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.52,"extraversion":0.84,"agreeableness":0.7,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.35,"narcissism":0.67,"psychopathy":0.26},"prospect_theory":{"lambda":1.27,"alpha":0.87,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced airdrop farmer who narrates the plan to whoever is nearby before committing to it. Needs the room''s approval more than it needs to be right. Takes on other people''s problems as if they were their own. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it; on a slow afternoon, screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"recency","strength":0.65},{"slug":"bandwagon","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.52,"extraversion":0.84,"agreeableness":0.7,"neuroticism":0.61}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced airdrop farmer who narrates the plan to whoever is nearby before committing to it. Needs the room''s approval more than it needs to be right. Takes on other people''s problems as if they were their own. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it; on a slow afternoon, screenshots the winners and never the losers.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f3e49eb6-ec2f-4912-9ae2-01c63f731bcb', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.35,"extraversion":0.86,"agreeableness":0.59,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.38,"narcissism":0.68,"psychopathy":0.31},"prospect_theory":{"lambda":1.38,"alpha":0.78,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A pronounced commodities speculator: dominates the room then wonders why others stayed quiet, collects half-finished manifestos and unconventional methods. Circles back to ask what someone else would do even after deciding, and when the pressure is off exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.6},{"slug":"bandwagon","strength":0.69},{"slug":"fomo","strength":0.69},{"slug":"dunning-kruger","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.64,"conscientiousness":0.35,"extraversion":0.86,"agreeableness":0.59,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A pronounced commodities speculator: dominates the room then wonders why others stayed quiet, collects half-finished manifestos and unconventional methods. Circles back to ask what someone else would do even after deciding, and when the pressure is off exits winners at the first green candle.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2787f6ef-bfa4-4a51-ab81-6164733ed5cf', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.47,"extraversion":0.88,"agreeableness":0.67,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.35,"narcissism":0.69,"psychopathy":0.28},"prospect_theory":{"lambda":1.29,"alpha":0.87,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Index-fund holdout, pronounced in style: narrates the plan to whoever is nearby before committing to it; chases novel frameworks and abandons them once the novelty fades. Waits for a permission that never quite arrives. When the downside gets concrete takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"fomo","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.47,"extraversion":0.88,"agreeableness":0.67,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Index-fund holdout, pronounced in style: narrates the plan to whoever is nearby before committing to it; chases novel frameworks and abandons them once the novelty fades. Waits for a permission that never quite arrives. When the downside gets concrete takes the crowd''s confidence as a substitute for its own analysis.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e1ee9322-9180-47ad-b2b0-f92624b3b694', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.72,"extraversion":0.77,"agreeableness":0.84,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.44,"narcissism":0.64,"psychopathy":0.41},"prospect_theory":{"lambda":2.28,"alpha":0.93,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Social-media strategist whose defining move is that they takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Front-loads the work and double-checks it twice. The moment risk appears, adopts a conviction mainly because the room already has; over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.78},{"slug":"authority-bias","strength":0.64},{"slug":"endowment","strength":0.57},{"slug":"herd-behavior","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.72,"extraversion":0.77,"agreeableness":0.84,"neuroticism":0.34}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Social-media strategist whose defining move is that they takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Front-loads the work and double-checks it twice. The moment risk appears, adopts a conviction mainly because the room already has; over-explains a boundary rather than just stating it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('b48a8536-9823-4889-8061-be3d71c2de3a', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.76,"extraversion":0.63,"agreeableness":0.76,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.47,"narcissism":0.46,"psychopathy":0.29},"prospect_theory":{"lambda":2.27,"alpha":0.94,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under a deadline, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady wedding-party diplomat who front-loads the work and double-checks it twice and treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right, and in the small things laughs first to test whether the room is safe to laugh.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.65},{"slug":"authority-bias","strength":0.59},{"slug":"sunk-cost","strength":0.56},{"slug":"herd-behavior","strength":0.6}],"tags":["social","dependent","community","mediator","high-agreeableness","disciplined","decision-making","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.55,"conscientiousness":0.76,"extraversion":0.63,"agreeableness":0.76,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','disciplined','decision-making','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under a deadline, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady wedding-party diplomat who front-loads the work and double-checks it twice and treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right, and in the small things laughs first to test whether the room is safe to laugh.', 0.88, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8e7a649f-01a6-4ffd-ad2e-7ed99713cbc8', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.52,"extraversion":0.72,"agreeableness":0.81,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.33,"narcissism":0.54,"psychopathy":0.34},"prospect_theory":{"lambda":2.31,"alpha":0.88,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Event host whose defining move is that they takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Recharges by being around people, not away from them. In a pinch, finds it hard to hold a contrarian position once the room disagrees; defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"endowment","strength":0.57},{"slug":"herd-behavior","strength":0.73},{"slug":"bandwagon","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.53,"conscientiousness":0.52,"extraversion":0.72,"agreeableness":0.81,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Event host whose defining move is that they takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Recharges by being around people, not away from them. In a pinch, finds it hard to hold a contrarian position once the room disagrees; defuses tension with a joke that lands most of the time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
