('d3d1b8e6-d1e5-4241-a686-b1682a3b2465', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.56,"extraversion":0.77,"agreeableness":0.87,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.35,"narcissism":0.58,"psychopathy":0.34},"prospect_theory":{"lambda":2.25,"alpha":0.9,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Group-chat ringleader whose defining move is that they reads other people''s discomfort before they voice it. Waits for a permission that never quite arrives. Draws energy from the crowd and wilts when working alone. When cornered, takes the crowd''s confidence as a substitute for its own analysis; remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.6},{"slug":"authority-bias","strength":0.65},{"slug":"fomo","strength":0.55},{"slug":"herd-behavior","strength":0.72}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.57,"conscientiousness":0.56,"extraversion":0.77,"agreeableness":0.87,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Group-chat ringleader whose defining move is that they reads other people''s discomfort before they voice it. Waits for a permission that never quite arrives. Draws energy from the crowd and wilts when working alone. When cornered, takes the crowd''s confidence as a substitute for its own analysis; remembers who didn''t get invited last time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2cb604de-da01-48a1-8bef-3b7bc9fa2199', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.64,"extraversion":0.81,"agreeableness":0.92,"neuroticism":0.37},"dark_triad":{"machiavellianism":0.4,"narcissism":0.67,"psychopathy":0.32},"prospect_theory":{"lambda":2.24,"alpha":0.91,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This social-media strategist defaults to trust and gives the benefit of the doubt too freely and over-prepares to the point of diminishing returns. Once things get tense finds it hard to hold a contrarian position once the room disagrees — in the unglamorous middle of things, mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"endowment","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.64,"extraversion":0.81,"agreeableness":0.92,"neuroticism":0.37}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This social-media strategist defaults to trust and gives the benefit of the doubt too freely and over-prepares to the point of diminishing returns. Once things get tense finds it hard to hold a contrarian position once the room disagrees — in the unglamorous middle of things, mediates conflicts they secretly started.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('57b63fd4-b55f-49e7-9cce-c004d3619a38', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.56,"extraversion":0.64,"agreeableness":0.86,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.39,"narcissism":0.55,"psychopathy":0.32},"prospect_theory":{"lambda":2.29,"alpha":0.93,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Nonprofit convener, pronounced in style: reads other people''s discomfort before they voice it; dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything. When the stakes rise takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.66},{"slug":"herd-behavior","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.56,"extraversion":0.64,"agreeableness":0.86,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Nonprofit convener, pronounced in style: reads other people''s discomfort before they voice it; dominates the room then wonders why others stayed quiet. Seeks a second, third, and fourth opinion before committing to anything. When the stakes rise takes the crowd''s confidence as a substitute for its own analysis.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('5b9ab52b-84a7-4704-aade-52e071fd8086', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.7,"extraversion":0.69,"agreeableness":0.71,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.47,"narcissism":0.57,"psychopathy":0.31},"prospect_theory":{"lambda":2.25,"alpha":0.93,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady community manager who would rather lose a point than win an argument badly. Needs the room''s approval more than it needs to be right. Narrates the plan to whoever is nearby before committing to it. Under a deadline adopts a conviction mainly because the room already has; in the unglamorous middle of things, keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.64},{"slug":"endowment","strength":0.58},{"slug":"bandwagon","strength":0.7},{"slug":"fomo","strength":0.56}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.7,"extraversion":0.69,"agreeableness":0.71,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady community manager who would rather lose a point than win an argument badly. Needs the room''s approval more than it needs to be right. Narrates the plan to whoever is nearby before committing to it. Under a deadline adopts a conviction mainly because the room already has; in the unglamorous middle of things, keeps score of favors without meaning to.', 0.9, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('80b28de6-5e27-4a83-bda4-ff86f6e25c99', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.39,"extraversion":0.89,"agreeableness":0.7,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.41,"narcissism":0.73,"psychopathy":0.29},"prospect_theory":{"lambda":1.35,"alpha":0.83,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This DeFi yield farmer fills silence reflexively, even when nobody asked it to and measures decisions by who they might upset. When the number turns red finds it easier to believe something once it stops being a minority view — day to day, keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.66},{"slug":"fomo","strength":0.76},{"slug":"bandwagon","strength":0.78},{"slug":"dunning-kruger","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.83,"conscientiousness":0.39,"extraversion":0.89,"agreeableness":0.7,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This DeFi yield farmer fills silence reflexively, even when nobody asked it to and measures decisions by who they might upset. When the number turns red finds it easier to believe something once it stops being a minority view — day to day, keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e3d62f0e-c097-46b9-af6e-7dd30c0c51d5', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.33,"extraversion":0.85,"agreeableness":0.67,"neuroticism":0.74},"dark_triad":{"machiavellianism":0.36,"narcissism":0.61,"psychopathy":0.33},"prospect_theory":{"lambda":1.5,"alpha":0.77,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A pronounced DeFi yield farmer: draws energy from the crowd and wilts when working alone, chases novel frameworks and abandons them once the novelty fades. Outsources conviction to whoever spoke last with authority, and without an audience calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.77},{"slug":"bandwagon","strength":0.66},{"slug":"recency","strength":0.67},{"slug":"dunning-kruger","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.33,"extraversion":0.85,"agreeableness":0.67,"neuroticism":0.74}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A pronounced DeFi yield farmer: draws energy from the crowd and wilts when working alone, chases novel frameworks and abandons them once the novelty fades. Outsources conviction to whoever spoke last with authority, and without an audience calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ce85a817-c412-471e-a495-dc7f671f5d45', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.61,"extraversion":0.81,"agreeableness":0.96,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.36,"narcissism":0.71,"psychopathy":0.37},"prospect_theory":{"lambda":2.4,"alpha":0.93,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced group-project default leader who takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Collects half-finished manifestos and unconventional methods. The instant the deadline moves up finds it easier to believe something once it stops being a minority view; as a rule, defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.6},{"slug":"authority-bias","strength":0.72},{"slug":"endowment","strength":0.67},{"slug":"bandwagon","strength":0.79}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.76,"conscientiousness":0.61,"extraversion":0.81,"agreeableness":0.96,"neuroticism":0.38}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced group-project default leader who takes on other people''s problems as if they were their own. Waits for a permission that never quite arrives. Collects half-finished manifestos and unconventional methods. The instant the deadline moves up finds it easier to believe something once it stops being a minority view; as a rule, defuses tension with a joke that lands most of the time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('61e9e3e7-239b-45b8-993c-6ea277af9a7f', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.51,"extraversion":0.74,"agreeableness":0.74,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.4,"narcissism":0.58,"psychopathy":0.31},"prospect_theory":{"lambda":1.26,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Options seller, steady in style: treats a quiet room as a problem to be solved; gets bored of the proven method exactly when it starts working. Trusts the group''s confidence more than its own. When the walls close in finds it hard to hold a contrarian position once the room disagrees.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.64},{"slug":"endowment","strength":0.58},{"slug":"fomo","strength":0.59}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.69,"conscientiousness":0.51,"extraversion":0.74,"agreeableness":0.74,"neuroticism":0.54}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Options seller, steady in style: treats a quiet room as a problem to be solved; gets bored of the proven method exactly when it starts working. Trusts the group''s confidence more than its own. When the walls close in finds it hard to hold a contrarian position once the room disagrees.', 0.89, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
