('90c31aa7-974c-42b2-afb1-c36a61d5b68b', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.35,"extraversion":0.87,"agreeableness":0.74,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.38,"narcissism":0.7,"psychopathy":0.33},"prospect_theory":{"lambda":1.23,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The instant the deadline moves up, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced discretionary swing trader who thinks out loud and recruits an audience for every decision and measures decisions by who they might upset. Feels the weight of a decision lighten the moment someone else co-signs it, and when the stakes are trivial talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.67},{"slug":"herd-behavior","strength":0.82},{"slug":"fomo","strength":0.73},{"slug":"recency","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.82,"conscientiousness":0.35,"extraversion":0.87,"agreeableness":0.74,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The instant the deadline moves up, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced discretionary swing trader who thinks out loud and recruits an audience for every decision and measures decisions by who they might upset. Feels the weight of a decision lighten the moment someone else co-signs it, and when the stakes are trivial talks in win rate and never mentions size.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('636240a1-574c-4601-ac2a-baba02be4a9c', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.68,"extraversion":0.77,"agreeableness":0.9,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.41,"narcissism":0.6,"psychopathy":0.34},"prospect_theory":{"lambda":2.41,"alpha":0.91,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced longtime regular at the same three places who would rather lose a point than win an argument badly. Outsources conviction to whoever spoke last with authority. Reads outside the field for ideas the field itself would reject. In a pinch finds it easier to believe something once it stops being a minority view; in the unglamorous middle of things, mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.65},{"slug":"bandwagon","strength":0.81}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.68,"extraversion":0.77,"agreeableness":0.9,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced longtime regular at the same three places who would rather lose a point than win an argument badly. Outsources conviction to whoever spoke last with authority. Reads outside the field for ideas the field itself would reject. In a pinch finds it easier to believe something once it stops being a minority view; in the unglamorous middle of things, mediates conflicts they secretly started.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9f7c22b1-86af-492d-b24d-125af9281bfd', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.33,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.36,"narcissism":0.68,"psychopathy":0.32},"prospect_theory":{"lambda":1.4,"alpha":0.86,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This perps degen thinks out loud and recruits an audience for every decision and apologizes first in disputes regardless of fault. Under pressure takes the crowd''s confidence as a substitute for its own analysis — when no one is watching, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.64},{"slug":"fomo","strength":0.66},{"slug":"herd-behavior","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.33,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This perps degen thinks out loud and recruits an audience for every decision and apologizes first in disputes regardless of fault. Under pressure takes the crowd''s confidence as a substitute for its own analysis — when no one is watching, treats a green week as proof of skill and a red one as proof of bad luck.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('7e6b0853-f850-4203-9ef6-072dd93673a3', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.4,"extraversion":0.85,"agreeableness":0.75,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.36,"narcissism":0.7,"psychopathy":0.35},"prospect_theory":{"lambda":1.55,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This retail momentum chaser fills silence reflexively, even when nobody asked it to and measures decisions by who they might upset. Once things get tense finds it easier to believe something once it stops being a minority view — left to their own devices, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.77},{"slug":"fomo","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.4,"extraversion":0.85,"agreeableness":0.75,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This retail momentum chaser fills silence reflexively, even when nobody asked it to and measures decisions by who they might upset. Once things get tense finds it easier to believe something once it stops being a minority view — left to their own devices, treats a green week as proof of skill and a red one as proof of bad luck.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('751d77cb-df11-4f4b-affc-c2bbb03df61c', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.39,"extraversion":0.8,"agreeableness":0.68,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.35,"narcissism":0.66,"psychopathy":0.39},"prospect_theory":{"lambda":1.53,"alpha":0.86,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A steady quant researcher: fills silence reflexively, even when nobody asked it to, measures decisions by who they might upset. Waits for a permission that never quite arrives, and in the routine of it names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.59},{"slug":"bandwagon","strength":0.67},{"slug":"herd-behavior","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.61,"conscientiousness":0.39,"extraversion":0.8,"agreeableness":0.68,"neuroticism":0.45}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A steady quant researcher: fills silence reflexively, even when nobody asked it to, measures decisions by who they might upset. Waits for a permission that never quite arrives, and in the routine of it names every strategy after the trade that almost worked.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('7c9ffd6e-0e09-463b-bb46-c42b0a984ccb', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.59,"extraversion":0.69,"agreeableness":0.84,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.39,"narcissism":0.56,"psychopathy":0.27},"prospect_theory":{"lambda":2.33,"alpha":0.94,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This reluctant plus-one would rather lose a point than win an argument badly and draws energy from the crowd and wilts when working alone. When the stakes rise gains confidence in a position in proportion to how many others hold it — across the quiet stretches, texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.7},{"slug":"herd-behavior","strength":0.7}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.57,"conscientiousness":0.59,"extraversion":0.69,"agreeableness":0.84,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This reluctant plus-one would rather lose a point than win an argument badly and draws energy from the crowd and wilts when working alone. When the stakes rise gains confidence in a position in proportion to how many others hold it — across the quiet stretches, texts an apology before confirming anyone is upset.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('59b278f7-48fc-409e-9a49-0a441b7c419c', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.56,"extraversion":0.72,"agreeableness":0.85,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.33,"narcissism":0.57,"psychopathy":0.31},"prospect_theory":{"lambda":2.52,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This family peacemaker defaults to trust and gives the benefit of the doubt too freely and recharges by being around people, not away from them. When the downside gets concrete adopts a conviction mainly because the room already has — across an ordinary week, says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.78},{"slug":"endowment","strength":0.62}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.56,"extraversion":0.72,"agreeableness":0.85,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This family peacemaker defaults to trust and gives the benefit of the doubt too freely and recharges by being around people, not away from them. When the downside gets concrete adopts a conviction mainly because the room already has — across an ordinary week, says yes out loud and no internally.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('ad14920b-153b-43ae-b33a-551914d13951', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.45,"extraversion":0.92,"agreeableness":0.69,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.39,"narcissism":0.72,"psychopathy":0.28},"prospect_theory":{"lambda":1.51,"alpha":0.84,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A pronounced futures spreader: fills silence reflexively, even when nobody asked it to, absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own, and on an ordinary week screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"optimism","strength":0.59},{"slug":"fomo","strength":0.75},{"slug":"dunning-kruger","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.45,"extraversion":0.92,"agreeableness":0.69,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A pronounced futures spreader: fills silence reflexively, even when nobody asked it to, absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own, and on an ordinary week screenshots the winners and never the losers.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c85f1af3-6987-47e6-b255-50d61ca46036', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.61,"extraversion":0.63,"agreeableness":0.96,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.4,"narcissism":0.52,"psychopathy":0.3},"prospect_theory":{"lambda":2.28,"alpha":0.88,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced online moderator who absorbs conflict to keep the peace, often at their own cost. Seeks a second, third, and fourth opinion before committing to anything. Collects half-finished manifestos and unconventional methods. When the number turns red adopts a conviction mainly because the room already has; on an ordinary week, says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"bandwagon","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.61,"extraversion":0.63,"agreeableness":0.96,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced online moderator who absorbs conflict to keep the peace, often at their own cost. Seeks a second, third, and fourth opinion before committing to anything. Collects half-finished manifestos and unconventional methods. When the number turns red adopts a conviction mainly because the room already has; on an ordinary week, says yes out loud and no internally.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bb91a5fb-fd1a-4754-8832-3ef60c0f8c87', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.42,"extraversion":0.93,"agreeableness":0.72,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.36,"narcissism":0.73,"psychopathy":0.31},"prospect_theory":{"lambda":1.57,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Crypto day-trader whose defining move is that they treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right. Treats established procedure as a first draft to be rewritten. The moment it stops being hypothetical, gains confidence in a position in proportion to how many others hold it; sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.77},{"slug":"optimism","strength":0.63},{"slug":"fomo","strength":0.7},{"slug":"bandwagon","strength":0.81}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.42,"extraversion":0.93,"agreeableness":0.72,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Crypto day-trader whose defining move is that they treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right. Treats established procedure as a first draft to be rewritten. The moment it stops being hypothetical, gains confidence in a position in proportion to how many others hold it; sizes every position at exactly 2% risk.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0a634779-6773-43b5-a718-c852fbf05d01', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.34,"extraversion":0.92,"agreeableness":0.71,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.39,"narcissism":0.78,"psychopathy":0.35},"prospect_theory":{"lambda":1.36,"alpha":0.84,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced macro allocator who narrates the plan to whoever is nearby before committing to it. Feels the weight of a decision lighten the moment someone else co-signs it. Takes on other people''s problems as if they were their own. Under pressure cannot watch a rally from the sidelines for long; on a slow afternoon, calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.73},{"slug":"fomo","strength":0.77},{"slug":"herd-behavior","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.34,"extraversion":0.92,"agreeableness":0.71,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced macro allocator who narrates the plan to whoever is nearby before committing to it. Feels the weight of a decision lighten the moment someone else co-signs it. Takes on other people''s problems as if they were their own. Under pressure cannot watch a rally from the sidelines for long; on a slow afternoon, calls a 90% drawdown a long-term hold.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c7ee8e18-f34b-41a9-bbad-861c22d3cad4', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.43,"extraversion":0.72,"agreeableness":0.88,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.34,"narcissism":0.59,"psychopathy":0.32},"prospect_theory":{"lambda":2.41,"alpha":0.91,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the downside gets concrete, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced team captain who defaults to trust and gives the benefit of the doubt too freely and treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right, and left to their own devices mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ESFP","suggested_biases":[{"slug":"sunk-cost","strength":0.66},{"slug":"herd-behavior","strength":0.77},{"slug":"authority-bias","strength":0.63},{"slug":"bandwagon","strength":0.76}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.49,"conscientiousness":0.43,"extraversion":0.72,"agreeableness":0.88,"neuroticism":0.48}'::jsonb, 'ESFP', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the downside gets concrete, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced team captain who defaults to trust and gives the benefit of the doubt too freely and treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right, and left to their own devices mediates conflicts they secretly started.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f1773eb6-5a8b-47cf-81f0-39bb4a9d4d32', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.57,"extraversion":0.76,"agreeableness":0.9,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.36,"narcissism":0.61,"psychopathy":0.3},"prospect_theory":{"lambda":2.49,"alpha":0.9,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This group-chat ringleader reads other people''s discomfort before they voice it and thinks out loud and recruits an audience for every decision. Once things get tense adopts a conviction mainly because the room already has — without an audience, laughs first to test whether the room is safe to laugh.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.69},{"slug":"bandwagon","strength":0.79},{"slug":"authority-bias","strength":0.6}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.51,"conscientiousness":0.57,"extraversion":0.76,"agreeableness":0.9,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This group-chat ringleader reads other people''s discomfort before they voice it and thinks out loud and recruits an audience for every decision. Once things get tense adopts a conviction mainly because the room already has — without an audience, laughs first to test whether the room is safe to laugh.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('1b81f7fb-f346-41de-bdda-8028db3b7a46', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.67,"extraversion":0.69,"agreeableness":0.76,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.4,"narcissism":0.56,"psychopathy":0.36},"prospect_theory":{"lambda":2.53,"alpha":0.87,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Wedding-party diplomat, steady in style: apologizes first in disputes regardless of fault; fills silence reflexively, even when nobody asked it to. Waits for a permission that never quite arrives. Under a deadline adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.57},{"slug":"endowment","strength":0.55},{"slug":"bandwagon","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.6,"conscientiousness":0.67,"extraversion":0.69,"agreeableness":0.76,"neuroticism":0.42}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Wedding-party diplomat, steady in style: apologizes first in disputes regardless of fault; fills silence reflexively, even when nobody asked it to. Waits for a permission that never quite arrives. Under a deadline adopts a conviction mainly because the room already has.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bb54298a-0fa1-45f8-9b04-646e3ce40ae8', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.49,"extraversion":0.82,"agreeableness":0.69,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.36,"narcissism":0.66,"psychopathy":0.26},"prospect_theory":{"lambda":1.53,"alpha":0.87,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"MEV searcher, steady in style: thinks out loud and recruits an audience for every decision; reframes every problem as an excuse to learn a new system. Seeks a second, third, and fourth opinion before committing to anything. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"herd-behavior","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.49,"extraversion":0.82,"agreeableness":0.69,"neuroticism":0.67}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'MEV searcher, steady in style: thinks out loud and recruits an audience for every decision; reframes every problem as an excuse to learn a new system. Seeks a second, third, and fourth opinion before committing to anything. When there is no clean exit takes the crowd''s confidence as a substitute for its own analysis.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('05c9ca72-ec27-468b-911d-dce910553593', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.63,"extraversion":0.7,"agreeableness":0.91,"neuroticism":0.37},"dark_triad":{"machiavellianism":0.39,"narcissism":0.58,"psychopathy":0.4},"prospect_theory":{"lambda":2.36,"alpha":0.86,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Adopts a conviction mainly because the room already has. A pronounced family peacemaker: absorbs conflict to keep the peace, often at their own cost, sleeps fine the night before the big call. Needs the room''s approval more than it needs to be right, and when no one is watching texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.65},{"slug":"bandwagon","strength":0.76}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.71,"conscientiousness":0.63,"extraversion":0.7,"agreeableness":0.91,"neuroticism":0.37}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Adopts a conviction mainly because the room already has. A pronounced family peacemaker: absorbs conflict to keep the peace, often at their own cost, sleeps fine the night before the big call. Needs the room''s approval more than it needs to be right, and when no one is watching texts an apology before confirming anyone is upset.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('79c5b693-7b34-4271-a362-ef8d59db4ccc', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.64,"extraversion":0.76,"agreeableness":0.84,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.37,"narcissism":0.58,"psychopathy":0.28},"prospect_theory":{"lambda":2.28,"alpha":0.9,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Online moderator, pronounced in style: absorbs conflict to keep the peace, often at their own cost; dominates the room then wonders why others stayed quiet. Waits for a permission that never quite arrives. When the number turns red abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.66},{"slug":"fomo","strength":0.67},{"slug":"herd-behavior","strength":0.76},{"slug":"endowment","strength":0.68}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.64,"extraversion":0.76,"agreeableness":0.84,"neuroticism":0.51}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Online moderator, pronounced in style: absorbs conflict to keep the peace, often at their own cost; dominates the room then wonders why others stayed quiet. Waits for a permission that never quite arrives. When the number turns red abandons a private read the instant the crowd leans the other way.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('11532adb-0232-41fb-8430-0e6228f2dbed', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.43,"extraversion":0.85,"agreeableness":0.75,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.4,"narcissism":0.68,"psychopathy":0.35},"prospect_theory":{"lambda":1.38,"alpha":0.83,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced airdrop farmer who recharges by being around people, not away from them and reframes every problem as an excuse to learn a new system. Seeks a second, third, and fourth opinion before committing to anything, and across the quiet stretches rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"dunning-kruger","strength":0.68},{"slug":"bandwagon","strength":0.8}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.43,"extraversion":0.85,"agreeableness":0.75,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced airdrop farmer who recharges by being around people, not away from them and reframes every problem as an excuse to learn a new system. Seeks a second, third, and fourth opinion before committing to anything, and across the quiet stretches rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('596d933c-dcbd-4588-9f75-d5661f00a328', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.61,"extraversion":0.82,"agreeableness":0.87,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.35,"narcissism":0.66,"psychopathy":0.28},"prospect_theory":{"lambda":2.44,"alpha":0.91,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Unofficial group historian, pronounced in style: absorbs conflict to keep the peace, often at their own cost; draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.81},{"slug":"herd-behavior","strength":0.8}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.72,"conscientiousness":0.61,"extraversion":0.82,"agreeableness":0.87,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Unofficial group historian, pronounced in style: absorbs conflict to keep the peace, often at their own cost; draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('246207e2-e32b-4a2b-90c6-5146478dc5c7', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.48,"extraversion":0.84,"agreeableness":0.76,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.39,"narcissism":0.63,"psychopathy":0.31},"prospect_theory":{"lambda":1.55,"alpha":0.85,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced index-fund holdout who thinks out loud and recruits an audience for every decision. Outsources conviction to whoever spoke last with authority. Takes on other people''s problems as if they were their own. In a pinch adopts a conviction mainly because the room already has; on a slow afternoon, sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"herd-behavior","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.48,"extraversion":0.84,"agreeableness":0.76,"neuroticism":0.7}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced index-fund holdout who thinks out loud and recruits an audience for every decision. Outsources conviction to whoever spoke last with authority. Takes on other people''s problems as if they were their own. In a pinch adopts a conviction mainly because the room already has; on a slow afternoon, sizes every position at exactly 2% risk.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f4ee90d8-c285-44ed-a620-4d3a62be4e65', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.65,"extraversion":0.59,"agreeableness":0.81,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.43,"narcissism":0.45,"psychopathy":0.26},"prospect_theory":{"lambda":2.33,"alpha":0.92,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the number turns red, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady nonprofit convener who measures decisions by who they might upset and treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority, and in the parts nobody grades drafts the apology before the mistake.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.61},{"slug":"authority-bias","strength":0.58},{"slug":"endowment","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.65,"extraversion":0.59,"agreeableness":0.81,"neuroticism":0.47}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the number turns red, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady nonprofit convener who measures decisions by who they might upset and treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority, and in the parts nobody grades drafts the apology before the mistake.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('595cdcd8-8a32-4ca3-9057-ff5d29271bfb', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.27,"extraversion":0.87,"agreeableness":0.68,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.36,"narcissism":0.7,"psychopathy":0.36},"prospect_theory":{"lambda":1.31,"alpha":0.8,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced onchain copy-trader who treats a quiet room as a problem to be solved. Waits for a permission that never quite arrives. Leaves loose ends and trusts future-self to handle them. The moment risk appears abandons a private read the instant the crowd leans the other way; left to their own devices, sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.77},{"slug":"fomo","strength":0.76},{"slug":"herd-behavior","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.27,"extraversion":0.87,"agreeableness":0.68,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced onchain copy-trader who treats a quiet room as a problem to be solved. Waits for a permission that never quite arrives. Leaves loose ends and trusts future-self to handle them. The moment risk appears abandons a private read the instant the crowd leans the other way; left to their own devices, sizes every position at exactly 2% risk.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('93ace3de-853f-48df-8b77-a17b68902620', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.49,"extraversion":0.77,"agreeableness":0.72,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.38,"narcissism":0.64,"psychopathy":0.28},"prospect_theory":{"lambda":1.34,"alpha":0.9,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A steady discretionary swing trader: treats a quiet room as a problem to be solved, absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding, and in the parts nobody grades apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"bandwagon","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.49,"extraversion":0.77,"agreeableness":0.72,"neuroticism":0.48}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A steady discretionary swing trader: treats a quiet room as a problem to be solved, absorbs conflict to keep the peace, often at their own cost. Circles back to ask what someone else would do even after deciding, and in the parts nobody grades apes the launch before the contract is verified.', 0.89, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
