('9969cfe9-d6e1-464d-b209-82b478907746', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.39,"extraversion":0.74,"agreeableness":0.7,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.38,"narcissism":0.58,"psychopathy":0.3},"prospect_theory":{"lambda":1.53,"alpha":0.84,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This futures spreader reads outside the field for ideas the field itself would reject and dominates the room then wonders why others stayed quiet. Once things get tense abandons a private read the instant the crowd leans the other way — in the pattern nobody else tracks, checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.68},{"slug":"dunning-kruger","strength":0.58},{"slug":"herd-behavior","strength":0.69},{"slug":"recency","strength":0.59}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.39,"extraversion":0.74,"agreeableness":0.7,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This futures spreader reads outside the field for ideas the field itself would reject and dominates the room then wonders why others stayed quiet. Once things get tense abandons a private read the instant the crowd leans the other way — in the pattern nobody else tracks, checks the P&L blotter forty times before lunch.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e7ad5451-2758-4b36-aa7f-b5e81f4933b0', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.44,"extraversion":0.86,"agreeableness":0.72,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.37,"narcissism":0.68,"psychopathy":0.27},"prospect_theory":{"lambda":1.39,"alpha":0.9,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A pronounced MEV searcher: dominates the room then wonders why others stayed quiet, chases novel frameworks and abandons them once the novelty fades. Waits for a permission that never quite arrives, and on an ordinary week trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.61},{"slug":"herd-behavior","strength":0.8},{"slug":"bandwagon","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.68,"conscientiousness":0.44,"extraversion":0.86,"agreeableness":0.72,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A pronounced MEV searcher: dominates the room then wonders why others stayed quiet, chases novel frameworks and abandons them once the novelty fades. Waits for a permission that never quite arrives, and on an ordinary week trusts the chart more than the fundamentals and won''t say why.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('503db79e-b55a-4130-815e-5425aa21ee77', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.57,"extraversion":0.71,"agreeableness":0.91,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.36,"narcissism":0.61,"psychopathy":0.33},"prospect_theory":{"lambda":2.25,"alpha":0.89,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment risk appears, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced nonprofit convener who measures decisions by who they might upset and dominates the room then wonders why others stayed quiet. Feels the weight of a decision lighten the moment someone else co-signs it, and left to their own devices laughs first to test whether the room is safe to laugh.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.62},{"slug":"endowment","strength":0.62},{"slug":"bandwagon","strength":0.8}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.73,"conscientiousness":0.57,"extraversion":0.71,"agreeableness":0.91,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment risk appears, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced nonprofit convener who measures decisions by who they might upset and dominates the room then wonders why others stayed quiet. Feels the weight of a decision lighten the moment someone else co-signs it, and left to their own devices laughs first to test whether the room is safe to laugh.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bd327649-7f9e-4b8e-92a0-a5af6a67192f', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.38,"extraversion":0.76,"agreeableness":0.81,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.32,"narcissism":0.66,"psychopathy":0.36},"prospect_theory":{"lambda":1.48,"alpha":0.81,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"As soon as real money or reputation is on the line, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady perps degen who defaults to trust and gives the benefit of the doubt too freely and treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority, and in the small things keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"sunk-cost","strength":0.68},{"slug":"fomo","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.79,"conscientiousness":0.38,"extraversion":0.76,"agreeableness":0.81,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'As soon as real money or reputation is on the line, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady perps degen who defaults to trust and gives the benefit of the doubt too freely and treats established procedure as a first draft to be rewritten. Outsources conviction to whoever spoke last with authority, and in the small things keeps a losing-trade journal they never re-read.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('793db88b-f813-4df6-8fc5-c8f1c39d7f40', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.4,"extraversion":0.91,"agreeableness":0.77,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.35,"narcissism":0.76,"psychopathy":0.32},"prospect_theory":{"lambda":1.39,"alpha":0.84,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced quant researcher who recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything. Chases novel frameworks and abandons them once the novelty fades. The instant the deadline moves up abandons a private read the instant the crowd leans the other way; on an ordinary week, apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"herd-behavior","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.4,"extraversion":0.91,"agreeableness":0.77,"neuroticism":0.52}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced quant researcher who recharges by being around people, not away from them. Seeks a second, third, and fourth opinion before committing to anything. Chases novel frameworks and abandons them once the novelty fades. The instant the deadline moves up abandons a private read the instant the crowd leans the other way; on an ordinary week, apes the launch before the contract is verified.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bea384e9-c6b6-4515-bfed-9794bf406bf2', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.4,"extraversion":0.82,"agreeableness":0.6,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.43,"narcissism":0.65,"psychopathy":0.29},"prospect_theory":{"lambda":1.5,"alpha":0.82,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady zero-DTE options gambler who treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right. Reframes every problem as an excuse to learn a new system. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it; once the urgency drains out, averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.65},{"slug":"bandwagon","strength":0.68},{"slug":"herd-behavior","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.4,"extraversion":0.82,"agreeableness":0.6,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady zero-DTE options gambler who treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right. Reframes every problem as an excuse to learn a new system. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it; once the urgency drains out, averages down on a name three times in a week.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('21f118b6-03a2-4ee5-ac88-684854be434a', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.48,"extraversion":0.86,"agreeableness":0.69,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.4,"narcissism":0.69,"psychopathy":0.27},"prospect_theory":{"lambda":1.42,"alpha":0.86,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This perps degen recharges by being around people, not away from them and reads other people''s discomfort before they voice it. Once things get tense jumps into whatever everyone else already seems to be winning at — in the small things, exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"recency","strength":0.56},{"slug":"dunning-kruger","strength":0.58},{"slug":"fomo","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.48,"extraversion":0.86,"agreeableness":0.69,"neuroticism":0.65}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This perps degen recharges by being around people, not away from them and reads other people''s discomfort before they voice it. Once things get tense jumps into whatever everyone else already seems to be winning at — in the small things, exits winners at the first green candle.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f953c398-8df9-4352-baac-deb90e35ab83', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.39,"extraversion":0.9,"agreeableness":0.59,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.44,"narcissism":0.69,"psychopathy":0.3},"prospect_theory":{"lambda":1.32,"alpha":0.83,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This crypto day-trader fills silence reflexively, even when nobody asked it to and reads outside the field for ideas the field itself would reject. When there is no clean exit treats being left out of a move as its own kind of loss — day to day, holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.77},{"slug":"herd-behavior","strength":0.7},{"slug":"bandwagon","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.39,"extraversion":0.9,"agreeableness":0.59,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This crypto day-trader fills silence reflexively, even when nobody asked it to and reads outside the field for ideas the field itself would reject. When there is no clean exit treats being left out of a move as its own kind of loss — day to day, holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9726e5ee-a418-4ed7-accd-d5ec38fb368a', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.38,"extraversion":0.84,"agreeableness":0.73,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.35,"narcissism":0.7,"psychopathy":0.3},"prospect_theory":{"lambda":1.56,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A pronounced onchain copy-trader: dominates the room then wonders why others stayed quiet, improvises past every deadline and calls it flexibility. Needs the room''s approval more than it needs to be right, and on a slow afternoon trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.66},{"slug":"herd-behavior","strength":0.78}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.38,"extraversion":0.84,"agreeableness":0.73,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A pronounced onchain copy-trader: dominates the room then wonders why others stayed quiet, improvises past every deadline and calls it flexibility. Needs the room''s approval more than it needs to be right, and on a slow afternoon trusts the chart more than the fundamentals and won''t say why.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('282fc9b7-622e-4b0c-9e97-5ef931a16686', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.68,"extraversion":0.7,"agreeableness":0.87,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.43,"narcissism":0.6,"psychopathy":0.31},"prospect_theory":{"lambda":2.32,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment it stops being hypothetical, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced event host who absorbs conflict to keep the peace, often at their own cost and cannot relax until the checklist is visibly complete. Needs the room''s approval more than it needs to be right, and across the quiet stretches keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.67},{"slug":"herd-behavior","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.68,"extraversion":0.7,"agreeableness":0.87,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The moment it stops being hypothetical, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced event host who absorbs conflict to keep the peace, often at their own cost and cannot relax until the checklist is visibly complete. Needs the room''s approval more than it needs to be right, and across the quiet stretches keeps score of favors without meaning to.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('0f9b0732-ab40-4e79-9558-062702964db6', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.46,"extraversion":0.93,"agreeableness":0.72,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.37,"narcissism":0.73,"psychopathy":0.34},"prospect_theory":{"lambda":1.57,"alpha":0.83,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Penny-stock gambler whose defining move is that they thinks out loud and recruits an audience for every decision. Needs the room''s approval more than it needs to be right. Chases novel frameworks and abandons them once the novelty fades. When cornered, abandons a private read the instant the crowd leans the other way; sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.85},{"slug":"optimism","strength":0.73},{"slug":"dunning-kruger","strength":0.61},{"slug":"fomo","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.66,"conscientiousness":0.46,"extraversion":0.93,"agreeableness":0.72,"neuroticism":0.41}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Penny-stock gambler whose defining move is that they thinks out loud and recruits an audience for every decision. Needs the room''s approval more than it needs to be right. Chases novel frameworks and abandons them once the novelty fades. When cornered, abandons a private read the instant the crowd leans the other way; sets stop-losses then cancels them at the open.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
