('ad4da266-065d-40af-b3e7-1cab3fa217f8', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.51,"extraversion":0.69,"agreeableness":0.86,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.3,"narcissism":0.52,"psychopathy":0.4},"prospect_theory":{"lambda":2.23,"alpha":0.84,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced wedding-party diplomat who would rather lose a point than win an argument badly. Needs the room''s approval more than it needs to be right. Dominates the room then wonders why others stayed quiet. The moment risk appears finds it hard to hold a contrarian position once the room disagrees; when the stakes are trivial, says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.59},{"slug":"herd-behavior","strength":0.68}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.51,"extraversion":0.69,"agreeableness":0.86,"neuroticism":0.35}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced wedding-party diplomat who would rather lose a point than win an argument badly. Needs the room''s approval more than it needs to be right. Dominates the room then wonders why others stayed quiet. The moment risk appears finds it hard to hold a contrarian position once the room disagrees; when the stakes are trivial, says yes out loud and no internally.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e050ca76-e11a-4a7a-a778-3f93f40b1cf8', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.55,"extraversion":0.79,"agreeableness":0.88,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.38,"narcissism":0.65,"psychopathy":0.32},"prospect_theory":{"lambda":2.39,"alpha":0.89,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under a deadline, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced group-project default leader who defaults to trust and gives the benefit of the doubt too freely and narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority, and in the version no one reviews over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.76},{"slug":"herd-behavior","strength":0.81}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.59,"conscientiousness":0.55,"extraversion":0.79,"agreeableness":0.88,"neuroticism":0.44}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under a deadline, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced group-project default leader who defaults to trust and gives the benefit of the doubt too freely and narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority, and in the version no one reviews over-commits to plans they later dread.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('835c0be4-3f6d-4f0f-b078-8d8defd66237', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.72,"extraversion":0.7,"agreeableness":0.89,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.46,"narcissism":0.59,"psychopathy":0.31},"prospect_theory":{"lambda":2.43,"alpha":0.96,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This community manager absorbs conflict to keep the peace, often at their own cost and treats established procedure as a first draft to be rewritten. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it — in the parts nobody grades, over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.55},{"slug":"authority-bias","strength":0.68},{"slug":"endowment","strength":0.59},{"slug":"bandwagon","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.72,"extraversion":0.7,"agreeableness":0.89,"neuroticism":0.49}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This community manager absorbs conflict to keep the peace, often at their own cost and treats established procedure as a first draft to be rewritten. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it — in the parts nobody grades, over-commits to plans they later dread.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('cc8e9bf7-30c8-4e9e-9c88-722779a06e14', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.44,"extraversion":0.86,"agreeableness":0.68,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.38,"narcissism":0.67,"psychopathy":0.32},"prospect_theory":{"lambda":1.34,"alpha":0.83,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Dividend-yield chaser whose defining move is that they treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right. Gets bored of the proven method exactly when it starts working. When the stakes rise, finds it easier to believe something once it stops being a minority view; rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"herd-behavior","strength":0.72}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.44,"extraversion":0.86,"agreeableness":0.68,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Dividend-yield chaser whose defining move is that they treats a quiet room as a problem to be solved. Needs the room''s approval more than it needs to be right. Gets bored of the proven method exactly when it starts working. When the stakes rise, finds it easier to believe something once it stops being a minority view; rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3deaed6b-eab4-47b0-a4ae-c69d38a60e6c', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.35,"extraversion":0.9,"agreeableness":0.69,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.35,"narcissism":0.66,"psychopathy":0.35},"prospect_theory":{"lambda":1.54,"alpha":0.8,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Liquidation-bot operator whose defining move is that they narrates the plan to whoever is nearby before committing to it. Circles back to ask what someone else would do even after deciding. Needs repeated reassurance that a decision was the right one. The moment risk appears, jumps into whatever everyone else already seems to be winning at; holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.66},{"slug":"herd-behavior","strength":0.72},{"slug":"recency","strength":0.65},{"slug":"fomo","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.35,"extraversion":0.9,"agreeableness":0.69,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Liquidation-bot operator whose defining move is that they narrates the plan to whoever is nearby before committing to it. Circles back to ask what someone else would do even after deciding. Needs repeated reassurance that a decision was the right one. The moment risk appears, jumps into whatever everyone else already seems to be winning at; holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('64f3f03c-fa21-4a59-9049-29df4b27ec0c', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.58,"extraversion":0.67,"agreeableness":0.83,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.37,"narcissism":0.58,"psychopathy":0.26},"prospect_theory":{"lambda":2.4,"alpha":0.91,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This social-media strategist reads other people''s discomfort before they voice it and draws energy from the crowd and wilts when working alone. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way — when the pressure is off, over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.63},{"slug":"endowment","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.58,"extraversion":0.67,"agreeableness":0.83,"neuroticism":0.49}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This social-media strategist reads other people''s discomfort before they voice it and draws energy from the crowd and wilts when working alone. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way — when the pressure is off, over-explains a boundary rather than just stating it.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2ade0000-d5d1-475e-a551-df9b6eff5443', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.38,"extraversion":0.83,"agreeableness":0.69,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.35,"narcissism":0.66,"psychopathy":0.38},"prospect_theory":{"lambda":1.55,"alpha":0.91,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Retail momentum chaser whose defining move is that they treats a quiet room as a problem to be solved. Seeks a second, third, and fourth opinion before committing to anything. Reframes every problem as an excuse to learn a new system. When the stakes rise, mistakes a little fluency for real mastery; names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.69},{"slug":"dunning-kruger","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.38,"extraversion":0.83,"agreeableness":0.69,"neuroticism":0.48}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Retail momentum chaser whose defining move is that they treats a quiet room as a problem to be solved. Seeks a second, third, and fourth opinion before committing to anything. Reframes every problem as an excuse to learn a new system. When the stakes rise, mistakes a little fluency for real mastery; names every strategy after the trade that almost worked.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('59734961-489c-4747-991b-02faefb92f54', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.57,"extraversion":0.71,"agreeableness":0.85,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.38,"narcissism":0.6,"psychopathy":0.34},"prospect_theory":{"lambda":2.57,"alpha":0.89,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The friend who always drives, pronounced in style: measures decisions by who they might upset; thinks out loud and recruits an audience for every decision. Outsources conviction to whoever spoke last with authority. Once things get tense finds it easier to believe something once it stops being a minority view.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"endowment","strength":0.61},{"slug":"authority-bias","strength":0.59}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.71,"conscientiousness":0.57,"extraversion":0.71,"agreeableness":0.85,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The friend who always drives, pronounced in style: measures decisions by who they might upset; thinks out loud and recruits an audience for every decision. Outsources conviction to whoever spoke last with authority. Once things get tense finds it easier to believe something once it stops being a minority view.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6060d0d7-5c27-466d-b932-26d91dd317e5', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.4,"extraversion":0.79,"agreeableness":0.62,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.36,"narcissism":0.67,"psychopathy":0.29},"prospect_theory":{"lambda":1.55,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A pronounced pairs trader: reads outside the field for ideas the field itself would reject, narrates the plan to whoever is nearby before committing to it. Waits for a permission that never quite arrives, and in the unglamorous middle of things keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"herd-behavior","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.87,"conscientiousness":0.4,"extraversion":0.79,"agreeableness":0.62,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A pronounced pairs trader: reads outside the field for ideas the field itself would reject, narrates the plan to whoever is nearby before committing to it. Waits for a permission that never quite arrives, and in the unglamorous middle of things keeps a losing-trade journal they never re-read.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3a0d31e8-1311-4344-a540-2be9af5081d3', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.54,"extraversion":0.7,"agreeableness":0.89,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.37,"narcissism":0.55,"psychopathy":0.35},"prospect_theory":{"lambda":2.55,"alpha":0.84,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the number turns red, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced wedding-party diplomat who would rather lose a point than win an argument badly and sleeps fine the night before the big call. Feels the weight of a decision lighten the moment someone else co-signs it, and left to their own devices mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.73},{"slug":"bandwagon","strength":0.76},{"slug":"authority-bias","strength":0.68},{"slug":"endowment","strength":0.66}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.54,"extraversion":0.7,"agreeableness":0.89,"neuroticism":0.35}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the number turns red, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced wedding-party diplomat who would rather lose a point than win an argument badly and sleeps fine the night before the big call. Feels the weight of a decision lighten the moment someone else co-signs it, and left to their own devices mediates conflicts they secretly started.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f9f53795-fe69-4856-9d7a-515f7621a57f', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.58,"extraversion":0.6,"agreeableness":0.84,"neuroticism":0.37},"dark_triad":{"machiavellianism":0.34,"narcissism":0.49,"psychopathy":0.37},"prospect_theory":{"lambda":2.35,"alpha":0.92,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A pronounced longtime regular at the same three places: takes on other people''s problems as if they were their own, is difficult to rattle even with genuinely bad news. Outsources conviction to whoever spoke last with authority, and when the pressure is off says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.63},{"slug":"endowment","strength":0.66},{"slug":"bandwagon","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.58,"conscientiousness":0.58,"extraversion":0.6,"agreeableness":0.84,"neuroticism":0.37}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A pronounced longtime regular at the same three places: takes on other people''s problems as if they were their own, is difficult to rattle even with genuinely bad news. Outsources conviction to whoever spoke last with authority, and when the pressure is off says yes out loud and no internally.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
