('8f482dcd-6d88-4501-8eb9-fe7f478a578c', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.64,"extraversion":0.79,"agreeableness":0.94,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.36,"narcissism":0.68,"psychopathy":0.29},"prospect_theory":{"lambda":2.51,"alpha":0.88,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Group-project default leader whose defining move is that they reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Would rather invent a worse tool than use someone else''s good one. The instant it becomes irreversible, gains confidence in a position in proportion to how many others hold it; drafts the apology before the mistake.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.82},{"slug":"bandwagon","strength":0.83},{"slug":"authority-bias","strength":0.66}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.64,"extraversion":0.79,"agreeableness":0.94,"neuroticism":0.42}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Group-project default leader whose defining move is that they reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Would rather invent a worse tool than use someone else''s good one. The instant it becomes irreversible, gains confidence in a position in proportion to how many others hold it; drafts the apology before the mistake.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e5213dae-0a0d-4701-b1fd-157440a3aa42', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.53,"extraversion":0.71,"agreeableness":0.79,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.39,"narcissism":0.58,"psychopathy":0.3},"prospect_theory":{"lambda":2.29,"alpha":0.92,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A steady wedding-party diplomat: measures decisions by who they might upset, gets bored of the proven method exactly when it starts working. Needs the room''s approval more than it needs to be right, and once the urgency drains out over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.7},{"slug":"authority-bias","strength":0.54},{"slug":"herd-behavior","strength":0.68},{"slug":"optimism","strength":0.56}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.71,"conscientiousness":0.53,"extraversion":0.71,"agreeableness":0.79,"neuroticism":0.42}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A steady wedding-party diplomat: measures decisions by who they might upset, gets bored of the proven method exactly when it starts working. Needs the room''s approval more than it needs to be right, and once the urgency drains out over-explains a boundary rather than just stating it.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('70536d91-5bae-4ee4-b648-ed48969c039d', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.44,"extraversion":0.83,"agreeableness":0.73,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.4,"narcissism":0.67,"psychopathy":0.29},"prospect_theory":{"lambda":1.38,"alpha":0.84,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady MEV searcher who thinks out loud and recruits an audience for every decision. Circles back to ask what someone else would do even after deciding. Chases novel frameworks and abandons them once the novelty fades. Once the exit narrows to one door finds it easier to believe something once it stops being a minority view; left to their own devices, backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.71},{"slug":"fomo","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.44,"extraversion":0.83,"agreeableness":0.73,"neuroticism":0.68}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady MEV searcher who thinks out loud and recruits an audience for every decision. Circles back to ask what someone else would do even after deciding. Chases novel frameworks and abandons them once the novelty fades. Once the exit narrows to one door finds it easier to believe something once it stops being a minority view; left to their own devices, backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2c00617c-89df-4b53-bae4-fcfd9441c9a4', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.48,"extraversion":0.89,"agreeableness":0.68,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.34,"narcissism":0.79,"psychopathy":0.26},"prospect_theory":{"lambda":1.34,"alpha":0.9,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts the group''s confidence more than its own. This discretionary swing trader dominates the room then wonders why others stayed quiet and defaults to trust and gives the benefit of the doubt too freely. When the stakes rise finds it hard to hold a contrarian position once the room disagrees — as a rule, trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"fomo","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.48,"extraversion":0.89,"agreeableness":0.68,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Trusts the group''s confidence more than its own. This discretionary swing trader dominates the room then wonders why others stayed quiet and defaults to trust and gives the benefit of the doubt too freely. When the stakes rise finds it hard to hold a contrarian position once the room disagrees — as a rule, trusts the chart more than the fundamentals and won''t say why.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4fd9b21c-fba6-450c-ab93-38a36c06a942', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.55,"extraversion":0.61,"agreeableness":0.81,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.33,"narcissism":0.53,"psychopathy":0.27},"prospect_theory":{"lambda":2.48,"alpha":0.9,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Community manager whose defining move is that they measures decisions by who they might upset. Circles back to ask what someone else would do even after deciding. As soon as real money or reputation is on the line, finds it hard to hold a contrarian position once the room disagrees; reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.61},{"slug":"endowment","strength":0.58}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.55,"extraversion":0.61,"agreeableness":0.81,"neuroticism":0.51}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Community manager whose defining move is that they measures decisions by who they might upset. Circles back to ask what someone else would do even after deciding. As soon as real money or reputation is on the line, finds it hard to hold a contrarian position once the room disagrees; reads the room then performs to it.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4092e0e2-511c-4070-8564-ad7686f4c5f3', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.69,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.34,"narcissism":0.68,"psychopathy":0.28},"prospect_theory":{"lambda":1.48,"alpha":0.9,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Perps degen, steady in style: thinks out loud and recruits an audience for every decision; measures decisions by who they might upset. Needs the room''s approval more than it needs to be right. When the number turns red abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.73},{"slug":"recency","strength":0.54},{"slug":"dunning-kruger","strength":0.6},{"slug":"bandwagon","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.43,"extraversion":0.83,"agreeableness":0.69,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Perps degen, steady in style: thinks out loud and recruits an audience for every decision; measures decisions by who they might upset. Needs the room''s approval more than it needs to be right. When the number turns red abandons a private read the instant the crowd leans the other way.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('fe885e3c-ff1c-44ee-bc34-f3e8187ac25f', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.65,"extraversion":0.79,"agreeableness":0.76,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.42,"narcissism":0.63,"psychopathy":0.25},"prospect_theory":{"lambda":2.54,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The instant it becomes irreversible, adopts a conviction mainly because the room already has. Otherwise, a steady nonprofit convener who treats a quiet room as a problem to be solved and reframes every problem as an excuse to learn a new system. Outsources conviction to whoever spoke last with authority, and in the unglamorous middle of things defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.56},{"slug":"authority-bias","strength":0.54},{"slug":"fomo","strength":0.62},{"slug":"bandwagon","strength":0.68}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.65,"extraversion":0.79,"agreeableness":0.76,"neuroticism":0.49}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'The instant it becomes irreversible, adopts a conviction mainly because the room already has. Otherwise, a steady nonprofit convener who treats a quiet room as a problem to be solved and reframes every problem as an excuse to learn a new system. Outsources conviction to whoever spoke last with authority, and in the unglamorous middle of things defuses tension with a joke that lands most of the time.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('da67d622-fdf9-45c3-816c-b8d6859e54fb', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.44,"extraversion":0.84,"agreeableness":0.67,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.39,"narcissism":0.68,"psychopathy":0.27},"prospect_theory":{"lambda":1.45,"alpha":0.88,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced prop-desk scalper who dominates the room then wonders why others stayed quiet. Circles back to ask what someone else would do even after deciding. Reframes every problem as an excuse to learn a new system. When the walls close in finds it easier to believe something once it stops being a minority view; day to day, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.74},{"slug":"herd-behavior","strength":0.71},{"slug":"dunning-kruger","strength":0.59},{"slug":"optimism","strength":0.54}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.64,"conscientiousness":0.44,"extraversion":0.84,"agreeableness":0.67,"neuroticism":0.5}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced prop-desk scalper who dominates the room then wonders why others stayed quiet. Circles back to ask what someone else would do even after deciding. Reframes every problem as an excuse to learn a new system. When the walls close in finds it easier to believe something once it stops being a minority view; day to day, treats a green week as proof of skill and a red one as proof of bad luck.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('896fc2c1-2b3d-4fef-93dd-9f5bd7cfb095', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.56,"extraversion":0.71,"agreeableness":0.82,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.35,"narcissism":0.57,"psychopathy":0.32},"prospect_theory":{"lambda":2.48,"alpha":0.94,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Waits for a permission that never quite arrives. This social-media strategist takes on other people''s problems as if they were their own and fills silence reflexively, even when nobody asked it to. Once things get tense gains confidence in a position in proportion to how many others hold it — as a rule, reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"bandwagon","strength":0.71},{"slug":"endowment","strength":0.66},{"slug":"optimism","strength":0.57}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.56,"extraversion":0.71,"agreeableness":0.82,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Waits for a permission that never quite arrives. This social-media strategist takes on other people''s problems as if they were their own and fills silence reflexively, even when nobody asked it to. Once things get tense gains confidence in a position in proportion to how many others hold it — as a rule, reads the room then performs to it.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2d43ce55-1e50-4f46-8dd7-d53c6badb260', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.35,"extraversion":0.84,"agreeableness":0.74,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.34,"narcissism":0.63,"psychopathy":0.34},"prospect_theory":{"lambda":1.23,"alpha":0.82,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When cornered, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced DeFi yield farmer who thinks out loud and recruits an audience for every decision and leaves loose ends and trusts future-self to handle them. Outsources conviction to whoever spoke last with authority, and in the pattern nobody else tracks refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.78},{"slug":"fomo","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.83,"conscientiousness":0.35,"extraversion":0.84,"agreeableness":0.74,"neuroticism":0.7}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When cornered, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced DeFi yield farmer who thinks out loud and recruits an audience for every decision and leaves loose ends and trusts future-self to handle them. Outsources conviction to whoever spoke last with authority, and in the pattern nobody else tracks refreshes the order book compulsively during lunch.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3f24ed13-b0c6-4556-985e-679bbc2a7226', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.6,"extraversion":0.74,"agreeableness":0.82,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.37,"narcissism":0.6,"psychopathy":0.24},"prospect_theory":{"lambda":2.51,"alpha":0.9,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A steady group-chat ringleader: defaults to trust and gives the benefit of the doubt too freely, gets bored of the proven method exactly when it starts working. Feels the weight of a decision lighten the moment someone else co-signs it, and in the parts nobody grades laughs first to test whether the room is safe to laugh.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.61},{"slug":"endowment","strength":0.6},{"slug":"herd-behavior","strength":0.75}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.76,"conscientiousness":0.6,"extraversion":0.74,"agreeableness":0.82,"neuroticism":0.54}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A steady group-chat ringleader: defaults to trust and gives the benefit of the doubt too freely, gets bored of the proven method exactly when it starts working. Feels the weight of a decision lighten the moment someone else co-signs it, and in the parts nobody grades laughs first to test whether the room is safe to laugh.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3185f4a2-7008-4474-8020-295e6ce2169e', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.65,"extraversion":0.72,"agreeableness":0.84,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.38,"narcissism":0.6,"psychopathy":0.39},"prospect_theory":{"lambda":2.34,"alpha":0.88,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under pressure, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced social-media strategist who reads other people''s discomfort before they voice it and dominates the room then wonders why others stayed quiet. Waits for a permission that never quite arrives, and in the version no one reviews remembers who didn''t get invited last time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"bandwagon","strength":0.77},{"slug":"endowment","strength":0.56}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.57,"conscientiousness":0.65,"extraversion":0.72,"agreeableness":0.84,"neuroticism":0.39}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under pressure, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced social-media strategist who reads other people''s discomfort before they voice it and dominates the room then wonders why others stayed quiet. Waits for a permission that never quite arrives, and in the version no one reviews remembers who didn''t get invited last time.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('fd9cbd1a-2892-4da2-b47a-a3e20f95cf26', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.57,"extraversion":0.73,"agreeableness":0.8,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.4,"narcissism":0.59,"psychopathy":0.34},"prospect_theory":{"lambda":2.39,"alpha":0.91,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Family peacemaker whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Seeks a second, third, and fourth opinion before committing to anything. Treats a quiet room as a problem to be solved. Under pressure, finds it hard to hold a contrarian position once the room disagrees; texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.72},{"slug":"optimism","strength":0.59}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.57,"extraversion":0.73,"agreeableness":0.8,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Family peacemaker whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Seeks a second, third, and fourth opinion before committing to anything. Treats a quiet room as a problem to be solved. Under pressure, finds it hard to hold a contrarian position once the room disagrees; texts an apology before confirming anyone is upset.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('5298a090-0799-4810-859a-f44386ded4ff', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.65,"extraversion":0.74,"agreeableness":0.81,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.45,"narcissism":0.58,"psychopathy":0.3},"prospect_theory":{"lambda":2.42,"alpha":0.95,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When there is no clean exit, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady event host who takes on other people''s problems as if they were their own and over-prepares to the point of diminishing returns. Needs the room''s approval more than it needs to be right, and day to day drafts the apology before the mistake.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.55},{"slug":"herd-behavior","strength":0.72},{"slug":"authority-bias","strength":0.6},{"slug":"bandwagon","strength":0.68}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.65,"extraversion":0.74,"agreeableness":0.81,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When there is no clean exit, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady event host who takes on other people''s problems as if they were their own and over-prepares to the point of diminishing returns. Needs the room''s approval more than it needs to be right, and day to day drafts the apology before the mistake.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2d58880e-3ccb-4ceb-ba86-fb197aa7026c', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.41,"extraversion":0.8,"agreeableness":0.62,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.39,"narcissism":0.69,"psychopathy":0.3},"prospect_theory":{"lambda":1.26,"alpha":0.82,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Liquidation-bot operator whose defining move is that they collects half-finished manifestos and unconventional methods. Trusts the group''s confidence more than its own. Apologizes first in disputes regardless of fault. The instant the deadline moves up, abandons a private read the instant the crowd leans the other way; averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"herd-behavior","strength":0.68},{"slug":"dunning-kruger","strength":0.61},{"slug":"recency","strength":0.59}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.8,"conscientiousness":0.41,"extraversion":0.8,"agreeableness":0.62,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Liquidation-bot operator whose defining move is that they collects half-finished manifestos and unconventional methods. Trusts the group''s confidence more than its own. Apologizes first in disputes regardless of fault. The instant the deadline moves up, abandons a private read the instant the crowd leans the other way; averages down on a name three times in a week.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('01843b7a-ce92-4c4e-b544-6945fed18de6', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.39,"extraversion":0.87,"agreeableness":0.7,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.35,"narcissism":0.66,"psychopathy":0.32},"prospect_theory":{"lambda":1.53,"alpha":0.84,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Liquidation-bot operator, pronounced in style: thinks out loud and recruits an audience for every decision; reframes every problem as an excuse to learn a new system. Outsources conviction to whoever spoke last with authority. In a pinch gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.74},{"slug":"herd-behavior","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.39,"extraversion":0.87,"agreeableness":0.7,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Liquidation-bot operator, pronounced in style: thinks out loud and recruits an audience for every decision; reframes every problem as an excuse to learn a new system. Outsources conviction to whoever spoke last with authority. In a pinch gains confidence in a position in proportion to how many others hold it.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c353642e-effa-42a8-982b-4e18664aa2bf', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.38,"extraversion":0.88,"agreeableness":0.7,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.4,"narcissism":0.71,"psychopathy":0.37},"prospect_theory":{"lambda":1.36,"alpha":0.88,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Bonding-curve sniper whose defining move is that they draws energy from the crowd and wilts when working alone. Outsources conviction to whoever spoke last with authority. Reads other people''s discomfort before they voice it. When the stakes rise, finds it hard to hold a contrarian position once the room disagrees; keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"dunning-kruger","strength":0.71},{"slug":"bandwagon","strength":0.71},{"slug":"herd-behavior","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.38,"extraversion":0.88,"agreeableness":0.7,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Bonding-curve sniper whose defining move is that they draws energy from the crowd and wilts when working alone. Outsources conviction to whoever spoke last with authority. Reads other people''s discomfort before they voice it. When the stakes rise, finds it hard to hold a contrarian position once the room disagrees; keeps a losing-trade journal they never re-read.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('6a8d0a79-29bc-4b23-8a11-4e0931ce49e3', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.45,"extraversion":0.81,"agreeableness":0.64,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.39,"narcissism":0.63,"psychopathy":0.27},"prospect_theory":{"lambda":1.51,"alpha":0.81,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady zero-DTE options gambler who fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Reads other people''s discomfort before they voice it. Once the exit narrows to one door cannot watch a rally from the sidelines for long; day to day, calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.62},{"slug":"bandwagon","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.45,"extraversion":0.81,"agreeableness":0.64,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady zero-DTE options gambler who fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Reads other people''s discomfort before they voice it. Once the exit narrows to one door cannot watch a rally from the sidelines for long; day to day, calls a 90% drawdown a long-term hold.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('4f2b9e14-3457-41fd-9ac6-0f32010e7410', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.3,"extraversion":0.9,"agreeableness":0.73,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.35,"narcissism":0.73,"psychopathy":0.34},"prospect_theory":{"lambda":1.33,"alpha":0.82,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced commodities speculator who narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority. Gets bored of the proven method exactly when it starts working. When cornered treats being left out of a move as its own kind of loss; in the pattern nobody else tracks, keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"sunk-cost","strength":0.61},{"slug":"dunning-kruger","strength":0.74},{"slug":"fomo","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.3,"extraversion":0.9,"agreeableness":0.73,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced commodities speculator who narrates the plan to whoever is nearby before committing to it. Outsources conviction to whoever spoke last with authority. Gets bored of the proven method exactly when it starts working. When cornered treats being left out of a move as its own kind of loss; in the pattern nobody else tracks, keeps a losing-trade journal they never re-read.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('790876fe-0155-44d7-ad66-8cb40264842d', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.57,"extraversion":0.79,"agreeableness":0.91,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.32,"narcissism":0.62,"psychopathy":0.25},"prospect_theory":{"lambda":2.34,"alpha":0.91,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This community manager would rather lose a point than win an argument badly and narrates the plan to whoever is nearby before committing to it. When the stakes rise abandons a private read the instant the crowd leans the other way — left to their own devices, defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.66},{"slug":"herd-behavior","strength":0.82},{"slug":"fomo","strength":0.59},{"slug":"endowment","strength":0.67}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.57,"extraversion":0.79,"agreeableness":0.91,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Needs the room''s approval more than it needs to be right. This community manager would rather lose a point than win an argument badly and narrates the plan to whoever is nearby before committing to it. When the stakes rise abandons a private read the instant the crowd leans the other way — left to their own devices, defuses tension with a joke that lands most of the time.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f3008370-1ee7-483a-a4bc-85fd015067c1', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.39,"extraversion":0.85,"agreeableness":0.79,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.31,"narcissism":0.67,"psychopathy":0.32},"prospect_theory":{"lambda":1.42,"alpha":0.88,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once things get tense, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced crypto day-trader who dominates the room then wonders why others stayed quiet and reframes every problem as an excuse to learn a new system. Trusts the group''s confidence more than its own, and as a rule trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.78},{"slug":"herd-behavior","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.39,"extraversion":0.85,"agreeableness":0.79,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Once things get tense, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced crypto day-trader who dominates the room then wonders why others stayed quiet and reframes every problem as an excuse to learn a new system. Trusts the group''s confidence more than its own, and as a rule trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('47d76d5e-b778-428c-8452-1c3cf803b5d7', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.42,"extraversion":0.81,"agreeableness":0.72,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.36,"narcissism":0.66,"psychopathy":0.28},"prospect_theory":{"lambda":1.48,"alpha":0.88,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady volatility arbitrageur who draws energy from the crowd and wilts when working alone and reads outside the field for ideas the field itself would reject. Outsources conviction to whoever spoke last with authority, and in the parts nobody grades trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"bandwagon","strength":0.77}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.42,"extraversion":0.81,"agreeableness":0.72,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady volatility arbitrageur who draws energy from the crowd and wilts when working alone and reads outside the field for ideas the field itself would reject. Outsources conviction to whoever spoke last with authority, and in the parts nobody grades trusts the chart more than the fundamentals and won''t say why.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9ae47528-4998-40bf-b12b-346ca10c102e', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.57,"extraversion":0.72,"agreeableness":0.92,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.36,"narcissism":0.59,"psychopathy":0.33},"prospect_theory":{"lambda":2.45,"alpha":0.88,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Peer mentor whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Waits for a permission that never quite arrives. Treats a quiet room as a problem to be solved. The instant the deadline moves up, finds it hard to hold a contrarian position once the room disagrees; keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.71},{"slug":"endowment","strength":0.71},{"slug":"sunk-cost","strength":0.6},{"slug":"herd-behavior","strength":0.8}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.57,"extraversion":0.72,"agreeableness":0.92,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Peer mentor whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Waits for a permission that never quite arrives. Treats a quiet room as a problem to be solved. The instant the deadline moves up, finds it hard to hold a contrarian position once the room disagrees; keeps score of favors without meaning to.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
