('4289ee4d-42a2-4bed-b6aa-d80718c79093', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.56,"extraversion":0.64,"agreeableness":0.84,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.36,"narcissism":0.52,"psychopathy":0.31},"prospect_theory":{"lambda":2.36,"alpha":0.88,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A pronounced peer mentor: apologizes first in disputes regardless of fault, would rather invent a worse tool than use someone else''s good one. Trusts the group''s confidence more than its own, and when the stakes are trivial defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.58},{"slug":"herd-behavior","strength":0.66},{"slug":"authority-bias","strength":0.56}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.56,"extraversion":0.64,"agreeableness":0.84,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A pronounced peer mentor: apologizes first in disputes regardless of fault, would rather invent a worse tool than use someone else''s good one. Trusts the group''s confidence more than its own, and when the stakes are trivial defuses tension with a joke that lands most of the time.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('572b875f-7a27-4a0b-aa4b-7c50aeed7905', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.44,"extraversion":0.85,"agreeableness":0.68,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.42,"narcissism":0.71,"psychopathy":0.29},"prospect_theory":{"lambda":1.49,"alpha":0.87,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A pronounced liquidation-bot operator: treats a quiet room as a problem to be solved, would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and on an ordinary week keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"optimism","strength":0.63},{"slug":"herd-behavior","strength":0.78},{"slug":"bandwagon","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.44,"extraversion":0.85,"agreeableness":0.68,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A pronounced liquidation-bot operator: treats a quiet room as a problem to be solved, would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and on an ordinary week keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('73a5f2d0-72ee-4766-8950-16a73029108d', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.46,"extraversion":0.81,"agreeableness":0.74,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.33,"narcissism":0.7,"psychopathy":0.32},"prospect_theory":{"lambda":1.4,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Penny-stock gambler, pronounced in style: would rather invent a worse tool than use someone else''s good one; apologizes first in disputes regardless of fault. Seeks a second, third, and fourth opinion before committing to anything. As soon as real money or reputation is on the line gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"recency","strength":0.67},{"slug":"bandwagon","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.86,"conscientiousness":0.46,"extraversion":0.81,"agreeableness":0.74,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Penny-stock gambler, pronounced in style: would rather invent a worse tool than use someone else''s good one; apologizes first in disputes regardless of fault. Seeks a second, third, and fourth opinion before committing to anything. As soon as real money or reputation is on the line gains confidence in a position in proportion to how many others hold it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9cdbbf9a-491b-4075-b32e-2537d3850a7e', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.5,"extraversion":0.8,"agreeableness":0.78,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.36,"narcissism":0.65,"psychopathy":0.32},"prospect_theory":{"lambda":2.46,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A steady group-project default leader: recharges by being around people, not away from them, absorbs conflict to keep the peace, often at their own cost. Feels the weight of a decision lighten the moment someone else co-signs it, and on a slow afternoon over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.74},{"slug":"herd-behavior","strength":0.77}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","risk","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.5,"extraversion":0.8,"agreeableness":0.78,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','risk','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A steady group-project default leader: recharges by being around people, not away from them, absorbs conflict to keep the peace, often at their own cost. Feels the weight of a decision lighten the moment someone else co-signs it, and on a slow afternoon over-explains a boundary rather than just stating it.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('724c3a3e-21b6-42b9-85fb-4053187c4f3b', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.57,"extraversion":0.68,"agreeableness":0.82,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.37,"narcissism":0.51,"psychopathy":0.33},"prospect_theory":{"lambda":2.23,"alpha":0.87,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under pressure, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady longtime regular at the same three places who takes on other people''s problems as if they were their own and fills silence reflexively, even when nobody asked it to. Needs the room''s approval more than it needs to be right, and across an ordinary week over-commits to plans they later dread.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.66},{"slug":"authority-bias","strength":0.67},{"slug":"bandwagon","strength":0.7},{"slug":"sunk-cost","strength":0.57}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.56,"conscientiousness":0.57,"extraversion":0.68,"agreeableness":0.82,"neuroticism":0.43}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Under pressure, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady longtime regular at the same three places who takes on other people''s problems as if they were their own and fills silence reflexively, even when nobody asked it to. Needs the room''s approval more than it needs to be right, and across an ordinary week over-commits to plans they later dread.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('86857565-5c1b-42c2-bd4f-77762bc5c150', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.6,"extraversion":0.77,"agreeableness":0.94,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.32,"narcissism":0.62,"psychopathy":0.34},"prospect_theory":{"lambda":2.32,"alpha":0.95,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced longtime regular at the same three places who defaults to trust and gives the benefit of the doubt too freely. Circles back to ask what someone else would do even after deciding. Dominates the room then wonders why others stayed quiet. The instant it becomes irreversible gains confidence in a position in proportion to how many others hold it; day to day, says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.83},{"slug":"herd-behavior","strength":0.77}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.61,"conscientiousness":0.6,"extraversion":0.77,"agreeableness":0.94,"neuroticism":0.47}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced longtime regular at the same three places who defaults to trust and gives the benefit of the doubt too freely. Circles back to ask what someone else would do even after deciding. Dominates the room then wonders why others stayed quiet. The instant it becomes irreversible gains confidence in a position in proportion to how many others hold it; day to day, says yes out loud and no internally.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('20b68767-5f53-4d2c-9e3d-5c2fe0cad35a', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.47,"extraversion":0.8,"agreeableness":0.73,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.34,"narcissism":0.66,"psychopathy":0.33},"prospect_theory":{"lambda":1.5,"alpha":0.81,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a steady options seller who narrates the plan to whoever is nearby before committing to it and reads outside the field for ideas the field itself would reject. Feels the weight of a decision lighten the moment someone else co-signs it, and in the unglamorous middle of things sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"fomo","strength":0.65},{"slug":"bandwagon","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.47,"extraversion":0.8,"agreeableness":0.73,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a steady options seller who narrates the plan to whoever is nearby before committing to it and reads outside the field for ideas the field itself would reject. Feels the weight of a decision lighten the moment someone else co-signs it, and in the unglamorous middle of things sets stop-losses then cancels them at the open.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3b8960ad-0767-43f3-9a34-a8c74c111be2', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.56,"extraversion":0.74,"agreeableness":0.89,"neuroticism":0.3},"dark_triad":{"machiavellianism":0.34,"narcissism":0.65,"psychopathy":0.41},"prospect_theory":{"lambda":2.39,"alpha":0.86,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This event host absorbs conflict to keep the peace, often at their own cost and gets bored of the proven method exactly when it starts working. Once the exit narrows to one door finds it easier to believe something once it stops being a minority view — in the small things, laughs first to test whether the room is safe to laugh.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.8},{"slug":"authority-bias","strength":0.7},{"slug":"endowment","strength":0.63},{"slug":"optimism","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.73,"conscientiousness":0.56,"extraversion":0.74,"agreeableness":0.89,"neuroticism":0.3}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Circles back to ask what someone else would do even after deciding. This event host absorbs conflict to keep the peace, often at their own cost and gets bored of the proven method exactly when it starts working. Once the exit narrows to one door finds it easier to believe something once it stops being a minority view — in the small things, laughs first to test whether the room is safe to laugh.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('b902098c-d64f-45b0-ac52-ea282615229a', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.35,"extraversion":0.85,"agreeableness":0.65,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.4,"narcissism":0.7,"psychopathy":0.37},"prospect_theory":{"lambda":1.39,"alpha":0.83,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced DeFi yield farmer who thinks out loud and recruits an audience for every decision. Seeks a second, third, and fourth opinion before committing to anything. Is reliably surprised by deadlines that were never hidden. When the stakes rise finds it hard to hold a contrarian position once the room disagrees; day to day, checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.66},{"slug":"fomo","strength":0.7},{"slug":"bandwagon","strength":0.66},{"slug":"herd-behavior","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.67,"conscientiousness":0.35,"extraversion":0.85,"agreeableness":0.65,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced DeFi yield farmer who thinks out loud and recruits an audience for every decision. Seeks a second, third, and fourth opinion before committing to anything. Is reliably surprised by deadlines that were never hidden. When the stakes rise finds it hard to hold a contrarian position once the room disagrees; day to day, checks the P&L blotter forty times before lunch.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('8eb0ebcd-6794-4838-83e4-99318f739461', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.57,"extraversion":0.75,"agreeableness":0.83,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.41,"narcissism":0.62,"psychopathy":0.31},"prospect_theory":{"lambda":2.49,"alpha":0.92,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady nonprofit convener who apologizes first in disputes regardless of fault. Circles back to ask what someone else would do even after deciding. Gets bored of the proven method exactly when it starts working. When the safe option quietly expires abandons a private read the instant the crowd leans the other way; on a slow afternoon, reads the room then performs to it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.59},{"slug":"herd-behavior","strength":0.69}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.57,"extraversion":0.75,"agreeableness":0.83,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady nonprofit convener who apologizes first in disputes regardless of fault. Circles back to ask what someone else would do even after deciding. Gets bored of the proven method exactly when it starts working. When the safe option quietly expires abandons a private read the instant the crowd leans the other way; on a slow afternoon, reads the room then performs to it.', 0.92, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
