('21c76f6c-96a9-4776-a900-619dc34474bd', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.54,"extraversion":0.64,"agreeableness":0.91,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.37,"narcissism":0.56,"psychopathy":0.27},"prospect_theory":{"lambda":2.35,"alpha":0.89,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When someone is watching the outcome, second-guesses its own read the moment someone senior disagrees. Otherwise, a pronounced the friend who always drives who reads other people''s discomfort before they voice it and draws energy from the crowd and wilts when working alone. Circles back to ask what someone else would do even after deciding, and left to their own devices says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.66},{"slug":"endowment","strength":0.68},{"slug":"bandwagon","strength":0.7},{"slug":"authority-bias","strength":0.71}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.7,"conscientiousness":0.54,"extraversion":0.64,"agreeableness":0.91,"neuroticism":0.55}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When someone is watching the outcome, second-guesses its own read the moment someone senior disagrees. Otherwise, a pronounced the friend who always drives who reads other people''s discomfort before they voice it and draws energy from the crowd and wilts when working alone. Circles back to ask what someone else would do even after deciding, and left to their own devices says yes out loud and no internally.', 0.98, 'approved', 'efad67da-ca57-