('325f5f81-c20d-41d5-838c-6966a7496c7b', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.4,"extraversion":0.93,"agreeableness":0.7,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.35,"narcissism":0.73,"psychopathy":0.33},"prospect_theory":{"lambda":1.25,"alpha":0.82,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Macro allocator whose defining move is that they thinks out loud and recruits an audience for every decision. Circles back to ask what someone else would do even after deciding. Reads outside the field for ideas the field itself would reject. In a pinch, cannot watch a rally from the sidelines for long; keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"fomo","strength":0.81}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.4,"extraversion":0.93,"agreeableness":0.7,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Macro allocator whose defining move is that they thinks out loud and recruits an audience for every decision. Circles back to ask what someone else would do even after deciding. Reads outside the field for ideas the field itself would reject. In a pinch, cannot watch a rally from the sidelines for long; keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('3540a859-a760-4401-8421-66888176108a', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.3,"extraversion":0.93,"agreeableness":0.73,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.39,"narcissism":0.78,"psychopathy":0.35},"prospect_theory":{"lambda":1.25,"alpha":0.82,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A pronounced airdrop farmer: fills silence reflexively, even when nobody asked it to, starts strong and lets follow-through evaporate. Seeks a second, third, and fourth opinion before committing to anything, and in the unglamorous middle of things names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.78},{"slug":"herd-behavior","strength":0.82}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.83,"conscientiousness":0.3,"extraversion":0.93,"agreeableness":0.73,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A pronounced airdrop farmer: fills silence reflexively, even when nobody asked it to, starts strong and lets follow-through evaporate. Seeks a second, third, and fourth opinion before committing to anything, and in the unglamorous middle of things names every strategy after the trade that almost worked.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e88f4383-3cb5-4e7d-b444-3b867b6cca99', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.33,"extraversion":0.9,"agreeableness":0.73,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.4,"narcissism":0.79,"psychopathy":0.39},"prospect_theory":{"lambda":1.55,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A pronounced discretionary swing trader: narrates the plan to whoever is nearby before committing to it, absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own, and when no one is watching keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"dunning-kruger","strength":0.7},{"slug":"sunk-cost","strength":0.61},{"slug":"bandwagon","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.71,"conscientiousness":0.33,"extraversion":0.9,"agreeableness":0.73,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A pronounced discretionary swing trader: narrates the plan to whoever is nearby before committing to it, absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own, and when no one is watching keeps three monitors for a portfolio that fits on one screen.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9a006872-ee37-4f7d-affc-973c0c4c88c4', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.62,"extraversion":0.77,"agreeableness":0.91,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.4,"narcissism":0.58,"psychopathy":0.3},"prospect_theory":{"lambda":2.29,"alpha":0.93,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This unofficial group historian absorbs conflict to keep the peace, often at their own cost and over-prepares to the point of diminishing returns. When there is no clean exit finds it hard to hold a contrarian position once the room disagrees — on an ordinary week, keeps score of favors without meaning to.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.77},{"slug":"herd-behavior","strength":0.82}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.58,"conscientiousness":0.62,"extraversion":0.77,"agreeableness":0.91,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Outsources conviction to whoever spoke last with authority. This unofficial group historian absorbs conflict to keep the peace, often at their own cost and over-prepares to the point of diminishing returns. When there is no clean exit finds it hard to hold a contrarian position once the room disagrees — on an ordinary week, keeps score of favors without meaning to.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('fc079ac4-49e2-4658-8b88-9fd982822e20', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.7,"extraversion":0.68,"agreeableness":0.73,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.46,"narcissism":0.6,"psychopathy":0.26},"prospect_theory":{"lambda":2.25,"alpha":0.96,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A steady neighborhood connector: would rather lose a point than win an argument badly, chases novel frameworks and abandons them once the novelty fades. Feels the weight of a decision lighten the moment someone else co-signs it, and without an audience keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.62},{"slug":"herd-behavior","strength":0.61}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.69,"conscientiousness":0.7,"extraversion":0.68,"agreeableness":0.73,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Gains confidence in a position in proportion to how many others hold it. A steady neighborhood connector: would rather lose a point than win an argument badly, chases novel frameworks and abandons them once the novelty fades. Feels the weight of a decision lighten the moment someone else co-signs it, and without an audience keeps a mental ledger of social debts.', 0.89, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('85c11e8e-472e-4f39-92aa-de4bfd810a4d', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.33,"extraversion":0.77,"agreeableness":0.67,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.38,"narcissism":0.64,"psychopathy":0.33},"prospect_theory":{"lambda":1.44,"alpha":0.84,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Liquidation-bot operator, steady in style: chases novel frameworks and abandons them once the novelty fades; is reliably surprised by deadlines that were never hidden. Circles back to ask what someone else would do even after deciding. The instant it becomes irreversible takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.58},{"slug":"herd-behavior","strength":0.72},{"slug":"bandwagon","strength":0.71},{"slug":"fomo","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.33,"extraversion":0.77,"agreeableness":0.67,"neuroticism":0.54}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Liquidation-bot operator, steady in style: chases novel frameworks and abandons them once the novelty fades; is reliably surprised by deadlines that were never hidden. Circles back to ask what someone else would do even after deciding. The instant it becomes irreversible takes the crowd''s confidence as a substitute for its own analysis.', 0.9, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('41d828d8-654c-4c5e-b781-62733e4fc7f7', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.69,"extraversion":0.76,"agreeableness":0.89,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.39,"narcissism":0.61,"psychopathy":0.26},"prospect_theory":{"lambda":2.45,"alpha":0.89,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Peer mentor whose defining move is that they reads other people''s discomfort before they voice it. Outsources conviction to whoever spoke last with authority. Collects half-finished manifestos and unconventional methods. When the downside gets concrete, abandons a private read the instant the crowd leans the other way; laughs first to test whether the room is safe to laugh.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.77},{"slug":"bandwagon","strength":0.74}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.69,"extraversion":0.76,"agreeableness":0.89,"neuroticism":0.53}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Peer mentor whose defining move is that they reads other people''s discomfort before they voice it. Outsources conviction to whoever spoke last with authority. Collects half-finished manifestos and unconventional methods. When the downside gets concrete, abandons a private read the instant the crowd leans the other way; laughs first to test whether the room is safe to laugh.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('c20001ce-dd9e-4ade-8f23-00e04fb4be9e', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.43,"extraversion":0.89,"agreeableness":0.61,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.36,"narcissism":0.74,"psychopathy":0.3},"prospect_theory":{"lambda":1.31,"alpha":0.83,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Algorithmic market-maker, pronounced in style: recharges by being around people, not away from them; chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding. When someone is watching the outcome finds it easier to believe something once it stops being a minority view.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.63},{"slug":"fomo","strength":0.74},{"slug":"bandwagon","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.65,"conscientiousness":0.43,"extraversion":0.89,"agreeableness":0.61,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Algorithmic market-maker, pronounced in style: recharges by being around people, not away from them; chases novel frameworks and abandons them once the novelty fades. Circles back to ask what someone else would do even after deciding. When someone is watching the outcome finds it easier to believe something once it stops being a minority view.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('abc8b32d-b31f-487a-8535-30ef0b34e83c', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.61,"extraversion":0.75,"agreeableness":0.89,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.34,"narcissism":0.57,"psychopathy":0.32},"prospect_theory":{"lambda":2.39,"alpha":0.91,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the safe option quietly expires, adopts a conviction mainly because the room already has. Otherwise, a pronounced team captain who measures decisions by who they might upset and gets bored of the proven method exactly when it starts working. Outsources conviction to whoever spoke last with authority, and across an ordinary week keeps a mental ledger of social debts.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.8},{"slug":"bandwagon","strength":0.81},{"slug":"authority-bias","strength":0.59},{"slug":"fomo","strength":0.64}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","decision-making","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.61,"extraversion":0.75,"agreeableness":0.89,"neuroticism":0.57}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','decision-making','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the safe option quietly expires, adopts a conviction mainly because the room already has. Otherwise, a pronounced team captain who measures decisions by who they might upset and gets bored of the proven method exactly when it starts working. Outsources conviction to whoever spoke last with authority, and across an ordinary week keeps a mental ledger of social debts.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('f91d19b5-0c48-4619-b9d3-b27203edc89d', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.7,"extraversion":0.69,"agreeableness":0.88,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.39,"narcissism":0.53,"psychopathy":0.33},"prospect_theory":{"lambda":2.33,"alpha":0.92,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A pronounced event host: apologizes first in disputes regardless of fault, reframes every problem as an excuse to learn a new system. Seeks a second, third, and fourth opinion before committing to anything, and across an ordinary week texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.62},{"slug":"bandwagon","strength":0.75}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.66,"conscientiousness":0.7,"extraversion":0.69,"agreeableness":0.88,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A pronounced event host: apologizes first in disputes regardless of fault, reframes every problem as an excuse to learn a new system. Seeks a second, third, and fourth opinion before committing to anything, and across an ordinary week texts an apology before confirming anyone is upset.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('9f6323dc-b66b-4e6f-9e63-5ea68eb230f2', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.42,"extraversion":0.84,"agreeableness":0.63,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.41,"narcissism":0.7,"psychopathy":0.35},"prospect_theory":{"lambda":1.44,"alpha":0.82,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced quant researcher who draws energy from the crowd and wilts when working alone. Feels the weight of a decision lighten the moment someone else co-signs it. Apologizes first in disputes regardless of fault. The instant it becomes irreversible finds it hard to hold a contrarian position once the room disagrees; without an audience, refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.6},{"slug":"dunning-kruger","strength":0.67},{"slug":"herd-behavior","strength":0.74},{"slug":"fomo","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.72,"conscientiousness":0.42,"extraversion":0.84,"agreeableness":0.63,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A pronounced quant researcher who draws energy from the crowd and wilts when working alone. Feels the weight of a decision lighten the moment someone else co-signs it. Apologizes first in disputes regardless of fault. The instant it becomes irreversible finds it hard to hold a contrarian position once the room disagrees; without an audience, refreshes the order book compulsively during lunch.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('41614e77-6e8d-452f-9a1f-af8e795e757d', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.57,"extraversion":0.84,"agreeableness":0.84,"neuroticism":0.33},"dark_triad":{"machiavellianism":0.37,"narcissism":0.68,"psychopathy":0.35},"prospect_theory":{"lambda":2.57,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When cornered, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced group-chat ringleader who fills silence reflexively, even when nobody asked it to and apologizes first in disputes regardless of fault. Feels the weight of a decision lighten the moment someone else co-signs it, and in the unglamorous middle of things defuses tension with a joke that lands most of the time.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.58},{"slug":"fomo","strength":0.62},{"slug":"herd-behavior","strength":0.75},{"slug":"bandwagon","strength":0.79}],"tags":["social","dependent","community","mediator","high-agreeableness","outgoing","cognition","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.67,"conscientiousness":0.57,"extraversion":0.84,"agreeableness":0.84,"neuroticism":0.33}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','outgoing','cognition','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When cornered, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced group-chat ringleader who fills silence reflexively, even when nobody asked it to and apologizes first in disputes regardless of fault. Feels the weight of a decision lighten the moment someone else co-signs it, and in the unglamorous middle of things defuses tension with a joke that lands most of the time.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238