('126d8d85-4990-4700-a554-5d4ddd4a6196', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.3,"extraversion":0.74,"agreeableness":0.72,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.39,"narcissism":0.58,"psychopathy":0.34},"prospect_theory":{"lambda":1.43,"alpha":0.8,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A steady index-fund holdout: reframes every problem as an excuse to learn a new system, reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own, and when the stakes are trivial sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"herd-behavior","strength":0.69},{"slug":"recency","strength":0.65},{"slug":"fomo","strength":0.61}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","open-minded","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.83,"conscientiousness":0.3,"extraversion":0.74,"agreeableness":0.72,"neuroticism":0.62}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','open-minded','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A steady index-fund holdout: reframes every problem as an excuse to learn a new system, reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own, and when the stakes are trivial sets alerts for a coin they already checked a minute ago.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('2b215f8c-d27b-4341-a580-98b4d53f7e06', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.46,"extraversion":0.78,"agreeableness":0.59,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.38,"narcissism":0.65,"psychopathy":0.3},"prospect_theory":{"lambda":1.38,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Crypto day-trader whose defining move is that they fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Reframes every problem as an excuse to learn a new system. Once the exit narrows to one door, adopts a conviction mainly because the room already has; calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.61},{"slug":"dunning-kruger","strength":0.61},{"slug":"bandwagon","strength":0.69},{"slug":"herd-behavior","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.46,"extraversion":0.78,"agreeableness":0.59,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Crypto day-trader whose defining move is that they fills silence reflexively, even when nobody asked it to. Seeks a second, third, and fourth opinion before committing to anything. Reframes every problem as an excuse to learn a new system. Once the exit narrows to one door, adopts a conviction mainly because the room already has; calls a 90% drawdown a long-term hold.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('32f20645-b3ec-4841-bb9f-2b65242e8c08', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.68,"extraversion":0.69,"agreeableness":0.89,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.42,"narcissism":0.57,"psychopathy":0.31},"prospect_theory":{"lambda":2.31,"alpha":0.89,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Wedding-party diplomat, pronounced in style: reads other people''s discomfort before they voice it; recharges by being around people, not away from them. Waits for a permission that never quite arrives. When the downside gets concrete gains confidence in a position in proportion to how many others hold it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"bandwagon","strength":0.72}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","temperament","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.68,"extraversion":0.69,"agreeableness":0.89,"neuroticism":0.4}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','temperament','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Wedding-party diplomat, pronounced in style: reads other people''s discomfort before they voice it; recharges by being around people, not away from them. Waits for a permission that never quite arrives. When the downside gets concrete gains confidence in a position in proportion to how many others hold it.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
