('407be721-de2e-41c0-9e12-c2b07243c027', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.37,"extraversion":0.89,"agreeableness":0.64,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.41,"narcissism":0.72,"psychopathy":0.33},"prospect_theory":{"lambda":1.49,"alpha":0.87,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A pronounced onchain copy-trader: narrates the plan to whoever is nearby before committing to it, leaves loose ends and trusts future-self to handle them. Outsources conviction to whoever spoke last with authority, and in the pattern nobody else tracks refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"recency","strength":0.61},{"slug":"herd-behavior","strength":0.75},{"slug":"dunning-kruger","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.37,"extraversion":0.89,"agreeableness":0.64,"neuroticism":0.59}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Abandons a private read the instant the crowd leans the other way. A pronounced onchain copy-trader: narrates the plan to whoever is nearby before committing to it, leaves loose ends and trusts future-self to handle them. Outsources conviction to whoever spoke last with authority, and in the pattern nobody else tracks refreshes the order book compulsively during lunch.', 0.95, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('7473a2c3-4a32-483c-a1ef-9f566ff89ecc', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.62,"extraversion":0.66,"agreeableness":0.83,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.4,"narcissism":0.56,"psychopathy":0.31},"prospect_theory":{"lambda":2.44,"alpha":0.92,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A steady community manager: takes on other people''s problems as if they were their own, draws energy from the crowd and wilts when working alone. Waits for a permission that never quite arrives, and without an audience can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.6},{"slug":"authority-bias","strength":0.59},{"slug":"bandwagon","strength":0.74}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.68,"conscientiousness":0.62,"extraversion":0.66,"agreeableness":0.83,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Finds it easier to believe something once it stops being a minority view. A steady community manager: takes on other people''s problems as if they were their own, draws energy from the crowd and wilts when working alone. Waits for a permission that never quite arrives, and without an audience can sense a mood shift from the doorway.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('1b245763-7d71-428a-9948-2fc7cb337dbe', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.51,"extraversion":0.86,"agreeableness":0.69,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.35,"narcissism":0.67,"psychopathy":0.26},"prospect_theory":{"lambda":1.42,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Commodities speculator whose defining move is that they recharges by being around people, not away from them. Needs the room''s approval more than it needs to be right. Needs repeated reassurance that a decision was the right one. As soon as real money or reputation is on the line, finds it easier to believe something once it stops being a minority view; holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.66},{"slug":"optimism","strength":0.63},{"slug":"bandwagon","strength":0.68},{"slug":"recency","strength":0.57}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.51,"extraversion":0.86,"agreeableness":0.69,"neuroticism":0.62}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Commodities speculator whose defining move is that they recharges by being around people, not away from them. Needs the room''s approval more than it needs to be right. Needs repeated reassurance that a decision was the right one. As soon as real money or reputation is on the line, finds it easier to believe something once it stops being a minority view; holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('79e2193d-5441-4920-b8e1-4115d885eac9', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.58,"extraversion":0.7,"agreeableness":0.83,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.36,"narcissism":0.56,"psychopathy":0.32},"prospect_theory":{"lambda":2.5,"alpha":0.92,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the walls close in, adopts a conviction mainly because the room already has. Otherwise, a steady neighborhood connector who would rather lose a point than win an argument badly and draws energy from the crowd and wilts when working alone. Trusts the group''s confidence more than its own, and day to day can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.69},{"slug":"authority-bias","strength":0.67},{"slug":"bandwagon","strength":0.74}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","cognition","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.62,"conscientiousness":0.58,"extraversion":0.7,"agreeableness":0.83,"neuroticism":0.49}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','cognition','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the walls close in, adopts a conviction mainly because the room already has. Otherwise, a steady neighborhood connector who would rather lose a point than win an argument badly and draws energy from the crowd and wilts when working alone. Trusts the group''s confidence more than its own, and day to day can sense a mood shift from the doorway.', 0.93, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('50144690-786d-4735-94a4-fd215061067d', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.79,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.38,"narcissism":0.62,"psychopathy":0.39},"prospect_theory":{"lambda":1.56,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady MEV searcher who draws energy from the crowd and wilts when working alone. Waits for a permission that never quite arrives. Reads outside the field for ideas the field itself would reject. When the stakes rise takes the crowd''s confidence as a substitute for its own analysis; once the urgency drains out, holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"fomo","strength":0.71},{"slug":"herd-behavior","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.67,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.79,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady MEV searcher who draws energy from the crowd and wilts when working alone. Waits for a permission that never quite arrives. Reads outside the field for ideas the field itself would reject. When the stakes rise takes the crowd''s confidence as a substitute for its own analysis; once the urgency drains out, holds a bag from 2021 out of pure spite.', 0.97, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e5181f7b-a3b7-40e3-ae65-574f922ad0e1', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.49,"extraversion":0.89,"agreeableness":0.68,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.38,"narcissism":0.73,"psychopathy":0.32},"prospect_theory":{"lambda":1.25,"alpha":0.83,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Prop-desk scalper, pronounced in style: treats a quiet room as a problem to be solved; would rather invent a worse tool than use someone else''s good one. Trusts the group''s confidence more than its own. When the walls close in abandons a private read the instant the crowd leans the other way.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.81},{"slug":"bandwagon","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.49,"extraversion":0.89,"agreeableness":0.68,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Prop-desk scalper, pronounced in style: treats a quiet room as a problem to be solved; would rather invent a worse tool than use someone else''s good one. Trusts the group''s confidence more than its own. When the walls close in abandons a private read the instant the crowd leans the other way.', 0.98, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('bc831d39-be5b-480e-b9bd-b800d319abb9', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.68,"extraversion":0.64,"agreeableness":0.78,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.45,"narcissism":0.53,"psychopathy":0.3},"prospect_theory":{"lambda":2.52,"alpha":0.93,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady unofficial group historian who reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Draws energy from the crowd and wilts when working alone. The moment it stops being hypothetical adopts a conviction mainly because the room already has; in the version no one reviews, says yes out loud and no internally.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.64},{"slug":"endowment","strength":0.53},{"slug":"authority-bias","strength":0.54}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","risk","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.65,"conscientiousness":0.68,"extraversion":0.64,"agreeableness":0.78,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','risk','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'A steady unofficial group historian who reads other people''s discomfort before they voice it. Trusts the group''s confidence more than its own. Draws energy from the crowd and wilts when working alone. The moment it stops being hypothetical adopts a conviction mainly because the room already has; in the version no one reviews, says yes out loud and no internally.', 0.96, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('a8718bdc-3cda-4aa6-88ff-bd266bc74874', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.44,"extraversion":0.84,"agreeableness":0.8,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.37,"narcissism":0.64,"psychopathy":0.29},"prospect_theory":{"lambda":1.45,"alpha":0.87,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the downside gets concrete, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced options seller who draws energy from the crowd and wilts when working alone and collects half-finished manifestos and unconventional methods. Feels the weight of a decision lighten the moment someone else co-signs it, and in the parts nobody grades talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.62},{"slug":"fomo","strength":0.74},{"slug":"endowment","strength":0.66},{"slug":"bandwagon","strength":0.81}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.44,"extraversion":0.84,"agreeableness":0.8,"neuroticism":0.64}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the downside gets concrete, gains confidence in a position in proportion to how many others hold it. Otherwise, a pronounced options seller who draws energy from the crowd and wilts when working alone and collects half-finished manifestos and unconventional methods. Feels the weight of a decision lighten the moment someone else co-signs it, and in the parts nobody grades talks in win rate and never mentions size.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
('e351408f-36eb-4e24-9a90-044227ebc50b', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.36,"extraversion":0.82,"agreeableness":0.64,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.38,"narcissism":0.7,"psychopathy":0.35},"prospect_theory":{"lambda":1.34,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Quant researcher whose defining move is that they treats a quiet room as a problem to be solved. Seeks a second, third, and fourth opinion before committing to anything. Apologizes first in disputes regardless of fault. The instant the deadline moves up, abandons a private read the instant the crowd leans the other way; sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"dunning-kruger","strength":0.69},{"slug":"recency","strength":0.62},{"slug":"herd-behavior","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.36,"extraversion":0.82,"agreeableness":0.64,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'Quant researcher whose defining move is that they treats a quiet room as a problem to be solved. Seeks a second, third, and fourth opinion before committing to anything. Apologizes first in disputes regardless of fault. The instant the deadline moves up, abandons a private read the instant the crowd leans the other way; sets alerts for a coin they already checked a minute ago.', 0.94, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
