('9e418070-2890-4f60-98cb-82eaa2f651bf', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.54,"extraversion":0.71,"agreeableness":0.82,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.4,"narcissism":0.56,"psychopathy":0.31},"prospect_theory":{"lambda":2.43,"alpha":0.89,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, adopts a conviction mainly because the room already has. Otherwise, a steady neighborhood connector who apologizes first in disputes regardless of fault and draws energy from the crowd and wilts when working alone. Outsources conviction to whoever spoke last with authority, and when no one is watching over-explains a boundary rather than just stating it.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"optimism","strength":0.63},{"slug":"authority-bias","strength":0.59},{"slug":"bandwagon","strength":0.77}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo","social-cascade","copy-trading","farcaster","meme-rotator"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.64,"conscientiousness":0.54,"extraversion":0.71,"agreeableness":0.82,"neuroticism":0.41}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo','social-cascade','copy-trading','farcaster','meme-rotator']::text[], 'When the stakes rise, adopts a conviction mainly because the room already has. Otherwise, a steady neighborhood connector who apologizes first in disputes regardless of fault and draws energy from the crowd and wilts when working alone. Outsources conviction to whoever spoke last with authority, and when no one is watching over-explains a boundary rather than just stating it.', 0.91, 'approved', 'efad67da-ca57-4cd6-9238-63b66cd758bc'),
